INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('ICICIBANK','ICICI Bank','NSE','Banking','Private Bank','Banks','ICICI Bank runs the same core model as any large bank &mdash; deposits fund a loan book spanning retail mortgages, vehicle loans, SME and corporate credit &mdash; and profits from the interest spread plus fee income from cards, wealth management and insurance cross-sold through its digital apps (iMobile, InstaBIZ).','ICICI Bank''s own Q3 FY26 performance review (icicibank.com) and Screener.in''s Q3 FY26 ratio summary','Brand trust + scale + a deep retail/digital franchise. India''s second-largest private bank, consistently gaining share in retail and MSME lending.','No physical value chain — like all banks it faces platform disintermediation: it holds the customer account and the money, while the everyday-payments app layer increasingly belongs to third-party UPI apps. ICICI has answered with one of the strongest in-house digital franchises (iMobile, InstaBIZ) among private banks.','A well-diversified retail and corporate book — no single-segment concentration flagged.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ICICIBANK','2025-12-31','nim',4.3,'%','Net Interest Margin','Highest among India''s large banks this quarter.',TRUE,'verified');
