INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('SBIN','State Bank of India','NSE','Banking','PSU Bank','Banks','State Bank of India is the country''s largest bank by assets and branch reach, majority government-owned. It takes deposits and lends across retail, agriculture, SME and corporate India, and earns additional fee income through subsidiaries like SBI Life, SBI Cards and SBI Mutual Fund that sit alongside the core lending business.','SBI''s own Q3 FY26 press release and analyst presentation (sbi.bank.in)','Sovereign-backed trust + an unmatched branch and agent network (23,000+ branches, more than the next five banks combined) + default banker for government and PSU flows.','No physical chain; the shared platform-disintermediation dynamic — but as a majority government-owned bank, SBI also carries the state''s policy priorities (financial-inclusion mandates, social schemes, sovereign borrowing programmes) alongside commercial goals. Its BHIM and YONO stack keep it closer to the payments layer than most.',NULL);
