INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('KOTAKBANK','Kotak Mahindra Bank','NSE','Banking','Private Bank','Banks','Kotak Mahindra Bank grew out of a diversified NBFC before converting to a bank &mdash; its book still leans toward secured retail and vehicle lending alongside corporate credit. Beyond deposits and loans, the wider Kotak group earns from broking, asset management and insurance, cross-sold to the same customer base.','Kotak Mahindra Bank''s own Q3 FY26 press release (kotak.bank.in) and corroborating market coverage','Digital-first franchise + disciplined underwriting culture + one of the strongest capital positions in Indian banking — historically commands a premium valuation for exactly that reason.','No physical chain; the same platform-disintermediation dynamic as every bank. Kotak''s distinctive sensitivity: in 2024 the RBI temporarily barred it from onboarding customers digitally and issuing new credit cards over IT-resilience gaps — a reminder that for a digital-first bank, tech-compliance is itself a core operational dependency.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('KOTAKBANK','2025-12-31','nim',4.54,'%','Net Interest Margin','Down from 4.93% a year ago — margin compression is the key watch item.',TRUE,'verified');
