INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('AXISBANK','Axis Bank','NSE','Banking','Private Bank','Banks','Axis Bank is India''s third-largest private bank: it takes deposits and lends across retail, SME and corporate banking, earning the interest spread plus fee income from cards, transaction banking and third-party product distribution (insurance, mutual funds) sold to its customers.','Axis Bank''s own Q3 FY26 results announcement (axis.bank.in) and corroborating market coverage','Scale as India''s third-largest private bank + a strong digital/UPI franchise (~36-39% market share in UPI Payer PSP volume) + a diversified retail/SME/corporate mix that spreads concentration risk.','No physical chain, but Axis sits unusually close to the payments layer itself — it is one of the largest UPI payer-PSP (sponsor) banks by volume, routing a big share of UPI payer-side transactions. That is strategically central to the rails, yet revenue-light under zero-MDR.',NULL);
