INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AXISBANK','2025-12-31','bear','CASA has slid for several straight quarters (41% a year ago to 39% now) — sector-wide, but worth tracking closely for Axis specifically.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('BAJFINANCE','Bajaj Finance','NSE','Banking','NBFC - Diversified','NBFCs','Bajaj Finance is a non-deposit-taking NBFC &mdash; instead of collecting public deposits like a bank, it borrows wholesale from banks and bond markets and re-lends that money at a spread. Its signature business is point-of-sale consumer lending (EMI financing for electronics and appliances in-store), alongside personal loans, SME loans and mortgages.','Bajaj Finance''s own Q3 FY26 investor presentation (bajajfinserv.in) and corroborating market coverage','Scale + a 115 million+ customer franchise + an early, aggressive bet on embedding AI into underwriting and collections (its own ''FinAI'' platform) — a distribution and data moat that''s hard for smaller NBFCs to replicate.','No physical chain — an NBFC''s value chain is funding cost versus lending yield. Bajaj borrows wholesale (it has no CASA deposits) and lends across consumer and SME, so it is structurally more rate- and funding-sensitive than a bank, and squarely inside the unsecured-consumer-credit segment RBI has been tightening.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJFINANCE','2025-12-31','nim',NULL,'%','Net Interest Margin','Not separately headlined this quarter — management said NIM ''remained steady,'' without a number. Shown as — rather than guessed.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJFINANCE','2025-12-31','gnpa_pct',1.21,'%','Gross NPA','Improved from 1.24% the prior quarter.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJFINANCE','2025-12-31','nnpa_pct',0.47,'%','Net NPA','Improved from 0.60% the prior quarter.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJFINANCE','2025-12-31','cost_of_borrowing_pct',7.45,'%','Cost of Borrowing','What it costs Bajaj Finance to fund itself — the NBFC equivalent of a bank''s CASA ratio. Lower is better.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJFINANCE','2025-12-31','car_pct',21.45,'%','Capital Adequacy','CRAR including Tier-II capital; Tier-1 alone was 20.60%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJFINANCE','2025-12-31','loan_book_growth',22,'%','AUM Growth','YoY growth in Assets Under Management — an NBFC''s equivalent of loan book growth.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJFINANCE','Unsecured-consumer-credit regulation: RBI raised risk weights on unsecured consumer loans (Nov 2023) over overheating, and FY26 is flagged as a stress year for exactly this segment — Bajaj''s large consumer book sits in the crosshairs','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJFINANCE','Funding-cost sensitivity: with no low-cost CASA base, Bajaj''s margins move with wholesale funding costs and the RBI rate path (repo held at 5.50%, June 2026)','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJFINANCE','Scale plus an early, aggressive bet on AI in underwriting (its FinAI platform) give it a data and cost moat smaller NBFCs cannot match','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJFINANCE','2025-12-31','bull','Asset quality keeps improving, not just holding steady: Gross NPA 1.21% and Net NPA 0.47%, both down from the prior quarter.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJFINANCE','2025-12-31','bull','AUM grew 22% YoY, on track for management''s own ~22-23% guidance and crossing ₹5 lakh crore in scale shortly after this quarter.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJFINANCE','2025-12-31','bull','Capital adequacy of 21.45% is far above the regulatory minimum, with cost of borrowing easing slightly (7.45%, down 7bps QoQ) even as rates stayed elevated sector-wide.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJFINANCE','2025-12-31','bear','Reported consolidated profit actually fell ~6% YoY this quarter due to an accelerated provisioning charge — core profit (excluding that one-off) still grew 23%, but headline optics were weak.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJFINANCE','2025-12-31','bear','Unlike every bank on this dashboard, Bajaj Finance doesn''t headline a single NIM% figure — a reminder that NBFC disclosures aren''t a drop-in replacement for bank disclosures, even when the underlying business is healthy.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJFINANCE','2025-12-31','bear','MSME growth has been deliberately muted for several quarters (management itself guides 2-3 more soft quarters there) — a self-imposed brake, not a crisis, but a real near-term growth drag.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('CHOLAFIN','Cholamandalam Investment & Finance','NSE','Banking','NBFC - Diversified','NBFCs','Cholamandalam Investment & Finance (Murugappa Group) is an NBFC built mainly around vehicle finance &mdash; commercial vehicles, cars and tractors &mdash; plus home loans and SME lending. Like Bajaj Finance, it borrows wholesale and lends at a spread, so its profit is driven by loan-book growth, asset quality through vehicle-financing cycles, and its own cost of borrowing.','Cholamandalam''s own Q3 FY26 press release (murugappa.com) and corroborating market/analyst coverage','A decades-old vehicle-finance distribution network (1,600+ branches) under the Murugappa Group umbrella, now diversifying into home loans, SME and gold loans to reduce reliance on any single credit cycle — though vehicle finance concentration is still its biggest single swing factor.','No physical chain — funding cost versus lending yield. Chola is anchored in vehicle finance, so it rides the commercial-vehicle and auto cycle, with a large rural and semi-urban customer base sensitive to the monsoon and rural income.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CHOLAFIN','2025-12-31','nim',NULL,'%','Net Interest Margin','Not headlined as an absolute number this quarter — management discussed only the direction (''NIM expansion expected''), not a figure. Shown as — rather than guessed.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CHOLAFIN','2025-12-31','gnpa_pct',4.63,'%','Gross NPA','RBI/IRACP-norms basis (the more conservative of two bases Chola reports — its Ind-AS ''Stage 3'' figure runs lower, around 3.4%).',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CHOLAFIN','2025-12-31','nnpa_pct',3.13,'%','Net NPA','RBI/IRACP-norms basis, up slightly from 3.07% the prior quarter.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CHOLAFIN','2025-12-31','cost_of_borrowing_pct',NULL,'%','Cost of Borrowing','Not disclosed as a single absolute figure this quarter in available sources — shown as — rather than estimated.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CHOLAFIN','2025-12-31','car_pct',19.79,'%','Capital Adequacy','Closest available figure is as of late Nov 2025, just before quarter-end — well above the 15% regulatory minimum.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CHOLAFIN','2025-12-31','loan_book_growth',21,'%','AUM Growth','YoY growth in Assets Under Management, consistent across the surrounding quarters.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CHOLAFIN','Vehicle and CV-cycle dependence: its largest segment tracks freight demand and the auto cycle — a slowdown flows through faster than for a diversified lender','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CHOLAFIN','Rural income and climate sensitivity: a big rural and semi-urban book is exposed to monsoon-linked income volatility, a structural risk RBI has flagged for FY26','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CHOLAFIN','Diversification into home loans, SME and gold loans is reducing single-cycle dependence, and funding access stays strong under the Murugappa Group umbrella','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CHOLAFIN','2025-12-31','bull','AUM grew ~21% YoY with broad-based strength — SME loans up 41%, home loans up 23%, and its largest segment (vehicle finance) regaining momentum after a soft patch.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CHOLAFIN','2025-12-31','bull','Capital adequacy of ~19.8% is comfortably above the 15% regulatory minimum, real headroom to sustain 20%+ AUM growth ambitions.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CHOLAFIN','2025-12-31','bull','Profitability stayed strong (ROE around 18-19%) even while investing in newer, faster-growing lines like gold loans and SME finance.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CHOLAFIN','2025-12-31','bear','Asset quality is the recurring worry: Gross NPA under RBI norms (4.63%) reads meaningfully worse than the Ind-AS ''Stage 3'' figure (~3.4%) the company also reports — know which number you''re looking at before comparing Chola''s asset quality to a bank''s GNPA%, since they''re not computed the same way.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CHOLAFIN','2025-12-31','bear','Vehicle finance, still its single largest segment, has seen rising delinquencies tied to weaker rural economies more than once in the past year — a cyclical risk, not a one-off.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CHOLAFIN','2025-12-31','bear','Trades at a premium valuation (P/E well above peer median) — several analysts have flagged this as pricing in close-to-flawless execution, leaving little room for a misstep.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('SHRIRAMFIN','Shriram Finance','NSE','Banking','NBFC - Diversified','NBFCs','Shriram Finance is India''s largest NBFC focused on financing used commercial vehicles &mdash; trucks bought by small, individual transport operators who banks typically won''t lend to. It''s a relationship- and cash-flow-underwriting-driven business (formed by the 2022 merger of Shriram Transport and Shriram City Union Finance) that also does two-wheeler, gold and MSME loans.','Shriram Finance''s own Q3 FY26 earnings call and CARE/ICRA rating notes (Dec 2025)','India''s largest player in used/pre-owned commercial vehicle financing, built on a four-decade-old distribution network (3,200+ branches, ~55% rural/semi-urban) and credit-assessment expertise in a segment most banks avoid — a genuine niche-scale moat.','No physical chain — funding cost versus lending yield. Shriram is India''s largest used commercial-vehicle financier, serving a structurally riskier, more rural and self-employed borrower base most banks avoid — high yield, high funding cost, deep cycle exposure.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SHRIRAMFIN','2025-12-31','nim',8.58,'%','Net Interest Margin','Up from 8.48% a year ago and 8.19% the prior quarter — actually expanding, unlike most lenders on this dashboard. Note: this NBFC does headline NIM clearly, unlike Bajaj Finance and Cholamandalam — disclosure varies by company, not by bank-vs-NBFC as a rule.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SHRIRAMFIN','2025-12-31','gnpa_pct',4.54,'%','Gross NPA','Reported as ''Gross Stage 3 assets'' (Ind-AS basis) — improved YoY and sequentially.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SHRIRAMFIN','2025-12-31','nnpa_pct',2.38,'%','Net NPA','Reported as ''Net Stage 3 assets'' — also improved.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SHRIRAMFIN','2025-12-31','cost_of_borrowing_pct',8.69,'%','Cost of Borrowing','Overall cost of liabilities; new incremental borrowing was cheaper at 7.73% this quarter on recent credit-rating upgrades.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SHRIRAMFIN','2025-12-31','car_pct',20.7,'%','Capital Adequacy','As of 30 Sep 2025 (closest available) — a pending ₹39,618 crore MUFG Bank equity infusion hadn''t yet been reflected at quarter-end.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SHRIRAMFIN','2025-12-31','loan_book_growth',14.63,'%','AUM Growth','YoY growth in Assets Under Management.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SHRIRAMFIN','Used-CV and freight-cycle dependence: earnings track the used commercial-vehicle and freight cycle and rural incomes — a more volatile base than a diversified lender','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SHRIRAMFIN','A pending ~39,618-crore equity infusion from Japan''s MUFG Bank brings major foreign capital and a strong external vote of confidence','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SHRIRAMFIN','Funding-cost sensitivity: the highest cost of borrowing among NBFCs tracked here, though recent rating upgrades have lowered incremental borrowing costs','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHRIRAMFIN','2025-12-31','bull','NIM actually expanded to 8.58%, up from 8.48% a year ago — a rare case of margin growth while most lenders on this dashboard are seeing compression.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHRIRAMFIN','2025-12-31','bull','Asset quality keeps improving (Gross Stage 3 4.54%, Net Stage 3 2.38%, both down YoY and sequentially) despite serving a structurally riskier customer base — used commercial vehicles, MSME, rural borrowers — than almost any other lender here.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHRIRAMFIN','2025-12-31','bull','A pending ₹39,618 crore equity infusion from MUFG Bank (Japan''s largest bank) would materially strengthen the capital base and is a strong external vote of confidence in the franchise.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHRIRAMFIN','2025-12-31','bear','Reported profit fell 22% YoY this quarter — almost entirely because last year''s quarter included a one-off gain from selling its housing-finance subsidiary; core profit (excluding that) actually grew over 21%, but the headline number alone looks weak.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHRIRAMFIN','2025-12-31','bear','Cost of liabilities (8.69%) is the highest of any NBFC on this dashboard — a structurally more expensive funding base that comes with serving a riskier, more rural/retail borrower profile.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHRIRAMFIN','2025-12-31','bear','Heavily tied to India''s commercial-vehicle cycle and rural/semi-urban incomes — a freight slowdown or weak monsoon flows through to this book faster than it would for a diversified bank.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('BANKBARODA','Bank of Baroda','NSE','Banking','PSU Bank','Banks','Bank of Baroda is a government-owned (PSU) bank that takes deposits and lends across retail, agriculture, MSME and corporate India, with a meaningful overseas branch network left from its historically international footprint. Profitability is driven by its interest spread and continued recovery in asset quality after the sector-wide PSU-bank bad-loan cycle.','Bank of Baroda''s own Q3 FY26 results and corroborating market coverage','Scale as India''s second-largest PSU bank + an extensive pan-India branch network + government-backed trust — the same structural advantages as SBI, at a smaller scale, with a credibly improving balance sheet after years of post-merger cleanup.','No physical chain; the shared platform-disintermediation dynamic. As a large government-owned bank, Bank of Baroda carries state policy priorities alongside commercial goals, and emerged bigger from India''s PSU-bank consolidation (the Vijaya and Dena merger).',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANKBARODA','2025-12-31','nim',2.79,'%','Net Interest Margin','Global NIM (domestic alone was stronger, 2.93%). Lowest of any bank here, and management flags further compression below 2.75% as a key risk.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANKBARODA','2025-12-31','gnpa_pct',2.04,'%','Gross NPA','The bank''s lowest-ever Gross NPA ratio.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANKBARODA','2025-12-31','nnpa_pct',0.57,'%','Net NPA','Provision coverage ratio of 92.73% sits behind this.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANKBARODA','2025-12-31','casa_pct',38.45,'%','CASA Ratio','Lowest of any bank on this dashboard, and slipping from 39.33% a year ago.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANKBARODA','2025-12-31','car_pct',15.29,'%','Capital Adequacy','Down from 16.54% the prior quarter, mostly on risk-weighted-asset growth — still comfortably above the regulatory minimum.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANKBARODA','2025-12-31','loan_book_growth',14.65,'%','Loan Book Growth','YoY growth in global advances; RAM (Retail/Agri/MSME) now 61.8% of the book.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BANKBARODA','Government majority ownership: policy and social-mandate obligations alongside commercial objectives','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BANKBARODA','Platform disintermediation plus zero-MDR, the shared UPI dynamic','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BANKBARODA','PSU-consolidation scale (post Vijaya and Dena merger) plus a cleaned-up balance sheet make it one of the stronger PSU franchises','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANKBARODA','2025-12-31','bull','Gross NPA fell to 2.04% — the lowest in the bank''s history — backed by a 92.73% provision coverage ratio.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANKBARODA','2025-12-31','bull','Loan growth accelerated to 14.65% YoY, with RAM (Retail/Agri/MSME) now 61.8% of advances — a real shift toward higher-quality, less concentrated lending.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANKBARODA','2025-12-31','bull','Five-year net profit CAGR above 50% reflects a genuine post-recapitalisation turnaround, not a one-quarter blip.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANKBARODA','2025-12-31','bear','NIM kept compressing to 2.79% from 2.96% the prior quarter — the lowest of any bank on this dashboard, with management itself flagging further compression below 2.75% as a real risk.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANKBARODA','2025-12-31','bear','Capital adequacy slid from 16.54% to 15.29% in a single quarter, mostly from risk-weighted-asset growth — still well above the regulatory floor, but the trend is worth tracking.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANKBARODA','2025-12-31','bear','CASA ratio (38.45%) is the lowest of any bank here and continuing to slip — a structurally thinner cheap-funding cushion than the larger private banks.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('PNB','Punjab National Bank','NSE','Banking','PSU Bank','Banks','Punjab National Bank is a large PSU bank (it absorbed Oriental Bank of Commerce and United Bank of India in 2020) that takes deposits and lends across retail, agriculture and MSME India. It has historically carried a heavier bad-loan legacy than private-bank peers, a position that has been steadily improving.','PNB''s own Q3 FY26 earnings call transcript and corroborating market coverage','Over 130 years of legacy + a 10,000+ branch pan-India network + ~70% government ownership — classic PSU scale and trust, paired with an aggressive digital push (95%+ of transactions now digital).','No physical chain; the shared platform-disintermediation dynamic. Around 70% government-owned. PNB''s history includes the 2018 ~14,000-crore Nirav Modi fraud, after which its governance and operational-risk controls were rebuilt — a durable reminder that operational risk is a real line item for a bank this size and structure.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('PNB','2025-12-31','nim',2.52,'%','Net Interest Margin','Global NIM, per management''s own earnings-call figure (domestic alone was 2.65%). Down from 2.93% a year ago.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('PNB','2025-12-31','gnpa_pct',3.19,'%','Gross NPA','Down sharply from 4.09% a year ago and from 9.76% a few years before that.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('PNB','2025-12-31','nnpa_pct',0.32,'%','Net NPA','Down from 0.41% a year ago, with provision coverage near 97%.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('PNB','2025-12-31','casa_pct',37.1,'%','CASA Ratio','Among the lowest here, and still slipping.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('PNB','2025-12-31','car_pct',16.77,'%','Capital Adequacy','Up 136 bps YoY — genuinely strengthening, not just stable.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('PNB','2025-12-31','loan_book_growth',10.9,'%','Loan Book Growth','YoY growth in advances; retail lending alone grew 18.9%, led by vehicle loans (+35.7%).',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PNB','Government majority ownership (~70%): policy and social mandates sit alongside commercial goals','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PNB','Platform disintermediation plus zero-MDR, the shared UPI dynamic','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PNB','Sharply improved asset quality and rising capital adequacy show the post-cleanup turnaround is real','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PNB','2025-12-31','bull','Net NPA fell to just 0.32% (from 0.41% a year ago), with provision coverage near 97% — among the strongest asset-quality positions of any PSU bank.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PNB','2025-12-31','bull','Capital adequacy improved meaningfully to 16.77%, up 136 bps from a year ago — a genuinely strengthening position, not just a stable one.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PNB','2025-12-31','bull','Retail loan growth was sharp (+18.9% YoY), led by vehicle loans (+35.7%) and housing (+14.5%) — a real shift toward higher-quality retail lending.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PNB','2025-12-31','bear','NIM fell to 2.52% (global) from 2.93% a year ago — among the steepest margin compression of any bank on this dashboard, with management guiding for further near-term pressure before stabilising around FY27.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PNB','2025-12-31','bear','CASA ratio (37.1%) is among the lowest here, and continuing to slip — a structurally costlier funding base than top private banks.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PNB','2025-12-31','bear','This quarter''s profit included a ₹700 crore one-off treasury gain from a stake sale — worth separating core banking profit from one-time gains when judging earnings quality.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('FEDERALBNK','Federal Bank','NSE','Banking','Private Bank','Banks','Federal Bank is a Kerala-headquartered private bank with an unusually large share of India''s inward NRI remittances flowing through its accounts, on top of standard retail, SME and corporate lending. It earns the interest spread plus fee income tied to that remittance and treasury franchise.','Federal Bank''s own Q3 FY26 results and Screener.in''s Q3 FY26 ratio summary','A century-old, deeply entrenched franchise among India''s NRI/Kerala diaspora (an unusually sticky, high-quality deposit base) + a newly secured large strategic capital partner (Blackstone) positioning it toward a top-5 private-bank ambition.','No physical chain; the shared platform-disintermediation dynamic. Federal''s distinctive exposure is a century-old NRI and Kerala-diaspora deposit franchise, giving it unusual sensitivity to global-Indian remittance flows and currency movements (Gulf economies, USD/INR).',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('FEDERALBNK','2025-12-31','nim',3.18,'%','Net Interest Margin','Up from 3.11% a year ago.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('FEDERALBNK','2025-12-31','gnpa_pct',1.72,'%','Gross NPA','Down from 1.95% a year ago.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('FEDERALBNK','2025-12-31','nnpa_pct',0.42,'%','Net NPA','The bank''s best in a decade.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('FEDERALBNK','2025-12-31','casa_pct',32.07,'%','CASA Ratio','Up 191 bps YoY, with record fee income reducing reliance on interest income alone.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('FEDERALBNK','2025-12-31','car_pct',15.2,'%','Capital Adequacy','A Blackstone capital infusion is expected to add ~50bps in Q4 FY26 alone, more through FY28.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('FEDERALBNK','2025-12-31','loan_book_growth',10.94,'%','Loan Book Growth','Slowest of any bank here — a deliberate choice, per management, to prioritise quality of growth over pace.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('FEDERALBNK','Diaspora and remittance exposure: a large NRI deposit base ties Federal to Gulf-economy health and USD/INR moves more than a typical domestic bank','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('FEDERALBNK','A large strategic capital partner (Blackstone) and a heavy fintech-partnership model extend distribution well beyond its Kerala base','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('FEDERALBNK','Platform disintermediation plus zero-MDR — the same UPI dynamic facing all banks','risk',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('FEDERALBNK','2025-12-31','bull','Net NPA improved to 0.42% — the bank''s best in a decade — with Gross NPA down to 1.72%, both moving the right direction for several straight quarters.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('FEDERALBNK','2025-12-31','bull','CASA ratio crossed 32% with record fee income (+19% YoY), genuine revenue diversification rather than just margin-chasing.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('FEDERALBNK','2025-12-31','bull','A landmark Blackstone capital infusion is expected to lift capital adequacy by roughly 50bps in Q4 FY26 alone, with more capital still arriving through FY28 — a multi-year capital tailwind most banks here don''t have lined up.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('FEDERALBNK','2025-12-31','bear','Loan growth (under 11% YoY) is the slowest of any bank on this dashboard — management is deliberately prioritising ''quality of growth'' over pace, which is defensible, but it does mean ceding scale gains to faster-growing peers right now.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('FEDERALBNK','2025-12-31','bear','Return on equity (12.9% over the last 3 years per Screener) trails most peers here — a structurally lower profitability ceiling unless the Blackstone capital and mix-shift translate into materially higher returns.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('FEDERALBNK','2025-12-31','bear','Contingent liabilities are large in absolute terms (₹2.17 lakh crore) — standard for a bank this size, but worth understanding what''s inside that figure rather than treating it as a red flag on its own.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('IDFCFIRSTB','IDFC First Bank','NSE','Banking','Private Bank','Banks','IDFC First Bank is a young private bank (formed from the 2018 merger of IDFC Bank and Capital First) that built a mostly retail loan book from scratch &mdash; home loans, vehicle loans, MSME credit and a fast-growing credit-card business &mdash; while still working through legacy corporate/infrastructure-project loans inherited from IDFC''s earlier project-finance roots.','IDFC First Bank''s own Q3 FY26 press release, investor presentation, and earnings-call transcript','A purpose-built, fintech-grade digital banking experience (built fresh after the 2018 IDFC Bank–Capital First merger, not retrofitted onto a legacy core) + the fastest CASA-funded growth among private banks tracked here — still a relatively young, unproven-through-a-full-credit-cycle franchise compared to century-old peers.','No physical chain; the shared platform-disintermediation dynamic. IDFC First''s specific exposure is a meaningful microfinance and unsecured book at a time of sector-wide MFI stress — even as its purpose-built digital stack and high CASA give it a strong funding base to weather it.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('IDFCFIRSTB','2025-12-31','nim',5.76,'%','Net Interest Margin','Highest of any bank here — but the bank itself reports this ''gross of IBPC & sell-down,'' a different methodology than most peers use, so treat the ranking directionally, not as a perfectly apples-to-apples figure.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('IDFCFIRSTB','2025-12-31','gnpa_pct',1.69,'%','Gross NPA','Improved from 1.86% the prior quarter and 1.94% a year ago.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('IDFCFIRSTB','2025-12-31','nnpa_pct',0.53,'%','Net NPA','Ticked up slightly from 0.52% a year ago, even as Gross NPA improved.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('IDFCFIRSTB','2025-12-31','casa_pct',51.64,'%','CASA Ratio','Highest of any bank on this dashboard, up 390 bps YoY.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('IDFCFIRSTB','2025-12-31','car_pct',16.22,'%','Capital Adequacy','Includes the effect of ₹7,500 crore in CCPS converting to equity this quarter.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('IDFCFIRSTB','2025-12-31','loan_book_growth',20.93,'%','Loan Book Growth','Fastest of any bank here; 89% of the growth came from mortgages, vehicle loans, consumer loans, business banking and wholesale — a diversified mix.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IDFCFIRSTB','Microfinance and unsecured exposure: sector-wide MFI stress (NBFC-MFI GNPA doubled to ~4.1% by March 2025, expected to peak by March 2026) touches its book directly — it flagged MFI slippages improving, but the cycle is not over','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IDFCFIRSTB','Platform disintermediation plus zero-MDR, the shared UPI dynamic','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IDFCFIRSTB','A purpose-built digital stack and the highest CASA among banks tracked here give it a low-cost funding base to absorb the cycle','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IDFCFIRSTB','2025-12-31','bull','NIM (5.76%) and CASA (51.64%) are both the highest of any bank on this dashboard by a wide margin — a genuinely differentiated funding and margin profile for a bank still under 8 years old in its current form.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IDFCFIRSTB','2025-12-31','bull','Loan book grew 20.93% YoY, the fastest here, with 89% of that growth spread across mortgages, vehicle loans, consumer loans, business banking and wholesale — a diversified mix, not one risky segment.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IDFCFIRSTB','2025-12-31','bull','Asset quality kept improving even through rapid growth: Gross NPA fell to 1.69%, with MFI-related slippages specifically called out as improving.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IDFCFIRSTB','2025-12-31','bear','NIM is reported ''gross of IBPC & sell-down'' — a different methodology than most banks use, so this figure isn''t perfectly apples-to-apples with other banks'' NIM on this dashboard.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IDFCFIRSTB','2025-12-31','bear','Net NPA ticked up slightly (0.53% from 0.52%) even as Gross NPA improved — a small but real divergence worth watching given past stress in its MFI/unsecured book.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IDFCFIRSTB','2025-12-31','bear','Return on assets, by management''s own admission on the earnings call, remains low (around 0.5%) — a bank still proving out the profitability of its post-merger retail transformation, not yet a finished story.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('BANDHANBNK','Bandhan Bank','NSE','Banking','Private Bank','Banks','Bandhan Bank grew out of India''s largest microfinance institution, so a meaningful share of its book is still unsecured, group-liability microfinance lending to low-income borrowers &mdash; higher-yield but higher-risk &mdash; alongside a growing secured retail and housing-finance business it''s been building to diversify.','Bandhan Bank''s own Q3 FY26 press release and corroborating market coverage','Deep, two-decade-old rural/semi-urban microfinance distribution and credit-assessment expertise — a genuine niche moat in a segment most universal banks avoid, though it carries structurally higher volatility through credit cycles than a diversified bank.','No physical chain, but Bandhan''s model is built on microfinance (its EEB book), so it sits at the sharp end of the sector-wide MFI stress cycle — and its footprint is also geographically concentrated in East India.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANDHANBNK','2025-12-31','nim',5.9,'%','Net Interest Margin','Highest on this dashboard — but read this as compensation for high-risk microfinance lending, not superior banking economics. It comes paired with the lowest CASA ratio here and one of the higher Gross NPA ratios.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANDHANBNK','2025-12-31','gnpa_pct',3.33,'%','Gross NPA','Down sharply from 5.02% just one quarter earlier — a 169bps improvement in a single quarter.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANDHANBNK','2025-12-31','nnpa_pct',0.99,'%','Net NPA','Down from 1.37% the prior quarter, with provision coverage at 70.8-84.3% depending on whether technical write-offs are included.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANDHANBNK','2025-12-31','casa_pct',27.3,'%','CASA Ratio','Lowest of any bank on this dashboard, down from 31.7% a year ago — fast-eroding cheap-deposit base.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANDHANBNK','2025-12-31','car_pct',17.33,'%','Capital Adequacy','Tier-1 alone was 16.5% — comfortably above regulatory requirements.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BANDHANBNK','2025-12-31','loan_book_growth',10,'%','Loan Book Growth','YoY growth in gross advances.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BANDHANBNK','Microfinance stress cycle: NBFC-MFI GNPA doubled to ~4.1% by March 2025 and is expected to peak by March 2026; Bandhan already sold ~6,872 crore of bad MFI loans (Dec 2025) and saw its own GNPA swing sharply — a direct read on this cycle','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BANDHANBNK','Geographic concentration: a heavy East-India footprint amplifies exposure to regional income shocks and climate-linked rural volatility','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BANDHANBNK','RBI cut the microfinance consumer-credit risk weight from 125% back to 100% (March 2025), and collection efficiency is recovering — early signs the worst of the cycle may be passing','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANDHANBNK','2025-12-31','bull','Gross NPA fell sharply to 3.33% from 5.02% just one quarter earlier — a remarkable 169bps improvement suggesting the worst of its microfinance stress cycle may be behind it.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANDHANBNK','2025-12-31','bull','Profit rebounded 84% sequentially on materially better collections, with microfinance (EEB) collection efficiency holding strong at 98.2%.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANDHANBNK','2025-12-31','bull','Capital adequacy of 17.33% remains comfortably above regulatory requirements, leaving room to keep growing without needing fresh capital soon.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANDHANBNK','2025-12-31','bear','That headline 5.9% NIM is the highest on this dashboard, but it reflects high-yield, high-risk microfinance lending, not efficient banking — it comes paired with the lowest CASA ratio here (27.3%) and one of the higher Gross NPA ratios (3.33%). Read it as ''compensation for risk taken,'' not ''best margins.''',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANDHANBNK','2025-12-31','bear','CASA ratio kept sliding — 31.7% a year ago to 28.0% to 27.3% now — the lowest and fastest-eroding cheap-deposit base of any bank tracked here.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BANDHANBNK','2025-12-31','bear','Profit is still down 51.7% YoY despite the sequential rebound, and the bank sold ₹6,872 crore of bad microfinance loans to asset reconstruction companies in December 2025 — a sign the cleanup is real, but also that there was a lot to clean up.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('AUBANK','AU Small Finance Bank','NSE','Banking','Small Finance Bank','Banks','AU Small Finance Bank converted from a vehicle-finance NBFC into a small finance bank in 2017. It lends heavily to underbanked retail and MSME customers in semi-urban and rural Rajasthan and neighbouring states &mdash; vehicle and MSME loans originally, now alongside a fuller banking suite of deposits and cards.','AU Small Finance Bank''s own Q3 FY26 results and corroborating market coverage','A digital-first, tech-forward small finance bank with the broadest branch network among SFBs (2,700+ touchpoints across 21 states) + a fresh in-principle approval to become a Universal Bank, a structural upgrade most SFB peers don''t yet have in hand.','No physical chain; the shared platform-disintermediation dynamic. AU''s specific exposure is the small-finance-bank sector''s microfinance stress plus an intense deposit-competition environment — set against a structural upgrade, an in-principle RBI approval to become a Universal Bank.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('AUBANK','2025-12-31','nim',5.7,'%','Net Interest Margin','Down from 5.9% a year ago, as deposit competition stays intense.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('AUBANK','2025-12-31','gnpa_pct',2.3,'%','Gross NPA','Improved from 2.41% the prior quarter; stable for three straight quarters.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('AUBANK','2025-12-31','nnpa_pct',0.88,'%','Net NPA','Unchanged for three consecutive quarters — a sign of consistent, not volatile, credit performance.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('AUBANK','2025-12-31','casa_pct',29,'%','CASA Ratio','Down from 31.0% a year ago.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('AUBANK','2025-12-31','car_pct',19.01,'%','Capital Adequacy','Well above regulatory requirements, supporting continued growth.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('AUBANK','2025-12-31','loan_book_growth',19.3,'%','Loan Book Growth','YoY growth in gross loan portfolio.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('AUBANK','Universal Bank transition: in-principle RBI approval to convert from an SFB should lower funding costs and widen its addressable market over time','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('AUBANK','Microfinance and unsecured stress: as an SFB with meaningful unsecured exposure, AU sits in the segment RBI flagged as FY26''s most stressed (unsecured personal loans, microfinance, SME)','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('AUBANK','Deposit-competition intensity: management itself calls the deposit environment highly competitive — NIM and CASA are under the same pressure as the whole sector','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AUBANK','2025-12-31','bull','Net profit jumped 26% YoY with provisions down 34% YoY even as the loan book grew a healthy 19.3% — growth and credit discipline improving together, not at each other''s expense.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AUBANK','2025-12-31','bull','Received in-principle RBI approval to transition into a Universal Bank — a structural unlock that should lower funding costs over time and let it compete more directly with full-service private banks.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AUBANK','2025-12-31','bull','Asset quality has been stable for three straight quarters (GNPA 2.30%, NNPA 0.88% unchanged), weathering the small-finance-bank sector''s recent microfinance stress better than several peers.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AUBANK','2025-12-31','bear','NIM kept compressing — 5.7%, down from 5.9% a year ago — as competition for deposits stays intense; management itself called the deposit environment ''highly competitive.''',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AUBANK','2025-12-31','bear','CASA ratio slipped from 31.0% a year ago to 29.0% now — the same cheap-deposit erosion playing out across nearly every bank on this dashboard, not unique to AU SFB.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AUBANK','2025-12-31','bear','At least one tracker has flagged the valuation as ''very expensive'' with a PEG ratio above 2 — a reminder that strong execution doesn''t automatically mean a cheap stock.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('CANBK','Canara Bank','NSE','Banking','PSU Bank','Banks','Canara Bank is a PSU bank with a large branch network concentrated in South India, taking deposits and lending across retail, agriculture, MSME and corporate customers. Like other PSU banks, its profitability is tied to the interest spread and to continued recovery in legacy asset quality.','Canara Bank''s own Q3 FY26 results, Screener.in''s ratio summary, and India Ratings commentary','Scale as India''s fourth-largest PSU bank and sixth-largest bank overall (10,000+ domestic branches), ranked #4 as lead bank across India''s states/UTs/districts — deep, sovereign-anchored distribution that''s nearly impossible for a private bank to replicate quickly.','No physical chain; the shared platform-disintermediation dynamic. Government-owned, and one of India''s largest PSU banks with a lead-bank role coordinating banking across many states and districts — deep, sovereign-anchored distribution.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CANBK','2025-12-31','nim',2.5,'%','Net Interest Margin','Down from 2.80% for all of FY25 — management is guiding to recover toward 2.75-2.80% during FY26.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CANBK','2025-12-31','gnpa_pct',2.08,'%','Gross NPA','A record low for the bank, down from 3.34% a year ago.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CANBK','2025-12-31','nnpa_pct',0.45,'%','Net NPA','Down from 0.89% a year ago, with provision coverage above 94%.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CANBK','2025-12-31','casa_pct',29.52,'%','CASA Ratio','Among the lower end of this dashboard; management''s own target is to recover to just 32%, still below its 32.4% level two years ago.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CANBK','2025-12-31','car_pct',16.5,'%','Capital Adequacy','CET1 alone is lower (12.37%) than most PSU peers with similar asset quality — the headline figure leans more on AT1/Tier-2 instruments.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CANBK','2025-12-31','loan_book_growth',13.59,'%','Loan Book Growth','YoY growth in global advances.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CANBK','Government majority ownership plus lead-bank role: coordinates priority-sector and inclusion banking across states, a mandate beyond pure commercial lending','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CANBK','Platform disintermediation plus zero-MDR, the shared UPI dynamic','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CANBK','Record-low NPAs and strong profit growth show a genuine turnaround, though core CET1 capital is thinner than some peers','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CANBK','2025-12-31','bull','Gross NPA hit a record low of 2.08% (from 3.34% a year ago) with Net NPA at just 0.45% and provision coverage above 94% — asset quality now genuinely rivals the better private banks, not just other PSU peers.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CANBK','2025-12-31','bull','Profit grew 25.6% YoY for the seventh straight quarter of 18%+ YoY growth — a sustained trend, not a one-off beat.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CANBK','2025-12-31','bull','Raised ₹3,500 crore via AT1 bonds during the quarter, reinforcing an already-comfortable 16.50% capital adequacy ratio with room to keep growing.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CANBK','2025-12-31','bear','A meaningful share of this quarter''s profit growth came from a one-time ~₹1,800 crore gain on reclassifying two subsidiaries (Canara Robeco AMC, Canara HSBC Life) as associates — worth separating from core lending performance when judging earnings quality.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CANBK','2025-12-31','bear','NIM kept falling to 2.50% from 2.80% across FY25, and CASA (29.52%) is among the lower end of this dashboard, with management''s own near-term target being just 32% — still below its level two years ago.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CANBK','2025-12-31','bear','CET1 — the purest measure of core capital — at 12.37% is lower than most PSU peers with comparable asset quality, per India Ratings; the comfortable headline capital ratio leans more on AT1/Tier-2 instruments than some peers.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('HINDUNILVR','Hindustan Unilever','NSE','FMCG','FMCG - Diversified','FMCG','Hindustan Unilever (Unilever''s Indian arm) is India''s largest FMCG company: it manufactures and sells everyday packaged goods &mdash; soaps, detergents, shampoos, packaged foods, skincare &mdash; under brands like Lux, Surf Excel and Dove, distributed through India''s largest retail reach network. Margins depend on brand pricing power versus input costs (palm oil and other commodity derivatives).','HUL''s own Q3 FY26 earnings call (Feb 12 2026), Business Standard, Axis Direct research note, Screener.in (FY26 annual), MarketsMojo — six sources cross-checked','20 ''billion-rupee brands'' including Dove, Surf Excel, Lux, Lipton, Horlicks, and Lakmé — a brand portfolio moat paired with a 9-million-outlet distribution network built over 90+ years. The moat is real; the question is whether the premium valuation already prices it in fully.','Downstream brand owner and manufacturer — HUL doesn''t grow its own raw materials, it captures value through 20 ''billion-rupee'' brands and a 9-million-outlet distribution network that turns commodity inputs into premium-priced finished goods.','Import-dependent on palm oil and crude-linked raw materials, named directly as the Q3 gross-margin headwind — a live, current example of the import-exposure pattern, not a hypothetical.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDUNILVR','2025-12-31','revenue_growth_pct',5.7,'%','Revenue Growth (YoY)','Continuing operations only, after the Dec 2025 ice cream (Kwality Wall''s) demerger. Underlying Sales Growth (USG) was 5%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDUNILVR','2025-12-31','volume_growth_pct',4,'%','Volume Growth (UVG)','Underlying Volume Growth — HUL''s own preferred demand measure. Management called this the highest UVG in the last 12 quarters.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDUNILVR','2025-12-31','gross_margin_pct',49.7,'%','Gross Margin','Down 28 bps YoY (Axis Direct). Key headwind: palm oil and crude-linked raw material inflation.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDUNILVR','2025-12-31','ebitda_margin_pct',23.3,'%','EBITDA Margin','Down 70 bps YoY. Within HUL''s own guided range of 22–23%; management reaffirmed the range for FY26.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDUNILVR','2025-12-31','roce_pct',31.61,'%','ROCE','Return on Capital Employed for FY26 (trailing). Zero long-term debt means essentially all capital is equity — the ROCE reflects genuine business quality, not financial leverage.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDUNILVR','2025-12-31','anp_spend_pct',9.4,'%','A&P Spend % Revenue','₹1,522 crore on advertising & promotion in Q3 FY26. Full-year FY26 was 9.8% of turnover. Display-only metric — higher is brand investment, not waste; lower isn''t automatically better.',NULL,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDUNILVR','Distribution disintermediation: quick-commerce now ~3% of sales and doubling each quarter — reshaping who controls shelf access and at what margin, a genuinely new risk this category didn''t face five years ago','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDUNILVR','Commodity/import exposure: palm oil and crude-linked raw materials, directly cited as the quarter''s gross-margin pressure point','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDUNILVR','Premium digital-native brand acquisitions (Minimalist, OZiva) give HUL its own foothold in the same disruptive channel rather than only defending against it','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDUNILVR','2025-12-31','bull','Volume growth (4% UVG) is the highest in 12 quarters, and management described demand trends as showing ''early signs of recovery'' on the Q3 earnings call — a genuine turning point after several quarters of soft volumes, not just narrative.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDUNILVR','2025-12-31','bull','ROCE of 31.61% and zero long-term debt — this company creates substantial returns on capital without leverage; that''s a quality of earnings test most companies fail.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDUNILVR','2025-12-31','bull','The portfolio rotation is real: ice cream (low-margin) is now demerged and separately listed; premium digital-native brands Minimalist and OZiva are fully owned; quick-commerce now ~3% of sales and doubling every quarter.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDUNILVR','2025-12-31','bear','The reported 121% profit surge is almost entirely a one-time accounting gain (₹4,485 crore exceptional item from the ice cream demerger) — adjusted PAT from continuing operations grew about 1% YoY, which is the real underlying number.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDUNILVR','2025-12-31','bear','EBITDA margins compressed 70 bps YoY to 23.3% — palm oil and crude-linked raw material costs are the named culprit; management guided to staying within 22–23%, not expanding back to historical 24–25%.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDUNILVR','2025-12-31','bear','Revenue growth of 5.7% (and 5-year sales CAGR of just ~6.5%) is unspectacular for a company trading at over 49x FY27E earnings per analyst estimates — the valuation assumes flawless execution on premiumisation and quick-commerce scaling, with little room for a miss.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('ITC','ITC Limited','NSE','FMCG','FMCG - Cigarettes & Diversified','FMCG','ITC is a diversified conglomerate whose historically dominant, highest-margin business is cigarettes (Gold Flake and other brands) &mdash; a reliable cash generator that funds a fast-growing FMCG-foods and personal-care portfolio (Aashirvaad, Sunfeast, Bingo, Savlon), plus hotels, paperboard/packaging and agri-trading businesses. Its profit mix remains cigarette-heavy even as management pushes to diversify.','ITC''s own Q3 FY26 investor presentation (itcportal.com), Motilal Oswal research note, Business Standard, Tobacco Insider, MarketsMojo, Screener.in — seven sources cross-checked','~80% share of India''s organized domestic cigarette market (entrenched brands, unique distribution, high switching friction) + a genuinely growing FMCG portfolio (Sunfeast, Bingo, Fiama, Classmate) + a valuable hotel and real estate portfolio. The core moat is durable; the regulatory and ESG risk discount on it is the ongoing debate.','Unusually vertically integrated for an FMCG company — ITC sources leaf tobacco directly through its own Agri Business arm, manufactures, brands, and distributes through a network giving it ~80% share of the organized cigarette market, capturing value at nearly every stage rather than depending on outside suppliers.',NULL);
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ITC','2025-12-31','revenue_growth_pct',6.7,'%','Revenue Growth (YoY)','Consolidated gross revenue +7.1% per ITC''s own presentation; net-of-excise revenue used here (+6.7%). Cigarettes excise duty flows through gross revenue — both bases are valid, but this is the net figure for comparability.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ITC','2025-12-31','volume_growth_pct',6.5,'%','Volume Growth','Cigarette segment volume growth, ITC''s single largest segment by revenue and profit. FMCG-Others (packaged foods, personal care) revenues grew +11.1% YoY — no single volume % disclosed for the combined company.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ITC','2025-12-31','gross_margin_pct',NULL,'%','Gross Margin','Not directly comparable to HUL. ITC''s gross revenue includes cigarette excise duty (a pass-through tax), which inflates the revenue denominator and makes computed gross margin meaningfully different in kind from a pure-FMCG company''s. Shown as — rather than presenting a misleading number.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ITC','2025-12-31','ebitda_margin_pct',35.1,'%','EBITDA Margin','Standalone EBITDA margin, up 50 bps YoY to 35.1%. Higher than HUL''s 23.3%, but driven primarily by the structurally higher-margin cigarette business — not a like-for-like comparison.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ITC','2025-12-31','roce_pct',44.26,'%','ROCE','Highest of any company on this dashboard. Reflects the high-margin, capital-light cigarette franchise. ROE was 27.82%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ITC','2025-12-31','anp_spend_pct',NULL,'%','A&P Spend % Revenue','Not disclosed as a combined % of net revenue for Q3. ITC reports advertising and promotion costs selectively at segment level. Shown as — rather than estimated.',NULL,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ITC','Regulatory/tax exposure: a cigarette excise duty hike (₹2.05-8.50 per stick) took effect Feb 1, 2026, just after this quarter closed — the single largest near-term risk to the value chain this profit depends on most','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ITC','Illicit trade risk: every legal price increase historically expands the untaxed market, eroding the volume base the legal, taxed supply chain depends on','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ITC','FMCG-Others diversification (+11.1% revenue growth this quarter) is a genuine, working hedge that reduces dependence on the cigarette value chain over time, even if it''s not yet large enough to offset it','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ITC','2025-12-31','bull','ROCE of 44.26% is the highest of any company on this dashboard — a direct result of the cigarette business''s structurally high margins and low capital requirements. The business model itself generates extraordinary returns on the capital it actually deploys.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ITC','2025-12-31','bull','FMCG-Others (non-cigarette packaged foods, personal care, agarbattis) grew +11.1% revenue YoY with EBITDA margins expanding 145 bps — the diversification away from cigarettes is actually delivering results, not just a stated ambition.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ITC','2025-12-31','bull','Dividend yield of ~2% is the highest among FMCG peers tracked here, backed by consistent FCF from the cigarette franchise. Management declared ₹6.50/share interim dividend this quarter.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ITC','2025-12-31','bear','A cigarette excise duty hike effective February 1, 2026 (₹2.05–₹8.50 per stick by length, replacing compensation cess) came just after Q3 ended — so this quarter''s results don''t reflect it yet. The stock fell ~20% from its 52-week high near ₹471 to ₹303–318 around results, pricing in the regulatory risk the numbers haven''t yet shown.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ITC','2025-12-31','bear','Cigarette EBIT margins already contracted 140 bps YoY to 56.7% even before the excise hike, on rising leaf tobacco costs — margin pressure was already building in the core business.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ITC','2025-12-31','bear','~70–75% of total profit still comes from cigarettes: a business facing annual regulatory risk, secular volume headwinds from health awareness, and an illicit trade market that grows every time legal prices are raised. The entire conglomerate''s financial health is structurally dependent on one regulated, shrinking-by-design category.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('TCS','Tata Consultancy Services','NSE','IT Services','IT - Large Cap','IT','Tata Consultancy Services sells software development, IT consulting and outsourced technology operations to large global enterprises, billed largely on consultant time or fixed-price/outcome contracts. Because revenue is fundamentally billed hours and project fees, headcount, utilisation rates and pricing per hour drive margins &mdash; and it now discloses a distinct, growing AI-services revenue line.','TCS''s own Q3 FY26 press release, fact sheet, and earnings-call transcript (tcs.com)','Scale (582,000+ employees, 202 delivery centers, 55 countries) + five decades of enterprise relationships + a Tata Group balance sheet that can absorb AI-transition investment most competitors can''t. The open question — explicit in the project plan''s value-chain analysis — is whether scale remains a moat or becomes a cost disadvantage as AI compresses the traditional staffing-pyramid economics this scale was built around.','Downstream IT service provider — there''s no physical raw-material chain here; the enterprise client sets project scope and retains the anchor position, while TCS competes on delivery quality, cost, and increasingly AI-augmented productivity within that scope.','Revenue is broadly diversified across BFSI (~28%), manufacturing, energy/utilities, and retail — no single client or vertical disclosed as a concentration risk.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TCS','2025-12-31','revenue_growth_pct',4.9,'%','Revenue Growth (YoY)','Reported INR terms. Constant-currency revenue actually fell 2.6% YoY — the gap is currency translation, not real growth. Worth reading both numbers together.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TCS','2025-12-31','operating_margin_pct',25.2,'%','Operating Margin','Held steady YoY despite wage hikes — margin discipline maintained through a soft-growth environment.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TCS','2025-12-31','attrition_pct',13.5,'%','Attrition (LTM)','Voluntary attrition, trailing twelve months, IT services.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TCS','2025-12-31','deal_tcv_usd_bn',9.3,'$bn','Deal TCV (Quarter)','Total Contract Value signed this quarter, including one mega deal in North America. A forward-looking demand signal, not revenue already booked.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TCS','2025-12-31','roce_pct',NULL,'%','ROCE','Not separately headlined by TCS in its own Q3 disclosures — shown as — rather than estimated.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TCS','2025-12-31','ai_revenue_growth_pct',17.3,'%','AI Revenue Growth (QoQ)','Annualised AI services revenue reached $1.8bn, up 17.3% sequentially in constant currency. Display-only: this is a new, inconsistently-disclosed metric across the sector — see the bear case for why it can''t yet be ranked fairly against peers.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TCS','AI/automation exposure: structural threat to the traditional staffing-pyramid billing model — this quarter''s constant-currency revenue actually fell 2.6% YoY even as reported INR revenue grew, the live evidence of pricing/volume pressure','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TCS','AI/automation exposure: also a measurable tailwind — $1.8bn annualised AI-native revenue, +17.3% QoQ, the fastest-growing disclosed line in the business','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TCS','Currency exposure: the bulk of revenue is billed in USD/GBP/EUR — a weaker rupee flatters reported INR growth even when underlying demand (constant-currency) is flat or falling','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TCS','2025-12-31','bull','AI is becoming a real, measurable revenue line, not just a talking point: annualised AI services revenue hit $1.8 billion, growing 17.3% sequentially — management''s stated ambition is to become ''the world''s largest AI-led technology services company.''',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TCS','2025-12-31','bull','Deal TCV of $9.3 billion this quarter (with a North America mega deal) gives strong revenue visibility — a forward indicator that current bookings exceed current billing, a healthy sign for future quarters.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TCS','2025-12-31','bull','Operating margin held steady at 25.2% despite wage hikes — disciplined cost management even while growth stayed modest.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TCS','2025-12-31','bear','Constant-currency revenue actually declined 2.6% YoY — the headline 4.9% INR growth is mostly currency translation, not real organic demand. This is the structural GenAI-era story the project plan flagged: pricing and volume pressure in traditional delivery work, even at the sector''s largest, most efficient player.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TCS','2025-12-31','bear','Reported net profit fell YoY, driven by exceptional items this quarter — management says this doesn''t reflect core business weakness, but it''s worth separating headline profit from underlying trend regardless.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TCS','2025-12-31','bear','AI revenue, while growing fast, is still a small fraction of TCS''s ~$30bn annual revenue base — the disclosed dollar figure ($1.8bn annualised) needs context against total scale, not just its growth rate, before treating it as a turnaround signal.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('INFY','Infosys','NSE','IT Services','IT - Large Cap','IT','Infosys runs the same core IT-services business model as TCS &mdash; global enterprise clients pay for software development, consulting and outsourced technology operations &mdash; with margins driven by utilisation, the offshore/onsite delivery mix and wage inflation. Unlike TCS, it does not disclose a separate standalone AI-revenue figure.','Infosys''s own Q3 FY26 SEC Form 6-K press release and fact sheet, plus corroborating market coverage (Zee Business, Republic World)','Deep enterprise AI partnerships (Topaz platform) + consulting-led client relationships across BFSI, manufacturing, and retail + one of the industry''s strongest cash-generation track records (consistently 100%+ FCF-to-net-profit conversion). Like TCS, the moat built on engineering headcount scale is the exact thing GenAI is putting the most pressure on — the project plan''s flagged sector risk, not a hypothetical one.','Downstream IT service provider — the same structural position as TCS: no physical chain, the enterprise client sets scope, and Infosys competes on consulting-led delivery and, increasingly, on enterprise AI integration through its Topaz platform.','Revenue concentration by segment is broadly similar to sector peers (financial services, manufacturing, retail) — no single client disclosed as a standout concentration risk.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INFY','2025-12-31','revenue_growth_pct',3.2,'%','Revenue Growth (YoY)','Reported INR terms, per Infosys''s own fact sheet. Constant-currency growth was just 1.7% — similar currency-vs-real gap to TCS, same sector-wide pattern.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INFY','2025-12-31','operating_margin_pct',18.4,'%','Operating Margin','Reported IFRS basis. Adjusted (excluding a one-time Labour Codes charge) was higher at 21.2%, sequentially up 0.2pp — the cleaner read of underlying margin trend.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INFY','2025-12-31','attrition_pct',12.3,'%','Attrition (LTM)','Down from 14.3% the prior quarter and 13.7% a year ago — the lowest of the two IT companies tracked here, and genuinely improving, not just stable.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INFY','2025-12-31','deal_tcv_usd_bn',4.8,'$bn','Deal TCV (Quarter)','Total Contract Value of large deal wins this quarter, with 57% net new (i.e., not just renewals of existing work).',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INFY','2025-12-31','roce_pct',NULL,'%','ROCE','Not separately headlined in Q3 disclosures (ROE was cited at 32.8% in the earnings call, a related but different measure) — shown as — rather than conflating the two.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INFY','2025-12-31','ai_revenue_growth_pct',NULL,'%','AI Revenue Growth (QoQ)','Infosys discloses AI traction qualitatively (via its ''Topaz'' platform) and ties it to deal wins and market-share commentary, but doesn''t publish a standalone AI-revenue growth % the way TCS does. Shown as — rather than guessed — itself a useful data point: AI-revenue disclosure isn''t yet standardised across the sector.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INFY','AI/automation exposure: structural threat to the traditional billing model — constant-currency revenue growth of just 1.7% YoY this quarter, barely positive, the same sector-wide pattern visible at TCS','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INFY','AI/automation exposure: Topaz platform is management''s stated growth strategy, tied to raised FY26 guidance — but without a disclosed revenue figure, it''s a qualitative tailwind for now, not yet a quantified one','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INFY','Currency exposure: similar USD-heavy revenue mix to TCS — the reported-vs-constant-currency growth gap (3.2% vs 1.7%) reflects rupee movement more than real demand change','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INFY','2025-12-31','bull','Attrition fell to 12.3% LTM, down from 14.3% the prior quarter — a real, improving trend, and the lowest of the two IT companies tracked here, suggesting better employee retention even amid sector-wide AI-driven uncertainty.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INFY','2025-12-31','bull','Management raised FY26 revenue guidance (to 3.0-3.5% constant currency) rather than cutting it — a vote of confidence from the company closest to its own numbers, not just analyst optimism.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INFY','2025-12-31','bull','Deal TCV of $4.8bn with 57% net new business signals real incremental demand, not just contract renewals — a healthier mix than pure renewal-driven bookings.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INFY','2025-12-31','bear','Constant-currency revenue growth of just 1.7% YoY is barely positive — the same structural pattern as TCS, the clearest evidence yet that this is a sector-wide GenAI-era growth slowdown, not one company''s execution problem.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INFY','2025-12-31','bear','Reported operating margin (18.4%) was meaningfully below the adjusted figure (21.2%) due to a one-time Labour Codes charge — worth using the adjusted number for trend analysis, but the gap itself shows how much one-off items can swing a single quarter''s headline margin.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INFY','2025-12-31','bear','Unlike TCS, Infosys doesn''t publish a standalone AI-revenue growth metric — making it genuinely harder to judge whether its AI investments (branded ''Topaz'') are translating into revenue at a comparable pace, or whether the absence of a disclosed number is itself information.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('SUNPHARMA','Sun Pharmaceutical Industries','NSE','Pharma','Pharma - Specialty & Generics','Pharma','Sun Pharmaceutical Industries, India''s largest drugmaker, sells both low-margin, volume-driven generic drugs (mainly in the US and India) and increasingly higher-margin branded specialty medicines &mdash; particularly dermatology &mdash; sold mostly in the US under its Innovative Medicines franchise. Recent profit growth has come from this shift toward specialty products, not just generic volumes.','Sun Pharma''s own Q3 FY26 press release and earnings call transcript (sunpharma.com), cross-checked against Business Standard and AlphaStreet','World''s largest specialty generics company + India''s #1 pharma franchise by both market share and prescription volume + a genuinely differentiated innovative pipeline (5 novel entities in clinical stage) smaller peers can''t easily replicate — though even this scale doesn''t fully insulate the legacy US generics book from sector-wide pricing pressure.','Vertically integrated specialty/generics manufacturer — API production mostly feeds its own formulation business internally (external API sales are tiny, under 4% of revenue), with an increasingly important Innovative/Specialty Medicines arm sold directly into the regulated US market.','Manufacturing facilities span five continents serving 100+ countries — geographically diversified supply, not concentrated in one country''s regulatory or trade-policy risk the way some peers are.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SUNPHARMA','2025-12-31','revenue_growth_pct',15.1,'%','Revenue Growth (YoY)','Includes a $55 million one-time milestone payment within Global Innovative Medicines — underlying growth ex-milestone was still strong but slightly lower.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SUNPHARMA','2025-12-31','gross_margin_pct',81,'%','Gross Margin','Up YoY on a better product mix — reflects the growing share of higher-margin specialty/branded business.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SUNPHARMA','2025-12-31','ebitda_margin_pct',31.9,'%','EBITDA Margin','Up 260bps YoY — rare to see margin expand alongside double-digit revenue growth in pharma this quarter.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SUNPHARMA','2025-12-31','us_business_growth_pct',0.6,'%','US Business Growth','Flat — Innovative Medicines growth offset by generic price erosion. The same US pricing pressure hitting the whole sector, just better-hedged here by the specialty mix.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SUNPHARMA','2025-12-31','rd_pct_sales',5.8,'%','R&D % of Sales','₹892.8 crore this quarter. Display-only: higher R&D is pipeline investment, not unambiguously ''better'' without knowing what it funds.',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SUNPHARMA','2025-12-31','anda_pending_approval_pipeline',116,'','ANDAs Pending FDA Approval','550 already approved in the US; 116 pending (28 with tentative approval). Display-only — pipeline depth, not a ranked quality measure.',NULL,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SUNPHARMA','US regulatory exposure: 116 ANDAs pending FDA approval — normal pipeline, but each carries unpredictable inspection/approval-timeline risk standard to the sector','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SUNPHARMA','US generic pricing pressure: flat US business this quarter as Innovative Medicines gains were offset by generic price erosion — a sector-wide structural headwind, not company-specific','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SUNPHARMA','Mix-shift tailwind: Innovative/Specialty Medicines now 21%+ of sales and growing faster than the overall business — a genuine, working hedge against commodity generic pricing pressure','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUNPHARMA','2025-12-31','bull','Revenue grew 15.1% YoY while EBITDA margin simultaneously expanded 260bps to 31.9% — growth and margin expansion together is the harder combination to pull off, and most pharma peers this quarter are managing only one or the other.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUNPHARMA','2025-12-31','bull','Global Innovative Medicines (the higher-margin, less price-competitive segment) grew 13.2% ex-milestone and now makes up 21.2% of sales — a real, working strategic shift away from commodity generics pricing pressure, not just a stated ambition.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUNPHARMA','2025-12-31','bull','Maintains India''s #1 pharma position with market share still increasing (8.4%), plus a fortress balance sheet ($3.2 billion net cash) to keep funding the pipeline without urgency.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUNPHARMA','2025-12-31','bear','US business was flat (+0.6%) — Innovative Medicines growth was offset by generic price erosion, the same structural US pricing pressure hitting the whole Indian pharma export sector. Better-hedged here, not immune.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUNPHARMA','2025-12-31','bear','An exceptional charge of ₹489.5 crore this quarter (wage-code gratuity + a legal settlement provision) means the headline 16% profit growth somewhat overstates underlying performance — adjusted net profit grew a more modest 9.9%.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUNPHARMA','2025-12-31','bear','116 ANDAs remain pending FDA approval — normal pipeline depth, but every pending filing carries unpredictable regulatory-timeline risk that can delay expected launches by quarters, sometimes years.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('DRREDDY','Dr. Reddy''s Laboratories','NSE','Pharma','Pharma - Generics & Biosimilars','Pharma','Dr. Reddy''s Laboratories sells generic drugs globally (US, Russia/CIS, India, Europe) alongside a smaller branded and biosimilars business. Revenue leans heavily on the US generics market, where pricing is volatile and one-off patent-cliff opportunities (like its Revlimid/Lenalidomide authorised-generic window) can swing a single product''s contribution sharply from year to year.','Dr. Reddy''s own Q3 FY26 SEC Form 6-K filing and earnings call transcript, cross-checked against Investing.com and AlphaSpread','Genuine ''end-to-end'' API-to-formulation development capability (a real vertical-integration moat, not just a slogan) + an early, credible biosimilars pipeline in oncology/autoimmune — historically more reliant than Sun Pharma on a handful of high-value US generic opportunities like Lenalidomide, which cuts both ways: outsized windfalls when they land, and now, visible pain as one of those windfalls fades on a schedule set years ago.','Integrated generics and emerging biosimilars player — develops products ''end-to-end across API and formulations'' per its own FY26 annual report, with historically heavier reliance on a small number of high-value US generic opportunities than Sun Pharma''s more diversified, specialty-tilted mix.','10 manufacturing facilities, 7 FDA-approved and 3 EMA-approved — a credible, internationally-inspected manufacturing base, not a single-site concentration risk.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('DRREDDY','2025-12-31','revenue_growth_pct',4.4,'%','Revenue Growth (YoY)','Broad-based growth in India/Europe/Emerging Markets/PSAI was largely offset by a sharp North America decline (see bear case).',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('DRREDDY','2025-12-31','gross_margin_pct',53.6,'%','Gross Margin','Down from 58.7% a year earlier — a real, sizeable compression reflecting pricing pressure and product mix, not a rounding difference.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('DRREDDY','2025-12-31','ebitda_margin_pct',23.5,'%','EBITDA Margin','Down from 27.5% a year ago. 24.8% excluding a one-time Indian labour-code provision — still down meaningfully YoY even adjusted.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('DRREDDY','2025-12-31','us_business_growth_pct',-16,'%','US Business Growth','North America declined specifically on falling Lenalidomide sales and price erosion — see the value chain note below for why this is structural, not random.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('DRREDDY','2025-12-31','rd_pct_sales',7,'%','R&D % of Sales','Down from 8.0% a year ago (6.8% excluding a one-off), reflecting lower biosimilar development spend as Abatacept investment completes. Display-only.',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('DRREDDY','2025-12-31','anda_pending_approval_pipeline',75,'','ANDAs Pending FDA Approval','Per FY26 annual report: 75 pending, 43 of which are Paragraph IV filings (challenging existing patents — higher potential reward, also higher litigation risk). Display-only.',NULL,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DRREDDY','Single-molecule concentration risk realized in real time: North America revenue fell 16% YoY as the Lenalidomide volume-cap settlement (from 2020 Celgene/BMS litigation) approaches its January 2026 full-unlock date, intensifying competition on what had been a uniquely profitable, volume-limited opportunity','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DRREDDY','Paragraph IV pipeline risk/reward: 43 of 75 pending ANDAs are Paragraph IV filings (challenging existing patents) — higher potential reward (180-day exclusivity if first-to-file) but also real patent-litigation risk, as seen in the company''s own recent Esperion/NEXLETOL settlement','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DRREDDY','Biosimilars pivot: active pipeline in oncology and autoimmune categories (trastuzumab, adalimumab) — a structural move toward higher-barrier-to-entry, higher-margin categories, away from commodity small-molecule generics','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DRREDDY','2025-12-31','bull','India business grew a strong 19% YoY (organic growth over 17%), led by innovation brands, new launches, and the acquired Stugeron portfolio — proof the domestic franchise is healthy even as other markets wobble.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DRREDDY','2025-12-31','bull','Actively pivoting toward biosimilars (trastuzumab, adalimumab in pipeline) and complex generics — a deliberate strategic shift away from the commodity small-molecule pricing pressure visible in this quarter''s results.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DRREDDY','2025-12-31','bull','Net cash surplus of ₹3,069 crore and positive free cash flow (₹374 crore) even in a tougher quarter — balance sheet strength to fund the pipeline pivot without urgency.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DRREDDY','2025-12-31','bear','North America revenue fell 16% YoY, driven specifically by declining Lenalidomide sales as the volume-capped settlement period (from the 2020 Celgene/BMS patent settlement) approaches its January 31, 2026 full-volume-unlock date — a single-molecule concentration risk now visibly playing out in the numbers, not a hypothetical risk anymore.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DRREDDY','2025-12-31','bear','EBITDA margin compressed sharply to 23.5% from 27.5% a year ago — even the adjusted figure (24.8%, excluding a one-time labour-code provision) is still down nearly 300bps YoY, a real deterioration, not just a one-off accounting item.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DRREDDY','2025-12-31','bear','Net profit fell 14% YoY and 16% sequentially — alongside revenue growth slowing to 4.4% and margin compression, three separate data points pointing the same direction this quarter.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('MARUTI','Maruti Suzuki India','NSE','Auto','Passenger Vehicles','Auto','Maruti Suzuki is India''s largest passenger-vehicle maker (majority owned by Japan''s Suzuki Motor Corp) — it designs, assembles and sells cars and SUVs (Swift, Baleno, Brezza, Fronx) mainly to Indian retail buyers through the country''s largest dealer network, plus a fast-growing export business. Revenue comes from vehicle sales; margin is squeezed between what buyers will pay and the cost of steel, semiconductors and other components.','Maruti Suzuki''s own Q3 FY26 results press release (marutisuzuki.com), Business Standard, and Multibagg AI''s ratio breakdown — cross-checked','Brand trust + India''s largest dealer/service network + decades of cost-engineering discipline with Suzuki. Still India''s largest carmaker by volume even as its share erodes.','Maruti sits at the assembly end of the auto value chain — it designs vehicles with Suzuki''s platform engineering and assembles them domestically, but depends on thousands of component suppliers for steel, electronics, semiconductors and, increasingly, rare-earth magnets used in hybrid/EV motors — a supply chain with real China exposure.','Its domestic dealer and service network is Maruti''s strongest moat layer — the widest reach of any Indian carmaker, hard for new entrants, including EV-first players, to replicate quickly.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MARUTI','2025-12-31','volume_growth_pct',17.9,'%','Volume Growth','Vehicles sold YoY — 667,769 units, its highest-ever quarterly sales.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MARUTI','2025-12-31','revenue_growth_pct',29.2,'%','Revenue Growth (YoY)','Boosted by the Sept 2025 GST cut on small cars (28% → 18%) pulling forward demand.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MARUTI','2025-12-31','ebitda_margin_pct',11.7,'%','EBITDA Margin','Down from 13.8% a year ago — a one-time ₹593.9 crore Labour Code provision alone cost ~125 bps.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MARUTI','2025-12-31','realization_growth_pct',9.6,'%','Realization/Mix Growth','Implied average price/mix growth (revenue growth minus volume growth) — a richer SUV-heavy mix, not just more units.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MARUTI','Rare-earth magnet supply: China''s export curbs on rare-earth magnets (used in EV/hybrid motors) are a sector-wide supply risk that touches Maruti''s hybrid and upcoming EV ramp-up directly','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MARUTI','GST 2.0 tailwind: the Sept 2025 cut in small-car GST from 28% to 18% structurally lowered price points and pulled forward demand — a policy tailwind still working through the order book','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MARUTI','BS-VII and stricter emission/safety norms on the horizon will require fresh R&D and capex across the industry, a cost sector-wide, not Maruti-specific','risk',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MARUTI','2025-12-31','bull','Highest-ever quarterly volumes (667,769 units) and a record December, with dealer inventory lean at just 3 days — real demand, not a stocking illusion.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MARUTI','2025-12-31','bull','Exports are now roughly 45% of India''s total PV exports, about double nearest rival Hyundai''s share — a genuine structural export moat.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MARUTI','2025-12-31','bull','Zero long-term debt and a large net-cash position fund its ₹70,000 crore FY31 investment plan (8 new SUVs, EV/hybrid rollout) without straining the balance sheet.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MARUTI','2025-12-31','bear','PV market share has slipped from around 50% in 2020 to below 40% now, as SUV-focused rivals (Mahindra, Tata, Hyundai) grow faster than the overall market.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MARUTI','2025-12-31','bear','EBITDA margin compressed 210 bps YoY on commodity costs, FX and a one-time labour-law provision — the GST-driven volume surge came at a real profitability cost.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MARUTI','2025-12-31','bear','Its first EV launched only in 2025, well behind Tata Motors and Mahindra, who already hold established EV market share — a late mover in the segment reshaping the industry.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('TMPV','Tata Motors Passenger Vehicles','NSE','Auto','Passenger Vehicles + Jaguar Land Rover','Auto','IMPORTANT CONTEXT: ''Tata Motors'' split into two separately-listed companies in Oct-Nov 2025. This entry is Tata Motors Passenger Vehicles (NSE: TMPV) — the cars/SUVs/EVs business plus Jaguar Land Rover (JLR). The commercial-vehicle (trucks/buses) business was demerged out and, confusingly, kept the original ''Tata Motors'' name and NSE ticker TATAMOTORS for itself. TMPV sells mass-market Indian cars/SUVs/EVs (Nexon, Punch, Tiago) domestically and owns JLR, the British luxury carmaker (Jaguar, Land Rover, Range Rover, Defender) selling mainly in the US, Europe and China.','Tata Motors Passenger Vehicles'' own Q3 FY26 press release (cars.tatamotors.com), Storyboard18, and InvestyWise — cross-checked. Note: ticker/name changed in Oct-Nov 2025 demerger — see business_core.','JLR''s brand heritage (Range Rover, Defender, Jaguar) commands genuine luxury pricing power globally; the India business leans on Tata Group distribution scale and an early, credible EV push (Tata.ev has sold 250,000+ EVs).','Two very different value-chain positions live under one ticker: the India business is a mass-market assembler competing on price/features with Maruti and Mahindra, while JLR is a premium/luxury brand competing globally on design and heritage — with its own UK/Slovakia manufacturing footprint and chip and rare-earth-magnet dependencies for its EV push.','JLR''s near-total production shutdown after the cyber incident is a live case study in how digitally-dependent modern auto manufacturing has become — a single cyberattack cost hundreds of millions of pounds in lost output.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TMPV','2025-12-31','volume_growth_pct',22,'%','Volume Growth','India-market PV+EV wholesale volumes (171,000 units, its highest-ever quarter). JLR volumes fell sharply after a cyber incident and aren''t separately disclosed in units.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TMPV','2025-12-31','revenue_growth_pct',-25.8,'%','Revenue Growth (YoY)','Consolidated, dominated by JLR: a cyberattack halted JLR production for weeks, collapsing its revenue 39% YoY. The India business alone grew 24%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TMPV','2025-12-31','ebitda_margin_pct',2.2,'%','EBITDA Margin','Consolidated margin crushed by the JLR shutdown; the India PV/EV business alone held a 7.0% EBITDA margin.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TMPV','2025-12-31','realization_growth_pct',NULL,'%','Realization/Mix Growth','Not meaningful this quarter — the JLR cyber incident distorts the consolidated revenue/volume relationship. India-only realization grew roughly in line with its 24% revenue vs. 22% volume growth.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TMPV','Cybersecurity as a production risk: a late-2025 cyberattack on JLR halted vehicle production for weeks — a direct demonstration that modern auto manufacturing''s IT/OT systems are now a single point of failure for revenue','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TMPV','US and EU tariff relief: UK-US and EU-US trade deals are reducing tariffs on JLR-produced vehicles exported to the US from 27.5% toward 10-15%, a meaningful cost tailwind still phasing in','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TMPV','China luxury-vehicle demand and a China-specific luxury tax are pressuring JLR''s China volumes, a market increasingly dominated by domestic premium EV brands','risk',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TMPV','2025-12-31','bull','India domestic PV+EV business hit its highest-ever quarterly wholesale (171,000 units, +22% YoY) and its first-ever 200,000+ retail month — the core India franchise is healthy independent of JLR''s troubles.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TMPV','2025-12-31','bull','The Oct-Nov 2025 demerger of the commercial-vehicle business unlocks a cleaner, focused PV+JLR entity — CV cyclicality and capital needs no longer distort this stock''s numbers.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TMPV','2025-12-31','bull','JLR''s cyber incident is a one-off operational shock, not a structural demand problem — production returned to normal by mid-November and management guides to a significant Q4 recovery.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TMPV','2025-12-31','bear','A cyberattack on JLR in late 2025 halted production for weeks, wiping out roughly 39% of JLR''s quarterly revenue and pushing the whole consolidated entity to a net loss — a stark reminder of how much this stock still depends on a single UK-based luxury subsidiary.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TMPV','2025-12-31','bear','JLR separately faces US tariffs, a China luxury-tax headwind, and the planned wind-down of legacy Jaguar models ahead of an unproven all-new electric Jaguar lineup — multiple overlapping risks stacked on top of the cyber recovery.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TMPV','2025-12-31','bear','FY26 JLR guidance was already cut to a 0-2% EBIT margin with a £2.2-2.5bn free cash outflow even before fully absorbing the cyber-incident hit.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('M&M','Mahindra & Mahindra','NSE','Auto','Diversified Auto, Farm & Financial Services','Auto','Mahindra & Mahindra is India''s largest tractor maker and a top-3 SUV maker (XUV700, Scorpio, Thar, XEV electric SUVs), organised as a diversified group: Auto and Farm Equipment are the core manufacturing businesses, alongside listed and unlisted financial-services, IT-services (Tech Mahindra), logistics and real-estate arms. Revenue mainly comes from vehicle and tractor sales; the group''s other businesses add meaningfully to consolidated profit.','Mahindra & Mahindra''s own Q3 FY26 press release (mahindra.com), Autocar Professional, and Business Standard — cross-checked','Scale + brand trust built over decades in both SUVs (Thar, Scorpio cult following) and tractors (India''s largest tractor maker); diversification into financial services captures financing margin on the same vehicles it sells.','Mahindra sits at the assembly end for both its SUV and tractor lines, sourcing components from a large domestic supplier base, while its financial-services arm (Mahindra Finance) sits downstream financing the same vehicles it manufactures — a vertically-integrated demand engine unusual among Indian auto majors.','The group deliberately runs multiple ''Growth Gems'' (Logistics, Lifespaces, Last Mile Mobility) as call options on future growth beyond its core auto/farm value chain.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('M&M','2025-12-31','volume_growth_pct',23,'%','Volume Growth','Both Auto (302,000 vehicles) and Farm Equipment (~150,000 tractors) segments grew unit volumes 23% YoY in the same quarter.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('M&M','2025-12-31','revenue_growth_pct',26,'%','Revenue Growth (YoY)','Consolidated — the first time M&M crossed ₹52,100 crore in a single quarter.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('M&M','2025-12-31','ebitda_margin_pct',13.7,'%','EBITDA Margin','Standalone (Auto+Farm) EBITDA margin; the wider consolidated group (incl. financial services, Tech Mahindra) reports profit separately by segment.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('M&M','2025-12-31','realization_growth_pct',2.4,'%','Realization/Mix Growth','Modest — management flagged ''lower average selling price growth'' in Auto this quarter; most of the revenue gain came from volume, not price/mix.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('M&M','US tariff relief on tractors: a US-India trade resolution cut tariffs from as high as 50% to 18%, directly unlocking previously-held export inventory — a live example of trade policy moving a business''s numbers quarter to quarter','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('M&M','Rural demand cycle: tractor volumes are tightly linked to monsoon quality and farm-income conditions — a structural weather/policy dependency unique to the Farm Equipment segment','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('M&M','EV/ICE transition capex: management flagged growing EV exposure may pressure Auto segment margins near-term even as it builds long-term optionality','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('M&M','2025-12-31','bull','#1 revenue market share in SUVs (24.1%) and #1 in tractors (44.0%) — genuine category leadership in both core manufacturing businesses at once.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('M&M','2025-12-31','bull','Financial services arm (Mahindra Finance) grew PAT 97% YoY while keeping asset quality strong, and two ''Growth Gems'' — Mahindra Logistics and Mahindra Lifespaces — turned sharply profitable this quarter, showing diversification is starting to pay off.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('M&M','2025-12-31','bull','Sold 41,000+ electric SUVs since its March 2025 EV launch, with management signalling readiness for a Last Mile Mobility (electric 3W/4W) IPO — real EV traction, not just plans.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('M&M','2025-12-31','bear','US tractor exports were choked for eight to nine months by tariffs as high as 50% before a trade resolution brought them down to 18% — a reminder that even ''domestic'' Indian manufacturers carry real global trade-policy exposure.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('M&M','2025-12-31','bear','Realization/pricing growth was notably weaker than volume growth this quarter — growth is increasingly volume-led, not price-led, which caps margin expansion if commodity costs (copper, aluminium, precious metals) keep rising.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('M&M','2025-12-31','bear','The group''s complexity — auto, farm, financial services, IT services, logistics, real estate all under one ticker — makes it harder to value cleanly against pure-play auto peers.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('BAJAJ-AUTO','Bajaj Auto','NSE','Auto','Two-Wheelers & Three-Wheelers','Auto','Bajaj Auto is India''s largest exporter of two/three-wheelers and a top-3 domestic two-wheeler maker (Pulsar, Platina, Chetak electric scooter), with KTM and Triumph premium-motorcycle partnerships/stakes. It manufactures and sells motorcycles, scooters and three-wheelers domestically and to over 70 export markets (notably Africa, Latin America, ASEAN), plus a fast-growing electric-vehicle portfolio.','Bajaj Auto''s own Q3 FY26 press release (bajajauto.com), JM Financial, Business Standard, and ICICI Direct — cross-checked','Brand strength across price points (mass-market Pulsar/Platina to premium KTM/Triumph) plus the widest export distribution network of any Indian two-wheeler maker — a scale and reach moat few domestic rivals can match.','Bajaj assembles two/three-wheelers domestically (Pune/Chakan/Aurangabad) and exports nearly half its volumes — giving it direct, quarter-by-quarter exposure to emerging-market currencies (especially the Nigerian naira and other African currencies) that a purely domestic-focused peer wouldn''t carry. Its KTM (Austria) and Triumph (UK) partnerships/stakes also plug it into European motorcycle-brand value chains.','KTM AG (Austria), in which Bajaj holds a significant stake, went through public financial distress in 2024-25 — Bajaj has been infusing capital into its subsidiaries partly to support this relationship, a direct real-time link between European industrial trouble and an Indian company''s balance sheet.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJAJ-AUTO','2025-12-31','volume_growth_pct',9.5,'%','Volume Growth','Total two/three-wheeler units sold YoY (~13.4 lakh) — domestic volumes grew a modest 3%, while exports jumped 18% to their highest level in four years.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJAJ-AUTO','2025-12-31','revenue_growth_pct',21.2,'%','Revenue Growth (YoY)','Company-level revenue from operations, a record quarterly high.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJAJ-AUTO','2025-12-31','ebitda_margin_pct',20.8,'%','EBITDA Margin','Record-high margin, up 157 bps YoY, despite absorbing margin drag from record EV two-wheeler sales (lower-margin than ICE).',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJAJ-AUTO','2025-12-31','realization_growth_pct',10.7,'%','Realization/Mix Growth','Strong — a richer product mix (KTM/Triumph premium bikes, 125cc+ Pulsar segment) pushed average realization up well beyond volume growth alone.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJAJ-AUTO','Emerging-market export currency exposure: nearly half of volumes are exported (Africa, LatAm, ASEAN), making reported revenue sensitive to currency swings in markets like Nigeria, where sales have been outright negative YoY','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJAJ-AUTO','KTM Austria financial distress: continued capital infusions into subsidiaries (partly to support the KTM transaction) reflect real spillover risk from a European partner''s balance-sheet troubles','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJAJ-AUTO','EV two/three-wheeler mix now 25% of domestic revenue — a genuine, monetizing transition rather than a future promise, though still margin-dilutive versus ICE','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJ-AUTO','2025-12-31','bull','Electric two- and three-wheelers now contribute 25% of domestic revenue, both individually crossing ₹1,000 crore in quarterly revenue — EV transition is already meaningful, not speculative.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJ-AUTO','2025-12-31','bull','Export volumes surpassed 600,000 units for the first time in 15 quarters, with KTM+Triumph domestic volumes/revenue up roughly 50% YoY — premiumization and geographic diversification happening simultaneously.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJ-AUTO','2025-12-31','bull','Record EBITDA margin (20.8%) even while absorbing lower-margin EV mix and cost inflation shows real pricing power and cost discipline.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJ-AUTO','2025-12-31','bear','Domestic motorcycle volume growth was a muted 3% YoY even with GST-rationalisation tailwinds and festive demand — most of this quarter''s strength came from exports and premiumization, not core domestic demand.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJ-AUTO','2025-12-31','bear','Long-term debt has risen sharply (from roughly ₹759 crore to over ₹6,200 crore within a year) as the company funds its financing subsidiary and the KTM Austria transaction — a real shift from its historically debt-free balance sheet.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJ-AUTO','2025-12-31','bear','A key export market, Nigeria, continues to show negative YoY sales — a reminder that Bajaj''s export-heavy model carries real emerging-market currency and demand volatility.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('EICHERMOT','Eicher Motors','NSE','Auto','Two-Wheelers (Royal Enfield) + Commercial Vehicles (VECV)','Auto','Eicher Motors owns Royal Enfield, India''s dominant premium/mid-weight motorcycle brand (350cc-650cc range, sold domestically and increasingly exported to Europe/the Americas), which contributes over 90% of revenue. It also holds roughly half of VE Commercial Vehicles (VECV), a joint venture with Sweden''s Volvo Group that makes Eicher-brand trucks and buses — giving it a foothold in commercial vehicles without full standalone exposure to that cycle.','Eicher Motors'' own Q3 FY26 results (via ICICI Direct and Zee Business), and Business Standard — cross-checked','Royal Enfield''s brand and community moat (heritage, rider culture, global recognition around its 125-year milestone) is close to unique in Indian manufacturing — few domestic brands can charge premium prices purely on brand equity the way Royal Enfield does.','Eicher''s core value-chain position is brand-and-design-led, not scale-led: Royal Enfield competes on heritage, styling and community rather than lowest cost, letting it hold industry-leading margins on relatively modest volumes versus Bajaj or Hero. VECV, by contrast, is a straightforward JV manufacturing play riding India''s infrastructure/logistics capex cycle.','Exports remain a small share of Royal Enfield''s revenue today but are an explicit long-term lever, with Europe — aligning with the brand''s adventure-touring positioning — targeted as a key growth market.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('EICHERMOT','2025-12-31','volume_growth_pct',21,'%','Volume Growth','Royal Enfield motorcycle sales YoY (325,773 units) — its best-ever Q3.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('EICHERMOT','2025-12-31','revenue_growth_pct',22.9,'%','Revenue Growth (YoY)','Consolidated (Royal Enfield + VECV).',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('EICHERMOT','2025-12-31','ebitda_margin_pct',25.5,'%','EBITDA Margin','Consolidated; Royal Enfield standalone margin was even higher at 26.6%, its best quarterly margin on record.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('EICHERMOT','2025-12-31','realization_growth_pct',1.6,'%','Realization/Mix Growth','Modest — management is deliberately prioritising ''growth over profitability'' (volume and market share) over price hikes right now.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('EICHERMOT','GST 2.0 demand pull-forward: the same tax cut that boosted Q3 volumes across the auto sector is now normalizing, meaning Royal Enfield''s exceptional growth rate this quarter is unlikely to repeat as-is','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('EICHERMOT','Electric motorcycle entrants (Eicher''s own new ''Flying Flea'' EV sub-brand, alongside emerging EV-native competitors) represent the first real technology-transition test to Royal Enfield''s century-old ICE-centric brand identity','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('EICHERMOT','CAFE emission-norm tightening from 2027 and BS7 will raise compliance costs sector-wide, a cost Royal Enfield''s premium pricing is better positioned to absorb than mass-market rivals','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('EICHERMOT','2025-12-31','bull','Royal Enfield''s EBITDA margin (26.6% standalone) is best-in-class for the entire Indian two-wheeler industry — brand pricing power no domestic competitor currently matches.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('EICHERMOT','2025-12-31','bull','Crossed 1 million motorcycles sold year-to-date, and approved a brownfield capacity expansion (14.6 lakh → 20 lakh units/year) — real, funded confidence in sustained demand, not just a one-quarter bump.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('EICHERMOT','2025-12-31','bull','VECV posted market-share gains across every commercial-vehicle segment it competes in, adding a second growth engine uncorrelated with two-wheeler demand cycles.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('EICHERMOT','2025-12-31','bear','Analysts flag that this quarter''s domestic volume strength was largely a pull-forward effect from the September 2025 GST rate cut — demand has since ''stabilised,'' meaning this growth rate may not repeat.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('EICHERMOT','2025-12-31','bear','Management''s explicit ''growth over profitability'' stance means margin expansion is likely to stay capped even as volumes grow — a strategic choice investors should price in, not assume away.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('EICHERMOT','2025-12-31','bear','Royal Enfield remains almost entirely a single-brand, single-category bet (90%+ of revenue) — any shift in premium-motorcycle demand or new EV-native competitors hits Eicher harder than more diversified auto peers.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('BHARTIARTL','Bharti Airtel','NSE','Telecom','Telecom Services','Telecom','Bharti Airtel sells mobile, home broadband and enterprise connectivity in India and 14 African countries, plus a growing digital/data-centre business. Revenue is billed per subscriber per month (ARPU) &mdash; so the whole thesis rests on getting more subscribers to pay more each month, in a market where a price war a few years ago wiped out a competitor (Vodafone Idea) and left effectively two strong players, Airtel and Reliance Jio.','Bharti Airtel''s own Q4 FY26 BSE filing/investor release (bseindia.com) and earnings-call highlights, cross-checked against multiple financial media reports','Spectrum licenses + a nationwide tower/fibre network are a real, expensive-to-replicate physical moat, reinforced by a rational two-player India pricing structure post-Vodafone Idea''s decline. The open question is whether Jio''s faster subscriber-acquisition pace (via FWA broadband) erodes Airtel''s premium-subscriber advantage over time.','Airtel sits as an infrastructure-owning network operator — it holds spectrum (licensed from the government, a major cost and regulatory dependency), builds towers/fibre, and sells connectivity directly to consumers and enterprises, with Africa run as a largely separate operating unit under its own listed subsidiary economics.','Effectively a two-player India wireless market after Vodafone Idea''s collapse in relevance — pricing discipline between Airtel and Jio (rather than aggressive share wars) has structurally supported ARPU premiumisation industry-wide.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BHARTIARTL','2026-03-31','revenue_growth_pct',15.7,'%','Revenue Growth (YoY)','Consolidated revenue ₹55,383 crore, driven by India premiumisation and a strong Africa business.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BHARTIARTL','2026-03-31','arpu_inr',257,'₹','ARPU (Monthly)','Up from ₹245 a year ago (+4.9% YoY), though down slightly QoQ from ₹259 on two fewer billing days this quarter.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BHARTIARTL','2026-03-31','ebitda_margin_pct',51.2,'%','EBITDA Margin (FY26)','Full-year FY26 consolidated margin per the earnings call. Africa''s margin runs lower than India''s; India wireless alone is comfortably above 55%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BHARTIARTL','2026-03-31','net_debt_ebitda',1.29,'x','Net Debt / EBITDA','Improved sharply from 1.86x a year ago — real deleveraging, not just a good quarter. Excluding lease obligations it''s just 0.79x.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BHARTIARTL','2026-03-31','india_revenue_growth_pct',7.7,'%','India Revenue Growth (YoY)','India mobile revenue grew a similar 8.3% YoY; the Homes (broadband) segment grew a much faster 37.3% YoY off a smaller base.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BHARTIARTL','Regulatory/spectrum exposure: AGR (Adjusted Gross Revenue) dues and spectrum-payment obligations to the Dept. of Telecom remain a structural liability overhang common to every Indian telco, Airtel included','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BHARTIARTL','Africa currency exposure: African-market revenue and margins are sensitive to local currency appreciation/depreciation versus the rupee — a tailwind this year, but a two-way risk going forward','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BHARTIARTL','Data-centre and AI-infrastructure buildout (including a Google partnership on an AI hub in Visakhapatnam) is a genuine new adjacency being funded from telecom cash flows — optionality beyond the core connectivity business','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BHARTIARTL','2026-03-31','bull','Consolidated net income before exceptional items jumped 38.7% YoY to ₹7,245 crore — a clean, comparable profit number, not flattered by one-offs the way the prior year''s headline PAT was.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BHARTIARTL','2026-03-31','bull','Deleveraging is real and fast: net debt/EBITDA fell from 1.86x to 1.29x in a single year while still funding heavy 5G, fibre and data-centre capex (₹16,066 crore this quarter alone) — rare to cut debt and invest aggressively at the same time.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BHARTIARTL','2026-03-31','bull','The Homes (broadband) business grew revenue 37.3% YoY with 1.1 million net customer adds this quarter — a genuine second growth engine beyond mobile, still early in its penetration curve.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BHARTIARTL','2026-03-31','bear','Management itself said India''s pricing architecture is ''fundamentally broken'' by unlimited-data plans that cap revenue per user — ARPU actually dipped slightly quarter-on-quarter, and a real tariff-hike catalyst remains more hoped-for than confirmed.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BHARTIARTL','2026-03-31','bear','Jio is pulling ahead in subscriber acquisition using fixed wireless access (FWA) for faster broadband rollout — the market-share gap between the two leaders is described as widening, not stable, in Airtel''s own segment commentary.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BHARTIARTL','2026-03-31','bear','Finance costs remain elevated relative to the pace of deleveraging, and international operations (Africa capex, INR depreciation) add a layer of currency and geopolitical cost sensitivity on top of the core India business.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('RELIANCE','Reliance Industries','NSE','Conglomerate','Diversified — Energy, Retail, Telecom','Conglomerate','Reliance Industries runs four largely separate businesses under one holding company: Oil-to-Chemicals (O2C — refining and petrochemicals at the giant Jamnagar complex, plus declining KG-D6 gas production), Jio (India''s largest telecom/digital-services operator), Retail (grocery, fashion, electronics and fast-growing quick-commerce), and an early-stage New Energy business (solar, batteries, green hydrogen). Each segment earns money in a completely different way &mdash; which is the entire investment thesis: commodity-cycle energy profits funding the buildout of consumer-facing, higher-multiple businesses.','Reliance Industries'' own Q4 & FY26 results release (ril.com) and earnings-call transcript, cross-checked against Tradebrains, Goodreturns and DSIJ result coverage','Scale and vertical integration across energy, telecom and retail that essentially no single competitor can replicate end-to-end, backed by the Ambani family''s capital access and government relationships. The flip side of scale: RIL is now four different businesses with four different investment cases bundled into one stock, and the O2C segment''s commodity-cycle volatility still shows up loudly in the consolidated numbers, as this quarter demonstrated.','Uniquely vertically integrated across an entire value chain most peers only occupy one link of: upstream gas production feeds into the world''s largest single-site refining/petrochemical complex (Jamnagar), while Jio and Retail sit at the pure consumer-facing end, and New Energy is being built as a forward-looking fifth pillar (solar, batteries, green hydrogen/ammonia).','Jio''s FWA-led broadband push and Retail''s hyperlocal quick-commerce expansion (1,200+ cities, 5,100+ pin codes) both lean on the same underlying logistics and distribution muscle RIL has spent two decades building.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('RELIANCE','2026-03-31','revenue_growth_pct',12.5,'%','Revenue Growth (YoY)','Consolidated revenue from operations ₹2,94,059 crore. O2C, Digital Services and Retail each posted double-digit growth; Oil & Gas (E&P) revenue declined on natural KG-D6 field decline.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('RELIANCE','2026-03-31','ebitda_margin_pct',15,'%','EBITDA Margin','Down from 16.8% a year ago — Middle East conflict disruption and higher crude premiums squeezed the O2C segment specifically; Jio and Retail margins held up far better.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('RELIANCE','2026-03-31','arpu_inr',214,'₹','Jio ARPU (Monthly)','Up 3.8% YoY. Jio''s own segment EBITDA margin was a much healthier 52.4%, up 170bps YoY — the digital-services engine running hot even as O2C struggled.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('RELIANCE','2026-03-31','retail_revenue_growth_pct',11.1,'%','Retail Revenue Growth (YoY)','Revenue from operations basis. Retail EBITDA margin fell to 7.9% on deliberate, heavy investment in hyper-local quick-commerce build-out — a growth-over-margin trade-off, not weakening demand.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('RELIANCE','2026-03-31','net_debt_ebitda',0.6,'x','Net Debt / EBITDA','Net debt ₹1,24,717 crore against FY26 capex of ₹1,44,271 crore — comfortable leverage (Interest Service Coverage 5.55x) even while funding Jio, Retail and New Energy build-out simultaneously.',FALSE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('RELIANCE','Geopolitical crude exposure: the West Asia conflict directly disrupted O2C physical operations and margins this quarter — a live, not hypothetical, example of how Middle East instability hits Reliance''s largest legacy segment','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('RELIANCE','Jio IPO catalyst: an ''imminent'' Jio Platforms listing would be a major value-unlock event, separating a fast-growing digital business from the conglomerate discount applied to the whole group today','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('RELIANCE','New Energy build-out (green ammonia supply deal with Samsung C&T, battery gigafactories) is a genuine long-duration bet on India''s energy transition, funded by O2C and Jio cash flows rather than external capital','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RELIANCE','2026-03-31','bull','Jio and Retail together contributed over 55% of consolidated EBITDA for the first time in FY26 — real, structural diversification away from the commodity energy cycle that used to define this stock, not just a talking point.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RELIANCE','2026-03-31','bull','FY26 was a record year on every headline metric (revenue ₹11.76 lakh crore, EBITDA ₹2.08 lakh crore, PAT) despite a rough Q4 — the diversified portfolio genuinely absorbed a bad quarter in one segment (O2C) without dragging the whole company down.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RELIANCE','2026-03-31','bull','Management describes the Jio Platforms IPO as ''fairly imminent'' — a listing would crystallise Jio''s standalone value (roughly ₹1.46 lakh crore FY26 revenue, ~₹7,900 crore quarterly PAT) separately from the conglomerate discount RIL currently trades at.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RELIANCE','2026-03-31','bear','Q4 consolidated PAT fell 12.6% YoY and 9% QoQ to ₹16,971 crore, driven almost entirely by O2C margin compression from Middle East supply-chain disruption, higher crude premiums, and windfall taxes (SAED) — proof the energy business still swings group profit meaningfully, diversification narrative aside.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RELIANCE','2026-03-31','bear','Retail''s EBITDA margin compression (7.9%, down YoY) reflects the cost of competing in quick-commerce against well-funded, singularly-focused rivals like Blinkit and Zepto — an expensive land-grab with no confirmed payoff timeline yet.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RELIANCE','2026-03-31','bear','One independent analysis flagged a weak trailing ROE (~9.5%) against a P/E premium to the broader market — a valuation that assumes the Jio/Retail growth story executes cleanly, leaving little room for O2C-style disappointments to repeat.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('ONGC','Oil and Natural Gas Corporation','NSE','Oil & Gas','Upstream E&P','Oil & Gas','ONGC is India''s largest crude oil and natural gas producer &mdash; a state-owned (Maharatna) upstream explorer that pumps oil and gas from fields like Bombay High and the KG basin. It has also built downstream integration through majority stakes in refiner HPCL and petrochemical arm OPaL/MRPL, so its blended results mix pure exploration-and-production economics (driven by global crude/gas prices) with refining-margin economics from its subsidiaries.','ONGC''s own Q4 & FY26 consolidated results (via Groww/BSE filing coverage), cross-checked against IndianChemicalNews and PSU Connect','State ownership of India''s largest producing domestic oil and gas fields is a genuinely irreplaceable, licence-and-resource-based moat — nobody else gets to drill Bombay High. That moat is capped, though, by the geological reality of ageing fields and by India''s structural crude-import dependency, which limits how much pricing power any single domestic producer can really have.','Sits at the extraction end of the energy value chain — explores and produces crude oil and natural gas from domestic fields — but has deliberately built downstream integration via majority ownership of refiner HPCL plus stakes in MRPL and petrochemical producer OPaL, capturing margin further along the barrel rather than just selling crude at the wellhead.','India still imports roughly 80-85% of its crude oil needs — even maximised domestic production from ONGC doesn''t materially change the country''s structural energy-import dependency, a macro backdrop worth keeping in view.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ONGC','2026-03-31','revenue_growth_pct',3.6,'%','Revenue Growth (YoY)','Consolidated revenue from operations ₹1,73,805 crore. Full-year FY26 revenue was broadly flat as lower average crude prices offset volume gains.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ONGC','2026-03-31','pat_growth_pct',45.6,'%','PAT Growth (YoY)','Profit attributable to owners hit ₹10,820 crore this quarter — a record full-year profit of ₹41,424 crore, driven mainly by much stronger subsidiary (HPCL, MRPL) performance, not the core E&P business alone.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ONGC','2026-03-31','domestic_ep_revenue_growth_pct',2.3,'%','Domestic E&P Revenue Growth (Q4 YoY)','The purer read on core upstream performance. Full-year domestic E&P revenue actually fell 3.4% on weaker average crude prices through the year — the Q4 uptick doesn''t undo a soft full year.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ONGC','2026-03-31','dividend_payout_pct',51,'%','Dividend Payout Ratio (FY26)','Total FY26 dividend ₹16,669 crore (₹13.25/share) — a record payout. Display-only: a high PSU payout reflects government capital-allocation priorities as much as pure business strength.',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ONGC','2026-03-31','new_well_gas_production_pct',17,'%','New-Well Gas Share of Production','Newer, higher-priced gas wells now supply 17% of production and over 21% of nomination-gas revenue — a favourable mix shift, though display-only since it''s a production-mix indicator, not a ranked performance metric.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ONGC','Global crude price cyclicality: ONGC''s realizations move directly with international oil and gas prices — a full-year revenue decline in the core E&P segment this year despite steady production volumes shows this exposure isn''t theoretical','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ONGC','Legacy field decline: mature assets like Bombay High require continuous new-well drilling and exploration capex just to hold production flat, let alone grow it — a structural treadmill common to all ageing oil basins','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ONGC','Downstream diversification tailwind: HPCL, MRPL and the broader subsidiary portfolio delivering ''remarkable improvement'' this year shows the vertical-integration strategy has real earnings power when refining margins cooperate','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ONGC','2026-03-31','bull','Consolidated PAT jumped 45.6% YoY to a record ₹41,424 crore for the full year, with subsidiaries HPCL, MRPL, OVL and OPaL delivering what the company itself called ''remarkable improvement'' — diversification beyond pure upstream E&P is genuinely paying off.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ONGC','2026-03-31','bull','New-well gas (priced higher than legacy nomination gas) now makes up 17% of production and over a fifth of nomination-gas revenue — a structural mix-shift toward better realizations as ONGC keeps investing in newer fields to offset natural decline in older ones.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ONGC','2026-03-31','bull','A record FY26 dividend of ₹13.25/share (₹16,669 crore total, ~51% payout) makes ONGC one of India''s most reliable large-cap dividend payers — a genuine, growing cash return to shareholders, not a one-off.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ONGC','2026-03-31','bear','Strip out the subsidiaries and the core story is softer: full-year domestic E&P revenue actually declined 3.4% as weaker average crude prices through the year offset production gains — the headline profit jump leans heavily on refining/downstream units, not the upstream business ONGC is fundamentally valued on.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ONGC','2026-03-31','bear','International operations (ONGC Videsh) revenue fell 22% YoY in Q4 — the overseas diversification arm, meant to reduce dependence on ageing domestic fields, underperformed even in a quarter when domestic subsidiaries did well.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ONGC','2026-03-31','bear','The petrochemicals arm (OPaL) posted a full-year loss of ₹382 crore — not every leg of ONGC''s downstream diversification strategy is working yet, a reminder that vertical integration doesn''t guarantee profitability in every segment.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('COALINDIA','Coal India','NSE','Oil & Gas','Coal Mining / Consumable Fuels','Oil & Gas','Coal India is the world''s largest coal-mining company &mdash; a state-owned (Maharatna) PSU that mines roughly 80% of India''s domestic coal and supplies it to power plants and industry, mostly through long-term Fuel Supply Agreements at government-notified prices, plus a smaller, more profitable e-auction channel at market-linked premium pricing. Revenue is fundamentally a function of production volume, offtake (how much actually gets sold/dispatched) and per-tonne realization &mdash; not open commodity trading.','Coal India''s own Q4 & FY26 consolidated results and production/offtake filings, cross-checked against Business Standard, Upstox and IndianPSU coverage','A state-granted, near-monopoly position as India''s dominant domestic coal supplier — decades of mining rights, Fuel Supply Agreement relationships with power utilities, and evacuation infrastructure that would be near-impossible for a private entrant to replicate. The same government relationship that creates this moat also caps CIL''s ability to behave like a pure profit-maximising commodity producer — pricing and dividend decisions carry a policy dimension private miners don''t have.','Sits at the pure extraction end of the energy value chain, mining coal across 310 mines in 8 states and delivering it mainly through long-term Fuel Supply Agreements to power utilities and industrial buyers at largely government-notified prices — with a smaller e-auction channel offering the more market-sensitive, higher-margin slice of volume.','As a Maharatna PSU under the Ministry of Coal, capital allocation (dividend policy especially) is shaped as much by government fiscal priorities as by pure commercial logic — a structural feature of the stock, not a temporary condition.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('COALINDIA','2026-03-31','revenue_growth_pct',5.75,'%','Revenue Growth (YoY)','Q4 FY26 revenue from operations ₹46,490 crore. Full-year FY26 revenue was roughly flat at ₹1,68,400 crore — the Q4 uptick doesn''t offset a soft first three quarters.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('COALINDIA','2026-03-31','ebitda_margin_pct',38.5,'%','EBITDA Margin (Q4)','Q4 EBITDA of ₹17,917 crore, up 12% YoY — genuine margin expansion this quarter from better realizations and lower stripping (overburden-removal) activity, not just higher volumes.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('COALINDIA','2026-03-31','production_growth_pct',-1.7,'%','Production Growth (FY26)','Full-year coal production fell to 768.2 million tonnes from 781.1MT. Q4 alone was actually up marginally (239MT vs 237.7MT) — the decline is concentrated earlier in the year.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('COALINDIA','2026-03-31','offtake_growth_pct',-2.4,'%','Offtake/Sales Growth (FY26)','Full-year coal sold/dispatched fell to 744.9MT from 763.0MT. Closing inventory jumped 21% YoY to 129.96MT — coal is piling up faster than it''s being absorbed by demand.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('COALINDIA','2026-03-31','pat_growth_pct',11.1,'%','PAT Growth (Q4 YoY)','Q4 PAT ₹10,839 crore, boosted by a 30% jump in other income and one-time accounting adjustments per analyst commentary. Full-year PAT actually fell ~12% to ₹31,071 crore — the quarterly number flatters the annual trend.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('COALINDIA','Energy-transition headwind: India''s expanding solar and wind capacity structurally caps long-run thermal coal demand growth, a slow-moving but real risk to CIL''s core volume story even as near-term power demand still leans on coal','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('COALINDIA','Production-offtake gap and rising inventory (+21% YoY) point to real, current demand softness or dispatch/logistics constraints worth watching in the next few quarters, not dismissing as one-off','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('COALINDIA','Government policy tailwind: an explicit national strategy to cut coal imports by 240+ million tonnes over the next decade gives CIL a real production-growth mandate, if execution (evacuation infrastructure, washeries) keeps pace','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('COALINDIA','2026-03-31','bull','Q4 profit and EBITDA both grew double digits even as tonnes sold declined — real evidence of pricing and cost discipline (better realizations, lower stripping costs), not just a volume story.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('COALINDIA','2026-03-31','bull','A ₹5.25/share final dividend continues Coal India''s reputation as one of India''s most dependable large-cap income stocks — the government''s fiscal reliance on CIL dividends provides real, if imperfect, downside protection for the payout.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('COALINDIA','2026-03-31','bull','Genuine, if early, diversification: listing of subsidiaries Bharat Coking Coal and CMPDI, a commissioned 100MW solar plant, and a new renewable-energy joint venture all point toward reducing pure-thermal-coal dependence over time.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('COALINDIA','2026-03-31','bear','The core mining business shrank in FY26: production down 1.7% and offtake down 2.4% for the full year, with closing inventory up 21% YoY — coal is being mined faster than it''s being sold, a real demand-side or logistics problem, not a rounding error.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('COALINDIA','2026-03-31','bear','Full-year PAT fell nearly 12% and EBITDA fell 11% despite the strong headline Q4 — that quarterly beat leaned on a 30% jump in ''other income'' and retrospective accounting adjustments per independent analysis, a weaker underlying operating trend than the Q4 print alone suggests.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('COALINDIA','2026-03-31','bear','India''s fast-growing renewable and solar capacity is a structural, long-duration headwind to thermal coal demand growth — even as government policy pushes CIL to expand output and cut coal imports, nothing guarantees the demand side of that plan materialises on schedule.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('TATASTEEL','Tata Steel','NSE','Metals & Mining','Integrated Steel','Metals & Mining','Tata Steel makes and sells steel &mdash; from raw material (iron ore, coking coal) through to finished flat and long steel products for construction, auto and packaging &mdash; with a large, profitable India operation and separate, historically weaker European businesses (Netherlands and UK) that face different cost structures and demand environments. Profitability is driven by steel realizations, volumes, and raw-material costs, with India increasingly the business that determines the group''s overall result.','Tata Steel''s own Q4 & FY26 consolidated results (via Sahi.com/NSE filing coverage), cross-checked against Business Standard and Upstox','Integrated raw-material access (iron ore, and partial coking coal self-sufficiency) plus decades of scale and brand in the Indian market give Tata Steel a genuine domestic cost and distribution advantage. That moat doesn''t extend to Europe, where the company is a price-taker facing structural regulatory and competitiveness headwinds it can''t engineer its way out of as easily as it can in India.','A fully integrated steelmaker — Tata Steel controls iron ore and (partly) coking coal supply in India, runs its own blast furnaces and finishing lines, and sells directly into automotive, construction and packaging end-markets, while its Netherlands and UK operations run as largely separate regional businesses with their own cost structures and demand cycles.','India now accounts for roughly 74% of the group''s total crude steel production — the centre of gravity has structurally shifted toward the domestic business, away from the historically larger but now-struggling European operations.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATASTEEL','2026-03-31','revenue_growth_pct',12.54,'%','Revenue Growth (YoY)','Consolidated revenue ₹63,270 crore. India alone grew even faster; Netherlands grew on higher deliveries while UK stayed subdued.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATASTEEL','2026-03-31','ebitda_margin_pct',15.53,'%','EBITDA Margin','Up sharply from 11.67% a year ago. India''s standalone margin was far higher still (~24-25%) — Europe continues to drag the blended consolidated number down.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATASTEEL','2026-03-31','volume_growth_pct',8,'%','India Deliveries Growth (FY26)','India delivered a ''best-ever'' 22.5 million tonnes for the full year, up 8% YoY — the clearest, cleanest growth signal in the business.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATASTEEL','2026-03-31','net_debt_ebitda',2.3,'x','Net Debt / EBITDA','Net debt fell ₹2,285 crore YoY to ₹80,144 crore even while funding the Kalinganagar capacity expansion — deleveraging and growth capex happening together.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATASTEEL','2026-03-31','pat_growth_pct',146.9,'%','PAT Growth (YoY)','Consolidated PAT ₹2,965 crore. Genuinely operational, not one-off-driven — higher India volumes, better product mix and a ₹10,868 crore cumulative cost-transformation benefit are the real drivers.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATASTEEL','European regulatory risk: Tata Steel Netherlands faces active non-compliance notices and a stated intent by regulators to revoke operating permits for its coke/gas plants — a concrete, near-term threat to a material part of the European business, not a hypothetical','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATASTEEL','Global steel dumping: Chinese overcapacity continues to pressure global steel prices; Tata Steel''s UK and Netherlands units are directly exposed even as India benefits from a 12% safeguard duty on imports','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATASTEEL','India infrastructure capex tailwind: government-driven infrastructure spending underpins the domestic demand growth that''s now doing most of the heavy lifting for group profitability','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATASTEEL','2026-03-31','bull','India delivered its best-ever annual volumes (22.5 million tonnes, +8% YoY) at a standalone EBITDA margin around 24-25% — the core domestic business is firing on both volume and margin at once, a rare combination.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATASTEEL','2026-03-31','bull','A structured, disclosed cost-transformation programme has delivered ₹10,868 crore in cumulative benefits and directly explains 320bps of the year''s EBITDA margin improvement — evidence this isn''t just a favourable pricing cycle, but real operational execution.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATASTEEL','2026-03-31','bull','Management is guiding for a further 2 million tonnes of India volume growth in FY27 from the Kalinganagar ramp-up, plus continued margin expansion — a company describing forward momentum with specific, checkable numbers rather than vague optimism.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATASTEEL','2026-03-31','bear','Europe remains a genuine drag: Tata Steel UK posted an EBITDA loss (₹591 crore) this quarter, and Tata Steel Netherlands has received multiple regulatory non-compliance notices plus over €20 million in penalties, with the local Environment Agency signalling intent to revoke permits and force an early closure of coke/gas plants — a real, live regulatory threat to a sizeable chunk of the business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATASTEEL','2026-03-31','bear','The FY26 profit surge is measured against an unusually weak FY25 base (full-year PAT +215% YoY) — a favourable comparison that flatters the growth rate more than it reflects a fundamentally transformed earnings level in absolute terms.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATASTEEL','2026-03-31','bear','Global steel markets face persistent Chinese overcapacity and dumping pressure — India''s domestic infrastructure-driven demand has insulated Tata Steel so far, but the company remains exposed to global pricing cycles it doesn''t control.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('JSWSTEEL','JSW Steel','NSE','Metals & Mining','Integrated Steel','Metals & Mining','JSW Steel is India''s largest private-sector steelmaker, producing flat and long steel products for infrastructure, auto, construction and engineering customers from an India-centric manufacturing base (with a smaller US operation). Revenue is driven by domestic volumes and realizations, which are in turn shaped by input costs (coking coal especially), capacity utilisation, and India''s steel-safeguard trade policy.','JSW Steel''s own Q4 FY26 earnings-call highlights and results release, cross-checked against Business Standard, Groww and MarketsMojo analysis','Scale (India''s largest private steelmaker), integrated raw-material access, and now a technology/JV partnership with JFE Steel for higher-value products form a real competitive position. The moat is partly policy-dependent (import safeguard duty) and the balance sheet, while improving, still carries enough leverage that execution of the multi-year capacity plan matters more to the long-term thesis than any single quarter''s headline profit number.','An integrated steelmaker controlling much of its own raw-material and production chain from iron ore to finished flat/long steel products, with a growing downstream and value-added-product mix; the BPSL joint venture with Japan''s JFE Steel also gives it a technology and export-market partnership beyond pure India-centric scale.','India''s 12% safeguard duty on steel imports gives domestic producers like JSW real near-term pricing protection from subsidised Chinese steel — a policy tailwind, not a permanent structural moat.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JSWSTEEL','2026-03-31','revenue_growth_pct',14.19,'%','Revenue Growth (YoY)','Consolidated revenue ₹51,180 crore, an all-time high, beating analyst estimates of 10-12% growth.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JSWSTEEL','2026-03-31','ebitda_margin_pct',16.87,'%','EBITDA Margin','Up from 14.23% a year ago — stronger net steel realisations outpaced input-cost pressure, even while a Vijayanagar blast furnace was offline for upgrades (India ops ran at ~87% utilisation, would''ve been ~96% excluding that unit).',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JSWSTEEL','2026-03-31','volume_growth_pct',6,'%','Steel Sales Growth (YoY)','All-time-high quarterly sales of 7.97 million tonnes, even as crude steel production actually fell 2% — sold from inventory/improved mix while a furnace was under maintenance.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JSWSTEEL','2026-03-31','net_debt_ebitda',1.81,'x','Net Debt / EBITDA','Net debt fell to roughly ₹53,870 crore, down over ₹26,000 crore quarter-on-quarter, almost entirely from the BPSL (Bhushan Power and Steel) slump-sale deleveraging, not organic cash generation alone.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JSWSTEEL','2026-03-31','pat_growth_pct',131,'%','PAT Growth (YoY, Normalised)','Normalised Q4 PAT (excluding exceptional items) was ₹3,475 crore vs ₹1,503 crore a year ago — real, strong operating improvement. The headline reported PAT of ₹16,370 crore (+989% YoY) is overwhelmingly a one-off ₹18,051 crore accounting gain from the BPSL slump sale to a JFE Steel joint venture, not repeatable operating profit — shown here on a normalised basis so it''s comparable to peers.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JSWSTEEL','Accounting distortion risk: the scale of the BPSL exceptional gain this quarter is large enough that headline PAT and P/E figures from data aggregators may be badly misleading unless explicitly normalised — worth double-checking any single-source number against the exceptional-items breakdown','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JSWSTEEL','Leverage from an aggressive, multi-year capex programme (₹1.26 lakh crore approved) creates execution risk — the payoff depends on new capacity ramping on schedule and steel prices/demand cooperating through FY30-32','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JSWSTEEL','Import-safeguard policy tailwind: the 12% duty on imported steel currently shields domestic realisations from Chinese overcapacity pricing — a real but policy-dependent, not permanent, advantage','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWSTEEL','2026-03-31','bull','Record quarterly revenue and an EBITDA beat (₹8,634 crore, +35% YoY) came even with a major blast furnace offline for upgrades — the underlying operating business is genuinely strong, independent of the one-off BPSL accounting gain.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWSTEEL','2026-03-31','bull','The BPSL joint-venture deal with JFE Steel cut net debt by roughly ₹26,000-37,000 crore in a single quarter — a real, structural balance-sheet improvement, not just an accounting event, freeing capacity for the company''s large approved capex programme.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWSTEEL','2026-03-31','bull','A disclosed, board-approved capacity roadmap (31.9 to 62 million tonnes per annum by FY32, ~78 mtpa including joint ventures) gives investors a specific, trackable growth plan rather than vague expansion ambitions.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWSTEEL','2026-03-31','bear','The headline ₹16,370 crore Q4 profit figure is overwhelmingly a one-time accounting gain (₹18,051 crore) from the BPSL slump sale — using it to judge ''earnings growth'' without adjustment would badly overstate the business''s actual improvement, as this dashboard''s normalised figure shows.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWSTEEL','2026-03-31','bear','Leverage remains real even after deleveraging: debt-to-EBITDA of roughly 3.3x on some measures and net debt/EBITDA of 1.81x on others still constrain financial flexibility, and the approved capex plan (₹1,26,000 crore over 4-5 years, plus ₹1,00,000 crore more for JVs/mining) will need continued strong cash generation to fund without leverage creeping back up.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWSTEEL','2026-03-31','bear','One independent valuation analysis flagged the stock''s P/E (near 40x) as ''Expensive'' relative to fundamentals, given only ''Average'' return ratios (ROE 14%, ROCE 14.5%) — a premium valuation resting heavily on the FY27-FY32 capacity-growth story executing as planned.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('HINDALCO','Hindalco Industries','NSE','Metals & Mining','Aluminium & Copper','Metals & Mining','Hindalco is the metals flagship of the Aditya Birla Group — India''s largest aluminium producer and a significant copper smelter/refiner domestically, plus (via its wholly-owned subsidiary Novelis) the world''s largest aluminium rolling and recycling company, supplying can sheet and auto-body sheet to global beverage and automotive customers. Roughly 60-65% of consolidated revenue comes from Novelis, so the stock''s fortunes are genuinely a blend of a fast-growing India metals story and a much larger, more industrial-cycle-sensitive global rolling business.','Hindalco''s own Q4 & FY26 results press release (hindalco.com / Aditya Birla Group), cross-checked against Business Standard, Groww and AlCircle','Full value-chain integration — from bauxite and alumina through primary metal smelting to Novelis''s global #1 position in aluminium rolling and recycling — is a scale-and-technology moat few competitors can match end-to-end. The flip side: Novelis''s international manufacturing footprint imports risks (plant fires, tariffs, global industrial-demand cycles) that a purely domestic metals producer simply wouldn''t be exposed to.','One of the most vertically integrated metals businesses on the exchange — spanning domestic bauxite mining and alumina refining, primary aluminium and copper smelting in India, and (via Novelis) advanced downstream rolling and the world''s largest aluminium recycling operation feeding directly into global beverage-can and automotive-body-panel supply chains.','The India business and Novelis are genuinely different investments bundled into one stock — a domestic, high-margin, high-growth metals franchise, and a larger, lower-margin, more industrially cyclical global rolling business with its own separate risks.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDALCO','2026-03-31','revenue_growth_pct',20,'%','Revenue Growth (YoY)','Record consolidated revenue of ₹78,133 crore, up 20% YoY and 17.5% QoQ — both India and Novelis contributed, though India did the heavier lifting.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDALCO','2026-03-31','ebitda_margin_pct',14.3,'%','EBITDA Margin','Record consolidated EBITDA of ₹11,197 crore. India Aluminium Upstream alone ran a much richer ~45% segment margin — the blended number is diluted by Novelis''s lower-margin rolling/recycling model.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDALCO','2026-03-31','volume_growth_pct',-12,'%','Novelis Shipment Growth (YoY)','Novelis (the larger revenue segment) saw rolled-product shipments fall 12% YoY, mainly due to production interruptions from fires at its Oswego, US plant — a real operational setback in the company''s biggest single business.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDALCO','2026-03-31','net_debt_ebitda',1.83,'x','Net Debt / EBITDA','Up sharply from 1.06x a year earlier — genuine leverage increase, not just a rounding shift, worth watching alongside the Oswego recovery timeline.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HINDALCO','2026-03-31','pat_growth_pct',10,'%','PAT Growth (YoY, Before Exceptionals)','PAT before exceptional items hit a record ₹5,796 crore, +10% YoY — the cleaner read on underlying profitability. Reported PAT actually fell 50.8% YoY to ₹2,597 crore after ~₹4,171 crore of Oswego fire-related exceptional charges (remediation, repairs, business interruption).',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDALCO','Novelis Oswego plant fires: a real, still-unfolding operational and financial disruption at the company''s largest single facility — recovery timeline and any further exceptional costs are a genuine near-term watch item','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDALCO','US tariff exposure: Novelis''s US manufacturing and export operations face direct tariff-policy risk that a purely India-based metals producer wouldn''t carry','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDALCO','EV/battery-materials diversification (battery foil, EV battery enclosures) is a genuine new growth vector building directly on existing aluminium and copper processing expertise, not an unrelated bolt-on','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDALCO','2026-03-31','bull','India''s three business lines all posted record results in the same quarter — Aluminium Upstream EBITDA +13%, Copper EBITDA +48%, Downstream sales volume +18% — broad-based domestic strength, not one segment carrying the group.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDALCO','2026-03-31','bull','PAT before exceptional items reached a record ₹5,796 crore (+10% YoY) even in a quarter Novelis was actively disrupted by fires — real underlying earnings power that the headline reported-PAT decline obscures.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDALCO','2026-03-31','bull','Genuine forward-looking diversification: commissioned a Battery Foil plant and began commercial lithium-ion cell supplies, with an EV battery-enclosure facility at Chakan also scaling up — an early, concrete move into EV/battery materials beyond commodity metal.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDALCO','2026-03-31','bear','The Oswego, US plant fires were a real, large financial hit — ~₹4,171 crore of exceptional charges drove reported consolidated PAT down 50.8% YoY, and Novelis rolled-product shipments (the company''s largest single revenue driver) fell 12% YoY as a direct result.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDALCO','2026-03-31','bear','Net debt/EBITDA nearly doubled from 1.06x to 1.83x in a single year — a genuine increase in balance-sheet risk, even if the absolute level remains manageable for now.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDALCO','2026-03-31','bear','Novelis still supplies roughly 60-65% of consolidated revenue and carries its own separate exposures — US tariff policy, plant-specific operational risk, global auto/beverage-can demand cycles — that India''s strong domestic results can''t fully offset if they persist.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('NTPC','NTPC','NSE','Power','Power Generation','Power','NTPC is India''s largest power generation utility (state-owned, Maharatna) — it mainly burns coal to generate electricity, plus a fast-growing renewable arm (NTPC Green Energy), and sells that power to state electricity distribution utilities under long-term Power Purchase Agreements at tariffs regulated by the Central Electricity Regulatory Commission (CERC). Because returns are formula-driven off a ''regulated equity'' asset base rather than open market pricing, growth comes almost entirely from adding new generation capacity, not from pricing power.','NTPC''s own Q4 & FY26 results and earnings-call highlights, cross-checked against MarketsMojo, Sarkaritel and Multibagg.ai coverage','Scale (India''s largest generator), decades of PPA relationships with state utilities, and a regulated-returns model that guarantees a return on the commissioned asset base once assets are capitalised — a genuinely low-risk moat. The trade-off: NTPC can''t out-earn its regulated formula in a strong pricing cycle the way a merchant generator could, so the ceiling on returns is as structurally fixed as the floor.','Sits purely in the generation link of the power value chain — NTPC doesn''t own transmission (that''s Power Grid) or distribution (state discoms) — selling bulk electricity to state utilities under long-term PPAs at CERC-regulated tariffs tied to its commissioned asset base.','NTPC Green Energy, the renewable subsidiary, is scaling fast (revenue +29% YoY) but still small relative to the thermal core — the long-term growth thesis increasingly depends on this arm executing at scale, not just the legacy coal fleet running efficiently.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NTPC','2026-03-31','revenue_growth_pct',-0.29,'%','Revenue Growth (Q4 YoY)','Revenue from operations was essentially flat at ₹49,688 crore. Full-year generation also fell slightly (432.2 vs 438.7 billion units) on softer demand and grid curtailment, despite record capacity additions.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NTPC','2026-03-31','pat_growth_pct',15,'%','Group PAT Growth (FY26)','Full-year consolidated group PAT was ₹27,547 crore, the cleaner read. Q4 alone jumped over 34% YoY on some measures, driven overwhelmingly by a one-off ₹9,062 crore tax credit and regulatory deferral adjustments — not a repeatable quarterly run-rate.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NTPC','2026-03-31','capacity_growth_pct',12.1,'%','Installed Capacity Growth (FY26)','Added 9,618 MW in FY26 — the highest annual addition in NTPC''s history — taking installed capacity past 89 GW, with over 34 GW more under construction.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NTPC','2026-03-31','plf_pct',72.04,'%','Coal Fleet PLF (Utilisation)','Comfortably above the national coal-fleet average of 63.20% — a genuine, sustained operational-efficiency edge over the rest of the sector.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NTPC','2026-03-31','capex_growth_pct',9.9,'%','Group Capex Growth (FY26)','Group capex rose to ₹49,068 crore from ₹44,636 crore. Display-only: higher capex funds future capacity growth but isn''t itself a performance signal without knowing the returns it generates.',NULL,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NTPC','Discom counterparty risk: NTPC''s primary customers are state electricity distribution companies, many of which remain financially stressed — a structural, sector-wide collection and receivables risk, even though NTPC''s own receivable days improved sharply this year','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NTPC','Renewable execution gap: NTPC''s own FY26 green-capacity addition fell short of internal targets, with projects spilling into FY27 — a concrete delivery risk on the part of the growth story most tied to India''s energy-transition narrative','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NTPC','Policy tailwind: India''s power demand growth and the 500 GW renewable-by-2030 national target give NTPC (thermal fleet plus NTPC Green Energy) a long, government-backed capacity growth runway','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPC','2026-03-31','bull','Added a record 9,618 MW of capacity in FY26 — the most in company history — with installed capacity now over 89 GW and another 34+ GW under construction, giving genuine multi-year regulated-return growth already locked into the pipeline.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPC','2026-03-31','bull','Coal fleet utilisation (PLF) of 72.04% beats the national average of 63.20% by a wide margin — real, sustained operational excellence, not a one-quarter anomaly.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPC','2026-03-31','bull','Balance-sheet discipline is improving alongside the growth: weighted average borrowing cost fell to 5.98% from 6.61%, and outstanding receivable days dropped sharply to 15 from 29 — working-capital and financing efficiency moving the right direction together.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPC','2026-03-31','bear','Despite record capacity additions, actual generation fell YoY (432.2 vs 438.7 billion units) on softer demand and grid curtailment — new capacity isn''t yet translating into proportionate output or revenue growth.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPC','2026-03-31','bear','The headline Q4 profit jump was overwhelmingly driven by a one-off ₹9,062 crore tax credit and regulatory deferral account movements — strip that out and the underlying quarterly operating trend is far more modest than the reported percentage suggests.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPC','2026-03-31','bear','NTPC''s own renewable capacity addition fell short of its FY26 targets, with projects spilling into FY27 — a real execution gap on the green-transition leg of the growth story, even as the core thermal business performs well.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('POWERGRID','Power Grid Corporation of India','NSE','Power','Power Transmission','Power','Power Grid is India''s central transmission utility (state-owned, Maharatna) — it doesn''t generate or sell electricity to consumers, it owns and operates the high-voltage transmission lines and substations (roughly 1,73,000 circuit km, 265 substations) that move power from generators like NTPC to state distribution networks. Revenue comes from CERC-regulated tariffs on its transmission asset base, plus smaller consultancy and telecom businesses — one of the most predictable, formula-driven earnings models on the exchange.','Power Grid''s own FY26 audited results release (via PSU Connect/BSE filing coverage), cross-checked against Whalesbook and Indian Masterminds','A near-monopoly position in India''s inter-state high-voltage transmission network, built over decades and effectively impossible for a new entrant to replicate at scale, combined with a CERC-regulated return model that guarantees earnings on commissioned assets. As with NTPC, this moat caps upside as much as it protects downside — Power Grid''s growth ceiling is set by how much new transmission infrastructure India builds and awards to it, not by pricing power.','The pure transmission link in the power value chain — Power Grid moves electricity in bulk from generators (like NTPC) to state distribution utilities over its own high-voltage network, earning a CERC-regulated return on its capitalised transmission assets rather than selling power itself.','As the primary implementing agency for India''s Green Energy Corridors and inter-state transmission bids (InSTS), Power Grid is structurally positioned to capture the transmission infrastructure spend required by the country''s renewable energy build-out, regardless of which generation company ultimately wins the underlying power-sale contracts.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('POWERGRID','2026-03-31','revenue_growth_pct',-1.27,'%','Revenue Growth (FY26)','Revenue from operations dipped slightly to ₹40,904 crore from ₹41,431 crore — the core transmission segment declined 2.7%, partly offset by consultancy revenue growing a fast 56.8% off a small base.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('POWERGRID','2026-03-31','pat_growth_pct',3,'%','PAT Growth (FY26)','Consolidated PAT ₹15,928 crore. Q4 alone grew a faster 9.7% YoY to ₹4,546 crore — a steadier, less lumpy earnings profile than generation-side utilities, consistent with the regulated-tariff model.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('POWERGRID','2026-03-31','ebitda_margin_pct',75.2,'%','EBITDA Margin (Q4)','Down from 83.98% a year ago — a real, notable compression worth watching, in a business where margins are usually very stable given the regulated-tariff structure.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('POWERGRID','2026-03-31','order_book_to_revenue',4.15,'x','Works-in-Hand / Revenue','Works-in-hand of ~₹1.70 lakh crore against FY26 revenue of ~₹40,900 crore — over 4x current annual revenue already committed, giving strong multi-year revenue visibility. A further ₹1.1 lakh crore bidding pipeline sits beyond this.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('POWERGRID','Rising leverage: total borrowings up ~13% YoY to fund transmission capex, with a further ₹5,000 crore raise approved — a real, growing balance-sheet commitment tied to execution of the multi-year build-out','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('POWERGRID','Margin compression in Q4 (EBITDA margin down nearly 900bps YoY) is unusual for a normally very stable regulated business and worth monitoring for whether it''s transient or a new cost baseline','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('POWERGRID','India''s ~₹2.44 lakh crore transmission investment requirement to support the 500 GW renewable-by-2030 target positions Power Grid, as the primary inter-state implementing agency, for a long structural capex and revenue-growth runway','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('POWERGRID','2026-03-31','bull','Works-in-hand of ~₹1.70 lakh crore (over 4x annual revenue) plus a further ₹1.1 lakh crore bidding pipeline give genuinely strong, multi-year revenue visibility — a rare degree of forward clarity for an infrastructure business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('POWERGRID','2026-03-31','bull','Consultancy revenue grew 56.8% YoY (albeit off a small base) — a real, if modest, diversification beyond the core regulated-tariff transmission business.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('POWERGRID','2026-03-31','bull','One of India''s most consistent dividend payers, with a total FY26 payout of ₹9/share and a track record of steady, predictable cash distributions that reflect the underlying regulated-earnings model.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('POWERGRID','2026-03-31','bear','EBITDA margin compressed sharply from 83.98% to 75.21% in Q4 — a real deterioration in a business where margins are usually extremely stable, worth understanding before assuming it''s a one-off.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('POWERGRID','2026-03-31','bear','Total borrowings rose from ₹1,30,964 crore to ₹1,48,009 crore in a single year to fund the transmission build-out — leverage is increasing alongside growth, and the company approved a further ₹5,000 crore fundraise at the same results meeting.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('POWERGRID','2026-03-31','bear','Core transmission-segment revenue actually declined 2.7% for the year — the growth story depends on new asset capitalisation (₹37,000 crore guided for FY27) converting into tariff income on schedule, not on the existing asset base.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('ULTRACEMCO','UltraTech Cement','NSE','Cement','Cement & Building Materials','Cement','UltraTech Cement (Aditya Birla Group) is India''s largest cement producer and, after crossing 200 million tonnes of capacity in April 2026, the largest cement company outside China. It sells grey cement, ready-mix concrete and building products (wall putty, construction chemicals, and a new wires & cables foray) mainly to India''s housing, infrastructure and commercial construction sector, with profitability driven by cement realizations, volumes, and energy/fuel costs (coal and petcoke are large, volatile inputs).','UltraTech''s own Q4 & FY26 results release and earnings-call transcript (via Investywise/Yahoo Finance coverage), cross-checked against Business Standard and Dailyhunt','Scale (largest cement producer outside China), vertically integrated limestone and captive-power access, and India''s widest cement dealer/distribution network form a genuine cost and reach moat that smaller regional players can''t match — reinforced by a deliberate shift toward premiumization (branded, higher-margin products and a broader building-materials portfolio) that extends the moat beyond commodity cement pricing alone.','Controls limestone reserves and a growing captive/green power base (43% green power mix, targeting 85% by FY30) feeding its own integrated cement plants, sells through India''s widest cement dealer network, and is deliberately extending into adjacent building-materials categories (construction chemicals +44% YoY, a new wires & cables foray with ₹1,800 crore approved) to capture more of the construction customer''s spend beyond pure cement.','Management guides to a sustainable 7-8% annual volume growth from India''s structural urbanisation, infrastructure spending and PMAY housing demand — a demand base they describe as undiluted by near-term geopolitical noise.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ULTRACEMCO','2026-03-31','revenue_growth_pct',11.8,'%','Revenue Growth (YoY)','Consolidated revenue ₹25,467 crore. Results aren''t fully comparable YoY since the company completed the India Cements and Kesoram acquisitions mid-cycle — some of this growth is inorganic.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ULTRACEMCO','2026-03-31','ebitda_margin_pct',21.7,'%','EBITDA Margin','Up from 17.9% in Q3 FY26. EBITDA per tonne reached ₹1,253 (aggregate), up 11% YoY, even absorbing an estimated ₹120/tonne cost headwind from the West Asia conflict.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ULTRACEMCO','2026-03-31','volume_growth_pct',9.3,'%','India Grey Cement Volume Growth (YoY)','Record 42.41 million tonnes for the quarter, capacity utilisation at 89%. The broader ''UltraTech'' brand (including acquired capacity) grew a faster 19% YoY — worth knowing how much of that is organic vs. acquired.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ULTRACEMCO','2026-03-31','net_debt_ebitda',0.94,'x','Net Debt / EBITDA','A healthy, disciplined level even while funding record capex and completing two acquisitions (India Cements, Kesoram) in the same period.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ULTRACEMCO','2026-03-31','pat_growth_pct',21,'%','PAT Growth (YoY)','Consolidated PAT ~₹3,000 crore. Board recommended a ₹240/share (2400%) dividend for the year, reflecting a genuinely strong full-year profit of over ₹8,000 crore.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ULTRACEMCO','West Asia conflict cost exposure: management quantified an ~₹120/tonne EBITDA impact from the conflict''s effect on imported fuel (petcoke/coal) costs — a real, current, and ongoing geopolitical cost pass-through','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ULTRACEMCO','Acquisition integration risk: India Cements and Kesoram are still ''moving from integration drag to earnings contributor'' per management''s own words — the full synergy payoff is a multi-year execution bet, not yet realised','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ULTRACEMCO','India infrastructure and housing (PMAY) demand tailwind: government capex commitments (e.g. Mumbai''s own $60bn infrastructure spend cited by management) underpin the 7-8% sustainable volume growth guidance','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ULTRACEMCO','2026-03-31','bull','Record consolidated volumes (44+ million tonnes) and 200 million tonnes of annual capacity — the largest cement producer outside China — with the completed India Cements and Kesoram integrations finishing ahead of schedule.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ULTRACEMCO','2026-03-31','bull','EBITDA per tonne improved 11% YoY to ₹1,253 even while absorbing a real, quantified West Asia-driven cost headwind (~₹120/tonne) — genuine pricing and cost-efficiency execution, not just a favourable environment.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ULTRACEMCO','2026-03-31','bull','Net debt/EBITDA held to a disciplined 0.94x while simultaneously funding record capex, two acquisitions, and a further 37 million tonnes of already-committed FY28 capacity — growth and balance-sheet discipline happening together.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ULTRACEMCO','2026-03-31','bear','The acquired India Cements business is still well below group profitability — its EBITDA/tonne of ₹497 in Q4, while improving fast from ₹333 in Q2, remains under half UltraTech''s core ₹1,296/tonne — full synergy realisation is a multi-year story, not already banked.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ULTRACEMCO','2026-03-31','bear','Management explicitly flagged the West Asia conflict as a live, ongoing cost headwind and absorbed ₹90 crore of one-off packaging costs this quarter — geopolitical volatility is a current, not hypothetical, drag on margins.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ULTRACEMCO','2026-03-31','bear','The company itself states that Q4/FY26 results ''are not comparable'' with the prior year because of the mid-cycle acquisitions — meaning some of the impressive headline volume and revenue growth is inorganic, not pure market-share gain worth extrapolating forward.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('GRASIM','Grasim Industries','NSE','Cement','Diversified Holding — Cement, Chemicals, Paints, Financial Services','Cement','Grasim Industries is the Aditya Birla Group''s diversified holding company. It directly manufactures Viscose Staple Fibre (VSF, a man-made textile fibre) and chlor-alkali/specialty chemicals (which also backward-integrate into VSF production), while separately holding a majority stake (~57%) in UltraTech Cement, a large stake in financial-services group Aditya Birla Capital (NBFC lending, insurance, asset management), and a fast-scaling paints challenger brand, Birla Opus. For investors, owning Grasim means owning a bundle of genuinely different businesses &mdash; cement, chemicals, textiles, financial services and paints &mdash; through one holding-company structure.','Grasim''s own Q4 & FY26 results release (grasim.com/Aditya Birla Group), cross-checked against Business Standard, Zeebiz and HDFC Sky coverage','Backward-integrated chemicals-to-fibre production gives the core legacy VSF business a genuine cost moat few global peers can match at scale, while majority ownership of India''s cement leader (UltraTech) and a rapidly scaling stake in Aditya Birla Capital provide optionality across three separate, large Indian growth markets. The moat here is less about any single product and more about the Aditya Birla Group''s demonstrated capital-allocation discipline — funding new bets like paints and B2B e-commerce from cash generated by mature, cash-rich legacy businesses.','Sits at the top of a genuinely diversified group structure — directly running backward-integrated VSF and chlor-alkali chemicals production (the chemicals feed the fibre process itself), while its majority UltraTech stake gives indirect exposure to the full cement value chain and its Aditya Birla Capital stake gives exposure to India''s consumer and corporate lending and insurance markets.','The Aditya Birla Capital equity raise (Grasim contributing ₹2,880 crore to keep its 52.3% stake) shows the group actively re-investing cash generated by mature businesses (cement, chemicals) into faster-growing ones (financial services, paints) — a deliberate, ongoing capital-allocation strategy, not a one-off.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('GRASIM','2026-03-31','revenue_growth_pct',15.4,'%','Revenue Growth (YoY)','Consolidated revenue ₹51,101 crore, a record quarter, with cement, paints, chemicals and financial services all contributing to growth simultaneously.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('GRASIM','2026-03-31','ebitda_margin_pct',15.7,'%','EBITDA Margin','Consolidated EBITDA ₹8,011 crore, up 22% YoY — margin expansion outpacing revenue growth, a genuinely positive operating-leverage signal across a diversified portfolio.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('GRASIM','2026-03-31','volume_growth_pct',11,'%','VSF Volume Growth (YoY)','Viscose Staple Fibre — Grasim''s original core business — grew sales volume 11% YoY with realizations up 2% YoY, maintaining global leadership and pricing power despite volatile raw-material costs.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('GRASIM','2026-03-31','pat_growth_pct',33.3,'%','Adjusted PAT Growth (FY26)','Full-year adjusted PAT (attributable to Grasim shareholders, excluding exceptional items) reached ₹5,203 crore. Grasim itself reported a standalone net loss in Q4 due to one-off exceptional items — the strong consolidated number depends heavily on subsidiary performance (UltraTech, Aditya Birla Capital), a nuance worth understanding before reading the headline growth rate as pure operating strength.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GRASIM','Holding-company complexity: Grasim''s own standalone results can diverge sharply from the consolidated headline (as this quarter''s standalone loss versus consolidated profit growth shows), making it harder to cleanly attribute value or risk to any single part of the business','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GRASIM','Paints market-share gains (Birla Opus crossing 10% share, +370bps) represent a genuine structural challenge to the paints category''s incumbent leader, still early in a multi-year trajectory toward the company''s own FY28 profitability target','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GRASIM','Crude-oil-linked raw material costs affect chemicals and VSF simultaneously — a shared commodity and currency sensitivity across multiple segments at once, not a risk isolated to a single business line','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GRASIM','2026-03-31','bull','Every major segment — cement, paints, chemicals, financial services and VSF — grew and improved profitability in the same quarter, a rare ''everything working at once'' result for a genuinely diversified holding company.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GRASIM','2026-03-31','bull','Birla Opus (paints) grew revenue 19% sequentially and crossed 10% market share (+370bps) — a real, fast challenge to the paints category''s historical incumbent, backed by a specific ₹10,000 crore profitable-revenue target by FY28.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GRASIM','2026-03-31','bull','Aditya Birla Capital''s lending book grew 32% YoY to ₹2.07 lakh crore, and Grasim is committing further capital (₹2,880 crore) to defend its majority stake as ABCL raises equity — the financial-services arm is becoming a large, fast-growing business in its own right.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GRASIM','2026-03-31','bear','Grasim''s own standalone results showed a net loss (₹163.54 crore) in Q4, driven by a chemical-plant impairment and new Labour Code cost impacts — the consolidated profit story leans heavily on subsidiaries, and the parent''s own core businesses had a genuinely rough quarter.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GRASIM','2026-03-31','bear','As a holding company spanning cement, chemicals, textiles, paints and NBFC lending, Grasim bundles businesses with fundamentally different risk profiles into one stock — a regulated-ish industrial cement business sits alongside a credit-risk-bearing financial-services arm, making this a genuinely complex single investment thesis to underwrite.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GRASIM','2026-03-31','bear','Birla Opus (paints), while growing fast, is still loss-making as it scales — management''s own guidance is that losses ''should reduce in FY27,'' meaning the payoff on this multi-year bet is still ahead of investors, not behind them.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('ASIANPAINT','Asian Paints','NSE','Consumer Durables','Paints & Coatings','Consumer Durables','Asian Paints is India''s largest paint company — decorative paints (interior/exterior wall paints) make up roughly 90% of revenue, sold through India''s largest paint dealer network, alongside a smaller industrial coatings business, international operations, and a growing ''Beautiful Homes Store'' push into home décor and renovation services to capture more of a customer''s overall home-improvement spend.','Asian Paints'' own Q4 & FY26 results release, cross-checked against Business Standard, Storyboard18 and Upstox','Decades of brand trust and India''s largest paint dealer/distribution network form a genuine, historically hard-to-replicate reach moat. That moat is being tested for the first time in years by a well-capitalised, Aditya Birla-backed competitor (Birla Opus) with clear ambitions and early, real market-share gains — worth watching whether Asian Paints'' distribution advantage holds up against a rival with comparable group-level financial backing.','Sits at the finished-goods end of the coatings value chain — sources crude-linked raw materials (titanium dioxide, resins, solvents) globally and converts them into branded paint sold through India''s largest paint dealer network, while extending into adjacent home-improvement services (Beautiful Homes Stores) to capture more of a customer''s total renovation spend beyond just the paint can.','Decorative paints (~90% of revenue) means the business is heavily tied to India''s residential real estate and repainting cycle — a slowdown in premium/luxury housing affordability could directly reduce repainting frequency and new-construction demand.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ASIANPAINT','2026-03-31','revenue_growth_pct',10.6,'%','Revenue Growth (YoY)','Revenue from operations ₹9,247 crore. Overall coatings business (decorative + industrial) grew value 11% on 12.7% volume growth.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ASIANPAINT','2026-03-31','volume_growth_pct',12.4,'%','India Decorative Volume Growth','Value growth in the same segment was 10.2% — volumes actually outpaced value, meaning realizations/mix were roughly flat to slightly down even as demand recovered strongly.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ASIANPAINT','2026-03-31','ebitda_margin_pct',19.3,'%','EBITDA Margin','Up sharply from 17.2% a year ago, helped by raw-material deflation (titanium dioxide, crude-linked derivatives) normalising after several quarters of cost pressure — a real tailwind, not just internal cost-cutting.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ASIANPAINT','2026-03-31','pat_growth_pct',69.3,'%','PAT Growth (YoY)','Net profit ₹1,172-1,185 crore. Measured against a weak year-ago base that included a ₹183 crore exceptional item — profit before exceptional items grew a more modest, still-solid 33.9% YoY.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ASIANPAINT','Birla Opus competitive intensity: Grasim''s paints challenger crossed 10% market share this same quarter and is explicitly flagged by Asian Paints'' own management as a FY27 watch item — the most direct, well-funded competitive threat the category leader has faced in years','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ASIANPAINT','Crude-linked raw material costs (titanium dioxide, monomers) remain a structural, largely uncontrollable margin swing factor — this quarter''s deflation was a tailwind, but the direction can reverse quickly','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ASIANPAINT','Raw material cost normalisation this quarter directly supported margin recovery — if sustained into FY27, it''s a real profitability tailwind independent of any pricing or volume actions the company takes','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ASIANPAINT','2026-03-31','bull','Genuinely ''all-round'' performance in management''s own words — double-digit volume AND value growth alongside meaningful margin expansion, a rare combination after several quarters where the company had to choose between growth and margin.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ASIANPAINT','2026-03-31','bull','Raw material deflation (titanium dioxide, crude-linked inputs) directly supported the EBITDA margin recovery to 19.3% from 17.2% — a real cost tailwind that, if sustained, supports FY27 profitability independent of pricing actions.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ASIANPAINT','2026-03-31','bull','International operations delivered ''resilient growth with improved profitability despite volatility in select markets'' — geographic diversification cushioning any single-market softness in India.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ASIANPAINT','2026-03-31','bear','The headline 69% profit jump leans partly on a weak year-ago comparison base (a ₹183 crore exceptional item in Q4 FY25) — the cleaner pre-exceptional profit growth of 33.9% YoY is still strong, but meaningfully less dramatic than the headline number.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ASIANPAINT','2026-03-31','bear','Management explicitly named Birla Opus (Grasim''s paints challenger, which crossed 10% market share this same quarter) as a genuine FY27 competitive-intensity risk — Asian Paints faces its first well-capitalised direct challenger in years, not just diffuse regional competition.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ASIANPAINT','2026-03-31','bear','Management''s own outlook flagged the West Asia conflict as contributing to ''near-term uncertainty in demand'' — the same geopolitical volatility hitting cement and steel input costs elsewhere in this dashboard also clouds paint demand visibility.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('TITAN','Titan Company','NSE','Consumer Durables','Jewellery & Watches','Consumer Durables','Titan Company (a Tata Group and Tamil Nadu government JV) is India''s largest organized jewellery retailer, with jewellery brands Tanishq, Mia, Zoya and CaratLane now contributing roughly 85% of revenue, alongside a watches business (Titan, Sonata, Fastrack) and a newly acquired international jewellery platform (Damas, GCC region). Because a large share of jewellery revenue is effectively the pass-through value of the gold itself, headline revenue growth can be heavily inflated by rising gold prices and bullion-related sales — buyer growth, like-for-like sales and consumer (secondary) sales are the more meaningful signals of real underlying demand.','Titan''s own Q4 FY26 business update and results release, cross-checked against Free Press Journal, TipRanks, Multibagg.ai and Investing.com coverage','Decades of brand trust — Tanishq is the dominant organized-jewellery brand in a market historically fragmented across small local jewellers who don''t offer the same purity/certification assurance — combined with India''s largest owned jewellery retail network form a genuine, hard-to-replicate moat, reinforced by a multi-brand segmentation strategy that captures different customer cohorts under one corporate roof.','Sits at the retail end of the jewellery and watch value chains — designing and selling finished products through its own large owned/franchised store network (3,603 stores across 440+ towns) rather than manufacturing at scale itself, giving strong brand and distribution control but real, largely unhedged exposure to gold and diamond price volatility.','The multi-brand strategy (Tanishq for mass-premium, Mia for younger urban women, Zoya for ultra-luxury, CaratLane for digital-first buyers) captures different customer segments under one corporate umbrella — a deliberate segmentation few single-brand jewellers can replicate.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TITAN','2026-03-31','revenue_growth_pct',80.48,'%','Reported Revenue Growth (YoY)','Consolidated revenue from operations ₹26,920 crore. This headline figure is significantly inflated by rising gold prices and bullion-related sales, which carry much thinner margins than core jewellery retail — see the consumer-sales figure below for a cleaner demand read.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TITAN','2026-03-31','volume_growth_pct',52,'%','Consumer (Secondary) Sales Growth','The cleaner underlying-demand signal: actual end-customer sales through Tanishq and Mia, up 52% YoY. Buyer count itself grew high-single-digits — a genuine recovery after three nearly-flat quarters — with higher average ticket sizes doing the rest of the work.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TITAN','2026-03-31','pat_growth_pct',35.36,'%','PAT Growth (YoY)','Consolidated PAT ₹1,179 crore — down 30% sequentially from Q3''s ₹1,684 crore (Q3 typically benefits from wedding/festive-season timing). Notably, gold coin sales (an investment product, not core jewellery demand) ''nearly tripled'' YoY — a category mix shift worth separating from genuine jewellery retail strength.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TITAN','2026-03-31','international_revenue_growth_pct',156,'%','International Revenue Growth (YoY)','Driven substantially by the newly acquired Damas Jewellery (67% stake, GCC region) rather than pure organic international expansion — a real but largely inorganic growth driver this quarter.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TITAN','Gold price volatility cuts both ways: it inflates headline reported revenue (as this quarter shows) while also being a genuine demand risk if prices rise faster than consumer incomes can absorb — a two-sided exposure specific to jewellery retail that plain-goods retailers don''t share','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TITAN','Smart watch category decline (-53% YoY) signals real competitive pressure in wearables even as the broader watches business (analog) stays healthy — a segment-specific, not company-wide, headwind','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TITAN','International expansion via the Damas acquisition gives Titan a credible new growth vector and diversifies geographic concentration risk beyond India for the first time at meaningful scale','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TITAN','2026-03-31','bull','Buyer growth recovered to high-single-digits in Q4 after being nearly flat for three straight quarters — genuine demand recovery, corroborated by like-for-like growth across retail formats of roughly 48% YoY, not just gold-price-driven value inflation.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TITAN','2026-03-31','bull','Consumer (secondary) sales — the cleanest read on real end-customer demand — grew 52% YoY, with both flagship brand Tanishq and youth-focused Mia posting robust growth, evidence of broad-based brand strength rather than a single-format fluke.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TITAN','2026-03-31','bull','The Damas acquisition gives Titan a genuine platform to scale jewellery retail internationally beyond India for the first time at real scale, diversifying a historically India-concentrated growth base.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TITAN','2026-03-31','bear','The headline 80%+ reported revenue growth is significantly inflated by rising gold prices and bullion-related sales that carry much thinner margins than core jewellery retail — reading only the top-line number risks overstating the real growth in Titan''s profitable core business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TITAN','2026-03-31','bear','PAT grew a much more modest 35% YoY and fell 30% sequentially — profitability growth lagged reported revenue growth by a wide margin, consistent with the bullion-distortion point above.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TITAN','2026-03-31','bear','The smart watch segment declined a sharp 53% YoY within Watches & Wearables — a real competitive/category headwind, even as analog watches (Titan, Sonata) grew a healthy 16% on premiumisation trends.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('SBILIFE','SBI Life Insurance','NSE','Insurance','Life Insurance','Insurance','SBI Life is India''s largest private life insurer, a joint venture between State Bank of India and France''s BNP Paribas Cardif, selling protection (term), savings, pension and ULIP policies mainly through SBI''s 29,000+ bank branches (bancassurance). Insurance economics aren''t measured like a normal product business &mdash; the key metrics are APE (Annualized Premium Equivalent, a standardized new-business volume measure), VNB margin (how profitable that new business is expected to be over its life), and Embedded Value (the actuarial estimate of the company''s total intrinsic worth).','SBI Life''s own FY26 results, cross-checked against ICICI Direct Research, Business Standard and Univest coverage','An unmatched, genuinely difficult-to-replicate bancassurance distribution relationship with India''s largest bank (SBI, 29,000+ branches) is the core moat. It''s a moat SBI Life doesn''t fully own or control, though — it depends on a continued preferential distribution arrangement rather than owned physical infrastructure, making it more fragile to regulatory change (like a mandated open-architecture shift) than a moat built on hard assets would be.','Sits at the underwriting/manufacturing end of the insurance value chain — designs policies and bears the actuarial and investment risk — while distribution is overwhelmingly outsourced to SBI''s branch network rather than built on the company''s own owned infrastructure, a genuine cost advantage but also a real dependency.','Analysts explicitly flag a possible regulatory mandate for ''open architecture'' bank distribution (letting SBI branches sell multiple insurers'' products rather than favouring SBI Life) as a structural risk to the core bancassurance moat — a policy risk, not a hypothetical one, currently under industry discussion.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SBILIFE','2026-03-31','ape_growth_pct',13.4,'%','APE Growth (FY26)','Full-year Annualized Premium Equivalent ₹24,270 crore. Q4 alone decelerated sharply to just 5.5% YoY (₹5,750 crore) — the specific quarter was notably softer than the full-year pace.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SBILIFE','2026-03-31','vnb_margin_pct',27.5,'%','VNB Margin (FY26)','At the upper end of the guided 26-28% range, down slightly from 27.8% in FY25 due to GST-related input tax credit losses. Excluding that GST impact, underlying margin would have been closer to 29%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SBILIFE','2026-03-31','embedded_value_growth_pct',15,'%','Embedded Value Growth (FY26)','EV reached ₹80,790 crore — real, compounding value creation on top of new-business volume growth, not just a topline story.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('SBILIFE','2026-03-31','roev_pct',19.7,'%','Return on Embedded Value','A strong operating return, reflecting efficient conversion of new business and in-force policies into actual value growth.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SBILIFE','GST/input-tax-credit changes are a real, current, sector-wide margin headwind on new-business profitability — VNB margin compression this year reflects an industry-wide regulatory shift, not company-specific execution issues','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SBILIFE','Open-architecture distribution risk: a potential regulatory mandate requiring SBI branches to sell multiple insurers'' products (not favour SBI Life) is a structural threat explicitly flagged by analysts to the core bancassurance moat','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SBILIFE','September 2025 GST reform removing 18% GST on individual life/ULIP/health policies is a genuine demand-side tailwind for the whole industry, with the full benefit still working through the order book into FY27','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SBILIFE','2026-03-31','bull','New Business Premium grew a strong 20% YoY for the full year, broad-based across group savings (+55%), annuity (+34%) and par (+123%) — genuine diversification beyond the historically ULIP-heavy product mix (ULIPs were up just 2%).',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SBILIFE','2026-03-31','bull','Embedded Value grew 15% YoY to ₹80,790 crore with a strong 19.7% Return on Embedded Value — real, compounding value creation, not merely premium volume growth.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SBILIFE','2026-03-31','bull','An unmatched bancassurance distribution moat via SBI''s 29,000+ branch network, contributing roughly 60% of APE — a structural advantage no purely private-sector insurer can replicate at this scale.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SBILIFE','2026-03-31','bear','VNB margin compressed from 30.6% to 28.35% in Q4 specifically, driven by GST-related input tax credit losses — a real, current, sector-wide profitability headwind on new business, even as absolute VNB still grew modestly for the full year.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SBILIFE','2026-03-31','bear','Q4 PAT declined marginally (~1%) and Q4 APE growth slowed sharply to just 5.5% YoY versus the 13.4% full-year pace — this specific quarter showed real deceleration, not a continuation of earlier momentum.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SBILIFE','2026-03-31','bear','AUM actually fell 4.8% quarter-on-quarter in Q4 due to equity and debt market pressure — a reminder that a meaningful share of SBI Life''s asset base (and future fee income, via ULIPs) is market-linked and directly exposed to market downturns.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('HDFCLIFE','HDFC Life Insurance','NSE','Insurance','Life Insurance','Insurance','HDFC Life (part of the HDFC Bank group) is one of India''s largest private life insurers, selling protection, savings, pension, ULIP and annuity products through a genuinely diversified mix of bancassurance, agency and digital/direct channels &mdash; a less single-bank-concentrated distribution model than SBI Life''s SBI-branch-led approach. Like all life insurers, economics are driven by APE (new-business volume), VNB margin (profitability of that new business), and Embedded Value (the actuarial measure of total company worth).','HDFC Life''s own FY26 press release (hdfclife.com) and ICICI Direct Research 9M FY26 result update, cross-checked against APAC Media News coverage','HDFC Bank''s brand and distribution reach, combined with a genuinely diversified multi-channel distribution strategy and a long-standing reputation for claims-servicing quality (99.8% settlement ratio), form a real trust-and-distribution moat. It''s a moat that protects market position more than it currently insulates near-term profitability or growth pace — both are visibly trailing SBI Life''s on the metrics available this year.','Sits at the underwriting/manufacturing end of the insurance value chain — designing and pricing policies and bearing actuarial/investment risk — with distribution spread across bancassurance (HDFC Bank), agency and digital/direct channels rather than concentrated in one dominant bank relationship, a structurally more diversified model than SBI Life''s.','That channel diversification is a double-edged trait: less single-point dependency risk than SBI Life, but also no single channel gives HDFC Life quite the same overwhelming distribution scale advantage SBI Life gets from SBI''s branch network.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HDFCLIFE','2026-03-31','ape_growth_pct',8,'%','APE Growth (FY26)','A two-year CAGR of 12%, but the FY26 single-year pace of 8% is meaningfully slower than peers like SBI Life''s ~13-14% — new-business volume momentum lags the sector''s strongest players right now.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HDFCLIFE','2026-03-31','vnb_margin_pct',24.2,'%','VNB Margin (FY26)','A real decline versus prior levels, driven by GST changes and new surrender regulations. Excluding those impacts, management says margin would have held flat at 25.5% — genuine regulatory headwind, not pure execution slippage.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HDFCLIFE','2026-03-31','embedded_value_growth_pct',15.6,'%','Embedded Value Growth (9M FY26)','Indian Embedded Value reached ₹61,565 crore as of 9M FY26 (most recent disclosed figure), up from ₹53,246 crore a year earlier.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HDFCLIFE','2026-03-31','roev_pct',15.6,'%','Operating Return on EV (9M FY26)','A solid, if not exceptional, operating return — notably below SBI Life''s 19.7% full-year RoEV, worth reading alongside the slower APE growth this year.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HDFCLIFE','GST and new surrender-regulation changes are a real, current, quantified margin headwind on new-business profitability, consistent with the sector-wide pressure also visible at SBI Life','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HDFCLIFE','Retail protection mix expansion (nearly 200bps YoY) is a genuine, deliberate shift toward higher-quality, more durable, typically higher-margin business — a real strategic improvement, not just a marketing talking point','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HDFCLIFE','Multi-channel distribution (bancassurance + agency + digital) reduces single-partner concentration risk relative to SBI Life''s SBI-branch dependency, at the cost of not having quite the same scale advantage in any one channel','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HDFCLIFE','2026-03-31','bull','Retail protection — the highest-quality, most profitable product category — grew a strong 46% in Q4 (43% for FY26), with its share of the overall mix expanding nearly 200bps YoY, a genuine, deliberate shift toward better-quality, longer-duration business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HDFCLIFE','2026-03-31','bull','Excluding the one-off impact of GST changes and new surrender regulations, VNB margin would have held flat at 25.5% and VNB growth would have tracked APE closely — the underlying business, stripped of regulatory noise, is performing roughly to plan.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HDFCLIFE','2026-03-31','bull','AUM grew 12% YoY to ₹3.75 lakh crore alongside a 99.8% claim settlement ratio — steady asset growth paired with genuinely excellent claims-servicing quality, a real trust signal for a business built on long-duration promises.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HDFCLIFE','2026-03-31','bear','Headline VNB margin fell to 24.2% for FY26 — a real decline, and even management''s own ''excluding GST/surrender impact'' framing concedes underlying profitability on new business is under genuine pressure this year, not just a presentation artefact.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HDFCLIFE','2026-03-31','bear','APE growth of just 8% YoY for FY26 is meaningfully slower than the ~13-14% pace SBI Life delivered over the same period — HDFC Life''s new-business volume momentum currently lags the sector''s strongest player on this dashboard.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HDFCLIFE','2026-03-31','bear','Q4 net profit grew just 4% YoY off an already modest base, and operating RoEV (15.6%) sits well below SBI Life''s 19.7% — the near-term earnings and value-creation story here reads as steady rather than fast-compounding.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('HCLTECH','HCLTech','NSE','IT Services','IT - Large Cap','IT','HCLTech is India''s third-largest IT services company, providing software development, IT consulting, engineering R&amp;D services and enterprise software (HCLSoftware) to global clients on the same time-and-materials/project-fee billing model as larger peers TCS and Infosys, with an increasing push into AI-led service offerings as the industry-wide staffing-pyramid growth model faces structural pressure.','HCLTech''s own Q4 & FY26 investor release (hcltech.com), cross-checked against AlphaSpread earnings-call summary and IndMoney coverage','Scale, decades of enterprise relationships, and a differentiated mix (Engineering & R&D Services plus HCLSoftware, which most peers lack at similar scale) provide some diversification beyond the pure staffing-pyramid model. HCLTech faces the identical AI-transition question as TCS and Infosys — whether scale remains an advantage or becomes a cost disadvantage as AI compresses the economics the industry''s pricing model was built around — and this quarter''s soft constant-currency growth doesn''t yet answer that question either way.','A downstream IT service provider like TCS and Infosys, with no physical raw-material chain — competes on delivery quality, cost, and increasingly AI-augmented productivity within client-defined project scope, differentiated by a larger relative weighting toward Engineering & R&D Services (the fastest-growing segment, +9.8% YoY in CC) and its own enterprise software business (HCLSoftware), which most Indian IT peers lack at comparable scale.','HCLSoftware''s annual recurring revenue actually declined slightly (-0.5% CC) this year and fell sharply in Q4 on seasonality and delayed client decisions — the software diversification arm is not currently a growth engine, worth watching rather than assuming as a given strength.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HCLTECH','2026-03-31','revenue_growth_pct',12.3,'%','Revenue Growth (YoY)','Reported INR terms. Constant-currency revenue grew just 2.4% YoY and actually fell 3.3% sequentially — the gap is currency translation, echoing the same pattern seen at TCS and Infosys.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HCLTECH','2026-03-31','operating_margin_pct',17.2,'%','EBIT Margin (FY26)','17.9% excluding a one-time ₹956 crore New Labour Code cost impact. Within FY26''s guided range, but FY27 guidance of 17.5-18.5% still implies only modest further improvement.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HCLTECH','2026-03-31','attrition_pct',12.5,'%','Attrition (LTM)','Down from 13.0% a year ago — continued workforce stabilisation across the sector.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HCLTECH','2026-03-31','deal_tcv_usd_bn',1.93,'$bn','Deal TCV (Quarter)','Moderated after two stronger quarters. Full-year TCV was $9.3 billion, flat YoY — management says AI-related deal-value deflation is a real, current factor, not just softer demand.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HCLTECH','2026-03-31','roce_pct',NULL,'%','ROCE','Not separately headlined by HCLTech in its own Q4 disclosures — shown as — rather than estimated.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('HCLTECH','2026-03-31','ai_revenue_growth_pct',620,'$m','Advanced AI Revenue (Annualized)','Crossed $620 million annualized in Q4 — a newly disclosed, fast-emerging line, though reported as an absolute level here rather than a growth rate since HCLTech doesn''t yet break out a comparable prior-period figure the way TCS does.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HCLTECH','AI/automation exposure: constant-currency growth of just 2.4% YoY, missing Q4 expectations specifically on lower discretionary telecom spend and the end of two SAP programs, is live evidence of the same structural staffing-pyramid pricing pressure flagged across the sector','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HCLTECH','AI/automation exposure: also a measurable tailwind — Advanced AI revenue crossing $620 million annualized is a genuine, fast-emerging new line, echoing the trend TCS discloses in more detail','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HCLTECH','Currency exposure: the large gap between reported INR growth (12.3%) and constant-currency growth (2.4%) means a weaker rupee is flattering headline numbers even as underlying dollar-denominated demand is much softer','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HCLTECH','2026-03-31','bull','FY26 constant-currency revenue growth of 3.9% came in even amid what management itself called ''an uncertain demand environment'' — modest but genuine execution against a tough industry-wide backdrop.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HCLTECH','2026-03-31','bull','Advanced AI revenue crossed $620 million annualized in Q4 — a newly and explicitly disclosed growth line, evidence the AI-services pivot is becoming a real, trackable part of the business.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HCLTECH','2026-03-31','bull','A highly shareholder-friendly capital allocation policy — 97.6% of FY26 net income returned via dividends (₹60/share for the year), with the board extending a 5-year commitment to return at least 75% of net income to shareholders.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HCLTECH','2026-03-31','bear','Constant-currency revenue grew just 2.4% YoY in Q4 and fell 3.3% sequentially — the market punished this with a roughly 10% stock decline on results day, reading it as evidence of real, current demand softness in telecom and the end of two SAP programs, not just noise.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HCLTECH','2026-03-31','bear','FY26 net income was roughly flat YoY despite 11.2% revenue growth — margin compression (partly from the Labour Code cost impact) absorbed essentially all of the topline growth at the bottom line.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HCLTECH','2026-03-31','bear','FY27 guidance of just 1.0-4.0% constant-currency revenue growth signals management itself expects continued near-term softness, not confident acceleration.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('TECHM','Tech Mahindra','NSE','IT Services','IT - Mid Cap','IT','Tech Mahindra (Mahindra Group) is a mid-sized Indian IT services company, historically concentrated in telecom-vertical clients but now deliberately diversifying across manufacturing, BFSI and healthcare. It''s currently in the middle of a multi-year margin-recovery turnaround after several years of underperforming larger peers (TCS, Infosys, HCLTech) on profitability.','Tech Mahindra''s own Q4 & FY26 results, cross-checked against ICICI Direct Research, Sahi.com and Whalesbook coverage','Historically built around deep telecom-sector domain expertise — a moat that weakened as telecom IT spending growth slowed industry-wide. The current turnaround strategy (cost discipline, vertical diversification, AI-led deal positioning) is rebuilding competitiveness from a genuine position of prior underperformance versus peers, not extending an already-dominant position the way TCS''s scale moat does.','The same downstream IT-services value-chain position as its larger peers, historically differentiated (and concentrated) by deep telecom-vertical specialization inherited from its origins — now deliberately diversifying into manufacturing, BFSI and healthcare as telecom-sector IT spending growth has structurally slowed industry-wide.','Manufacturing grew 11.8% YoY this quarter, part of a broad-based diversification push away from historical telecom concentration — a deliberate de-risking strategy still mid-execution, not yet complete.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TECHM','2026-03-31','revenue_growth_pct',12.6,'%','Revenue Growth (YoY)','Reported INR terms. Constant-currency growth was a much softer 2.4% YoY — a rupee tailwind is doing a lot of the work in the headline number, similar to every other IT company on this dashboard.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TECHM','2026-03-31','operating_margin_pct',13.8,'%','EBIT Margin','Up 330bps YoY — the tenth consecutive quarter of margin expansion, per the CFO''s own comments. Still the lowest EBIT margin among the four IT companies tracked here, with a company-set FY27 target of ~15%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TECHM','2026-03-31','attrition_pct',12.1,'%','Attrition (LTM)','Down ~20bps QoQ — the lowest attrition rate among the four IT companies tracked here.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TECHM','2026-03-31','deal_tcv_usd_bn',1.073,'$bn','Deal TCV (Quarter)','Up 34.5% YoY, including two mega deals and a five-year strategic partnership with Orange Business. Full-year TCV of $3.79bn (+41.6% YoY) was the highest in five years.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TECHM','2026-03-31','roce_pct',NULL,'%','ROCE','Not separately headlined in Q4 disclosures — shown as — rather than estimated.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TECHM','AI automation could reduce traditional IT services revenue by an estimated 2-3% annually industry-wide as efficiency gains lower pricing — the same structural risk facing every IT peer here, arguably more acute for a smaller player still mid-turnaround','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TECHM','Ten consecutive quarters of margin expansion is a genuinely rare, sustained execution track record that, if it continues, closes the profitability gap with larger peers over time','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TECHM','Historical telecom-client concentration is actively being diversified (broad-based growth across Manufacturing, BFSI, healthcare) — a deliberate de-risking still in progress, not a completed transition','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TECHM','2026-03-31','bull','EBIT margin expanded for a tenth consecutive quarter to 13.8% — a genuinely sustained, multi-year turnaround, not a one-quarter blip, explicitly called out by the CFO.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TECHM','2026-03-31','bull','Full-year deal TCV of $3.79 billion (+41.6% YoY) was the highest in five years, while revenue concentration in the top 5 clients actually declined from 15.5% to 14.9% — real diversification alongside real demand momentum, not growing dependency on a few large accounts.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TECHM','2026-03-31','bull','Free cash flow reached 115% of reported PAT for FY26 — genuinely strong cash conversion, evidence the earnings recovery isn''t relying on accounting flexibility.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TECHM','2026-03-31','bear','Q4 net profit of ₹1,354 crore missed analyst estimates by roughly 10%, and the constant-currency growth (just 2.4% YoY) driving the ''recovery'' narrative depends partly on a rupee tailwind that independent analysts note ''will not be infinite.''',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TECHM','2026-03-31','bear','Even after ten quarters of improvement, the 13.8% EBIT margin remains the lowest among the four IT companies on this dashboard — reaching the FY27 target of ~15% requires continued, uninterrupted execution with limited room for error.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TECHM','2026-03-31','bear','The stock''s P/E (around 32x) sits at a significant premium to larger, more profitable peers (Infosys ~18-19x, Wipro ~16x, HCLTech ~23x) and 61% above its own 10-year median — the market has already priced in much of the turnaround succeeding, leaving less room for disappointment.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('WIPRO','Wipro','NSE','IT Services','IT - Large Cap','IT','Wipro is India''s fourth-largest IT services company, providing software development, consulting and outsourced technology operations to global enterprise clients on the same billing model as larger peers TCS, Infosys and HCLTech. Growth momentum has lagged those larger peers for several years, and the company is currently emphasizing cost discipline and shareholder capital returns (its first buyback in three years) over aggressive growth reinvestment.','Wipro''s own Q4 & FY26 results release (wipro.com), cross-checked against MarketsMojo and Outlook Business coverage','Scale and decades of enterprise relationships provide some baseline moat, but Wipro''s multi-year growth underperformance relative to TCS, Infosys and HCLTech suggests its competitive position within the traditional staffing-pyramid IT services model has eroded more than peers''. The current strategic response — cost discipline plus capital returns — is a defensible reaction to that weaker position, not evidence the underlying moat has itself strengthened.','The same downstream IT-services value-chain position as TCS, Infosys and HCLTech — no physical raw-material chain, competing on delivery cost, quality and increasingly AI-augmented productivity within client-defined project scope — though Wipro currently occupies a distinctly weaker growth position within that peer group.','The shift toward cost discipline and shareholder returns (buyback plus dividends) over aggressive reinvestment is a reasonable response to that weaker growth position, but also a tacit signal that management sees limited near-term high-return growth opportunities to deploy capital into instead.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('WIPRO','2026-03-31','revenue_growth_pct',7.7,'%','Revenue Growth (YoY)','Reported INR terms (gross revenue ₹242.4bn). Independent analysis flagged an organic constant-currency decline of roughly 1.3% QoQ — the reported growth leans heavily on currency translation.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('WIPRO','2026-03-31','operating_margin_pct',17.3,'%','IT Services Operating Margin','Down slightly from 17.6% QoQ (Q3 was 18.24% on an adjacent ''excluding other income'' basis) but broadly stable YoY — margin discipline holding even as revenue growth stays weak.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('WIPRO','2026-03-31','attrition_pct',13.8,'%','Attrition (LTM)','The highest attrition rate among the four IT companies tracked on this dashboard.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('WIPRO','2026-03-31','deal_tcv_usd_bn',3.5,'$bn','Deal TCV (Quarter)','Total bookings, up 3.2% QoQ in constant currency. Large deal bookings alone surged 65.1% QoQ to $1.44bn — a genuinely strong forward-order-book signal, if it converts to billed revenue.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('WIPRO','2026-03-31','roce_pct',NULL,'%','ROCE','Not separately headlined in Q4 disclosures — shown as — rather than estimated.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('WIPRO','AI/automation exposure and weak organic/constant-currency growth (roughly -1.3% QoQ) are the clearest, most current evidence among the IT peers tracked here of structural staffing-pyramid pricing pressure','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('WIPRO','Strong large-deal bookings growth (+45.4% YoY) provides a real, if not-yet-converted, source of potential future revenue recovery — worth watching whether Q4''s momentum shows up in billed revenue over the next few quarters','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('WIPRO','The ₹15,000 crore buyback signals management sees better near-term use of capital in returning cash to shareholders than in aggressive growth reinvestment — a defensible capital-allocation choice, but also a tacit acknowledgment of limited near-term growth options','neutral',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WIPRO','2026-03-31','bull','Operating margin held at 17.3% even amid weak revenue growth — genuine, disciplined cost optimisation (a declining employee-cost-to-revenue ratio) that other IT companies with faster growth haven''t needed to demonstrate as clearly.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WIPRO','2026-03-31','bull','Large deal bookings surged 45.4% YoY for the full year to $7.8 billion, and total bookings grew 14% YoY to $16.4 billion — real forward-order-book momentum that could support a growth recovery if it converts to billing on schedule.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WIPRO','2026-03-31','bull','The board approved Wipro''s first share buyback in three years (₹15,000 crore at ₹250/share) alongside continued dividends — a sizeable, concrete capital-return signal during a period of weak growth, not just a promise.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WIPRO','2026-03-31','bear','Constant-currency, organic growth was genuinely weak this quarter — independent analysis flagged an organic decline of roughly 1.3% QoQ, with FY26 revenue essentially flat-to-down on an organic basis, meaningfully underperforming TCS, Infosys and HCLTech.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WIPRO','2026-03-31','bear','Net profit fell 1.9% YoY despite the margin improvement — even disciplined cost management couldn''t fully offset weak top-line momentum this quarter.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WIPRO','2026-03-31','bear','Five-year EBIT CAGR of just 5.44% trails Wipro''s own revenue growth over the same period, per independent analysis — a structural profitability-growth challenge that one strong quarter of margin recovery doesn''t resolve.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('NESTLEIND','Nestle India','NSE','FMCG','FMCG - Packaged Foods & Beverages','FMCG','Nestle India (majority-owned by Switzerland''s Nestlé S.A.) is one of India''s most trusted packaged-foods and beverages companies, owning iconic brands including Maggi noodles, KitKat, Nescafé and Milkmaid, sold through one of India''s deepest FMCG distribution networks. Unlike much of the sector this year, its growth has been genuinely volume-led rather than price-led, funded by a sharp increase in advertising and promotional investment.','Nestle India''s own Q4 & FY26 results release, cross-checked against Business Standard, India Infoline and Whalesbook coverage','Globally recognized, category-defining brands — Maggi is near-synonymous with ''instant noodles'' in India, a rare moat few competitors have matched in two decades of trying — backed by parent Nestlé S.A.''s R&D, sourcing scale and brand equity, reinforced by one of India''s deepest FMCG distribution networks. The near-term test is whether this quarter''s volume growth can be sustained without permanently elevated A&P spending becoming the new cost of doing business.','Sits at the finished-goods end of the food & beverage value chain — sources agricultural commodities (coffee, cocoa, dairy, wheat) globally and through domestic contract farming, converting them into branded packaged foods sold through one of India''s deepest FMCG distribution networks, leveraging parent Nestlé S.A.''s global R&D and brand equity.','Quick-commerce and modern trade channel expansion give Nestle India new, faster-growing distribution avenues beyond traditional general trade, though the company didn''t break out channel-specific growth this quarter the way some peers do.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NESTLEIND','2026-03-31','revenue_growth_pct',22.6,'%','Revenue Growth (YoY)','Revenue ₹6,748 crore, significantly beating analyst estimates (₹6,230-6,370 crore).',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NESTLEIND','2026-03-31','volume_growth_pct',18,'%','Volume Growth','Management confirmed this was volume-led, not price-led — the highest-quality kind of FMCG growth, achieved even as the broader sector deals with urban consumption softness.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NESTLEIND','2026-03-31','gross_margin_pct',NULL,'%','Gross Margin','Not separately disclosed in Q4 reporting reviewed — shown as — rather than estimated.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NESTLEIND','2026-03-31','ebitda_margin_pct',26.3,'%','EBITDA Margin','Held healthy even as A&P spending rose over 50% YoY — volume growth is absorbing the higher marketing investment with room to spare.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NESTLEIND','2026-03-31','roce_pct',NULL,'%','ROCE','Not confirmed from Q4 disclosures reviewed. A peer comparison table cited Nestle India''s ROE at a very high 65.72% — a related but different measure, shown here as — rather than conflating the two.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('NESTLEIND','2026-03-31','anp_spend_pct',NULL,'%','A&P Spend % Revenue','Growth in absolute A&P spend (+50%+ YoY) was disclosed, but not as a % of revenue — shown as — rather than estimated. Display-only metric regardless: higher A&P reflects brand investment, not waste.',NULL,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NESTLEIND','Coffee and cocoa cost volatility (global commodity prices) directly affects margins on two of the company''s largest brand franchises (Nescafé, KitKat) — a live, current input-cost exposure, not hypothetical','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NESTLEIND','A forecast drier monsoon threatens rural demand recovery, a segment increasingly important to sustaining FMCG volume growth industry-wide','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NESTLEIND','Quick-commerce and modern trade expansion give Nestle India new, faster-growing distribution channels beyond traditional general trade','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NESTLEIND','2026-03-31','bull','Genuinely volume-led growth (~18%) rather than price-led is the highest-quality kind of FMCG growth — achieved even as the broader sector deals with urban consumption softness, with market share gains across every product category simultaneously.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NESTLEIND','2026-03-31','bull','EBITDA margin held at a healthy 26.3% even as A&P spending rose over 50% YoY — the volume growth is genuinely absorbing the higher marketing investment with room to spare, not being funded by margin sacrifice.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NESTLEIND','2026-03-31','bull','Cash generation nearly doubled YoY (₹5,047.6 crore vs ₹2,934.5 crore in FY25) and the balance sheet is now clear of short-term debt — real, not just paper, financial strength underpinning the growth story.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NESTLEIND','2026-03-31','bear','The >50% increase in A&P spending to sustain volume momentum raises a genuine sustainability question — if this level of marketing investment is now required to maintain double-digit volume growth, underlying organic demand strength may be less than the headline growth rate implies.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NESTLEIND','2026-03-31','bear','Rising input costs (coffee, cocoa, crude-linked packaging) plus a forecast drier monsoon (a risk to rural demand) create real margin and demand headwinds heading into FY27, with brokerages already flagging possible 3-4% price hikes in Q1 FY27.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NESTLEIND','2026-03-31','bear','The stock trades at a rich ~80x FY26 P/E — a premium valuation that assumes this exceptional, ad-spend-fuelled growth rate is sustainable, leaving little room for a disappointing quarter.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('TATACONSUM','Tata Consumer Products','NSE','FMCG','FMCG - Beverages & Packaged Foods','FMCG','Tata Consumer Products (Tata Group) sells packaged tea and coffee (Tata Tea, Tetley, Tata Coffee) and salt (Tata Salt) &mdash; categories where it holds clear domestic market leadership &mdash; alongside a growing portfolio of newer categories (pulses and spices under Sampann, ready-to-drink beverages via the NourishCo joint venture) built partly through acquisitions, making it a more diversified but also more capital-intensive, still-integrating business than older, more organically-grown FMCG peers.','Tata Consumer''s own Q4 & FY26 results release, cross-checked against MarketsMojo and ScanX coverage','Clear category leadership in tea (Tata Tea, Tetley) and salt (Tata Salt) — decades-old, hard-to-dislodge household brand positions — combined with Tata Group parentage lending trust and distribution reach. The moat''s current limitation is financial rather than brand-related: capital efficiency lags peers significantly, meaning the brand strength hasn''t yet translated into the same quality of shareholder returns HUL or ITC generate from comparably strong brands.','Sits at the finished-goods end of the beverages and packaged-foods value chain, sourcing tea, coffee and salt (including through its own tea estates and Tata Coffee''s plantations, giving some backward integration) and branding/distributing through India''s general trade network plus a fast-growing quick-commerce presence.','Newer categories (NourishCo ready-to-drink beverages, pulses/spices under Sampann) have been built through a mix of organic launches and acquisitions — worth distinguishing which growth engine is actually driving results in any given quarter.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATACONSUM','2026-03-31','revenue_growth_pct',17.91,'%','Revenue Growth (YoY)','Consolidated revenue ₹5,433.62 crore, beating brokerage estimates and driving CLSA and Goldman Sachs to reaffirm bullish ratings.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATACONSUM','2026-03-31','volume_growth_pct',16,'%','India Volume Growth','Described by CLSA as ''industry-leading'' among FMCG peers this quarter, with particularly strong traction in Salt and the Sampann pulses/spices brand.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATACONSUM','2026-03-31','gross_margin_pct',NULL,'%','Gross Margin','Not separately disclosed in Q4 reporting reviewed — shown as — rather than estimated.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATACONSUM','2026-03-31','ebitda_margin_pct',14.57,'%','EBITDA Margin','Up from 13.47% a year ago — a multi-quarter high, with management guiding a further 50-75bps expansion for FY27.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATACONSUM','2026-03-31','roce_pct',9.02,'%','ROCE','Dramatically weaker than FMCG peers on this dashboard (HUL 31.61%, ITC 44.26%) — reflecting the capital-intensive, still-integrating nature of a business built substantially through acquisitions rather than purely organic brand-building.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TATACONSUM','2026-03-31','anp_spend_pct',NULL,'%','A&P Spend % Revenue','Not disclosed as a % of revenue in Q4 reporting reviewed — shown as — rather than estimated.',NULL,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATACONSUM','Weak capital efficiency (ROCE 9.02%) relative to FMCG peers signals real, unresolved integration and capital-allocation challenges from an acquisition-heavy growth strategy — not yet fixed despite improving revenue and margin trends','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATACONSUM','Tea price volatility (a globally traded agricultural commodity) is a structural input-cost swing factor management currently calls ''benign'' but is not guaranteed to stay that way','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATACONSUM','Quick-commerce/e-commerce growth of 62%+ in FY26 shows genuine share capture in India''s fastest-growing retail channel, a real tailwind independent of the acquisition-integration questions elsewhere in the business','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATACONSUM','2026-03-31','bull','India volume growth of 16% is industry-leading among FMCG peers this quarter, with particularly strong traction in Salt and the Sampann pulses/spices brand — genuine category-level demand strength, not just price-led growth.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATACONSUM','2026-03-31','bull','EBITDA margin expanded to a multi-quarter high of 14.57% (from 13.47%), with management guiding a further 50-75bps expansion in FY27 — a credible, quantified margin-improvement trajectory, not just an aspiration.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATACONSUM','2026-03-31','bull','Quick-commerce and e-commerce channels grew over 62% in FY26 — genuine share capture in India''s fastest-growing retail channel, not just defending the traditional general-trade base.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATACONSUM','2026-03-31','bear','Return on Capital Employed of just 9.02% is dramatically weaker than FMCG peers on this dashboard (HUL 31.61%, ITC 44.26%) — reflecting the capital-intensive, still-integrating nature of a business built substantially through acquisitions.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATACONSUM','2026-03-31','bear','The stock trades at a rich ~80x P/E — the second-highest multiple among the FMCG names covered here — despite delivering by far the weakest capital-efficiency metrics in the group, a genuine valuation-versus-fundamentals tension worth understanding before assuming the multiple is justified.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATACONSUM','2026-03-31','bear','Five-year sales growth of 12.15%, while ahead of some peers, has come partly through acquisitions rather than pure organic execution — worth separating inorganic contribution from genuine like-for-like brand strength when assessing growth quality.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('CIPLA','Cipla','NSE','Pharma','Pharma - Generics & Respiratory','Pharma','Cipla is India''s third-largest pharmaceutical company, selling respiratory, anti-diabetes, cardiac and urology branded generics domestically (its ''One-India'' business) alongside a US generics/specialty business and a growing Africa/emerging-markets presence. Its US business, historically a key profit driver, is currently going through a rough patch as several high-margin legacy products lose their earning power at the same time.','Cipla''s own Q4 & FY26 press release (cipla.com) and results filing, cross-checked against Business Standard, Whalesbook and ICICI Direct Research','A genuinely strong, market-leading India respiratory franchise (Cipla is historically India''s #1 respiratory brand) plus a broad emerging-markets footprint provide real, durable moats. The US specialty-generics business, historically a high-margin growth driver, has just demonstrated real fragility to single-product and single-facility concentration risk — a moat weakness this quarter exposed rather than created, and one management is now directly addressing through US-based manufacturing.','A vertically-oriented generics and specialty pharma manufacturer with meaningful India-based manufacturing (multiple USFDA-inspected facilities: Bommasandra, Sitec, Medispray) plus a newly operational US manufacturing facility (Fall River) aimed directly at reducing the geographic/regulatory concentration risk that contributed to this quarter''s Lanreotide disruption.','The Fall River facility and a newly approved first AB-rated generic Ventolin from a US site are direct, concrete responses to the single-facility fragility this quarter''s results just exposed — not a hypothetical mitigation plan.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CIPLA','2026-03-31','revenue_growth_pct',-2.8,'%','Revenue Growth (YoY)','Revenue from operations ₹6,541 crore, down from ₹6,729 crore — India and Africa growth wasn''t enough to offset the North America decline this quarter.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CIPLA','2026-03-31','gross_margin_pct',NULL,'%','Gross Margin','Not separately disclosed in Q4 reporting reviewed — shown as — rather than estimated.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CIPLA','2026-03-31','ebitda_margin_pct',14.6,'%','EBITDA Margin','Collapsed from 22.8% a year ago — a genuinely severe compression, driven by the loss of high-margin US products (Lanreotide, generic Revlimid) plus a 20% YoY jump in R&D spending.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CIPLA','2026-03-31','us_business_growth_pct',-26,'%','US Business Growth','North America revenue fell to $155 million for the quarter, driven by a temporary Lanreotide manufacturing halt (a USFDA observation at a Greek contract manufacturer) and the expiry of generic Revlimid exclusivity — two of Cipla''s most profitable US products losing earning power simultaneously.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CIPLA','2026-03-31','rd_pct_sales',7.8,'%','R&D % of Sales','Up from 6.3% a year ago (₹509 crore this quarter), driven by product filings and development for upcoming respiratory and peptide launches. Display-only.',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('CIPLA','2026-03-31','anda_pending_approval_pipeline',NULL,'','ANDAs Pending FDA Approval','Not disclosed in the Q4 FY26 materials reviewed — shown as — rather than estimated. Display-only.',NULL,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CIPLA','Single-facility concentration risk realized in real time: a manufacturing halt at a Greek contract manufacturer directly caused a chunk of this quarter''s US revenue and margin collapse — live evidence of supply-chain fragility, not a hypothetical risk','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CIPLA','US generic pricing pressure and patent-cliff product transitions (loss of Revlimid exclusivity) are a structural, sector-wide headwind also visible at Dr. Reddy''s and other Indian pharma exporters on this dashboard','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CIPLA','A newly operational US manufacturing facility (Fall River) plus the first AB-rated generic Ventolin approval from a US site are concrete steps toward reducing the single-facility supply-chain concentration that caused this quarter''s disruption','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CIPLA','2026-03-31','bull','India business (One-India) grew a strong 15% YoY in Q4, crossing the ₹12,500 crore annual revenue milestone for the first time, with broad-based double-digit growth across respiratory, urology, anti-diabetes and cardiac therapies — the domestic franchise remains genuinely healthy even as the US business struggles.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CIPLA','2026-03-31','bull','Africa and emerging markets crossed the $400 million annual revenue milestone with 7-8% YoY growth — real geographic diversification cushioning the North America decline, not just a India-only story.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CIPLA','2026-03-31','bull','Management laid out a specific, checkable FY27 recovery roadmap — four respiratory launches and one major peptide launch in the US, targeting a $1 billion US revenue run-rate and 18.5-20% EBITDA margins — a concrete plan with named milestones, not vague reassurance.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CIPLA','2026-03-31','bear','North America revenue fell a sharp 26% YoY, driven by a temporary halt in Lanreotide manufacturing at a Greek contract manufacturer (a USFDA observation) and the loss of generic Revlimid exclusivity — two of Cipla''s most profitable US products losing earning power at the same time, a real concentration-risk failure, not gradual softening.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CIPLA','2026-03-31','bear','EBITDA margin collapsed to 14.6% from 22.8% a year ago — a severe compression, not a modest miss, and full-year PAT fell 26-27% YoY despite record annual revenue.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CIPLA','2026-03-31','bear','Cipla''s own FY27 EBITDA margin guidance (18.5-20%) explicitly excludes any assumed Lanreotide recovery — management itself isn''t counting on a quick fix to the specific product that caused this quarter''s collapse.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('APOLLOHOSP','Apollo Hospitals','NSE','Healthcare','Hospitals & Healthcare Services','Healthcare','Apollo Hospitals is India''s largest private healthcare provider, running a network of hospitals (its core, most profitable ''Healthcare Services'' segment) alongside a large omni-channel pharmacy and digital health business (Apollo HealthCo, including Apollo 24/7) and a retail diagnostics/healthcare arm (AHLL) — a genuinely integrated healthcare ecosystem beyond just hospital beds, with a planned demerger of the pharmacy/digital arm into a separately listed entity targeted by Q4 FY27.','Apollo Hospitals'' own Q4 & FY26 results, cross-checked against BW Healthcare World, Business Today and MarketsMojo coverage','India''s largest, most recognized private hospital brand plus a genuinely integrated ecosystem (hospitals + pharmacy + diagnostics + digital) that few competitors replicate at this scale — reinforced by high-end specialty capabilities (oncology, cardiac, transplants, robotics) that are expensive and slow for regional competitors to build from scratch.','Spans the healthcare value chain from hospital-based tertiary/quaternary care (the core, most profitable segment) through omni-channel pharmacy distribution (Apollo HealthCo, ~7,289 stores) to digital health and diagnostics (Apollo 24/7, AHLL) — a genuinely integrated ecosystem most single-format hospital chains or pure-play pharmacy retailers don''t have.','International/medical-value-travel patients (from Africa, the Middle East, Bangladesh and Southeast Asia) provide an additional, typically higher-realization revenue stream leveraging India''s cost and clinical-quality advantage in specialties like oncology, transplants and robotic surgery.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('APOLLOHOSP','2026-03-31','revenue_growth_pct',18,'%','Revenue Growth (YoY)','Consolidated revenue ₹6,605 crore, an all-time high. Healthcare Services (hospitals) grew a somewhat slower 16%; Apollo HealthCo (pharmacy+digital) grew faster at 20%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('APOLLOHOSP','2026-03-31','ebitda_margin_pct',16.7,'%','EBITDA Margin','Consolidated EBITDA ₹1,017 crore. The core hospital segment margin actually moderated slightly (45bps YoY to 23.8%) — this quarter''s overall margin improvement leans more on the pharmacy/digital turnaround than the hospital business getting structurally more profitable.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('APOLLOHOSP','2026-03-31','occupancy_pct',68,'%','Group-wide Occupancy','Up from 67% a year ago. Eastern-cluster hospitals ran highest at 77%; metro hospitals at 71%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('APOLLOHOSP','2026-03-31','arpob_inr',71206,'₹','ARPOB (Healthcare Services)','Average Revenue Per Occupied Bed, up 12% YoY — pricing/mix strength and occupancy improvement happening simultaneously, a healthy combination.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('APOLLOHOSP','2026-03-31','roce_pct',NULL,'%','ROCE','Not confirmed on a clean consolidated basis from Q4 disclosures reviewed — shown as — rather than estimated. The Healthcare Services segment alone was cited at 30.3% in an earlier quarter.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('APOLLOHOSP','Heavy capex intensity: new hospitals run at a loss for multiple quarters after commissioning (management guides to roughly ₹150 crore of expected EBITDA losses from newly opened facilities) — a real, disclosed near-term earnings drag from the expansion pipeline','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('APOLLOHOSP','The planned pharmacy/digital demerger by Q4 FY27 is a significant corporate restructuring with real execution and regulatory-approval timeline risk, not yet complete','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('APOLLOHOSP','Medical value travel (international patients) is a genuine, higher-realization growth driver leveraging India''s cost and clinical-quality advantage relative to Western healthcare markets','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('APOLLOHOSP','2026-03-31','bull','Highest-ever quarterly revenue (₹6,605 crore) and operating margin (16.7%, up from 13.76% a year ago on one measure) show genuine operating leverage — growth and margin expansion happening together, not a trade-off.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('APOLLOHOSP','2026-03-31','bull','Apollo HealthCo (pharmacy + digital) posted its first full year of profitability in FY26 — EBITDA up from ₹168 crore to ₹488 crore, PAT from ₹47 crore to ₹324 crore — the long-heralded digital/pharmacy optionality is now demonstrably real, not just a future promise.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('APOLLOHOSP','2026-03-31','bull','ARPOB grew 12% YoY even as occupancy also improved — pricing/mix strength and volume growth happening simultaneously, a genuinely healthy combination for a hospital operator.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('APOLLOHOSP','2026-03-31','bear','The core hospital segment''s operating margin actually moderated 45bps YoY to 23.8% even as the overall group margin improved — the margin story this quarter is more about the pharmacy/digital arm''s turnaround than the core hospital business getting structurally more profitable.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('APOLLOHOSP','2026-03-31','bear','A large capex pipeline (4,400 planned new beds, roughly ₹5,100 crore of remaining spend over five years) means continued heavy capital intensity — management itself flagged around ₹150 crore of expected EBITDA losses from newly commissioned hospitals as they ramp up, a real near-term drag before they mature.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('APOLLOHOSP','2026-03-31','bear','The planned demerger of the pharmacy/digital business by Q4 FY27, while framed as unlocking value, means investors are also betting on a significant corporate restructuring executing cleanly and on schedule — a real execution risk, not yet resolved.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('MAXHEALTH','Max Healthcare Institute','NSE','Healthcare','Hospitals & Healthcare Services','Healthcare','Max Healthcare operates a network of premium hospitals historically concentrated in North India (Delhi NCR and surrounding states), recently expanding into Eastern India via the Kalinga Hospital acquisition. Its business model is built around high occupancy and premium positioning — Max''s ARPOB is among the highest in the Indian hospital sector — plus a growing digital health and home-care business (Max@Home, Max Lab).','Max Healthcare''s own Q4 & FY26 results, cross-checked against ScanX and Tradebrains'' Apollo-vs-Max comparative coverage','A premium, high-ARPOB hospital network concentrated in North India''s most lucrative healthcare market (Delhi NCR), reinforced by industry-leading operating efficiency (EBITDA per bed of ₹72 lakh) and a disciplined, low-leverage balance sheet. It''s a narrower geographic moat than Apollo''s national footprint, but a genuinely more profitable one on a per-bed basis.','Sits primarily in hospital-based tertiary care, with growing digital health (Max@Home for home healthcare, Max Lab for diagnostics) and international patient revenue (9% of hospital revenue) providing adjacent, higher-margin growth vectors — a narrower ecosystem than Apollo''s pharmacy-inclusive model, built around premium positioning and operational efficiency.','Digital revenue now makes up 31% of overall revenue — used mainly to improve patient acquisition and experience rather than to build a separate pharmacy-led ecosystem the way Apollo has, a deliberately different strategic emphasis.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MAXHEALTH','2026-03-31','revenue_growth_pct',10,'%','Revenue Growth (YoY)','Network gross revenue ₹2,664 crore for the quarter. Full-year FY26 network revenue grew faster at 16% YoY to ₹10,538 crore.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MAXHEALTH','2026-03-31','ebitda_margin_pct',25.6,'%','EBITDA Margin','Q4 operating EBITDA ₹682 crore, up 8% YoY. Full-year FY26 EBITDA margin was 26.2%, among the highest in the Indian hospital sector.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MAXHEALTH','2026-03-31','occupancy_pct',75,'%','Average Occupancy (FY26)','Held above 75% despite growing operational bed capacity — occupied bed days grew 8% YoY, meaning growth is coming from genuinely more patients, not just more beds sitting empty.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MAXHEALTH','2026-03-31','arpob_inr',77900,'₹','ARPOB (Q4)','Among the highest in the Indian hospital sector — reflects Max''s deliberately premium market positioning rather than a volume/scale strategy.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('MAXHEALTH','2026-03-31','roce_pct',22,'%','Pre-tax ROCE (FY26)','A strong capital-efficiency figure, supported by net debt/EBITDA held below 1x — genuine balance-sheet discipline alongside growth.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MAXHEALTH','Historical North India geographic concentration means regional demand or regulatory shifts affect Max more than more diversified peers — a risk the Kalinga acquisition is only beginning to address','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MAXHEALTH','High existing occupancy (75%+) means further growth increasingly requires capital-intensive bed-capacity expansion rather than simple utilisation improvement, raising the capital intensity of the next growth phase','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MAXHEALTH','Digital revenue (31% of overall revenue) and international patient revenue (9% of hospital revenue) are genuine, higher-margin growth vectors diversifying beyond core inpatient hospital revenue','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAXHEALTH','2026-03-31','bull','ARPOB of ₹77,900+ is among the highest in the Indian hospital sector, backed by occupancy held above 75% — Max has built a genuinely premium-positioned network rather than competing primarily on volume or scale.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAXHEALTH','2026-03-31','bull','Net debt of just ₹1,908 crore against net debt/EBITDA below 1x, combined with strong free cash flow (₹1,541 crore for FY26) — a financially disciplined balance sheet with real capacity to self-fund expansion without excessive leverage.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAXHEALTH','2026-03-31','bull','The Kalinga Hospital acquisition marks Max''s first entry into Eastern India — a genuine new-market growth vector beyond its historical North India concentration, backed by disciplined capital allocation (22% pre-tax ROCE).',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAXHEALTH','2026-03-31','bear','Q4 revenue growth of just 10% YoY is meaningfully slower than Apollo''s 18% — Max''s premium positioning and already-high occupancy (75%+) may leave less headroom for volume-driven growth without new bed capacity coming online.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAXHEALTH','2026-03-31','bear','Historical geographic concentration in North India (Delhi NCR) means Max has been more exposed to regional demand and regulatory dynamics than more geographically diversified peers like Apollo — the Kalinga acquisition is a first step toward diversification, not yet a completed transition.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAXHEALTH','2026-03-31','bear','With occupancy already running above 75%, further growth increasingly depends on capital-intensive bed-capacity expansion (brownfield/greenfield) rather than simply filling more of the existing network — a more expensive growth path than utilisation improvement alone.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('LT','Larsen & Toubro','NSE','Infra & Capital Goods','Engineering, Procurement & Construction','Infra & Capital Goods','Larsen & Toubro (L&T) is India''s largest engineering, procurement and construction (EPC) conglomerate — it designs, builds and delivers large infrastructure, energy, and hi-tech manufacturing projects (roads, metros, power transmission, hydrocarbon plants, defence electronics) for governments and corporations in India and internationally, especially the Middle East. Revenue is driven by converting a massive multi-year order book into executed, billed project revenue, making order inflow and order-book size the most forward-looking health indicators, more than any single quarter''s reported profit.','L&T''s own Q4 & FY26 results release, cross-checked against MarketsMojo, Multibagg.ai and PL Capital research coverage','Scale, end-to-end EPC execution capability, and decades of relationships with governments and large corporate clients across India and the Middle East form a genuine moat few competitors can match project-for-project — reinforced by a deliberate strategic shift toward a more focused, higher-return core EPC and hi-tech manufacturing business, away from capital-intensive concessions assets.','Sits across the entire infrastructure project value chain — winning contracts through competitive bidding, executing design and engineering in-house, procuring materials and managing subcontractors, and delivering completed projects — end-to-end control that smaller, more narrowly-focused EPC players don''t have.','A deliberate strategic shift toward a more focused, higher-return core: L&T is divesting non-core Concessions assets (full stakes in Nabha Power and L&T Metro Rail Hyderabad, expected to close by June 30, 2026), sharpening the portfolio around core EPC and hi-tech manufacturing.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('LT','2026-03-31','revenue_growth_pct',11.25,'%','Revenue Growth (YoY)','Consolidated revenue from operations ₹82,762 crore, the highest quarterly level in company history, driven by Infrastructure Projects, Energy Projects and Hi-Tech Manufacturing execution.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('LT','2026-03-31','ebitda_margin_pct',10.4,'%','EBITDA Margin','Down from 11.0% a year ago. Energy Projects saw the sharpest pressure (margin fell to 6.5% from 8.2%) on cost overruns and close-out costs in legacy hydrocarbon projects.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('LT','2026-03-31','order_book_to_revenue',2.59,'x','Order Book / Revenue','Record order book of ₹7,40,327 crore (+28% YoY) against FY26 revenue of ₹2,85,874 crore — roughly 2.6 years of already-secured future work, exceptional visibility for a project-execution business.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('LT','2026-03-31','pat_growth_pct',18,'%','Recurring PAT Growth (FY26)','Recurring PAT (excluding one-off exceptional items) grew 18% YoY to ₹17,238 crore — the cleaner underlying figure. Reported Q4 PAT actually fell 3% YoY due to a swing in one-off items between periods.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LT','Middle East geopolitical exposure is concrete and quantified — management explicitly guided that supply chain disruptions from the regional conflict will dampen H1 FY27 execution, directly affecting a ~40%-of-order-book geography','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LT','Energy Projects margin pressure (EBITDA margin fell to 6.8% from 8.5% for FY26) from cost overruns and close-out costs on legacy projects is a live example of large-project execution risk actually materialising, not hypothetical','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LT','A ₹17.8 lakh crore addressable prospects pipeline for FY27 gives L&T visibility into future bidding opportunities well beyond the already-secured order book','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LT','2026-03-31','bull','Record order book of ₹7.4 lakh crore (+28% YoY) provides roughly 2.6x FY26 revenue in already-secured future work — genuinely exceptional multi-year revenue visibility for a project-execution business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LT','2026-03-31','bull','FY26 recurring PAT (the cleaner, less one-off-distorted profit measure) grew a strong 18% YoY to ₹17,238 crore on record order inflows of ₹4.36 lakh crore (+22% YoY) — real, broad-based execution and demand strength, not accounting noise.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LT','2026-03-31','bull','International orders now make up 52% of the total order book — genuine geographic diversification beyond India-only infrastructure spending cycles, with a large ₹17.8 lakh crore addressable prospects pipeline for FY27.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LT','2026-03-31','bear','EBITDA margin contracted to 10.4% from 11.0% YoY, and management''s own FY27 guidance flags ''flattish'' project margins (~7.8%) — even with strong revenue growth, per-project profitability isn''t improving, and management isn''t promising it will soon.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LT','2026-03-31','bear','Heavy Middle East order-book concentration (~40% of total, ~78% of the international book) is a real geopolitical exposure — management itself flagged that supply chain disruptions from the regional conflict will ''dampen'' execution in H1 FY27, a concrete, near-term guided headwind.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LT','2026-03-31','bear','Reported Q4 PAT actually fell 3% YoY (versus the cleaner recurring PAT''s +18% full-year growth) due to a swing in one-off exceptional items — a reminder that L&T''s headline quarterly profit can be noisy period to period.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('BEL','Bharat Electronics','NSE','Infra & Capital Goods','Defence Electronics','Infra & Capital Goods','Bharat Electronics (BEL) is India''s leading state-owned (Navratna PSU) defence electronics company, designing and manufacturing radar systems, avionics, electronic warfare equipment and communication systems almost exclusively for the Indian armed forces, with a growing export component. It''s a direct beneficiary of India''s ''Atmanirbhar Bharat'' defence-indigenisation push, which favours domestic suppliers like BEL over imports.','Bharat Electronics'' own Q4 & FY26 results, cross-checked against Groww, PSU Connect and ChartAlert coverage','A uniquely protected position as India''s leading state-owned defence electronics manufacturer — decades of relationships with the Indian armed forces, security clearances and technology capabilities competitors (especially foreign ones) can''t easily replicate, reinforced by explicit government policy favouring domestic defence suppliers. This is about as close to a government-guaranteed moat as exists on this dashboard, though BEL''s growth is also somewhat capped by defence budget allocation decisions outside its own control.','Sits at the design-and-manufacture end of India''s defence electronics value chain, selling almost exclusively to the Indian Ministry of Defence and armed forces (with export sales a smaller but growing share) — a uniquely captive, policy-protected customer relationship commercial electronics manufacturers don''t have.','That same government-customer concentration means payment timing and receivables are shaped more by government budget cycles than typical commercial terms — a structural feature of the business model, not a temporary issue.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BEL','2026-03-31','revenue_growth_pct',16.15,'%','Revenue Growth (FY26)','Full-year revenue ₹27,480 crore. Q4 alone grew a slightly slower 11.6% YoY — revenue is structurally back-half loaded, with roughly 37% of the full year landing in Q4.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BEL','2026-03-31','ebitda_margin_pct',29.1,'%','EBITDA Margin (Q4)','Down from 30.7% a year ago — employee costs and other expenses grew faster than revenue this quarter, a real cost-discipline question even as topline growth stays strong.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BEL','2026-03-31','order_book_to_revenue',2.69,'x','Order Book / Revenue','Order book of ₹73,882 crore against FY26 revenue of ₹27,480 crore — roughly 2.7 years of already-secured future work, backed by ~₹30,000 crore of FY26 order inflow.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BEL','2026-03-31','pat_growth_pct',14.38,'%','PAT Growth (FY26)','Full-year PAT ₹6,048 crore. Q4 alone grew a slower 4.6% YoY — profit growth is lagging revenue growth slightly, a margin-dilution signal worth watching into FY27.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BEL','Receivables and cash-conversion quality: a large, growing receivable book tied to government payment cycles could pressure working capital and free cash flow if it doesn''t normalise — an active watch item flagged by independent analysts','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BEL','Q4/year-end execution concentration (~37% of annual revenue in one quarter) makes results structurally lumpy and dependent on year-end order-conversion timing','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BEL','India''s Atmanirbhar Bharat defence-indigenisation policy directly favours domestic suppliers like BEL over imports — a structural, government-backed demand tailwind, with a disclosed pipeline including a potential QRSAM mega-order and accelerating exports','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BEL','2026-03-31','bull','FY26 revenue and profit grew a strong 16% and 14% respectively, with margins holding near management''s own 27%+ guidance — genuine execution against a large, growing order book, not just favourable one-off timing.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BEL','2026-03-31','bull','A debt-free balance sheet with fortress-level cash and deposits (~₹8,572 crore) gives BEL exceptional financial flexibility to invest in R&D and capacity without any leverage risk — rare for a capital-intensive manufacturer.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BEL','2026-03-31','bull','Order book of ₹73,882 crore provides roughly 2.7x FY26 revenue in already-secured future work, with strong FY26 order inflow (~₹30,000 crore) including a growing export component — genuine multi-year visibility backed by India''s structural defence-spending increase.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BEL','2026-03-31','bear','EBITDA margin contracted to 29.1% from 30.7% YoY — employee costs and other expenses grew faster than revenue, a real cost-discipline question even as the topline growth story stays intact.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BEL','2026-03-31','bear','Free cash flow conversion is notably thin (roughly 9% per one independent analysis) despite strong reported profit, with a large and growing receivables book — defence PSU customers (primarily government entities) are typically slow payers, a working-capital dynamic that could pressure returns if it doesn''t normalise.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BEL','2026-03-31','bear','Revenue is heavily back-half/Q4-loaded (roughly 37% of full-year revenue in one quarter) — a structural execution-timing concentration that makes any single quarter''s results disproportionately important and potentially volatile if year-end order execution slips.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('ADANIPORTS','Adani Ports and Special Economic Zone','NSE','Infra & Capital Goods','Ports & Logistics','Infra & Capital Goods','Adani Ports and Special Economic Zone (APSEZ) is India''s largest private port operator, running 12+ ports across India''s coastline (Mundra being the flagship) plus a growing international portfolio (Australia''s NQXT, Colombo''s CWIT, Haifa in Israel). It''s deliberately evolving from a pure cargo-handling port operator into an integrated logistics and marine (offshore support vessel) platform, capturing more of the value chain around each container or tonne of cargo.','APSEZ''s own Q4 & FY26 results release, cross-checked against ITLN, Newkerala and Dailyhunt coverage','Scale (India''s largest private port operator, ~27-28% market share) combined with strategic port locations (Mundra especially) and an increasingly integrated ports-to-logistics-to-marine platform create a genuine infrastructure moat that''s expensive and slow for competitors to replicate — reinforced by the ports-privatisation policy tailwind that continues to favour established, well-capitalised operators.','Sits at the critical trade-infrastructure chokepoint between global shipping and India''s domestic economy — its ports handle roughly 27-28% of India''s total port cargo — and it''s deliberately extending both backward (marine/offshore vessel services) and forward (logistics, trucking, warehousing, rail) to capture more of the value chain around each tonne of cargo.','India''s port-privatisation policy tailwind continues to favour established, well-capitalised operators like APSEZ for new concessions, reinforcing scale advantages already built over two decades.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ADANIPORTS','2026-03-31','revenue_growth_pct',26,'%','Revenue Growth (YoY)','Revenue from operations ₹10,738 crore, exceeding the company''s own FY26 guidance. Logistics revenue grew a much faster 55% YoY and Marine revenue 134% YoY — the diversification businesses are growing far faster than the core port business.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ADANIPORTS','2026-03-31','ebitda_margin_pct',56.1,'%','EBITDA Margin','Q4 EBITDA ₹6,020 crore. International ports margin rose sharply to a record ~29% (from 13.7% a year ago) — the overseas portfolio is now genuinely accretive, not a growth-stage drag.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ADANIPORTS','2026-03-31','cargo_volume_growth_pct',13,'%','Cargo Volume Growth (YoY)','133.4 million tonnes handled this quarter. FY26 total cargo crossed 500 million tonnes for the first time by any Indian integrated transport operator — a genuine scale milestone.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ADANIPORTS','2026-03-31','net_debt_ebitda',1.9,'x','Net Debt / EBITDA','Reflects continued heavy capex (₹15,320 crore in FY26) funding the ports-to-logistics transformation and international expansion, tied to an FY31 target of doubling revenue and EBITDA.',FALSE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIPORTS','Heavy, ongoing capex and rising leverage (net debt/EBITDA 1.9x) tied to an ambitious FY31 growth target — real execution risk on a genuinely large, multi-year capital deployment plan','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIPORTS','Adani Group affiliation brings governance and disclosure scrutiny carrying real reputational and cost-of-capital implications, independent of APSEZ''s own operational performance','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIPORTS','India''s port-privatisation tailwind and growing trade volumes support structural demand growth, while international expansion (Australia, Colombo, Israel) diversifies revenue beyond India-only trade cycles','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPORTS','2026-03-31','bull','Became the first Indian integrated transport company to handle over 500 million tonnes of cargo in a single financial year, with results exceeding the company''s own FY26 guidance on revenue, EBITDA and capex simultaneously.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPORTS','2026-03-31','bull','International ports EBITDA surged 180% YoY with margins reaching a record ~29% (up from 13.7%) — the overseas portfolio (Australia, Colombo) is now genuinely accretive to consolidated profitability, not just a growth-stage cost centre.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPORTS','2026-03-31','bull','Logistics (+55% YoY) and Marine (+134% YoY) are scaling explosively as APSEZ deliberately diversifies beyond pure port cargo handling into an integrated, end-to-end supply chain platform — real business-model evolution.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPORTS','2026-03-31','bear','Net debt/EBITDA of 1.9x reflects continued heavy capex to fund the ports-to-logistics transformation and international expansion — a real, ongoing leverage commitment tied to execution of an ambitious FY31 target (1 billion tonnes of cargo by December 2030).',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPORTS','2026-03-31','bear','Q4 PAT growth of 9.4% lagged well behind revenue growth of 26% — results were specifically affected by depreciation on newly commissioned assets, meaning near-term reported profit doesn''t yet fully reflect the earnings power of the capital being deployed.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPORTS','2026-03-31','bear','As part of the broader Adani Group, APSEZ carries governance and disclosure scrutiny that peer infrastructure companies without the same corporate-group history don''t face to the same degree — a real, ongoing consideration for investors independent of operational performance.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('ADANIENT','Adani Enterprises','NSE','Conglomerate','Diversified — Infrastructure Incubator','Conglomerate','Adani Enterprises is the flagship ''incubator'' company of the Adani Group — it builds and scales new infrastructure businesses (airports, roads, data centers, green hydrogen/new energy, copper smelting, mining services) from greenfield stage to maturity, then either keeps them as core holdings or spins them off into separately listed entities (as it has done historically with Adani Ports, Adani Green and Adani Power, and this year with its Adani Wilmar stake). Because it''s perpetually building new capital-intensive assets, reported quarterly profit is often distorted by depreciation on newly commissioned projects and one-off divestment gains &mdash; the underlying operating EBITDA trend is a more useful signal than any single quarter''s headline PAT.','Adani Enterprises'' own Q4 & FY26 results release (adani.com), cross-checked against Republic World, Outlook Business and Business Today','A genuinely distinctive ''business incubation'' model within Indian conglomerates — the demonstrated ability to build, fund and scale multiple large infrastructure businesses from greenfield to maturity and eventually spin them off as independently valuable listed entities is a real, differentiated capability few Indian corporate groups have replicated at this scale. The moat''s dependence on continued access to large-scale capital at reasonable cost is also its key vulnerability, tightly linked to the broader group''s governance reputation.','Operates a distinctive ''build-mature-monetise'' model — incubating capital-intensive infrastructure businesses from scratch (funded by group capital and debt), scaling them to commercial maturity, and then either retaining the cash flows or spinning them off as separately listed companies once self-sustaining — the model that created Adani Ports, Adani Green, Adani Power and Adani Energy Solutions as independent entities.','This is a genuinely different value-creation mechanism than a typical single-business operating company — investors are effectively buying exposure to the Adani Group''s next generation of infrastructure businesses before they''re mature enough to stand alone.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ADANIENT','2026-03-31','revenue_growth_pct',20,'%','Revenue Growth (YoY)','Q4 revenue from operations ₹32,439 crore. Full-year FY26 total income grew a much slower 3% YoY — the Q4 acceleration doesn''t represent the full-year trend.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ADANIENT','2026-03-31','ebitda_margin_pct',13.8,'%','EBITDA Margin (Q4)','Q4 EBITDA ₹4,479 crore, up just 3% YoY even as revenue grew 20% — margin compression this quarter, reflecting the mix shift as newer, lower-margin capex-heavy businesses (like the copper plant) ramp up.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ADANIENT','2026-03-31','pat_growth_pct',31,'%','PAT Growth (FY26)','Full-year PAT ₹9,339 crore. This is overwhelmingly driven by a one-off ₹9,215 crore exceptional gain from selling stakes in Adani Wilmar and cement units to Ambuja Cements — full-year EBITDA was roughly flat YoY, a far less impressive underlying trend. Q4 alone swung to a net loss of ₹221 crore on higher depreciation from newly commissioned assets.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ADANIENT','2026-03-31','core_business_ebitda_pct',80,'%','EBITDA from Mature/Contracted Businesses','Management''s own disclosed figure — a genuine, structural shift toward earnings stability as the incubation portfolio matures. Display-only: a higher figure generally signals more predictable earnings, though it also means less exposure to the newer, higher-growth-potential ventures.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIENT','Newly commissioned assets (Navi Mumbai Airport, Kutch copper plant) are currently depreciation-heavy and loss-making at the consolidated level — a real, current earnings drag until they ramp to full utilisation','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIENT','Adani Group affiliation brings governance and disclosure scrutiny carrying real reputational and cost-of-capital implications, independent of AEL''s own operational performance','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIENT','The shift to 80% of EBITDA from mature, contracted businesses is a genuine de-risking of the earnings base as the incubation portfolio matures, reducing dependence on any single new venture''s success','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENT','2026-03-31','bull','80% of consolidated EBITDA now comes from mature, long-term, contracted businesses (core infrastructure and mining services) — a genuine, disclosed shift toward earnings stability as the incubation portfolio matures, not just an aspiration.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENT','2026-03-31','bull','Major infrastructure milestones landed in FY26: the Ganga Expressway (India''s largest greenfield expressway project) completed in under 3.5 years, plus continued build-out of Navi Mumbai and Guwahati airports — tangible execution of a genuinely large infrastructure pipeline.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENT','2026-03-31','bull','Solar module manufacturing sales surged 95% YoY and data center capacity keeps scaling (a new 358MW hyperscale order in Hyderabad) — the newer ''incubating'' businesses are showing real commercial traction, not just capex spend.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENT','2026-03-31','bear','Adani Enterprises swung to a net loss of ₹221 crore in Q4 (from a ₹3,845 crore profit a year earlier), driven by higher depreciation on newly commissioned assets (Navi Mumbai Airport, the Kutch copper plant) — a real, current earnings hit from the capex-heavy incubation model.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENT','2026-03-31','bear','FY26''s headline 31% PAT growth is overwhelmingly attributable to a one-off ₹9,215 crore exceptional gain from selling stakes in Adani Wilmar and cement units — full-year EBITDA (the cleaner operating measure) was essentially flat YoY, a much less impressive underlying trend than the reported PAT growth suggests.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENT','2026-03-31','bear','As part of the broader Adani Group, AEL carries the same governance and disclosure scrutiny as its listed affiliates — a real, ongoing consideration for investors independent of the company''s own operational execution.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('INDIGO','InterGlobe Aviation (IndiGo)','NSE','Aviation','Airlines','Aviation','IndiGo (InterGlobe Aviation) is India''s largest airline by market share, operating 441 aircraft across 97 domestic and 45 international destinations on a low-cost-carrier model. Revenue comes from passenger ticket sales plus a growing ancillary business (baggage, seat selection, cargo), while costs are dominated by fuel and aircraft-lease expenses — unit economics (revenue and cost per available-seat-kilometre) matter more than absolute revenue for judging underlying airline profitability.','IndiGo''s own Q4 & FY26 results press release (goindigo.in), cross-checked against Travel Turtle and Business News This Week coverage','India''s largest airline by domestic market share and route network breadth, reinforced by strong balance-sheet liquidity that lets it weather industry downturns better than smaller or more leveraged rivals — a real advantage in a historically brutal, bankruptcy-prone industry. Airline economics remain fundamentally difficult, though: limited pricing power over fuel and lease costs means even the market leader posted a net loss this year.','Sits at the passenger-facing end of the aviation value chain, leasing (rather than owning) most of its fleet and buying jet fuel and airport slots as its two largest cost inputs — limited pricing power over its biggest expenses means it competes instead on operational efficiency, India''s widest domestic route network, and increasingly on ancillary revenue and premium-segment yield.','The push into long-haul international routes (wide-body aircraft, business class) and a loyalty programme represents a structural shift toward higher-yield revenue segments beyond pure domestic low-cost flying — a multi-year strategic bet still in its early stages.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INDIGO','2026-03-31','revenue_growth_pct',6.4,'%','Total Income Growth (FY26)','Total income ₹89,513 crore. Q4 alone grew a slower 3.2% YoY, partly due to Middle East conflict-related capacity disruptions.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INDIGO','2026-03-31','capacity_growth_pct',9.5,'%','Capacity Growth (ASKs, FY26)','Available Seat Kilometres. Q4 capacity growth was a slower 3.4% YoY ''despite disruptions arising from the ongoing Middle East conflict,'' per the company''s own release.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INDIGO','2026-03-31','cask_ex_fuel_growth_pct',3.8,'%','Non-Fuel Unit Cost Growth (CASK ex-fuel)','Cost per Available Seat Kilometre excluding fuel rose to ₹3.00 — non-fuel costs are outpacing revenue growth, even as fuel costs (CASK ex-fuel... fuel CASK specifically) fell 11.5% YoY.',FALSE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('INDIGO','2026-03-31','pat_growth_pct',-15.4,'%','Adjusted Profit Growth (FY26)','Profit excluding forex and exceptional items fell to ₹7,503 crore from ₹8,868 crore a year earlier — a genuine decline even on this ''clean'' basis. Reported results were far worse: a full-year net loss of ₹2,394 crore, driven by sharp rupee depreciation and new labour-code costs.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INDIGO','Non-fuel cost inflation (CASK ex-fuel +3.8%) is outpacing revenue growth, a structural profitability concern independent of fuel price swings or currency effects','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INDIGO','Middle East conflict-related disruptions directly constrained capacity growth this quarter, and rupee depreciation plus new labour-code costs are additional, current macro/regulatory headwinds explicitly named by management','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INDIGO','Falling fuel costs (CASK ex-fuel down 11.5% YoY) provide real near-term margin relief, and the internationalisation/premiumisation strategy targets structurally higher-yield revenue beyond domestic low-cost flying','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDIGO','2026-03-31','bull','Even in what management called ''an exceptionally challenging operating environment,'' IndiGo delivered ₹7,503 crore of profit excluding forex and exceptional items for FY26, while growing capacity 9.5% and maintaining a strong balance sheet with over ₹5.1 lakh crore of total cash — real resilience, not just survival.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDIGO','2026-03-31','bull','Fuel costs (fuel CASK) fell 11.5% YoY, a genuine tailwind from lower crude prices, partially offsetting non-fuel cost inflation.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDIGO','2026-03-31','bull','A deliberate internationalisation and premiumisation push (business class introduction, loyalty programme, long-haul wide-body and XLR aircraft induction, new routes like Delhi/Mumbai-Athens) targets higher-yield segments beyond the traditional domestic low-cost model — genuine strategic evolution, not just capacity expansion.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDIGO','2026-03-31','bear','IndiGo swung to a full-year net loss of ₹2,394 crore (from a substantial profit the prior year) — even excluding forex and exceptional items, the ''clean'' profit figure fell 15.4% YoY, meaning underlying profitability genuinely deteriorated, not just currency-swing optics.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDIGO','2026-03-31','bear','Total costs grew 17.2% YoY for the full year against just 6.4% total income growth — a serious, structural cost-growth-outpacing-revenue problem, with non-fuel unit costs (CASK ex-fuel) rising 3.8% even as fuel costs fell, meaning non-fuel costs are the real pressure point.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDIGO','2026-03-31','bear','Sharp rupee depreciation and new labour-code-related costs were both explicitly named by management as offsetting operational gains — real, current macro and regulatory headwinds outside the company''s direct control, on top of Middle East conflict-related capacity disruptions.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('BAJAJFINSV','Bajaj Finserv','NSE','Financial Services','Diversified Financial Holding','Financial Services','Bajaj Finserv is the holding company of the Bajaj group''s financial-services businesses — its value comes almost entirely from three large subsidiaries: Bajaj Finance (India''s leading consumer-lending NBFC), Bajaj Allianz General Insurance and Bajaj Allianz Life Insurance (now renamed after Bajaj bought out Allianz''s stake). Owning Bajaj Finserv is effectively owning a bundle of lending plus general and life insurance through one listed vehicle, with a smaller set of emerging businesses (health, digital, asset management) still in investment/loss-making mode.','Bajaj Finserv''s own Q4 & FY26 results and investor presentation, cross-checked against MarketsMojo, Whalesbook and APAC Media coverage','A rare, genuinely diversified financial-services platform under one roof — a market-leading consumer-lending NBFC (Bajaj Finance) plus now-wholly-owned general and life insurers — combined with a strong brand and one of India''s widest financial-product distribution reaches. The moat is real, but the holding-company structure means investors get diluted, indirect exposure to each business, and this year''s insurance weakness shows the diversification cuts both ways: no single strong business fully offsets a weak one at the group level.','Sits at the top of a diversified financial-services group as a holding company — it doesn''t directly originate loans or underwrite policies itself, but captures the aggregate value of India''s leading consumer-lending NBFC (Bajaj Finance) plus now-wholly-owned general and life insurers, giving investors bundled exposure to both credit-risk-bearing lending and insurance underwriting in one vehicle.','The buyout of Allianz''s stake marks a strategic pivot from a joint-venture model (shared control, shared risk) to full ownership (full control, full risk) — greater strategic flexibility, but also greater concentration of both upside and execution risk in Bajaj Finserv''s own hands.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJAJFINSV','2026-03-31','revenue_growth_pct',6,'%','Revenue Growth (Q4 YoY)','Q4 consolidated total income growth was held down by mark-to-market losses on debt and equity portfolios (linked to Middle East conflict-driven market volatility). Excluding those MTM losses, the company says revenue growth would have been 14% — the underlying operating trend is stronger than the headline.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJAJFINSV','2026-03-31','pat_growth_pct',5.05,'%','PAT Growth (Q4 YoY)','Q4 consolidated PAT ₹2,539 crore. Full-year FY26 PAT grew a similar 10% to ₹9,801 crore — solid but far below the group''s historical 20%+ growth pace, reflecting a genuinely tougher year for the underlying financial-services businesses.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJAJFINSV','2026-03-31','aum_growth_pct',22,'%','Bajaj Finance AUM Growth','The lending arm (Bajaj Finance) remains the key growth engine — AUM grew 22% YoY to ₹5.09 lakh crore, with Q4 net total income up 21%. Lending is carrying the group while insurance disappoints.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('BAJAJFINSV','2026-03-31','roe_pct',12.74,'%','Return on Equity','A modest figure for a financial-services group, reflecting the holding-company structure (value is spread across subsidiaries) plus drag from loss-making emerging businesses (₹539 crore of losses in FY26).',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJAJFINSV','Insurance underperformance is a real, current weak spot — flat general-insurance GWP and missed Q4 profit targets, now fully borne by Bajaj Finserv following the Allianz buyout rather than shared with a JV partner','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJAJFINSV','Regulatory scrutiny on unsecured lending plus elevated funding costs are squeezing margins across the lending business industry-wide — a structural, sector-level pressure, not company-specific','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BAJAJFINSV','India''s insurance market is projected for significant multi-decade expansion, and full ownership now gives Bajaj Finserv complete strategic flexibility to capture that growth with faster product launches and decisions','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJFINSV','2026-03-31','bull','The lending arm (Bajaj Finance) delivered strongly — AUM up 22% YoY to ₹5.09 lakh crore with Q4 net total income up 21% — genuinely carrying group growth while other segments disappointed, a proven, market-leading consumer-lending franchise.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJFINSV','2026-03-31','bull','Excluding one-off mark-to-market portfolio losses from market volatility, Q4 revenue growth would have been 14% (versus the 6% reported) — the underlying operating momentum is materially stronger than the headline number suggests.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJFINSV','2026-03-31','bull','Full ownership of the insurance businesses (Bajaj bought out Allianz''s 24-year JV stake for ~₹21,390 crore) gives the group complete strategic control and flexibility over product launches and decisions for the first time — a genuine structural change, not just a shareholding reshuffle.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJFINSV','2026-03-31','bear','The general insurance arm genuinely disappointed — Q4 Gross Written Premium was flat (~9% below analyst targets) and Q4 profit grew just 2% (26% below targets) — a real, current weak spot in one of the group''s three core businesses, at a time the insurance industry is expected to grow ~10% CAGR.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJFINSV','2026-03-31','bear','Full-year PAT growth of 10% is well below the group''s historical 20%+ pace, and independent analysts flag margin pressure across lending and insurance from elevated funding costs and regulatory scrutiny on unsecured lending — a genuinely tougher operating environment, not a one-quarter blip.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BAJAJFINSV','2026-03-31','bear','Now that Bajaj fully owns the insurance businesses, it carries 100% of their execution risk directly — the same insurance weakness that showed up this quarter now flows entirely to Bajaj Finserv rather than being shared with a JV partner, and emerging businesses (health, digital, AMC) remain loss-making (₹539 crore drag in FY26).',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('JIOFIN','Jio Financial Services','NSE','Financial Services','Fintech / Diversified Financial Holding','Financial Services','Jio Financial Services (JFS), demerged from Reliance Industries in 2023, is a Mukesh Ambani-led financial-services platform building four verticals in parallel &mdash; lending (Jio Credit/Jio Finance), payments (Jio Payments Bank, Jio Payment Solutions), asset management (the Jio BlackRock JV) and insurance broking/underwriting. Its entire thesis rests on cross-selling financial products to Reliance''s 450+ million Jio telecom subscriber base via a digital-first app. It''s a genuine early-stage buildout: revenue is scaling explosively but profit is deliberately depressed by heavy investment.','Jio Financial''s own Q4 FY26 results and earnings call, cross-checked against Univest, Medianama, AlphaSpread and Whalesbook coverage','The core moat is potential rather than proven: privileged access to Reliance''s 450M+ Jio subscriber base is a genuinely unique distribution advantage no standalone fintech can replicate, and marquee partnerships (BlackRock for AMC, Allianz for insurance) add credible product expertise. But unlike an incumbent like Bajaj Finance with a decades-proven lending book, JFS''s moat is still a thesis being tested — the explosive revenue growth is real evidence it''s working, but durable, profitable competitive advantage is still years of execution away from being confirmed.','Building an integrated, digital-first financial-services stack (Borrow / Invest / Transact / Protect) that sits directly on top of Reliance''s existing consumer ecosystem — the differentiator isn''t any single product but the ability to cross-sell lending, payments, mutual funds and insurance to a captive 450M+ Jio subscriber base through one AI-driven app, a distribution advantage no standalone fintech can match.','Strategic partnerships anchor each vertical: BlackRock for asset management, Allianz for reinsurance and upcoming general/life insurance — JFS is combining Reliance''s distribution reach with established global partners'' product expertise rather than building every capability from scratch.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JIOFIN','2026-03-31','revenue_growth_pct',106.5,'%','Revenue Growth (Q4 YoY)','Q4 revenue from operations nearly doubled to ₹1,018.51 crore. FY26 total income (ex-dividends) rose 78% to ₹3,274 crore — genuinely explosive top-line scaling off a small base, driven by lending, payments and insurance broking all ramping at once.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JIOFIN','2026-03-31','pat_growth_pct',-13.88,'%','PAT Growth (Q4 YoY)','Consolidated Q4 PAT fell to ₹272.22 crore. The decline is a deliberate growth-vs-profitability trade-off: total expenses rose 327% YoY on heavy business-building investment, plus Jio Payments Bank''s operating loss now consolidates fully into JFS''s books (it became a 100% subsidiary in June 2025).',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JIOFIN','2026-03-31','aum_growth_pct',156,'%','Lending AUM Growth (Jio Credit)','Jio Credit AUM surged to ₹25,711 crore, up 156% YoY (a ~149x jump since FY24 off a near-zero base), driven entirely by organic disbursements. Home loans/LAP are 45% of the book, corporate loans 44%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('JIOFIN','2026-03-31','roe_pct',NULL,'%','Return on Equity','Not meaningful yet — JFS carries a very large ₹1.33 lakh crore net worth (much of it from the Reliance demerger) against still-small early-stage profits, so a computed RoE would understate the business and mislead. Shown as — rather than a distorted figure.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JIOFIN','Deep growth-stage unprofitability: PAT falling 14% while expenses surge 327% means investors are underwriting years of continued heavy investment before profitability matches the revenue scaling — real execution risk over a multi-year horizon','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JIOFIN','Intense competition in India''s digital-lending and payments markets means the 49% disbursement growth and rapid AUM ramp must be sustained against well-funded fintech and bank rivals — not guaranteed','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JIOFIN','The Reliance ecosystem cross-sell opportunity (450M+ Jio subscribers, 19,000+ pin codes, 23M app users) plus marquee partnerships (BlackRock, Allianz) give JFS a genuinely differentiated distribution-and-expertise combination few fintechs can replicate','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JIOFIN','2026-03-31','bull','Revenue nearly doubled YoY (Q4 +106.5%, FY26 +78%) with lending AUM up 156% — genuinely explosive scaling across lending, payments, asset management and insurance broking simultaneously, all driven by organic growth rather than acquisitions.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JIOFIN','2026-03-31','bull','Core operating income now drives 54% of net total income (up from 20% a year ago) — a real, structural shift away from passive treasury/dividend income toward a genuine operating financial-services business, exactly the maturation the thesis requires.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JIOFIN','2026-03-31','bull','The Jio BlackRock AMC reached ₹15,200+ crore AUM with over 40% of inflows from beyond India''s top 30 cities — evidence the Reliance-scale distribution advantage (450M+ Jio subscribers, 19,000+ pin codes) is translating into genuine financial-product reach, not just a theoretical edge.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JIOFIN','2026-03-31','bear','Consolidated PAT fell 14% YoY as total expenses surged 327% — this is a company deliberately sacrificing near-term profit for growth, which means investors are underwriting 3-5 years of continued execution before profitability catches up to the revenue scaling, with no guarantee it does.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JIOFIN','2026-03-31','bear','At a ~₹1.55 lakh crore market cap against current profitability, the valuation prices in substantial future success that hasn''t yet been proven — the buildout is real, but so is the execution risk in a fiercely competitive digital-lending and payments market.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JIOFIN','2026-03-31','bear','Treasury volatility (from late-March market/geopolitical stress) hit both treasury income and JioBlackRock''s AUM this quarter — a reminder that a meaningful part of the current asset base is market-linked and exposed to downturns while the core operating businesses are still too young to fully offset it.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('ETERNAL','Eternal (formerly Zomato)','NSE','Consumer Services','Food Delivery & Quick Commerce','Consumer Services','Eternal (renamed from Zomato) is India''s leading consumer-internet platform spanning four businesses: Zomato (food delivery), Blinkit (quick commerce &mdash; 10-minute grocery/essentials delivery, now the company''s biggest growth engine), Hyperpure (B2B restaurant supplies) and District (going-out/events). Because Blinkit shifted from a marketplace model to an inventory-led (1P) model in FY26, reported revenue is mechanically inflated &mdash; Net Order Value (NOV, the total value of goods/orders flowing through the platform) is the cleaner metric to judge real business scale, not headline revenue.','Eternal''s own Q4 FY26 results and shareholder letter, cross-checked against Sahi.com, Business Standard, Angel One and Quash coverage','Genuine network effects and scale in both food delivery (a two-sided marketplace of restaurants and diners built over 18 years) and quick commerce (Blinkit''s dark-store density and supply-chain efficiency, now demonstrably profitable). The moat is real and Blinkit''s first-ever positive EBITDA is strong evidence it''s durable at scale — but quick commerce is a young, capital-intensive, fiercely contested category, so the moat''s durability is still being actively tested against well-funded rivals rather than fully established.','Operates asset-heavier than a pure marketplace now — Blinkit''s shift to an inventory-led (1P) model and its 2,243 dark stores mean Eternal increasingly owns inventory and last-mile fulfilment infrastructure directly, capturing more margin per order but also carrying more operational and working-capital risk than a commission-only marketplace.','The four businesses (Zomato food delivery, Blinkit quick commerce, Hyperpure B2B supplies, District going-out) each sit at different points of maturity — Blinkit is the growth engine, food delivery the steady profitable base, and District/Hyperpure smaller optionality plays still being built.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ETERNAL','2026-03-31','nov_growth_pct',54,'%','B2C Net Order Value Growth (Q4 YoY)','B2C NOV reached ₹26,880 crore. This is the cleanest measure of real platform scale — Blinkit''s NOV alone surged 95.4% YoY to ₹14,386 crore, now exceeding Zomato food delivery''s NOV. Food delivery NOV grew a steadier 18.8%.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ETERNAL','2026-03-31','revenue_growth_pct',64,'%','Adjusted Revenue Growth (Q4 YoY)','Like-for-like adjusted revenue growth of 64% is the honest figure. The headline reported revenue growth of 196% (to ₹17,292 crore) is mechanically inflated by Blinkit''s marketplace-to-inventory (1P) accounting shift — reading the headline number badly overstates real growth.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ETERNAL','2026-03-31','adj_ebitda_growth_pct',160,'%','Adjusted EBITDA Growth (Q4 YoY)','Consolidated Adjusted EBITDA ₹429 crore. The single most important milestone this quarter: Blinkit turned Adjusted-EBITDA positive for the first time (₹37 crore) — the quick-commerce business is now demonstrably profitable at scale, not just growing.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('ETERNAL','2026-03-31','pat_growth_pct',346,'%','PAT Growth (Q4 YoY)','Q4 PAT ₹174 crore, well above estimates. But full-year FY26 PAT actually fell to ₹366 crore (from ₹527 crore) — a heavier investment phase earlier in the year (especially Q1) means the strong Q4 doesn''t represent the full-year trend. The quarterly trajectory (Q1 loss → ₹102cr Q3 → ₹174cr Q4) is the more relevant signal.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ETERNAL','Fierce quick-commerce competition (Zepto and other well-funded rivals) means Blinkit''s lead and newly-achieved profitability must be continuously defended — a genuine, ongoing competitive risk, not a settled position','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ETERNAL','Deliberate profitability sacrifice for growth: full-year PAT fell despite explosive revenue, so investors are underwriting a multi-year path to the FY29 $1bn Adjusted-EBITDA target rather than current earnings','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ETERNAL','Quick commerce is still early-innings geographically and by assortment (concentrated in top cities, narrow SKU range outside metros) — a long structural runway of expansion, densification and category deepening ahead, each compounding the others','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ETERNAL','2026-03-31','bull','Blinkit turned Adjusted-EBITDA positive for the first time (₹37 crore) while NOV surged 95.4% YoY — the single biggest milestone this quarter, proving quick commerce can translate explosive scale into actual operating profit, not just growth.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ETERNAL','2026-03-31','bull','109 million Indians transacted over $10 billion through the platform in FY26, with Blinkit''s NOV compounding at 104% CAGR from FY23-26 — genuine, category-defining scale, and management targets $1 billion in Adjusted EBITDA by FY29 (roughly 8x in five years from an already-profitable base).',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ETERNAL','2026-03-31','bull','Quick commerce is still concentrated in the top 15-20 cities and a narrow product range (Delhi NCR offers ~80,000 SKUs versus ~20,000 in newer markets) — geographic expansion, assortment deepening and demand densification are all still early innings, each compounding on the others.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ETERNAL','2026-03-31','bear','Full-year FY26 PAT actually declined to ₹366 crore (from ₹527 crore) despite the explosive revenue growth — profitability is being deliberately sacrificed for expansion, so investors are underwriting continued execution rather than banking current earnings.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ETERNAL','2026-03-31','bear','The headline 196% reported revenue growth is mechanically inflated by Blinkit''s marketplace-to-inventory accounting shift — the honest like-for-like figure is 64%, and reading the headline number badly overstates the real underlying growth rate.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ETERNAL','2026-03-31','bear','Competitive intensity in quick commerce is genuinely fierce and repeatedly flagged by analysts — Zepto and other well-funded rivals are building speed and density, meaning Blinkit''s lead and margins must be defended continuously against deep-pocketed competition, not assumed as durable.',3);
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note) VALUES ('TRENT','Trent','NSE','Consumer Services','Fashion & Value Retail','Consumer Services','Trent (Tata Group) is one of India''s fastest-growing fashion and value retailers, operating premium family-fashion stores (Westside), a rapidly expanding value-fashion format (Zudio, its main growth engine, approaching 1,000 stores) and a grocery/essentials business (Star). Growth is driven overwhelmingly by aggressive new-store rollout &mdash; especially Zudio into Tier 2/3 cities &mdash; making store additions and like-for-like (same-store) sales the two metrics that together reveal whether growth is genuine expansion or just running to stand still.','Trent''s own Q4 & FY26 results release, cross-checked against ICICI Direct Research, HDFC Sky and MarketsMojo coverage','A powerful own-brand/private-label model (Zudio and Westside are almost entirely proprietary merchandise) combined with fast, disciplined store-rollout execution gives Trent a genuine cost and exclusivity moat in India''s organised value-retail shift — Zudio in particular has proven a durable, hard-to-replicate value-fashion format. The moat is real, but the low like-for-like growth and premium valuation mean the market is pricing in near-flawless continued execution of the expansion story rather than just the strength of the existing base.','A vertically-engaged fashion retailer — Trent designs and sources most of its own private-label merchandise (Westside and Zudio are almost entirely own-brand, unlike department stores reselling third-party labels), controls pricing and inventory tightly, and sells through its own rapidly expanding owned/leased store network, capturing more margin than a multi-brand reseller.','The heavy own-brand/private-label model (own-brand share in Star grocery rose to 73%) is central to the margin story — private labels generate higher margins, create exclusivity, and drive repeat purchases since the products are only available in Trent''s own stores.');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TRENT','2026-03-31','revenue_growth_pct',19,'%','Revenue Growth (Q4 YoY)','Consolidated revenue ₹5,028 crore. Driven almost entirely by store-count expansion (retail area +30% YoY) rather than existing-store productivity — revenue per square foot actually declined ~6% as like-for-like growth stayed in low single digits.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TRENT','2026-03-31','ebitda_margin_pct',18.6,'%','EBITDA Margin (Q4)','Expanded 242bps YoY, driven by gross-margin improvement (better mix, lower discounting) plus lower employee and rent cost per square foot. Note it fell sequentially from Q3''s ~20.2% on seasonal softness.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TRENT','2026-03-31','store_growth_pct',30,'%','Retail Area Growth (YoY)','Total retail footprint grew 30% YoY to ~17.7 million sq ft. Trent added 60 Westside and 212 Zudio stores in FY26 (~1.2 Zudio stores per day in Q4), with ~80% of new Zudio stores in Tier 2/3 cities.',TRUE,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,higher_is_better,status) VALUES ('TRENT','2026-03-31','pat_growth_pct',30,'%','Adjusted PAT Growth (Q4 YoY)','Adjusted PAT ₹455 crore (standalone). Full-year FY26 PAT grew a more modest 13-25% depending on the measure and labour-code adjustment. Trent also announced its first-ever bonus issue (1:2) — a management confidence signal.',TRUE,'verified');
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TRENT','Low single-digit like-for-like growth and declining revenue per square foot mean growth is almost entirely dependent on continued aggressive store rollout — if new-store economics or the expansion pace falter, the growth story is more exposed than the headline revenue number suggests','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TRENT','Cautious discretionary consumer sentiment (flagged by management, tied to geopolitical/inflation uncertainty) is a real, current demand-side headwind for a value-fashion retailer, plus a rich valuation that leaves little room for disappointment','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TRENT','Deep, underpenetrated Tier 2/3 city expansion runway (~80% of new Zudio stores) combined with genuine operating leverage as scale builds gives a long structural growth path in India''s organised-value-retail shift','tailwind',TRUE);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TRENT','2026-03-31','bull','Explosive, disciplined store expansion — 212 new Zudio stores in FY26 (~1.2 per day in Q4), with ~80% of new stores in Tier 2/3 cities targeting underpenetrated, faster-growing markets — a genuine, repeatable growth engine, not a one-off.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TRENT','2026-03-31','bull','EBITDA margin expanded 242bps YoY in Q4 even while expanding aggressively, driven by better product mix, lower discounting, and falling employee/rent cost per square foot (aided by RFID supply-chain integration) — real operating leverage kicking in as scale builds.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TRENT','2026-03-31','bull','Emerging categories (beauty, innerwear, footwear) now contribute over 21% of revenue and Westside online grew 25% — genuine diversification beyond core apparel, plus a maiden 1:2 bonus issue signalling management''s confidence in the medium-term outlook.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TRENT','2026-03-31','bear','Like-for-like (same-store) growth stayed in low single digits and revenue per square foot actually declined ~6% YoY — the impressive 19% headline revenue growth is almost entirely new-store-driven, meaning the existing store base is barely growing, a genuine quality-of-growth concern.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TRENT','2026-03-31','bear','The stock trades at a very rich ~95x P/E (per one analysis) with a PEG around 8x — a valuation leaving minimal room for execution missteps, especially as Q4 PAT fell ~22% sequentially and FII holdings declined from ~19.7% to ~15.6% over the year.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TRENT','2026-03-31','bear','Management explicitly flagged cautious discretionary consumer sentiment (geopolitical uncertainty, inflation, cost-of-living concerns) softening as Q4 progressed — a real demand-side headwind for a value-fashion retailer whose growth depends on continued consumer willingness to spend.',3);
