INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('RELIANCE',50.01,'Ambani family (via promoter group entities)','No promoter pledge flagged in the quarter''s shareholding trackers.','FY26 dividend of ₹6/share declared; the flagship capital event is the Jio Platforms IPO — DRHP filed 19 Jun 2026 — which would unlock value from inside the promoter-controlled structure.','Mar 2026','Choice/Angel/Screener shareholding trackers');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('TCS',71.77,'Tata Sons (core holding of the Tata group)','None — TCS''s own SEBI filings state promoter shares are not pledged or encumbered.','The Tata group''s cash engine: consistently high dividend payouts (board meets 9 Jul 2026 to consider the next interim dividend) and a history of regular buybacks routed largely to Tata Sons.','Mar 2026','Angel/Screener + TCS exchange SHP filing');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('HDFCBANK',0,'No promoter — professionally managed since the HDFC Ltd merger (Jul 2023)','Not applicable — there is no promoter to pledge.','Institutions hold ~74%; capital allocation is board-driven. FY26 brought the bank''s first-ever bonus issue plus a special interim dividend — a professionally-run register in action.','Mar 2026','Choice + IIFL shareholding trackers');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('ICICIBANK',0,'No promoter — fully institutionally owned, board-managed','Not applicable — there is no promoter to pledge.','Institutions hold ~75% of the register; management incentives run on performance, not family control.','Mar 2026','Choice + IIFL shareholding trackers');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('SBIN',55.5,'Government of India','Not applicable — the promoter is the sovereign.','GoI stake diluted from ~57.5% after the FY26 equity raise (QIP) — the bank funded growth by issuing shares, trimming the state''s slice while keeping clear majority control.','Mar 2026','Kotak Neo (Mar''26) + Choice tracker');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('BHARTIARTL',48.87,'Bharti Telecom (Mittal family + Singtel) 40.47% + other promoter entities','No pledge flagged in current trackers; promoter action is about buying more, not borrowing against it.','Chairman Mittal''s stated decade plan: consolidate promoter holding under Bharti Telecom to 51% using "twin levers" of buybacks and dividends — while explicitly refusing to hollow out the business the way he says IT firms have. FY26 also saw a ₹28,200 cr share-swap lifting Airtel''s stake in Airtel Africa to 79%.','Mar 2026','Choice tracker + Business Standard (May 2026 earnings call)');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('INFY',14.4,'Founders'' families (Nilekani, Murthy, Gopalakrishnan et al)','None — promoter Nandan Nilekani''s Apr-2026 SEBI declaration confirms zero encumbrance.','Ran a record ₹18,000 cr buyback at ₹1,800/share (Nov 2025) that promoters chose NOT to tender — their stake rose mechanically as the share count shrank. New tax rules that treat buyback proceeds as dividend income made tendering unattractive for them.','Mar 2026','Choice tracker + SEBI Reg 31(4) filing + Business Today');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('ITC',0,'No classified promoter — British American Tobacco''s arm (TMI) holds 17.79% as the largest shareholder, but as a public shareholder','Not applicable — no classified promoter.','BAT has been steadily trimming: TMI''s stake fell from 24.0% (Dec 2022) to 17.79% (Mar 2026), while still collecting ₹3,896 cr of FY26 dividends. ITC also bought three brand trademarks from BAT for ₹404 cr — the two are slowly disentangling.','Mar 2026','Choice tracker + FY26 related-party disclosures (Whalesbook)');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('HINDUNILVR',61.9,'Unilever PLC (multinational parent)','None reported — an MNC parent has no need to pledge its subsidiary''s shares.','Classic MNC-parent model: high, steady dividend payouts (₹22/share due Jun 2026) flowing largely to Unilever; strategy set in lockstep with the global parent.','Mar 2026','Kotak Neo (Mar''26) + Choice/Groww/Upstox trackers');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('BAJFINANCE',54.7,'Bajaj Finserv Ltd (the listed holding company)','No pledge flagged in current trackers.','The promoter is itself a listed company on this platform — Bajaj Finserv — so ''promoter confidence'' here is really a group capital-allocation decision one level up.','Mar 2026','Kotak Neo (Mar''26) + Angel tracker');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('BAJAJFINSV',58.81,'Bajaj family (via Bajaj Holdings & promoter group)','No pledge flagged in current trackers.','FY26''s defining move: buying out Allianz''s 26% in both insurance JVs to own them 100% — concentrating the group''s insurance economics under the family-controlled holding company.','Mar 2026','Choice tracker (Mar''26)');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('MARUTI',58.5,'Suzuki Motor Corporation, Japan (56.28% held directly)','None reported — the promoter is a global carmaker parent.','Parent-driven allocation: Suzuki''s India subsidiary is now its largest, and capex flows into new capacity (Kharkhoda) and EV/hybrid programmes are set jointly with Japan — royalty payments to Suzuki remain the standing minority-shareholder watch-item.','Mar 2026','Kotak Neo (Mar''26) + Screener');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('ADANIENT',74.67,'Adani family (S.B. Adani Family Trust holds 49.67% directly)','The promoter trust''s FY26 SEBI declaration states NO fresh encumbrance was created during the year; the group had prepaid over $2 bn of share-backed financing after the 2023 short-seller episode. History says watch this line every quarter.','Promoters BOUGHT through the year — stake rose from 73.97% (Dec 2025) to 74.67% (Mar 2026); FY26 also closed the Jaiprakash Associates insolvency acquisition (May 2026) and a rights-issue call. Aggressive, promoter-funded expansion is the model.','Mar 2026','SEBI Reg 31(4) FY26 filing + Kotak Neo/Screener + Tradebrains');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('KOTAKBANK',25.9,'Uday Kotak & family — founder, now non-executive director','No pledge flagged in current trackers.','Unusual case: the RBI capped the founder''s stake at ~26% by agreement, so promoter holding here is regulator-shaped, not sentiment-shaped. Still among the largest founder stakes in Indian banking.','Q4 FY26','Univest research (Apr 2026) + RBI-agreement record');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('LT',0,'No promoter — India''s flagship promoter-less engineering company','Not applicable — there is no promoter to pledge.','Ownership by institutions (LIC ~11%) and the L&T Employees Trust (~14.3%) with professional management; recent record includes a ₹10,000 cr buyback (2023-24) and steadily rising dividends — capital returned, not hoarded.','Mar 2026','Choice/IIFL trackers + MarketsMojo holdings breakdown');
INSERT INTO cross_company_narratives (id,kind,title,blurb,stages,flows,pairs,evidence) VALUES ('power','flow','How electricity reaches you','India''s power travels through three listed links in a row. Coal India digs the coal, NTPC burns it to make electricity, and Power Grid carries that electricity across the country to the state distributors who hand it to homes and factories. A shock at any one link (a coal shortage, a plant trip, a grid bottleneck) ripples down the whole line.','[{"label": "Fuel", "nodes": [{"tk": "COALINDIA"}]}, {"label": "Generation", "nodes": [{"tk": "NTPC"}]}, {"label": "Transmission", "nodes": [{"tk": "POWERGRID"}]}, {"label": "End users", "nodes": [{"t": "State discoms \u2192 homes & industry"}]}]'::jsonb,'["coal (long-term supply pacts)", "power onto the grid", "wheeled to distributors"]'::jsonb,NULL,'Coal India delivers coal to power utilities via Fuel Supply Agreements; NTPC generates and sells bulk power; Power Grid''s own profile describes moving electricity “from generators (like NTPC)” to distributors.');
INSERT INTO cross_company_narratives (id,kind,title,blurb,stages,flows,pairs,evidence) VALUES ('metals-auto','input','Metals into mobility','Every car, truck and motorcycle begins life as steel and aluminium. India''s big metal makers sit upstream of every listed vehicle maker, so when steel prices, import duties or the Novelis plants move, the effect eventually reaches the automakers'' cost sheets. This is an input dependency — not a single named contract — but it is structurally real for all of them.','[{"label": "Raw metal", "nodes": [{"tk": "TATASTEEL"}, {"tk": "JSWSTEEL"}, {"tk": "HINDALCO"}]}, {"label": "Vehicle makers", "nodes": [{"tk": "MARUTI"}, {"tk": "M&M"}, {"tk": "TMPV"}, {"tk": "EICHERMOT"}, {"tk": "BAJAJ-AUTO"}]}]'::jsonb,'["steel & aluminium \u2014 the metal in every vehicle"]'::jsonb,NULL,'Tata Steel and JSW Steel sell into automotive end-markets; Hindalco''s Novelis supplies automotive body-panel sheet; each automaker lists steel and components among its core inputs.');
INSERT INTO cross_company_narratives (id,kind,title,blurb,stages,flows,pairs,evidence) VALUES ('holding','ownership','Who owns whom — holding-company trees','Some of these 58 tickers are really parent and child. Knowing the tree tells you when two “separate” companies actually rise and fall together, and where a parent''s value is just the sum of what it owns.',NULL,NULL,'[{"parent": "ADANIENT", "child": "ADANIPORTS", "note": "Adani Enterprises incubated Adani Ports from scratch and then listed it separately \u2014 its \u201cbuild-mature-monetise\u201d model."}, {"parent": "GRASIM", "child": "ULTRACEMCO", "note": "Grasim holds the majority stake in UltraTech, India''s largest cement maker \u2014 so Grasim''s value partly is UltraTech."}, {"parent": "BAJAJFINSV", "child": "BAJFINANCE", "note": "Bajaj Finserv is the holding company; Bajaj Finance is the consumer-lending NBFC it owns and captures the value of."}, {"parent": "RELIANCE", "child": "JIOFIN", "note": "Jio Financial was demerged out of Reliance and still sits on top of the Reliance/Jio consumer ecosystem it was born from."}]'::jsonb,NULL);
INSERT INTO cross_company_narratives (id,kind,title,blurb,stages,flows,pairs,evidence) VALUES ('banca','ownership','Banks that sell insurance for their own insurer','A life insurer needs somewhere to sell policies. These two lean on their sister bank''s branch network to do exactly that — “bancassurance.” So the bank''s reach is quietly the insurer''s growth engine, and anything that changes the bank changes the insurer.',NULL,NULL,'[{"parent": "SBIN", "child": "SBILIFE", "note": "SBI Life reaches customers overwhelmingly through State Bank of India''s own branches \u2014 a big cost advantage and a real dependency."}, {"parent": "HDFCBANK", "child": "HDFCLIFE", "note": "HDFC Life sells a large share of its policies through HDFC Bank branches (alongside agency and digital channels)."}]'::jsonb,NULL);
