INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('ADANIGREEN','Adani Green Energy','NSE','Renewable Energy','Solar & Wind IPP','Renewable Energy','Adani Green Energy builds, owns and operates utility-scale solar, wind and hybrid power plants across India, then sells the electricity onward under long-term Power Purchase Agreements (PPAs) to state distribution companies (DISCOMs), the government''s Solar Energy Corporation of India (SECI), and increasingly to commercial & industrial (C&I) customers directly. It earns a spread between what it costs to generate power (largely fixed, once a plant is built) and what buyers pay under multi-decade contracts. It is India''s largest renewable energy company by operating capacity.','Adani Green Energy FY26 results presentation & press release (adanigreenenergy.com); Screener.in; MarketsMojo Q4 FY26 result analysis; SEBI Reg 31(4) promoter declaration coverage (scanx.trade)','Scale, balance-sheet access, and the Khavda site itself — the world''s largest single renewable energy park (30 GW planned) on barren land, a location and land-bank advantage that is extremely difficult for any competitor to replicate.','An upstream power generator — Adani Green builds and owns utility-scale solar, wind and hybrid plants, then sells the electricity onward under long-term contracts. It sits between land/equipment suppliers and the buyers (DISCOMs, SECI, and increasingly C&I customers) who consume the power.','Because a sister Adani company (Adani Energy Solutions) builds much of the transmission infrastructure that carries this power to market, AGEL is unusually exposed to how fast that related company''s grid build-out keeps pace — the FY26 curtailment losses are a direct, measurable example of that dependency.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIGREEN','2026-03-31','operating_capacity_mw',19294,'MW','Operating Capacity','Up 35% YoY; India''s largest renewable portfolio, spread across 12 states.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIGREEN','2026-03-31','capacity_growth_pct',35,'%','Capacity Growth (YoY)','5.1 GW added in FY26 alone — the highest greenfield addition by any company outside China.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIGREEN','2026-03-31','revenue_growth_pct',22,'%','Revenue Growth (Power Supply, YoY)','Revenue from power supply rose to ₹11,602 crore in FY26.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIGREEN','2026-03-31','ebitda_margin_pct',91.2,'%','EBITDA Margin (Power Supply)','Industry-leading margin — renewable generation has very low variable operating cost once built.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIGREEN','2026-03-31','net_debt_ebitda',10.92,'x','Net Debt / EBITDA','Very high leverage even for a capital-intensive utility; funds the aggressive capacity build-out toward the 50 GW-by-2030 target.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIGREEN','2026-03-31','bull','Added a record 5.1 GW of greenfield capacity in FY26 — the highest of any company outside China — taking total operating capacity to 19.3 GW, up 35% YoY.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIGREEN','2026-03-31','bull','Zero promoter share pledging and an inaugural JCR BBB+ credit rating, aligned with India''s own sovereign rating, signal growing financial credibility despite the scale of the build-out.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIGREEN','2026-03-31','bull','28 GW of capacity is already signed against the 50 GW-by-2030 target, with over 90% of the portfolio locked into long-term PPAs — unusually strong multi-year revenue visibility for a growth-stage utility.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIGREEN','2026-03-31','bear','Net debt/EBITDA near 11x and net debt/equity around 4.2x are extreme even by capital-intensive utility standards — real refinancing risk if rates or funding conditions tighten.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIGREEN','2026-03-31','bear','Grid curtailment cost the company an estimated ₹1,300–1,500 crore of EBITDA in FY26 alone — transmission build-out (much of it via a sister Adani company) hasn''t kept pace with generation capacity.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIGREEN','2026-03-31','bear','FII holding has been drifting down, and at a P/E north of 100x the stock prices in years of flawless execution, leaving little room for disappointment.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIGREEN','Grid evacuation infrastructure lagging capacity build-out cost an estimated ₹1,300–1,500 crore of EBITDA in FY26 via curtailment','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIGREEN','India''s 50 GW-by-2030 renewable target and long-term PPA regime give a multi-year policy tailwind for utility-scale solar and wind','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIGREEN','Rising commercial & industrial demand for green power, including data-centre buyers, offers higher-margin sales than regulated DISCOM contracts','tailwind',TRUE);
