INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('ADANIGREEN',62.43,'Adani family, via Adani Trading Services LLP (28.80%) and S.B. Adani Family Trust (19.96%), plus other promoter entities','No new encumbrances declared for FY26 per the promoter group''s SEBI Regulation 31(4) filing — zero pledging reported.','Funding a ₹40,000–42,000 crore FY27 capex plan largely through promoter warrants (~US$1.125bn) and non-dilutive debt; the company pays no dividend, reinvesting fully into the 50 GW build-out.','Mar 2026','SEBI Reg 31(4) promoter declaration (via scanx.trade); AGEL FY26 investor presentation');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,status) VALUES ('ADANIGREEN','2026-03-31','market_cap_cr',256211,'crore','Market Capitalisation','verified');
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('SUZLON','Suzlon Energy','NSE','Renewable Energy','Wind Turbine Manufacturing (OEM)','Renewable Energy','Suzlon designs, manufactures, installs and services wind turbine generators (WTGs) — making its own rotor blades, tubular towers, generators, gearboxes and control systems, then selling complete turbines to wind-farm developers and utilities. It also earns recurring, annuity-like revenue from long-term operations & maintenance (O&M) contracts on its 21 GW+ installed base across 17 countries. It is India''s largest wind energy solutions provider and a rare example of a vertically integrated Indian-origin equipment manufacturer in the sector.','Suzlon Energy FY26 results coverage (DSIJ, Upstox, Quartr summary of company release); Screener.in; Kotak Neo & Angel One share-price and shareholding data (as of Jul 2026)','The only vertically-integrated Indian-origin wind turbine maker — in-house design, manufacturing and O&M across a 21 GW+ installed base — full-stack control that pure-play developers and import-dependent rivals lack, reinforced by a hard-won balance-sheet turnaround after near-collapse in 2015.','A capital-goods manufacturer sitting upstream of the wind-power value chain — Suzlon designs and builds the turbines, towers and generators that wind-farm developers (including rivals of Adani Green) then operate for 20+ years, and earns recurring revenue servicing that installed base.','Suzlon''s manufacturing is import-dependent on a few critical inputs, especially rare-earth permanent magnets, which places a Chinese supply-chain risk underneath an otherwise largely domestic Indian manufacturing story.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SUZLON','2026-03-31','order_book_gw',5.9,'GW','Order Book','66% from PSU and commercial & industrial (C&I) customers — the most bankable, highest-visibility segment.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SUZLON','2026-03-31','revenue_growth_pct',54,'%','Revenue Growth (YoY)','FY26 revenue from operations rose to ₹16,679 crore from ₹10,851 crore in FY25.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SUZLON','2026-03-31','ebitda_margin_pct',18.1,'%','EBITDA Margin','Up from 17.1% in FY25 as scale drove operating leverage.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SUZLON','2026-03-31','net_debt_ebitda',-0.79,'x','Net Debt / EBITDA','Negative because Suzlon holds NET CASH of ₹2,384 crore, not net debt — a striking turnaround after 2015''s debt restructuring.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUZLON','2026-03-31','bull','FY26 revenue grew 54% to ₹16,679 crore with EBITDA margin expanding to 18.1% — scale is now translating into both growth and profitability, not just one or the other.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUZLON','2026-03-31','bull','A ₹2,384 crore NET CASH position as of March 2026 is a remarkable turnaround for a company that went through Corporate Debt Restructuring in 2015 — the balance-sheet risk that once defined this stock is largely gone.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUZLON','2026-03-31','bull','Order book of ~5.9 GW, with 66% from PSU and commercial/industrial customers, gives multi-quarter revenue visibility in a domestic wind market targeting 100 GW by 2030.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUZLON','2026-03-31','bear','At a P/E near 25x and P/B over 8x, the market is already pricing in continued high growth — any order-book slowdown would hit the stock hard.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUZLON','2026-03-31','bear','FY26 net profit included a large deferred-tax-asset benefit; core operating profit growth, while strong, is smaller than the headline PAT growth suggests on its own.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SUZLON','2026-03-31','bear','More than 90% of revenue is domestic-India — a slowdown in Indian wind tenders or a policy shift would hit Suzlon far harder than globally diversified equipment peers.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SUZLON','China''s dominance of rare-earth magnets, used in permanent-magnet wind generators, is a direct input-supply risk if export curbs tighten','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SUZLON','India crossed 50 GW of installed wind capacity and targets 100 GW by 2030 — a structural multi-year demand tailwind for domestic turbine makers','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SUZLON','PSU and C&I customers now make up 66% of the order book, a shift toward more bankable buyers than merchant/private developers alone','tailwind',TRUE);
