INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('SUZLON',11.7,'Tanti family (Vinod R. Tanti — Chairman, Girish R. Tanti — Executive Vice Chairman), via Tanti Holdings, Samanvaya Holdings and family trusts','0% promoter pledge — a deliberate marker of the post-2015 balance-sheet turnaround, when pledging was a major overhang on the stock.','No dividend paid despite a return to strong profitability; the FY26 net cash position of ₹2,384 crore is being retained to fund capacity scale-up and the S144 turbine platform ramp rather than distributed to shareholders.','Mar 2026','Screener.in; Kotak Neo shareholding data; company filings');
