INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('WAAREEENER','Waaree Energies','NSE','Renewable Energy','Solar Module Manufacturing','Renewable Energy','Waaree Energies manufactures solar photovoltaic modules — buying or making the raw ingots, wafers and cells, assembling them into panels, and selling them to project developers, utilities, and retail rooftop customers. It is India''s largest solar module manufacturer and the largest non-Chinese manufacturer globally, and is increasingly integrating backward into polysilicon, ingots, wafers, battery storage and even green hydrogen to capture more of the value chain than a pure module assembler.','Waaree Energies FY26 & Q4 FY26 results coverage (SaurEnergy, Mercom India, SolarQuarter, ChartAlert analysis of company filings); Screener.in; Kotak Neo shareholding data','Scale and backward integration — as the largest non-Chinese solar module manufacturer with an expanding in-house supply chain from ingots to modules to batteries, Waaree captures margin at multiple stages that pure assemblers or import-dependent rivals cannot.','Sits upstream in the solar value chain as a manufacturer — Waaree makes the ingots, wafers, cells and modules that project developers like Adani Green then buy and install, and is now integrating even further upstream into polysilicon sourcing and battery storage.','Waaree''s strategy is explicitly to control more of this chain rather than just sell modules — recent moves into PV glass, transformers, battery cells and green hydrogen electrolysers aim to capture value at multiple stages rather than compete purely on module price.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('WAAREEENER','2026-03-31','module_capacity_gw',26,'GW','Module Manufacturing Capacity','Largest non-Chinese solar module manufacturer globally.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('WAAREEENER','2026-03-31','order_book_cr',53000,'crore','Order Book','Backed by a bidding pipeline exceeding 100 GW.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('WAAREEENER','2026-03-31','revenue_growth_pct',83.7,'%','Revenue Growth (YoY)','FY26 revenue rose to ₹26,537 crore from ₹14,445 crore in FY25.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('WAAREEENER','2026-03-31','ebitda_margin_pct',22.3,'%','Operating EBITDA Margin','Operating EBITDA of ₹5,909 crore on ₹26,537 crore revenue; margin expanded even at higher volume.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WAAREEENER','2026-03-31','bull','FY26 revenue more than doubled effectively — up 83.7% to ₹26,537 crore — while PAT grew even faster at 101.4% to ₹3,884 crore, meaning profitability scaled faster than the topline itself.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WAAREEENER','2026-03-31','bull','Order book of ~₹53,000 crore against a pipeline exceeding 100 GW gives multi-year revenue visibility, and Waaree is the largest non-Chinese solar module manufacturer globally at ~26 GW capacity.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WAAREEENER','2026-03-31','bull','Backward integration into ingots, wafers, PV glass, batteries and a US manufacturing base (Brookings, South Dakota) reduces reliance on any single input or market, and the company pays a real dividend (₹4/share FY26) unlike most high-growth sector peers.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WAAREEENER','2026-03-31','bear','Free cash flow was deeply negative in FY26 — inventory and receivables grew faster than profits, meaning P&L strength hasn''t yet been matched by cash generation; this working-capital cycle is the key swing factor for FY27.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WAAREEENER','2026-03-31','bear','Q4 FY26 margins showed signs of moderation even as revenue doubled, and depreciation nearly tripled (₹402 crore to ₹990 crore) as the aggressive capacity build-out weighs on the balance sheet.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('WAAREEENER','2026-03-31','bear','A significant share of revenue comes from US exports, and the company was recently examined by US Customs over anti-circumvention allegations (cleared, per the company) — a reminder that trade-policy risk sits directly on top of the growth story.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('WAAREEENER','India''s ALMM (Approved List of Models and Manufacturers) policy mandates domestically-approved modules for many government and subsidised solar projects, a direct tailwind for local manufacturers over Chinese imports','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('WAAREEENER','US Customs recently examined Waaree over anti-circumvention allegations tied to Chinese-origin solar inputs; the company reports no broad evasion was found, but US trade policy remains a live risk given how much revenue comes from American exports','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('WAAREEENER','India added nearly 45 GW of new solar capacity in FY26 alone, an 87% jump over FY25, a structural demand tailwind for domestic module manufacturers','tailwind',TRUE);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('WAAREEENER','upstream','Polysilicon & wafer suppliers, incl. new Oman-based stake (United Solar Holding)',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('WAAREEENER','upstream','Steel, glass & aluminium framing inputs',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('WAAREEENER','upstream','In-house ingot-wafer capacity (10 GW Nagpur facility under construction)','tailwind','reduces reliance on external wafer suppliers as it ramps');
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('WAAREEENER','downstream','Utility-scale developers & IPPs, incl. peers like Adani Green',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('WAAREEENER','downstream','Retail / B2C rooftop solar buyers','tailwind','20.8% of FY26 revenue — a higher-margin channel than pure utility supply');
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('WAAREEENER','downstream','US & overseas export customers','risk','33% of FY26 revenue is overseas; exposed to US trade/anti-dumping policy shifts');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('WAAREEENER',64.2,'Doshi family (Hitesh Chimanlal Doshi — Chairman & Managing Director — and family), consolidated under individual promoter holdings since a June 2025 intra-group restructuring','No promoter pledge flagged in available shareholding trackers.','Paid a final dividend of ₹2/share (₹4/share total for FY26) despite being in a heavy capex phase, and has board approval to raise up to ₹10,000 crore via QIP or other eligible securities to fund continued backward-integration investment.','Mar 2026','Kotak Neo shareholding data; company regulatory filings (Reg 10(1)(g) promoter consolidation, Jun 2025); Q4 FY26 results release');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,status) VALUES ('WAAREEENER','2026-03-31','market_cap_cr',82831,'crore','Market Capitalisation','verified');
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('NTPCGREEN','NTPC Green Energy','NSE','Renewable Energy','Solar & Wind IPP (PSU-backed)','Renewable Energy','NTPC Green Energy is the renewable energy arm of NTPC Limited, India''s largest power generator and a state-owned Maharatna company. It develops, builds and operates utility-scale solar and wind power plants, selling electricity under long-term contracts to state distribution companies and other buyers — the same basic generator model as Adani Green, but built on its parent''s government backing, credit rating and access to low-cost capital rather than aggressive private leverage.','NTPC Green Energy FY26 & Q4 FY26 results coverage (MarketsMojo, SaurEnergy, Kotak Neo); Screener.in; NTPC Green Energy investor relations (ngel.in)','Government ownership itself is the moat here — 89% NTPC backing gives access to land, financing and tender pipelines that private renewable developers must compete for on commercial terms alone.','An upstream power generator, structurally identical to Adani Green — it builds and owns solar and wind plants and sells electricity under long-term contracts — but sitting inside a state-owned parent''s balance sheet and credit profile rather than standing alone as a private developer.','Being majority-owned by NTPC gives it privileged access to NTPC''s existing land banks, transmission relationships and government tender pipelines, a structural advantage private-sector peers must build from scratch.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('NTPCGREEN','2026-03-31','operating_capacity_mw',10671,'MW','Operating Capacity (Group)','As of mid-2026, includes joint ventures such as ONGC NTPC Green.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('NTPCGREEN','2026-03-31','revenue_growth_pct',29.4,'%','Revenue Growth (YoY)','FY26 revenue rose to ₹2,858 crore from ₹2,209 crore in FY25.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('NTPCGREEN','2026-03-31','net_debt_ebitda',4.65,'x','Net Debt / EBITDA','Moderate versus Adani Green''s ~11x, but rising fast as the group borrows to fund its 60 GW-by-2032 target.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('NTPCGREEN','2026-03-31','roe_pct',3.24,'%','Return on Equity','Genuinely weak for a company trading near 150x earnings — growth has outpaced capital efficiency so far.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPCGREEN','2026-03-31','bull','Backed by NTPC Ltd. (a Maharatna CPSE) which owns ~89% of the company, giving access to government-linked project pipelines, cheaper financing, and credibility to win large PSU-anchored tenders private developers can''t easily match.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPCGREEN','2026-03-31','bull','FY26 revenue grew to ₹2,858 crore and Q4 revenue hit a record ₹913 crore (+46.7% YoY), with the company already the largest by market capitalisation in the power sector.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPCGREEN','2026-03-31','bull','Part of NTPC group''s 60 GW renewable-by-2032 target, with a 30 GW project pipeline and new joint ventures (including with ONGC and a data-centre-focused tie-up with CtrlS) extending its addressable market.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPCGREEN','2026-03-31','bear','Return on equity of just 3.24% is weak by any standard, and at a P/E north of 150x, the stock is priced for a growth story that current capital efficiency doesn''t yet support.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPCGREEN','2026-03-31','bear','Debt-funded expansion is accelerating faster than earnings: non-current borrowings jumped from ₹17,301 crore to ₹28,637 crore in a single year, pushing the debt-to-equity ratio from 0.97 to 1.54.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NTPCGREEN','2026-03-31','bear','Interest coverage of just 1.49x leaves little cushion — rising interest costs (up 45.6% YoY in Q4 alone) are already eating into the operating profit that revenue growth is generating.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NTPCGREEN','NTPC group''s 60 GW renewable-by-2032 target and a 30 GW project pipeline give multi-year policy-backed growth visibility','tailwind',TRUE);
