INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('DLF','DLF','NSE','Realty','Residential & Commercial Real Estate Developer','Realty','DLF develops and sells residential real estate — from mass housing to super-luxury towers — and separately leases commercial office space, retail malls and hospitality assets for recurring rental income. It earns large, lumpy cash inflows when residential projects are sold and completed, plus steadier annuity income from long-term leases, and is India''s largest private real estate developer by scale and land bank.','DLF FY26 & Q4 FY26 results coverage (Zeebiz, InvestyWise); Screener.in; Kotak Neo & IndiaInfoline shareholding/market cap data','A multi-decade land bank across Gurugram and other NCR micro-markets, built up since the 1970s, combined with a premium brand (DLF Camellias, Privana, Dahlias) that commands pricing power new entrants cannot easily replicate.','A real estate developer sitting between land and the end buyer or tenant — DLF acquires land, builds residential and commercial projects, then either sells units outright (development business) or leases office and retail space for recurring rental income (annuity business).','Unlike an industrial company, DLF''s core ''input'' is land itself — its decades-accumulated land bank in Gurugram and other NCR locations is arguably a bigger competitive asset than any single project, since new entrants cannot easily replicate a multi-decade land position.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DLF','2026-03-31','new_sales_bookings_cr',20143,'crore','New Sales Bookings','Met FY26 guidance of ₹20,000 crore, though down ~5% YoY.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DLF','2026-03-31','revenue_growth_pct',13.1,'%','Revenue Growth (YoY)','FY26 revenue rose to ₹10,174 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DLF','2026-03-31','ebitda_margin_pct',30.2,'%','EBITDA Margin','EBITDA of ₹3,070 crore on ₹10,174 crore revenue.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DLF','2026-03-31','roe_pct',9.37,'%','Return on Equity','Modest for a stock trading near 40x earnings.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DLF','2026-03-31','bull','FY26 net profit grew 16% to ₹4,256 crore, sales bookings met the ₹20,000 crore guidance at ₹20,143 crore, and the development business now carries zero gross debt with a net cash surplus — a striking balance-sheet position for a real-estate developer.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DLF','2026-03-31','bull','The annuity business (leased offices, malls, hospitality) gives DLF a second, steadier income stream on top of the lumpy, cyclical project-sales business, insulating it somewhat from housing-market swings.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DLF','2026-03-31','bull','Super-luxury launches like Dahlias generated ₹3,967 crore of bookings in a single quarter, showing DLF can command premium pricing in India''s high-end residential upcycle.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DLF','2026-03-31','bear','Q4 alone told a weaker story: EBITDA fell 42.3% YoY and margin contracted to 28.2% from 31.3%, missing analyst estimates on revenue, EBITDA and margin all at once.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DLF','2026-03-31','bear','Full-year sales bookings actually declined about 5% YoY even though they met guidance — growth has plateaued rather than accelerated.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DLF','2026-03-31','bear','Return on equity of just 9.37% is modest for a company trading near 40x earnings — the market is paying a growth premium that recent bookings data hasn''t clearly justified.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DLF','India''s premium and luxury housing upcycle continues to support pricing power for large developers with strong brands, evident in Dahlias'' ₹3,967 crore in single-quarter bookings','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DLF','A zero gross-debt development business gives DLF unusual insulation from interest-rate cycles that hurt more leveraged real estate peers','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DLF','Q4 FY26''s sharp margin contraction (31.3% to 28.2%) shows real estate earnings remain lumpy and execution-dependent quarter to quarter, unlike steadier annuity businesses','risk',TRUE);
