INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('LICI','Life Insurance Corporation','NSE','Insurance','Life Insurance (PSU)','Insurance','Life Insurance Corporation of India collects premiums from policyholders across individual and group life insurance, pension, health and annuity products, invests the pooled money across India''s capital markets, and pays out claims, maturities and bonuses from the investment returns and premium income. It is India''s largest life insurer by a wide margin and one of the largest institutional investors in the Indian stock market.','LIC FY26 results release (licindia.in via Sujatawde coverage); Screener.in; Tickertape','Unmatched scale and distribution reach built over nearly 70 years — India''s largest life insurer by a wide margin, with a brand recognized by nearly 200 million policyholders that no private insurer, however well-capitalized, can replicate quickly.','LIC sits at the center of India''s life insurance value chain — it collects premiums from nearly 200 million policyholders, invests that pooled capital (AUM of ₹57.29 lakh crore) across bonds, equities and government securities, and pays out claims, maturities and bonuses from the returns, keeping the spread as profit.','Because LIC''s investment book is so enormous, it is also one of the largest single shareholders in the Indian stock market itself — its buying and selling decisions can meaningfully move prices in the very market it operates in, a scale advantage (and systemic-risk factor) no private insurer has.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LICI','2026-03-31','premium_income_cr',535984,'crore','Total Premium Income','Up 9.80% YoY.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LICI','2026-03-31','market_share_pct',56.66,'%','New Business Premium Market Share','By First Year Premium Income (IRDAI); down slightly from 57.05% in FY25 as private insurers gain share.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LICI','2026-03-31','vnb_margin_pct',21,'%','VNB Margin','Value of New Business grew 41.63% to ₹14,179 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LICI','2026-03-31','solvency_ratio',2.35,'x','Solvency Ratio','Regulatory minimum is 1.50x; LIC carries a healthy buffer, up from 2.11x.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LICI','2026-03-31','bull','FY26 net profit grew 19.25% to ₹57,419 crore on Total Premium Income of ₹5,35,984 crore, and remains India''s overwhelming market leader with 56.66% share of new business premium — more than the rest of the industry''s private insurers combined.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LICI','2026-03-31','bull','Value of New Business (VNB) grew 41.63% to ₹14,179 crore with margin above 21%, and the Non-Par product share rose sharply to 35.11% from 27.69% — the mix is shifting toward higher-margin products, not just growing in volume.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LICI','2026-03-31','bull','Trading at a trailing P/E near 9.5x against an ROE near 40%+, LIC is priced far cheaper than most large-cap financials despite a solvency ratio that improved to 2.35 from 2.11, comfortably above the regulatory minimum.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LICI','2026-03-31','bear','Persistency ratios — how many policyholders keep paying premiums over time — slipped slightly (13th month 67.77% vs 68.62%, 61st month 54.13% vs 58.54%), a real quality signal worth watching even amid strong headline growth.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LICI','2026-03-31','bear','Market share in new business premium edged down from 57.05% to 56.66% as private insurers continue to chip away at LIC''s historic dominance, particularly in higher-margin non-par and ULIP products.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LICI','2026-03-31','bear','The Government of India holds 96.5% of the company and media reports point to a possible further stake sale — any large secondary share sale could pressure the stock regardless of underlying business performance.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LICI','Private insurers continue to gain share in higher-margin non-par and ULIP products, slowly eroding LIC''s historic market dominance even as LIC''s absolute premium income keeps growing','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LICI','A reported government plan to sell a further stake (potentially raising ~₹10,000 crore) could increase share supply and pressure the stock independent of business performance','risk',TRUE);
