INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('PIDILITIND','Pidilite Industries','NSE','Chemicals','Specialty Chemicals & Adhesives','Chemicals','Pidilite Industries manufactures and sells adhesives, sealants, waterproofing compounds and construction chemicals under well-known consumer brands (Fevicol, Dr. Fixit, M-Seal, Fevikwik), selling both to individual consumers and small contractors through hardware retail (Consumer & Bazaar) and to larger industrial and project customers (Business-to-Business). It converts petrochemical inputs into higher-margin branded products, capturing much more value than a commodity chemicals maker.','Pidilite FY26 & Q4 FY26 results coverage (Angel One, ScanX, Bajaj Broking, MarketsMojo); Screener.in','Brand equity built over decades — ''Fevicol'' is used generically in India the way ''Xerox'' once was for photocopying — giving Pidilite pricing power and shelf preference that new entrants cannot buy their way into quickly.','Pidilite sits downstream of petrochemical input suppliers (vinyl acetate monomer and other crude derivatives) and upstream of the hardware stores, contractors, retailers and industrial customers who buy its adhesives, sealants and construction chemicals — a classic branded-consumer-goods position layered on top of a chemicals manufacturing base.','Because its key raw materials are crude-oil derivatives, Pidilite''s margins are structurally linked to the same crude price cycle that affects fuel and petrochemical companies elsewhere in this dataset, even though its end products look nothing like fuel.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('PIDILITIND','2026-03-31','revenue_growth_pct',11.8,'%','Revenue Growth (YoY)','FY26 consolidated revenue reached ₹14,601 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('PIDILITIND','2026-03-31','ebitda_margin_pct',24.2,'%','EBITDA Margin','Up ~120 bps YoY on lower input costs.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('PIDILITIND','2026-03-31','volume_growth_pct',11.1,'%','Underlying Volume Growth','Double-digit growth across both Consumer & Bazaar and B2B segments.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('PIDILITIND','2026-03-31','working_capital_days',116,'days','Working Capital Days','Up sharply from 51.2 days a year earlier — the clearest red flag in an otherwise strong year.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PIDILITIND','2026-03-31','bull','FY26 revenue grew 11.8% to ₹14,601 crore with EBITDA margin expanding to 24.2%, and Q4 alone saw PAT jump 36.6% — profit growing meaningfully faster than sales as input costs eased.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PIDILITIND','2026-03-31','bull','Iconic, hard-to-displace consumer brands (Fevicol, Dr. Fixit, M-Seal, Fevikwik) give Pidilite pricing power that generic adhesive and chemical makers lack, evident in a payout ratio of 70.2% — the business generates more cash than it needs to reinvest.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PIDILITIND','2026-03-31','bull','Double-digit volume growth across both the Consumer & Bazaar and Business-to-Business segments shows demand strength isn''t concentrated in one channel or product line.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PIDILITIND','2026-03-31','bear','Working capital days jumped from 51.2 to 116 — more than doubling — a real deterioration in how quickly the company converts sales into cash, even as the income statement looks strong.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PIDILITIND','2026-03-31','bear','Margins benefited significantly from lower vinyl acetate monomer and crude-linked input costs this year; a reversal in those raw material prices would directly compress the margin expansion investors are currently rewarding.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PIDILITIND','2026-03-31','bear','At roughly 62–66x trailing earnings, the stock prices in continued flawless execution, leaving little room for a miss even though B2B export volumes actually declined amid Middle East-related disruption.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PIDILITIND','Vinyl acetate monomer and other crude-linked input costs eased in FY26, directly driving margin expansion — a reversal would compress margins just as directly','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PIDILITIND','Export demand in the B2B segment was hit by Middle East conflict disruption even as domestic project demand stayed strong','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PIDILITIND','India''s construction and real estate upcycle is a direct tailwind for Pidilite''s waterproofing (Dr. Fixit) and tile-fixing product lines','tailwind',TRUE);
