INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('PIDILITIND','downstream','Hardware stores, dealers & retail distribution (Consumer & Bazaar)',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('PIDILITIND','downstream','Contractors, builders & industrial B2B customers','tailwind','double-digit domestic volume growth in FY26');
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('PIDILITIND','downstream','Export markets','risk','B2B export volumes declined amid Middle East-linked disruption');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('PIDILITIND',69.32,'Parekh family, via entities including Triveni Corporations, J. Ben & Co. and Pbs Business Corporation','No pledge reported; promoter holding essentially stable quarter over quarter.','Proposed a final dividend of ₹11.5/share on top of an earlier special interim dividend of ₹5/share (post a bonus issue adjustment), taking the total FY26 payout ratio to 70.2% — a mature, cash-generative business returning capital rather than chasing growth via leverage.','Mar 2026','MarketsMojo shareholding detail; Screener.in; company Q4 FY26 results release');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,status) VALUES ('PIDILITIND','2026-03-31','market_cap_cr',160819,'crore','Market Capitalisation','verified');
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('BPCL','Bharat Petroleum','NSE','Oil & Gas','Oil Marketing & Refining (PSU)','Oil & Gas','Bharat Petroleum Corporation refines crude oil into petrol, diesel, LPG, aviation turbine fuel and other products, then sells them through its own retail network, alongside a smaller exploration & production business. As a government-controlled Maharatna PSU, it is one of India''s three dominant oil marketing companies, with earnings driven mainly by refining margins (the spread between crude cost and refined product prices) and steady domestic fuel demand growth.','BPCL FY26 & Q4 FY26 results coverage (Groww, PSU Connect, Upstox); Screener.in; BPCL Q4 FY26 earnings call transcript; ScanX SEBI filing coverage','A Maharatna PSU with an extensive, hard-to-replicate retail fuel network across India, integrated refining capacity, and government backing — scale and distribution reach that would take a private competitor decades and enormous capital to build from scratch.','BPCL sits in the middle of the oil value chain — downstream of crude oil producers like ONGC, it refines crude into petrol, diesel, LPG and other fuels, then sells them onward through its own retail network, distinguishing it from purely upstream companies that only extract crude.','Because crude oil is priced globally in dollars while BPCL sells fuel domestically in rupees at government-influenced prices, the company sits at the exact point where global crude volatility and Indian currency and policy risk intersect — a structurally different exposure than a pure producer or a pure retailer would have.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BPCL','2026-03-31','revenue_growth_pct',4.46,'%','Revenue Growth (YoY)','FY26 consolidated revenue reached ₹5,22,820 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BPCL','2026-03-31','pat_growth_pct',93.78,'%','PAT Growth (YoY)','Net profit nearly doubled to ₹25,843 crore on stronger refining margins.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BPCL','2026-03-31','grm_usd_bbl',11.74,'$/bbl','Gross Refining Margin','More than double FY25''s much weaker margin environment.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BPCL','2026-03-31','refinery_utilization_pct',116,'%','Refinery Utilisation','Highest-ever throughput of 41.15 MMT for the year.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BPCL','2026-03-31','bull','FY26 consolidated PAT nearly doubled, up 93.78% YoY to ₹25,843 crore, as gross refining margins recovered sharply to $11.74/barrel from a much weaker prior year, alongside record refinery throughput of 41.15 MMT at 116% utilisation.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BPCL','2026-03-31','bull','Domestic fuel demand kept growing across the board — petrol +5.7%, diesel +1%, ATF +11.4%, and CNG sales surged 62.1% — showing volume growth well beyond just a margin-driven profit story.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BPCL','2026-03-31','bull','At a trailing P/E near 5x with an ROE near 28%, BPCL trades at a steep discount to the broader market despite genuinely strong FY26 execution and continued government backing as a Maharatna PSU.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BPCL','2026-03-31','bear','Refining margins are a volatile, largely externally-determined number — the same $11.74/barrel GRM that nearly doubled profit this year can just as easily collapse in a weaker global refining environment, as FY25''s much lower margins already showed.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BPCL','2026-03-31','bear','The Exploration & Production segment (via subsidiary BPRL, including the Mozambique LNG project) remains loss-making, though the loss narrowed as a force-majeure situation resolved — a reminder that not every part of the business is profitable yet.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BPCL','2026-03-31','bear','As a PSU oil marketing company, BPCL''s retail fuel pricing and subsidy exposure are ultimately subject to government policy, not pure market economics — a structural risk private-sector peers don''t carry.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BPCL','Gross refining margins are directly exposed to global crude price volatility and West Asia geopolitical tensions, which nearly doubled FY26 profit but could just as easily reverse','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BPCL','CNG sales volume grew 62.1% YoY, tracking India''s broader shift toward gas-based and cleaner transport fuels','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BPCL','As a Maharatna PSU, BPCL''s retail fuel pricing carries government policy influence that private refiners don''t face, cutting both ways as a stability factor and a constraint','neutral',TRUE);
