INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('ABB','ABB India','NSE','Capital Goods','Industrial Automation & Electrification (MNC)','Capital Goods','ABB India manufactures and sells industrial automation, electrification, motion control and robotics products and systems — the equipment and software that runs factories, power grids, data centres and infrastructure projects. It operates as the Indian listed subsidiary of Swiss-headquartered ABB Group, combining global engineering technology with local manufacturing and service.','ABB India Q4/CY25 results coverage (ICICI Direct, Motilal Oswal, Upstox, Whalesbook, Samco); Screener.in','Decades of ABB Group''s global engineering technology, brand trust with large industrial and utility customers, and an integrated local ecosystem of manufacturing, service and support that new entrants cannot replicate quickly, even as competitive intensity from Chinese suppliers grows.','ABB India sits in the middle of the industrial value chain as a technology and equipment supplier — it manufactures and sells automation, electrification and motion products and systems to industrial, infrastructure, utility and data-centre customers, who then use that equipment to run their own factories, grids and facilities.','As a majority-owned subsidiary of Swiss-headquartered ABB Group, its product roadmap, technology transfer and even strategic decisions about specific business lines (like the recent robotics divestment question) flow from group-level decisions made outside India.','CY25 (calendar year ended 31 Dec 2025)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ABB','2026-03-31','revenue_growth_pct',8,'%','Revenue Growth (CY25)','CY25 revenue reached a record ₹13,203 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ABB','2026-03-31','order_inflow_growth_pct',52,'%','Order Inflow Growth (Q4 YoY)','Highest Q4 order intake in five years, at ₹4,096 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ABB','2026-03-31','ebitda_margin_pct',15.5,'%','EBITDA Margin (Q4 CY25)','Contracted from ~17.2–19% a year earlier on higher imported material costs.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ABB','2026-03-31','order_book_to_revenue',0.77,'x','Order Backlog / Revenue','Backlog of ₹10,470 crore as of Dec''25, providing under a year of revenue visibility.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ABB','2026-03-31','bull','Q4 CY25 order inflow surged 52% YoY to ₹4,096 crore — the strongest Q4 order intake in five years — with a large data centre order now representing 10-11% of the total order book, tapping directly into India''s AI infrastructure buildout.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ABB','2026-03-31','bull','CY25 revenue hit a record ₹13,203 crore (+8% YoY), with export revenue growing across all major divisions and strategic focus on 23 high-growth segments including renewables, electronics, and grid modernisation.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ABB','2026-03-31','bull','Backed by decades of ABB Group''s global technology and an integrated ecosystem, the company is positioned to benefit from an anticipated resurgence in India''s private capex cycle in 2026.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ABB','2026-03-31','bear','Q4 CY25 net profit fell 18.08% YoY to ₹432.85 crore even as revenue grew, with EBITDA margin contracting roughly 230-400 basis points on higher imported raw material costs tied to new Quality Control Order (QCO) localisation rules.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ABB','2026-03-31','bear','Material costs rose to 61% of revenue from 58% a year earlier as the company was forced to import more components during a QCO compliance transition period extending into September 2026 — a self-inflicted near-term cost headwind from a policy meant to help domestic manufacturers.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ABB','2026-03-31','bear','At a P/E near 53-57x, the stock prices in a clean recovery story, but intensifying Chinese competition in the Electrification and Motion segments and ABB Group''s global divestment of its Robotics business add real uncertainty.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ABB','India''s new Quality Control Order (QCO) mandates BIS-tested localisation for many components, and limited domestic testing lab capacity has forced ABB to rely on costlier imports during the compliance transition through September 2026','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ABB','Rising data centre capex in India is generating large orders — now roughly 10-11% of ABB''s order book — directly tied to the AI infrastructure buildout','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ABB','Intensifying Chinese competition in the Electrification and Motion segments is pressuring pricing power that ABB previously enjoyed','risk',TRUE);
