INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('ABB','downstream','Data centre operators','tailwind','large data-centre orders now ~10-11% of the order book');
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('ABB','downstream','Export markets, incl. group-company preference for India-made exports',NULL,NULL);
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('ABB',75.0,'ABB Group (Switzerland), the global parent','No pledge — promoter is a listed multinational''s Indian subsidiary structure, not a family or individual holding.','Board recommended a final dividend of ₹29.95/share; the company continues to reinvest in expanding across 23 target segments while managing near-term margin pressure from input costs.','Dec 2025','Screener.in; ICICI Direct & Motilal Oswal Q4 CY25 result reviews; Upstox coverage');
