INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('SIEMENS','Siemens','NSE','Capital Goods','Industrial Automation & Smart Infrastructure (MNC)','Capital Goods','Siemens India provides intelligent infrastructure technology for buildings and decentralised energy systems, automation and digitalisation software for process and manufacturing industries, and smart mobility solutions for rail and road transport. Following the FY26 demerger of its Energy business into separately-listed Siemens Energy India, the company is now more narrowly focused on Smart Infrastructure, Digital Industries and Mobility.','Siemens Ltd FY26/Q2 FY26 results coverage (MarketsMojo, Univest); Screener.in','Global Siemens engineering and brand trust across decades of infrastructure and industrial projects, combined with deep relationships with anchor customers like Power Grid and Indian Railways that a new entrant could not win quickly.','Siemens India sells intelligent infrastructure, automation and mobility technology to industrial, infrastructure and transport customers — buildings, factories, rail networks and utilities all run partly on Siemens equipment, software and systems, positioning it as a technology supplier rather than an end-product maker.','The FY26 demerger of its Energy business into a separately-listed entity (Siemens Energy India) means the remaining company is now more narrowly focused on Smart Infrastructure, Digital Industries and Mobility — a structurally different, smaller business than the one reflected in most pre-2026 historical comparisons.','FY26 (TTM basis, post-demerger)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SIEMENS','2026-03-31','revenue_cr',24846,'crore','Revenue (TTM)','Post the FY26 demerger of the Energy business into separately-listed Siemens Energy India.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SIEMENS','2026-03-31','ebitda_margin_pct',11.93,'%','Operating Margin','Down from 15.34% over six quarters, coinciding with the FY26 Energy business demerger.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SIEMENS','2026-03-31','roe_pct',12.96,'%','Return on Equity','Trails peer average; capital efficiency has been diluted post-demerger.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SIEMENS','2026-03-31','working_capital_days',67.6,'days','Working Capital Days','Up from 41.9 days — a genuine cash-conversion concern echoing a pattern seen at other capital goods peers.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SIEMENS','2026-03-31','bull','Q2 FY26 revenue reached a record ₹5,171 crore on strong order execution across infrastructure and industrial segments, with order intake climbing 18% on a comparable basis and record levels across most divisions.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SIEMENS','2026-03-31','bull','The German parent dramatically consolidated its promoter stake to 75% (from a fragmented ~6.67% base) during the FY26 Energy business demerger, signalling long-term strategic commitment to the Indian subsidiary even as the corporate structure was reorganised.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SIEMENS','2026-03-31','bull','Siemens India sits at the intersection of India''s biggest capex themes — infrastructure, energy transition, digitalisation and urbanisation — with key clients including Power Grid, Indian Railways, data centre operators and state DISCOMs.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SIEMENS','2026-03-31','bear','Operating margins compressed sharply from 15.34% to 11.93% over six quarters, and Q2 FY26 net profit fell 41.63% YoY even as revenue grew — a genuine disconnect between topline momentum and bottom-line delivery.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SIEMENS','2026-03-31','bear','Working capital days nearly doubled from 41.9 to 67.6, signalling slower cash conversion despite reported revenue strength.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SIEMENS','2026-03-31','bear','The FY26 demerger of the Energy business into separately-listed Siemens Energy India makes year-over-year comparisons genuinely difficult — investors are effectively underwriting a smaller, restructured company at a premium valuation built on pre-demerger growth assumptions.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SIEMENS','India''s approximately ₹11 lakh crore infrastructure budget is directly driving electrification, automation and metro rail order flow for Siemens India','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SIEMENS','Data centre capex growth is generating switchgear and energy management orders, tapping the same AI infrastructure boom benefiting peers like ABB','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SIEMENS','The FY26 Energy business demerger into Siemens Energy India has temporarily clouded margin and growth comparisons, adding real near-term analytical uncertainty for investors','risk',TRUE);
