INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('SIEMENS','downstream','Power Grid, state DISCOMs & utility customers',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('SIEMENS','downstream','Indian Railways & metro rail projects','tailwind','India''s infrastructure capex cycle is a direct order-flow driver');
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('SIEMENS','downstream','Data centre & industrial manufacturing customers','tailwind','switchgear and energy management orders tied to the AI infrastructure boom');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('SIEMENS',75.0,'Siemens AG (Germany), via Siemens International Holding B.V., Siemens Aktiengesellschaft and related entities','No pledge; the 75% stake reflects a 2026 consolidation move by the German parent, not encumbrance.','Maintains a healthy dividend payout of around 19.1% and remains almost debt-free, even as working capital efficiency has weakened post-demerger.','2026 (post-demerger)','Screener.in; MarketsMojo Q2 FY26 result analysis; Univest coverage');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,status) VALUES ('SIEMENS','2026-03-31','market_cap_cr',127313,'crore','Market Capitalisation','verified');
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('HAL','Hindustan Aeronautics','NSE','Infra & Capital Goods','Defence Aerospace (PSU)','Defence & Aerospace','Hindustan Aeronautics designs, manufactures, and maintains fighter aircraft (including the indigenous LCA Tejas), helicopters, aircraft engines, and related systems, selling almost exclusively to the Indian Air Force, Navy and other government defence customers. As India''s primary state-owned aerospace manufacturer, its revenue is driven by both new-platform manufacturing and long-term repair, overhaul and maintenance contracts on aircraft already in service.','HAL FY26 & Q4 FY26 results coverage (Drishti earnings call transcript, MarketsMojo); Screener.in; Yahoo Finance','A near-monopoly position as India''s primary military aircraft and helicopter manufacturer, built over decades of exclusive government contracts, deep engineering expertise, and a scale of institutional knowledge that no private competitor could replicate without government backing.','HAL sits at the top of India''s defence aerospace value chain as the primary manufacturer — it designs, builds and maintains fighter aircraft, helicopters, engines and related systems almost exclusively for the Indian armed forces, making it both a supplier and a strategic national-security asset.','Because HAL''s key inputs — like GE engines for the LCA program — are sourced from foreign suppliers, its delivery timelines are structurally exposed to geopolitical and supply chain factors outside India''s control, even though its customer base is almost entirely domestic and government-controlled.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HAL','2026-03-31','revenue_growth_pct',7,'%','Revenue Growth (YoY)','FY26 revenue reached ₹33,050 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HAL','2026-03-31','ebitda_margin_pct',30,'%','EBITDA Margin','Maintained at a healthy 30% despite LCA delivery delays and supply chain pressure.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HAL','2026-03-31','order_book_to_revenue',7.7,'x','Order Book / Revenue','Order book of ₹2,54,538 crore — nearly 8 years of current revenue — provides exceptional visibility.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HAL','2026-03-31','roe_pct',24.71,'%','Return on Equity','Among the highest in the defence sector, trailing only Mazagon Dock.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAL','2026-03-31','bull','Order book swelled to ₹2,54,538 crore — nearly 8 times FY26 revenue — after ₹97,028 crore of fresh orders including 97 LCA Mark-1A aircraft, giving HAL exceptional multi-year revenue visibility rare in any industry.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAL','2026-03-31','bull','FY26 EBITDA grew 11% to ₹13,472 crore while maintaining a healthy 30% margin, and return on equity of 24.71% ranks among the best in the defence sector — trailing only Mazagon Dock.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAL','2026-03-31','bull','Trading at a P/E of roughly 32-33x against a defence sector average near 55x, HAL is priced at a meaningful discount to peers despite comparable or superior fundamentals — a genuine relative-value case.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAL','2026-03-31','bear','LCA Mark-1A deliveries have faced repeated delays, now targeted for August-September 2026, driven partly by GE Aerospace engine supply shortfalls outside HAL''s control — a reminder that even strong order books depend on external supply chains.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAL','2026-03-31','bear','Revenue growth of 7% YoY is modest for a company trading at this valuation, and operating margin actually contracted in Q4 FY26 (36.28% from 38.65%) even as headline profit surged on a large jump in other income.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAL','2026-03-31','bear','HAL''s revenue mix is expected to shift from roughly 30-70 to 50-50 between manufacturing and other work in FY27, a structural change management believes it can navigate — but which adds execution uncertainty to the growth story.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HAL','LCA Mark-1A deliveries are delayed to August-September 2026 partly due to GE Aerospace engine supply shortfalls, highlighting HAL''s dependence on foreign critical components despite its otherwise indigenous manufacturing story','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HAL','A record ₹2,54,538 crore order book, including 97 LCA Mark-1A jets and new engine and satellite-launch programs, reflects sustained government defence capex and India''s push for self-reliance in aerospace manufacturing','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HAL','Planned investment of ~₹12,000 crore by 2030 in LCA Mark-II, GE-414 engines, IMRH engines and SSLV manufacturing infrastructure signals a structural expansion of India''s indigenous defence manufacturing base','tailwind',TRUE);
