INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('MAZDOCK','Mazagon Dock Shipbuilders','NSE','Infra & Capital Goods','Defence Shipbuilding (PSU)','Defence & Aerospace','Mazagon Dock Shipbuilders designs, constructs and repairs warships and submarines — including destroyers, stealth frigates, corvettes and submarines — almost exclusively for the Indian Navy and Coast Guard, alongside a smaller and growing commercial shipbuilding and offshore platform business. As India''s largest and oldest warship-building yard (established 1774), it holds a near-monopoly on the country''s most complex naval vessels.','Mazagon Dock FY26 & Q4 FY26 results coverage (Angel One, ChartAlert, Multibagg AI); Screener.in','A near-monopoly on complex naval shipbuilding, particularly submarines, built over 250 years of continuous operation and decades of exclusive Indian Navy contracts — technical and trust barriers that would take a new entrant decades to replicate.','Mazagon Dock sits at the top of India''s naval shipbuilding value chain as the country''s largest warship-building yard — it designs, constructs and maintains destroyers, submarines and frigates almost exclusively for the Indian Navy, with a nascent push into commercial shipbuilding and offshore platforms.','Its near-monopoly position on complex naval platforms like submarines comes from decades of accumulated technical expertise and government-backed contracts — a barrier to entry that protects the business, but also means its fortunes are tightly linked to the pace of government defence procurement decisions like the P-75(I) approval.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('MAZDOCK','2026-03-31','revenue_growth_pct',13.8,'%','Revenue Growth (YoY)','FY26 revenue from operations reached ₹13,006 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('MAZDOCK','2026-03-31','pat_growth_pct',6.8,'%','PAT Growth (YoY)','Profit growth lagged revenue growth — margin compression, particularly a sharp Q4 dip tied to contract-loss provisions.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('MAZDOCK','2026-03-31','order_book_cr',23758,'crore','Order Book','Down sharply from ₹49,700 crore at the end of FY21 — the pending P-75(I) submarine deal (~₹99,000 crore) would reverse this if finalised.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('MAZDOCK','2026-03-31','contingent_liabilities_cr',37852,'crore','Contingent Liabilities','A genuine balance-sheet risk factor flagged by analysts, typical of large multi-year defence contracts.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAZDOCK','2026-03-31','bull','FY26 revenue grew 13.8% to ₹13,006 crore with essentially zero long-term debt and ₹13,097 crore in combined cash and fixed deposits — a fortress balance sheet rare among industrial companies.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAZDOCK','2026-03-31','bull','Contract Negotiation Committee talks for the P-75(I) submarine program (~₹99,000 crore for six stealth AIP submarines with Germany''s TKMS) have been completed and now await government approval — a deal that alone could roughly quadruple the current order book.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAZDOCK','2026-03-31','bull','The company is actively diversifying beyond pure defence dependency, signing a commercial contract with the Shipping Corporation of India for a methanol dual-fuel vessel — its re-entry into commercial shipbuilding.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAZDOCK','2026-03-31','bear','The order book has fallen sharply to ₹23,758 crore as of December 2025, less than half the ₹49,700 crore level at the end of FY21 — the P-75(I) deal is a hoped-for catalyst, not yet a booked order.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAZDOCK','2026-03-31','bear','Q4 FY26 EBITDA margin collapsed to 13.74% from 35.1% in the prior quarter, as the company took provisions on two contracts where management now expects losses — a reminder that shipbuilding margins can swing sharply on project-specific risk.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MAZDOCK','2026-03-31','bear','Receivables spiked 144% year-over-year and contingent liabilities stand at ₹37,852 crore, both worth watching even though the core balance sheet remains fundamentally strong.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MAZDOCK','Contract Negotiation Committee talks for the P-75(I) submarine program (~₹99,000 crore, with Germany''s TKMS) are complete and awaiting government approval — the single largest potential catalyst for the order book in years','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MAZDOCK','Rising regional maritime security concerns, including tensions linked to the Iran-Israel conflict and a naval incident near Sri Lanka, have renewed investor and policy attention on naval shipbuilding capacity','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MAZDOCK','The order book has nearly halved since FY21 even as execution on existing contracts continues, showing that strong delivery alone hasn''t offset slower new-order replenishment','risk',TRUE);
