INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('TATAPOWER','Tata Power','NSE','Power','Diversified Power (Generation, T&D, Renewables, Solar Mfg)','Power','Tata Power operates across nearly every part of India''s electricity value chain: coal-fired power generation (including the Mundra plant), a fast-growing renewable energy portfolio (solar and wind), power transmission and distribution (including the turned-around Odisha DISCOMs), solar cell and module manufacturing (TP Solar), and India''s leading rooftop solar installation business (Solaroof). This diversification is unusual even among large utilities, most of which specialise in just one or two of these segments.','Tata Power FY26 & Q4 FY26 results coverage (company press release, MarketsMojo, PSU Connect); Screener.in','Unmatched diversification across the entire power value chain — generation, transmission, distribution, solar manufacturing and rooftop installation — under the Tata Group''s brand trust and balance sheet backing, giving it resilience that single-segment competitors lack.','Tata Power is India''s most diversified private power company — spanning coal-fired generation (Mundra), renewable generation, power transmission and distribution (including the Odisha DISCOMs it turned around), solar cell and module manufacturing (TP Solar), and rooftop solar installation (Solaroof) — giving it exposure to nearly every link in the electricity value chain at once.','Because Tata Power both manufactures solar equipment AND builds/operates solar plants AND distributes the resulting power, it captures value at multiple stages that a single-purpose generator or pure-play manufacturer cannot — though weakness in any one segment (like Q4''s Mundra regulatory headwind) can still drag on an otherwise strong quarter.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('TATAPOWER','2026-03-31','revenue_cr',62429,'crore','Revenue (FY26)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('TATAPOWER','2026-03-31','renewables_pat_growth_pct',59,'%','Renewables PAT Growth (YoY)','Renewables PAT reached ₹1,994 crore in FY26.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('TATAPOWER','2026-03-31','net_debt_ebitda',5.98,'x','Net Debt / EBITDA','High leverage; interest coverage of just 1.43x leaves limited buffer.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('TATAPOWER','2026-03-31','roe_pct',10.2,'%','Return on Equity','Lags peer averages despite strong renewable and solar manufacturing growth.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATAPOWER','2026-03-31','bull','Renewables PAT grew 59% to ₹1,994 crore and Solar Manufacturing (TP Solar) PAT grew 103% to ₹857 crore in FY26, with industry-leading module/cell yields above 95% — Tata Power is monetising the energy transition across generation, manufacturing and rooftop simultaneously.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATAPOWER','2026-03-31','bull','T&D business PAT rose 49% to ₹2,978 crore and Odisha DISCOMs PAT rose 84% to ₹809 crore, showing the distribution and discom-turnaround businesses are genuinely improving, not just the flashier renewables story.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATAPOWER','2026-03-31','bull','Rooftop Solar (Solaroof) has ranked #1 in India for 11 consecutive years, with FY26 PAT up 150% to ₹499 crore — a high-margin, fast-growing consumer-facing business layered on top of the core utility.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATAPOWER','2026-03-31','bear','Q4 FY26 revenue fell 12.84% YoY and operating margin dropped to a seven-quarter low of 17.44%, driven partly by the Mundra plant losing Section 11 cost-recovery benefits — a reminder that regulatory support, not just execution, drives parts of this business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATAPOWER','2026-03-31','bear','Debt-to-EBITDA of 5.98x and interest coverage of just 1.43x are genuine leverage concerns for a company still funding an 11.6 GW renewable build-out.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TATAPOWER','2026-03-31','bear','Return on equity of just 10.2% and ROCE of 8.0% are weak for a stock trading near 35x earnings — the growth story hasn''t yet translated into best-in-class capital returns.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATAPOWER','The Mundra plant''s loss of Section 11 government cost-recovery benefits in Q4 FY26 directly hit generation segment profitability, showing how regulatory mechanisms still shape parts of even a diversified private utility''s earnings','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATAPOWER','TP Solar''s cell and module manufacturing, with industry-leading yields above 95%, is scaling rapidly to serve both Tata Power''s own renewable build-out and third-party demand for domestically-made solar equipment','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TATAPOWER','Rising competition from pure-play renewable IPPs and manufacturers is a structural pressure on Tata Power''s legacy generation margins even as its own renewable segment grows strongly','risk',TRUE);
