INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('ADANIENSOL','Adani Energy Solutions','NSE','Power','Power Transmission & Distribution','Power','Adani Energy Solutions builds and operates high-voltage power transmission lines and distributes electricity directly to consumers, primarily serving metropolitan Mumbai and the Mundra Special Economic Zone through subsidiary Adani Electricity Mumbai. As India''s largest private transmission company, it earns revenue from regulated transmission tariffs and direct electricity distribution and metering to over 13 million consumers.','Adani Energy Solutions Q4 FY26 results coverage (MarketsMojo); Screener.in; company investor presentation','India''s largest private transmission company, with an extensive high-voltage network (nearly 28,000 circuit kilometres) and regulatory licenses that are difficult and slow for new entrants to obtain, reinforced by its position within the broader Adani energy ecosystem.','Adani Energy Solutions builds and operates the transmission lines and distribution networks that carry electricity from generators — including renewable plants like sister company Adani Green Energy — to end consumers, plus directly distributes power to over 13 million consumers in Mumbai and the Mundra SEZ.','AESL sits at the exact chokepoint that determines whether renewable power actually reaches the market: its own group disclosures acknowledge that Adani Green''s FY26 curtailment losses were partly a function of how fast AESL''s own transmission build-out could keep pace — a direct, quantifiable link between these two related companies.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIENSOL','2026-03-31','revenue_growth_pct',16.76,'%','Revenue Growth (Q4 YoY)','Q4 FY26 net sales of ₹7,443 crore — the highest quarterly figure on record.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIENSOL','2026-03-31','pat_growth_pct',5.66,'%','PAT Growth (Q4 YoY)',NULL,'verified');
