INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENSOL','2026-03-31','bull','Q4 FY26 net sales reached ₹7,443 crore, the highest quarterly figure on record, with a 5-year sales CAGR of 20.62% and EBIT CAGR of 20.08% demonstrating consistent, structural growth in transmission demand.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENSOL','2026-03-31','bull','Promoter stake increased to 72.73%, signalling Adani family alignment with minority shareholders even as some foreign institutional investors have been selling.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENSOL','2026-03-31','bull','As India''s largest private transmission company, AESL is directly positioned to capture the multi-decade build-out needed to connect new renewable capacity (including sister company Adani Green''s projects) to the grid — exemplified by its 6,000 MW Integrated Green Energy Corridor project.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENSOL','2026-03-31','bear','Operating margin compressed sharply to 28.82% in Q4 FY26 from 34.71% the prior quarter and 35.31% a year earlier — a 649 basis point year-over-year decline that raises real questions about cost discipline even as revenue grows.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENSOL','2026-03-31','bear','At roughly 73x trailing earnings — nearly three times the sector average — the stock prices in years of flawless execution, and return on equity of just 10.5% doesn''t yet justify that premium.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIENSOL','2026-03-31','bear','Low interest coverage and continued FII selling, even alongside promoter buying, suggest institutional investors remain divided on whether current valuations reflect the underlying business quality.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIENSOL','AESL''s own transmission build-out pace directly affects how much of sister company Adani Green''s renewable generation can actually reach the grid without curtailment — a concrete example of infrastructure bottlenecks shaping India''s energy transition','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIENSOL','The 6,000 MW Integrated Green Energy Corridor project positions AESL to directly capture India''s multi-decade need for renewable-ready transmission infrastructure','tailwind',TRUE);
