INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('JSWENERGY','JSW Energy','NSE','Power','Power Generation (Thermal + Renewable)','Power','JSW Energy generates electricity from a mix of thermal (coal) and renewable (solar and wind) sources, selling power under long-term power purchase agreements and on the merchant market. Part of the JSW Group, it is aggressively expanding capacity toward a 30 GW target by 2030, combining organic renewable build-out with opportunistic thermal plant acquisitions.','JSW Energy Q4 FY26 results coverage (BusinessToday, brokerage notes via JM Financial & Elara Capital); Screener.in; Groww','Part of the JSW Group''s industrial and infrastructure ecosystem, with a hybrid thermal-plus-renewable generation model and aggressive, well-funded capacity expansion that positions it among India''s largest private power generators by the end of the decade.','JSW Energy generates electricity from both thermal and renewable sources and sells it under long-term power purchase agreements and on the merchant market — a hybrid generator model that, unlike pure renewable IPPs, still carries meaningful coal-based capacity alongside its fast-growing clean energy build-out.','The company''s recent acquisition of Maruti Clean Coal and Power (a 300 MW thermal plant) alongside its 30 GW renewable target shows a deliberate strategy of growing through both organic renewable build and opportunistic thermal M&A, rather than committing exclusively to one path.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('JSWENERGY','2026-03-31','revenue_growth_pct',38,'%','Revenue Growth (Q4 YoY, adjusted)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('JSWENERGY','2026-03-31','ebitda_growth_pct',78,'%','EBITDA Growth (Q4 YoY)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('JSWENERGY','2026-03-31','net_debt_ebitda',6,'x','Net Debt / EBITDA','Improved from 7.8x in FY25 — genuine deleveraging progress, though still elevated.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('JSWENERGY','2026-03-31','pat_growth_pct',-36,'%','Adjusted PAT Growth (Q4 YoY)','Profit fell even as revenue and EBITDA grew sharply, on rising depreciation and interest costs from new capacity.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWENERGY','2026-03-31','bull','Q4 FY26 adjusted revenue grew 38% YoY and EBITDA grew 78% YoY, driven by robust capacity additions and a 48% YoY increase in power sales — genuine operational momentum, not just a base-effect illusion.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWENERGY','2026-03-31','bull','Net Debt/EBITDA improved to 6x in FY26 from 7.8x in FY25, with EBITDA per MW and gross block per MW both improving — real evidence that past capacity investments are starting to pay off.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWENERGY','2026-03-31','bull','The company is confident of reaching its 30 GW by 2030 target, with 13.4 GW already operational, 14 GW under construction and a further 4.6 GW in the pipeline — exceptional forward capacity visibility.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWENERGY','2026-03-31','bear','Adjusted PAT actually fell 36% YoY in Q4 FY26 despite EBITDA growing 78% — rising depreciation and interest costs from the capacity build-out are eating deeply into the bottom line even as operations scale.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWENERGY','2026-03-31','bear','The stock fell 8% on results day despite headline-strong numbers, as brokerages flagged expensive valuation (12.5x EBITDA vs 11.3x historical median) following a sharp prior rally.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JSWENERGY','2026-03-31','bear','Promoter holding declined 2.74% over the last quarter and return on equity remains weak at 7.62% — capital efficiency hasn''t caught up with the scale of investment yet.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JSWENERGY','JSW Energy is part of a group of private players (alongside Adani Power, NTPC and Torrent) planning a combined ₹5.5 lakh crore investment for 50 GW of new capacity, reflecting a structural, sector-wide capacity race','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JSWENERGY','Rising depreciation and interest costs from rapid capacity expansion are compressing profit growth even as revenue and EBITDA scale rapidly — a classic growth-phase margin squeeze','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JSWENERGY','The recent acquisition of Maruti Clean Coal and Power shows continued opportunistic thermal capacity growth even as the long-term target remains overwhelmingly renewable-weighted','neutral',TRUE);
