INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('ADANIPOWER','Adani Power','NSE','Power','Thermal Power Generation (Private)','Power','Adani Power generates electricity primarily from coal-fired thermal plants — led by the 4,620 MW Mundra facility — and sells it under a mix of long-term Power Purchase Agreements with state utilities, shorter-term contracts, and open merchant-market sales. As India''s largest private thermal power producer, it plays a central role in the country''s baseload electricity supply even as the broader system adds renewable capacity.','Adani Power FY26 & Q4 FY26 results release (adani.com); Screener.in; Kotak Neo shareholding data','Scale as India''s largest private thermal power producer, accounting for roughly 7.3% of India''s domestic coal-based power generation capacity, backed by the Adani Group''s execution track record and access to captive and contracted coal supply.','Adani Power burns coal to generate baseload electricity at large thermal plants (led by the 4,620 MW Mundra facility), then sells that power through a mix of long-term Power Purchase Agreements with state utilities, shorter-term contracts, and open merchant-market sales — a classic thermal generator business model.','Because a meaningful share of its output is sold on the merchant market rather than locked into long-term contracts, Adani Power''s earnings are directly exposed to day-ahead power price swings — exactly the kind of swing that cut average realisations 13.7% in FY26 as renewable penetration rose.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIPOWER','2026-03-31','revenue_growth_pct',10,'%','Revenue Growth (Q4 YoY)','Q4 FY26 revenue of ₹15,989 crore.','verified');
