INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIPOWER','2026-03-31','pat_cr',12971,'crore','PAT (FY26)','Broadly flat vs FY25''s ₹12,750 crore; helped by a lower tax provision rather than pure operating growth.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ADANIPOWER','2026-03-31','operating_capacity_gw',17.5,'GW','Operating Capacity','Targeting 30.6 GW by 2030; India''s largest private thermal power producer.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPOWER','2026-03-31','bull','Q4 FY26 PAT grew 64% YoY to ₹4,271 crore on 10% revenue growth and 27% EBITDA growth, with expansion tie-ups now reaching 13.3 GW including a new 1.6 GW long-term PPA awarded by Maharashtra''s DISCOM.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPOWER','2026-03-31','bull','As India''s largest private thermal power producer with 17.5 GW of operating capacity and a target of 30.6 GW by 2030, Adani Power is positioned to capture a large share of India''s continuing baseload power demand even as renewables grow.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPOWER','2026-03-31','bull','All-India power demand growth resumed in Q4 FY26 (+1.6% YoY) after a soft winter, with warmer weather driving renewed offtake — a near-term operational tailwind.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPOWER','2026-03-31','bear','Full-year FY26 EBITDA was essentially flat versus FY25 (₹21,285 crore vs ₹21,575 crore) despite higher operating capacity, as lower merchant power realisations (average IEX price down 13.7% YoY) offset volume gains — growth in assets hasn''t yet translated into growth in core earnings.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPOWER','2026-03-31','bear','Adani Power pays no dividend on its equity shares despite consistent profitability, and screening tools flag potential capitalisation of interest costs — a detail worth understanding since it can make reported profits look stronger than underlying cash generation.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ADANIPOWER','2026-03-31','bear','Rising renewable power penetration is structurally pressuring merchant thermal tariffs, creating a slow-moving headwind for the non-contracted portion of Adani Power''s capacity even as its own PPA-backed volumes stay resilient.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIPOWER','Rising renewable power penetration is structurally compressing merchant market power prices (down 13.7% YoY in FY26), a slow-building headwind for thermal generators'' non-contracted capacity','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIPOWER','All-India power demand growth resumed with the onset of summer in Q4 FY26, reversing a soft winter driven by cold weather and unseasonal rains','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ADANIPOWER','New long-term PPAs, including a 1,600 MW Maharashtra DISCOM award under Design-Build-Finance-Own-Operate terms, provide contracted revenue visibility that insulates part of the portfolio from merchant price volatility','tailwind',TRUE);
