INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('HYUNDAI','Hyundai Motor India','NSE','Auto','Passenger Vehicles (MNC)','Auto','Hyundai Motor India designs, manufactures and sells passenger vehicles — including the Venue, Verna, Exter, Creta and Aura — for both the domestic Indian market and export to emerging markets, as a wholly-owned subsidiary of South Korea''s Hyundai Motor Company. It is India''s second-largest passenger vehicle manufacturer and exporter.','Hyundai Motor India FY26 & Q4 FY26 results coverage (company press release, MarketsMojo, ScanX, InvestyWise); Screener.in; Kotak Neo','Three decades of brand trust in India, a wide dealership and service network, and backing from Hyundai Motor Company''s global platform engineering and design — advantages a new entrant would need many years and enormous capital to replicate.','Hyundai Motor India designs, manufactures and sells passenger vehicles domestically and for export, sourcing components from a large supplier base (including companies like Bosch and Motherson elsewhere in this dataset) and selling through dealership networks — positioning it squarely as an OEM at the consumer-facing end of the automotive value chain.','As a wholly-owned Korean subsidiary, Hyundai India''s capacity decisions (like the new Pune plant) and product roadmap are made with both the Indian market and Hyundai''s global export hub strategy in mind, meaning its growth isn''t purely a bet on domestic demand alone.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HYUNDAI','2026-03-31','revenue_growth_pct',2.3,'%','Revenue Growth (FY26)','FY26 consolidated revenue reached ₹70,763 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HYUNDAI','2026-03-31','ebitda_margin_pct',12.2,'%','EBITDA Margin','Down from 12.9% in FY25.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HYUNDAI','2026-03-31','pat_growth_pct',-3.7,'%','PAT Growth (FY26)','FY26 PAT of ₹5,432 crore vs ₹5,640 crore in FY25.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HYUNDAI','2026-03-31','export_growth_pct',16.4,'%','Export Growth (FY26)','Grew despite acknowledged geopolitical headwinds.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HYUNDAI','2026-03-31','bull','Record Q4 FY26 domestic sales (wholesale volume +8.7% YoY to 208,275 units), highest-ever quarterly and full-year CNG/rural penetration, and 16.4% export growth despite geopolitical headwinds show broad-based demand strength, not just one segment.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HYUNDAI','2026-03-31','bull','Celebrating 30 years in India, the company commenced its Pune plant in FY26 (first product: New Venue, 5-star Bharat NCAP rated), expanding capacity toward 1.14 million units by 2030 — real physical capacity backing the growth guidance.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HYUNDAI','2026-03-31','bull','Zero promoter encumbrance and a stable 82.5% holding from Hyundai Motor Company signal long-term parent commitment, while FY27 guidance targets 8-10% volume growth and margin recovery to 11-14%.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HYUNDAI','2026-03-31','bear','Q4 FY26 operating margin contracted sharply to 10.66% from 14.45% a year earlier — a 379 basis point erosion — driven by vendor compensation, labour code costs, commodity inflation and an unfavourable SUV/export mix.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HYUNDAI','2026-03-31','bear','Net profit fell 22.2% YoY in Q4 FY26 to ₹1,256 crore even as revenue hit a record high, and FY26 full-year PAT was below FY25''s — growth in volume hasn''t yet translated into growth in profit.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HYUNDAI','2026-03-31','bear','Persistent FII selling (down from 7.35% to 5.42% since September 2025) suggests foreign institutional investors remain cautious on near-term earnings trajectory despite management''s optimistic FY27 guidance.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HYUNDAI','GST 2.0 reforms provided a direct demand tailwind in Q4 FY26, contributing to record quarterly domestic sales','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HYUNDAI','Rising input costs, new labour code compliance, and vendor compensation payments compressed margins sharply in Q4 FY26, showing cost-side pressures can outpace even record revenue','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HYUNDAI','Export growth of 16.4% in FY26 came despite acknowledged geopolitical headwinds, positioning India as a resilient hub for Hyundai''s emerging-market export strategy','tailwind',TRUE);
