INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('TVSMOTOR','TVS Motor Company','NSE','Auto','Two-Wheelers','Auto','TVS Motor Company designs, manufactures and sells motorcycles, scooters, mopeds and three-wheelers across ICE, CNG and electric powertrains, selling domestically and to export markets. It is India''s third-largest two-wheeler manufacturer by volume, competing directly with Bajaj Auto, Hero MotoCorp and Eicher Motors'' Royal Enfield.','TVS Motor FY26 & Q4 FY26 results coverage (MarketsMojo, Univest); Screener.in','Nearly a century of brand trust in Indian two- and three-wheelers, a vast dealership and service network, and continuous product innovation across ICE, CNG and EV powertrains that smaller or newer entrants struggle to match at scale.','TVS Motor designs, manufactures and sells two-wheelers and three-wheelers across India and export markets, sourcing components from suppliers and selling through an extensive dealership network — positioning it as an OEM at the consumer end of the two-wheeler value chain, competing directly for market share against Bajaj Auto and Eicher Motors elsewhere in this dataset.','As India''s third-largest two-wheeler manufacturer, TVS''s growth increasingly depends on capturing share in EVs and premium segments rather than just riding overall market growth, since the core commuter segment is mature and highly competitive.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('TVSMOTOR','2026-03-31','revenue_growth_pct',30.42,'%','Revenue Growth (Q4 YoY)','Q4 FY26 net sales of ₹15,053 crore, an all-time high.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('TVSMOTOR','2026-03-31','ebitda_margin_pct',14.53,'%','Operating Margin (Q4 FY26)','Down from 16.63% a year earlier.','verified');
