INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TVSMOTOR','2026-03-31','bull','Q4 FY26 net sales hit an all-time high of ₹15,053 crore, up 30.42% YoY, with FY26 full-year net sales of ₹56,070 crore — broad-based demand strength across the two-wheeler and three-wheeler portfolio.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TVSMOTOR','2026-03-31','bull','Rock-solid 50.27% promoter holding (TVS Holdings, formerly Sundaram Clayton) with zero pledging reflects strong long-term family commitment, and ten-year stock returns exceeding 1,000% demonstrate a genuine track record of value creation.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TVSMOTOR','2026-03-31','bull','Rising EV sales and export expansion give TVS multiple growth vectors beyond the core domestic ICE two-wheeler market, which remains competitive but stable.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TVSMOTOR','2026-03-31','bear','Q4 FY26 operating margin contracted to 14.53% from 16.63% a year earlier, and net profit fell 8.29% sequentially despite revenue growth — the classic sign of rising costs outpacing volume gains.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TVSMOTOR','2026-03-31','bear','Debt-to-equity of 3.24x and debt-to-EBITDA of 4.17x represent real leverage, and screening tools flag possible capitalisation of interest costs — worth independent scrutiny of reported profitability.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TVSMOTOR','2026-03-31','bear','FII holding declined for the first time in four quarters (down 52 basis points to 22.57%), suggesting some foreign investors are booking profits or growing cautious after a strong run.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TVSMOTOR','Rising employee costs and input cost pressures compressed operating margin by over 200 basis points year-over-year in Q4 FY26, even as revenue grew 30%','risk',TRUE);
