INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('BOSCHLTD','Bosch','NSE','Auto Components','Auto & Industrial Technology (MNC)','Auto Components','Bosch India manufactures and supplies technology and components across four sectors: Mobility (automotive parts like fuel injection and chassis systems), Industrial Technology, Consumer Goods (power tools and appliances), and Energy and Building Technology. As the Indian flagship of Germany''s Robert Bosch group, it combines global engineering technology with extensive local manufacturing, supplying both automotive OEMs and industrial/retail customers directly.','Bosch India Q4 FY26 results coverage (Bajaj Finserv, Univest); Screener.in; Bosch Limited shareholder information (bosch.in); Kotak Neo','Deep engineering technology transfer from Robert Bosch GmbH''s global R&D, combined with nearly 18 manufacturing units and decades of relationships with India''s major automotive and industrial OEMs — scale and technical trust that would take a new entrant decades to replicate.','Bosch India manufactures components, technology and systems — spanning automotive parts (fuel injection, chassis systems), industrial automation, consumer goods (power tools, appliances) and building technology — selling to OEMs like Hyundai and TVS Motor as well as directly to industrial and retail customers, positioning it upstream of the vehicles and products that use its technology.','Because Bosch India sits inside a much larger German multinational group, its own corporate structure is periodically reshuffled (subsidiaries transferred in or spun out) as part of global Bosch strategy — a structural factor investors need to track separately from underlying business performance.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BOSCHLTD','2026-03-31','revenue_growth_pct',16,'%','Revenue Growth (Q4 YoY)','Q4 FY26 revenue of ₹4,911 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BOSCHLTD','2026-03-31','ebitda_growth_pct',16.1,'%','EBITDA Growth (Q4 YoY)',NULL,'verified');
