INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BOSCHLTD','2026-03-31','promoter_pct_ref',70.54,'%','Promoter Holding (context metric)','Shown here as a metric for reference; also recorded in the management profile.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BOSCHLTD','2026-03-31','bull','Q4 FY26 revenue grew 16% YoY to ₹4,911 crore with EBITDA growing 16.1%, and the company declared a substantial ₹512/share dividend — consistent, well-funded shareholder returns from a genuinely diversified technology business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BOSCHLTD','2026-03-31','bull','Operating across four distinct sectors — Mobility, Industrial Technology, Consumer Goods, and Energy and Building Technology — Bosch India isn''t purely an auto-cycle bet, giving it more resilience than a pure-play auto component maker.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BOSCHLTD','2026-03-31','bull','Backed by Robert Bosch GmbH''s global engineering and R&D, with nearly 18 manufacturing units across India, Bosch combines deep local manufacturing scale with world-class parent technology.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BOSCHLTD','2026-03-31','bear','At a P/E near 40-43x, the stock is priced at a significant premium, and ongoing corporate restructuring within the broader Bosch India group (including a planned Offer For Sale in Bosch Home Comfort India) adds complexity for investors trying to value the standalone entity.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BOSCHLTD','2026-03-31','bear','As a subsidiary of a German multinational, Bosch India''s strategic direction — including which businesses stay, get transferred, or get restructured — is ultimately decided at the global parent level, not by Indian shareholders.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BOSCHLTD','2026-03-31','bear','Heavy reliance on the automotive sector for its Mobility segment means Bosch India remains meaningfully exposed to the same auto-cycle risks facing its OEM customers like Hyundai and TVS Motor elsewhere in this dataset.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BOSCHLTD','Ongoing intra-group restructuring, including a planned Offer For Sale in Bosch Home Comfort India and the Bosch Chassis Systems India consolidation, reflects the German parent''s periodic reshuffling of its Indian corporate structure','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BOSCHLTD','Diversification across Mobility, Industrial Technology, Consumer Goods and Energy/Building Technology reduces Bosch India''s dependence on any single sector''s cycle, unlike a pure-play auto component maker','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BOSCHLTD','As a key supplier to auto OEMs, Bosch India''s Mobility segment remains exposed to the same demand and margin pressures facing vehicle manufacturers like Hyundai and TVS Motor','risk',TRUE);
