INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('MOTHERSON','Samvardhana Motherson','NSE','Auto Components','Global Auto Components Supplier','Auto Components','Samvardhana Motherson International is one of the world''s largest automotive component manufacturers, producing wiring harnesses, rear-view mirrors, polymer-based interior and exterior modules, and vision systems, alongside emerging businesses in aerospace and consumer electronics. Operating across more than 30 countries and serving nearly every major global automotive OEM as a full-system solutions provider, it is India''s largest auto ancillary company by scale.','Samvardhana Motherson FY26 & Q4 FY26 results coverage (Univest, MarketsMojo); Screener.in','Scale as one of the world''s largest automotive component suppliers, with deep, long-standing relationships across nearly every major global OEM and a full-system product breadth that few competitors can match — reinforced by continuous strategic acquisitions extending that breadth further.','Samvardhana Motherson manufactures a broad range of automotive components — wiring harnesses, rear-view mirrors, polymer modules, interior and exterior trim — supplying tier-1 parts directly to global automotive OEMs across Europe, North America and Asia, positioning it as one of the world''s largest full-system automotive component suppliers.','Motherson''s strategy of becoming a ''full system solutions provider'' rather than a single-component specialist means it increasingly competes with companies like Bosch on breadth, not just on individual parts — and its continuous global M&A is explicitly aimed at deepening that breadth further.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('MOTHERSON','2026-03-31','pat_growth_pct',42.5,'%','PAT Growth (Q4 YoY)','Q4 FY26 PAT of ₹1,497 crore, recovering strongly from a weak Q4 FY25.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('MOTHERSON','2026-03-31','booked_business_usd_bn',83.9,'$bn','Automotive Booked Business','Provides exceptional multi-year revenue visibility.','verified');
