INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('MOTHERSON','2026-03-31','interest_coverage',8.92,'x','Interest Coverage','Improved as the company steadily deleverages.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MOTHERSON','2026-03-31','bull','Q4 FY26 consolidated PAT jumped 42.5% YoY to ₹1,497 crore, recovering strongly from a weak Q4 FY25, with an automotive booked business exceeding USD 83.9 billion providing exceptional multi-year revenue visibility.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MOTHERSON','2026-03-31','bull','Operating across four divisions (Modules & Polymer Products, Vision Systems, Wiring Harnesses, and Emerging Businesses including aerospace and consumer electronics) spanning 30+ countries gives genuine diversification against any single customer, geography or auto segment.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MOTHERSON','2026-03-31','bull','Interest costs have been declining steadily as the company deleverages, with interest coverage improving to nearly 9x — a real, ongoing balance-sheet improvement story.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MOTHERSON','2026-03-31','bear','Promoter holding dropped sharply from 58.13% to 48.60% in mid-2025 due to corporate restructuring — a significant ownership change investors should understand rather than overlook.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MOTHERSON','2026-03-31','bear','Return on equity of just 11.6% is weak for a company of this scale, and the wide gap between 5-year sales CAGR and EBIT CAGR points to a persistent struggle to convert growth into proportionate profit.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('MOTHERSON','2026-03-31','bear','An aggressive, ongoing string of global acquisitions (Nexans autoelectric, Elektrokontakt, Yutaka Giken, Shinnichi, Vacuform, among others) creates real integration risk even as it extends the company''s global footprint.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MOTHERSON','An automotive booked business exceeding USD 83.9 billion gives Motherson exceptional multi-year revenue visibility, insulating it somewhat from any single quarter''s demand swings','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('MOTHERSON','A steady stream of global acquisitions (Nexans autoelectric, Elektrokontakt, Yutaka Giken, Shinnichi, Vacuform) is expanding Motherson''s product range and geographic footprint, though each deal carries real integration execution risk','neutral',TRUE);
