INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('ICICIGI','ICICI Lombard General Insurance','NSE','Insurance','General Insurance','Insurance','ICICI Lombard General Insurance sells non-life insurance products — including motor, health, property and liability coverage — to individuals and businesses, collecting premiums and paying out claims, while investing the pooled premium float for additional income. It is one of India''s largest private-sector general insurers, jointly promoted by ICICI Bank and Canada''s Fairfax Financial Holdings.','ICICI Lombard FY26 & Q4 FY26 results coverage (Sahi, ICICI Direct); Screener.in; Kotak Neo','Backing from ICICI Bank''s brand and distribution network, combined with decades of underwriting data and a diversified product portfolio spanning health, motor and commercial lines, giving ICICI Lombard scale advantages that smaller general insurers cannot easily match.','ICICI Lombard collects insurance premiums from individuals and businesses across health, motor, property and liability lines, invests that pooled capital, and pays out claims when policyholders experience covered losses — a classic general (non-life) insurance model, distinct from LIC''s life insurance business elsewhere in this dataset.','General insurance differs structurally from life insurance in that policies are typically annual and claims can arise quickly (a car accident, a hospital visit), making underwriting discipline and claims management far more central to profitability quarter-to-quarter than in the multi-decade life insurance business.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ICICIGI','2026-03-31','gdpi_growth_pct',7.0,'%','GDPI Growth (FY26)','Below industry growth of 9.2%; excluding Crop and Mass Health, growth was 10.2% vs industry 13.3%.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ICICIGI','2026-03-31','pat_growth_pct',10.5,'%','PAT Growth (FY26)',NULL,'verified');
