INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ICICIGI','2026-03-31','solvency_ratio',2.67,'x','Solvency Ratio','Comfortably above the 1.50x regulatory minimum.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ICICIGI','2026-03-31','bull','FY26 PAT grew 10.5% to ₹2,772 crore, and the retail health segment — the standout performer — grew net earned premiums over 55%, showing real momentum in one of general insurance''s most attractive product lines.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ICICIGI','2026-03-31','bull','Q4 FY26 GDPI grew 18.2% versus industry growth of just 10.9%, indicating genuine market share gains rather than simply riding an industry-wide upcycle.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ICICIGI','2026-03-31','bull','A comfortable solvency ratio of 2.67x (versus a 1.50x regulatory minimum) and a healthy dividend of ₹13.50/share for FY26 reflect a well-capitalised, shareholder-friendly business.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ICICIGI','2026-03-31','bear','The combined ratio — the key measure of underwriting profitability — worsened slightly to 103.4% in FY26 from 102.8% in FY25, meaning core underwriting alone remains unprofitable and the company still depends on investment income to generate overall profit.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ICICIGI','2026-03-31','bear','Full-year GDPI growth of 7.0% lagged industry growth of 9.2%, suggesting ICICI Lombard is losing some ground in aggregate market share even as specific segments like retail health outperform.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ICICIGI','2026-03-31','bear','Return on Average Equity declined to 17.8% in FY26 from 19.1% in FY25, and Q4 FY26 ROAE fell further to 13.3% from 14.5% — a genuine profitability trend worth watching, not just a one-quarter blip.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ICICIGI','Retail health insurance grew net earned premiums over 55% in Q4 FY26, reflecting rising consumer demand for health coverage and successful product innovation like the Elevate offering','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ICICIGI','The company migrated major product lines to a new enterprise-wide technology platform (Artemis) during FY26, a modernisation effort that could improve efficiency but also carries execution risk during transition','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ICICIGI','A combined ratio persistently above 100% means the business structurally depends on investment income to be profitable, exposing overall earnings to capital market volatility beyond pure insurance risk','risk',TRUE);
