INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,status) VALUES ('ICICIGI','2026-03-31','market_cap_cr',87752,'crore','Market Capitalisation','verified');
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('IRFC','IRFC','NSE','Financial Services','Railway Finance (PSU)','PSU Infrastructure Lenders','Indian Railway Finance Corporation is the dedicated financing arm of Indian Railways, raising funds from domestic and international debt markets and channelling that capital exclusively into acquiring rolling stock (locomotives, coaches, wagons) and financing railway infrastructure projects. It operates on a leasing, lending and borrowing model with Indian Railways as its sole effective customer.','IRFC FY26 & Q4 FY26 results coverage (MarketsMojo, Sahi, Torus Digital); Screener.in','A government-mandated, effectively exclusive role as Indian Railways'' dedicated financing arm — a position protected by policy design rather than competitive advantage, meaning its ''moat'' is regulatory rather than commercial.','IRFC raises funds from domestic and international debt markets, then channels that capital exclusively to Indian Railways to finance rolling stock (locomotives, coaches, wagons) and railway infrastructure projects — a specialised, single-customer financing arm rather than a diversified lender.','Because its only real borrower is the Indian government''s own railway system, IRFC''s credit risk is about as low as a lender can have — but that same concentration means its growth is entirely capped by how much Indian Railways itself chooses to borrow, with no ability to diversify into new customer segments the way PFC or REC can.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('IRFC','2026-03-31','interest_income_growth_pct',9.12,'%','Interest Income Growth (Q4 YoY)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('IRFC','2026-03-31','pat_growth_pct',0.15,'%','PAT Growth (Q4 YoY)','Essentially flat; fell 6.54% sequentially as interest expenses rose faster than income.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('IRFC','2026-03-31','roe_pct',13.74,'%','Return on Equity','Significantly trails peers PFC (19.17%) and REC (~20%).','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('IRFC','2026-03-31','net_debt_equity',2.73,'x','Debt / Equity','Lower leverage than PFC (7.88x), reflecting a more conservative, single-customer lending model.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IRFC','2026-03-31','bull','Q4 FY26 interest income reached ₹7,336 crore, the highest quarterly figure in the company''s history, up 9.12% YoY, reflecting continued expansion of IRFC''s loan book to Indian Railways.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IRFC','2026-03-31','bull','IRFC exceeded its FY26 disbursement guidance, disbursing ₹35,000 crore against a ₹30,000 crore target — genuine execution beyond plan.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IRFC','2026-03-31','bull','As the dedicated financing arm of Indian Railways with a government promoter, IRFC carries very low credit risk on its core lending book — its borrower is effectively the Indian state.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IRFC','2026-03-31','bear','Q4 FY26 net profit was essentially flat YoY (+0.15%) and fell 6.54% sequentially, as interest expenses surged 14.80% QoQ — faster than revenue growth — directly compressing profitability.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IRFC','2026-03-31','bear','Return on equity of just 13.74% trails peers PFC (19.17%) and REC (~20%) significantly, yet IRFC trades at a P/E of 18.70x versus peers'' sub-6x — a valuation premium that''s increasingly difficult to justify on fundamentals alone.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IRFC','2026-03-31','bear','IRFC''s entire business model depends on a single customer, Indian Railways — a concentration risk with no meaningful diversification, unlike PFC and REC which lend across many power-sector borrowers.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IRFC','IRFC exceeded its FY26 disbursement target (₹35,000 crore actual vs ₹30,000 crore guided), reflecting Indian Railways'' accelerating capital expenditure on rolling stock and infrastructure','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IRFC','Rising interest costs in a still-elevated rate environment are compressing IRFC''s margins faster than its interest income is growing, a direct near-term profitability risk','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IRFC','A single-customer business model tied entirely to Indian Railways caps diversification and pricing flexibility compared to power-sector lenders like PFC and REC that serve many borrowers','risk',TRUE);
