INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('IRFC',84.65,'Government of India, via the Ministry of Railways','No encumbrance on promoter shares confirmed for FY26 per SEBI Reg 31(4) filing; however promoter holding itself declined 1.71 percentage points in Q4 FY26 after three stable quarters.','Continues raising domestic and international debt to fund Indian Railways'' rolling stock and infrastructure needs; no equity dilution signalled beyond the modest promoter stake reduction.','Mar 2026','Screener.in; MarketsMojo Q4 FY26 result analysis; ScanX SEBI filing coverage; Sahi FY26 results');
