INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('PFC','Power Finance Corporation','NSE','Financial Services','Power Sector Lending (PSU)','PSU Infrastructure Lenders','Power Finance Corporation is a government-owned non-banking financial company that raises capital in debt markets and lends it to power-sector companies across generation, transmission, distribution and renewable energy, spanning both public and private borrowers. It is India''s largest NBFC by loan book and is in the process of merging with sister PSU lender REC to form a single, dominant power-sector financing institution.','PFC FY26 & Q4 FY26 results coverage (InvestyWise, MarketsMojo); Screener.in; Ventura Securities PFC-REC merger analysis','Scale as India''s largest NBFC lender with deep, government-backed relationships across every major power-sector borrower, reinforced by the pending REC merger which would make the combined entity even more dominant in power-sector financing.','Power Finance Corporation raises capital in domestic and international debt markets and lends it to power-sector borrowers — generation, transmission, distribution and renewable energy companies — across both public and private sectors, functioning as India''s largest dedicated infrastructure financier for the power industry.','PFC''s planned merger with REC (approved by both boards at an 88:100 share swap ratio, with the combined entity''s loan book exceeding ₹11 lakh crore) will create a single, dominant power-sector financing institution — a structural consolidation that directly reshapes the lending side of every power company in this dataset''s value chain.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('PFC','2026-03-31','standalone_pat_growth_pct',16,'%','Standalone PAT Growth (FY26)','Record standalone net profit of ₹20,051 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('PFC','2026-03-31','net_npa_pct',0.13,'%','Net NPA','Excellent asset quality for a large infrastructure lender.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('PFC','2026-03-31','roe_pct',19.17,'%','Return on Equity','Second-highest among PSU infrastructure lenders after REC.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('PFC','2026-03-31','net_debt_equity',7.88,'x','Debt / Equity','High leverage typical for a government-backed infrastructure financier; well above peer IRFC''s 2.73x.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PFC','2026-03-31','bull','FY26 standalone net profit hit a record ₹20,051 crore (+16% YoY), with consolidated PAT reaching ₹33,625 crore and net NPA at an excellent 0.13% — scale, growth and asset quality all pointing the same direction.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PFC','2026-03-31','bull','PFC maintains the largest NBFC loan book in India at ₹11.64 lakh crore, including a leading ₹1.65 lakh crore renewable energy financing portfolio, positioning it at the center of India''s entire power-sector capital needs.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PFC','2026-03-31','bull','At a P/E of just 5.5-6x versus a finance sector average near 21x, PFC is statistically inexpensive for a company delivering a 19.17% ROE and a well-capitalised 23.44% CRAR.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PFC','2026-03-31','bear','Debt-to-equity of 7.88x is meaningfully higher than peers like IRFC (2.73x), amplifying both earnings volatility and refinancing risk even though this leverage is typical for government-backed infrastructure lenders.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PFC','2026-03-31','bear','Q4 FY26 interest income was essentially flat quarter-on-quarter (down 0.60%) and down 1.18% YoY, raising real questions about loan book growth velocity even as reported profit hit a record — the profit surge leaned partly on provision reversals rather than pure operating growth.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('PFC','2026-03-31','bear','The approved merger with REC, while strategically rational, will dilute existing PFC shareholders'' equity by roughly 34% and introduces real integration and governance complexity during the transition period through the planned 2027 completion.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PFC','PFC''s board-approved merger with REC (88:100 share swap, targeted completion by April 1, 2027) will create a combined power-sector lender with a loan book exceeding ₹11 lakh crore, the single largest structural event in India''s infrastructure financing sector this year','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PFC','Q4 FY26 interest income was flat to slightly down despite record reported profit, suggesting the earnings jump leaned on provision reversals and other one-off factors rather than pure loan book growth','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('PFC','A leading ₹1.65 lakh crore renewable energy financing portfolio positions PFC to directly fund the capacity build-out of companies like Adani Green, NTPC Green, Suzlon and Waaree elsewhere in this dataset','tailwind',TRUE);
