INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('PFC',56.0,'Government of India','No pledge; promoter holding has remained largely constant over the past six months.','Proposed a final dividend of ₹3.95/share, taking the total FY26 dividend to ₹18.55/share; simultaneously executing the REC merger process, which will dilute existing shareholders'' equity by roughly 34% upon completion.','Mar 2026','Screener.in; InvestyWise Q4 FY26 results & merger coverage; MarketsMojo Q4 FY26 result analysis; Ventura Securities merger analysis');
