INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('RECLTD','REC Limited','NSE','Financial Services','Power Sector Lending (PSU)','PSU Infrastructure Lenders','REC Limited is a government-owned Maharatna CPSE that finances projects across the entire power sector value chain — generation, transmission, distribution and renewable energy — lending to state electricity boards, private power producers, central utilities and infrastructure developers. Originally focused on rural electrification since 1969, it has broadened into a full power-sector financier and is now in the process of merging into sister PSU lender PFC.','REC FY26 & Q4 FY26 results coverage (Tickertape, Trade Brains); Screener.in; ScanX & Groww PFC-REC merger coverage','Nearly 60 years of relationships across India''s power sector as a Maharatna CPSE, financing everything from rural electrification to renewable energy — a position about to be consolidated further through the pending merger into PFC, creating an even more dominant combined lender.','REC raises capital in domestic and international debt markets and lends across the entire power sector value chain — generation, transmission, distribution and renewable energy — to state electricity boards, private power producers, central utilities and infrastructure developers, historically rooted in rural electrification financing.','REC''s pending absorption into PFC (rather than the other way around) means its distinct corporate identity is set to disappear, even though its loan book and lending relationships will continue inside the combined entity — a reminder that in this dataset, a company''s value chain position can itself be in the process of structural change.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('RECLTD','2026-03-31','pat_growth_pct',2.67,'%','PAT Growth (FY26)','Full-year growth modest; Q4 FY26 profit alone fell 21.7% YoY.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('RECLTD','2026-03-31','revenue_growth_pct',5.67,'%','Total Income Growth (FY26)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('RECLTD','2026-03-31','roe_pct',20,'%','Return on Equity','Highest among the PSU infrastructure lenders in this dataset.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('RECLTD','2026-03-31','dividend_yield_pct',5.64,'%','Dividend Yield','Among the highest yields of any company in this dataset.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RECLTD','2026-03-31','bull','FY26 total income grew 5.67% to ₹59,628 crore with net profit up 2.67% to ₹16,308 crore, and REC delivers the highest ROE (~20%) among PSU infrastructure lenders in this dataset, ahead of both PFC and IRFC.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RECLTD','2026-03-31','bull','A dividend yield of 5.64% (₹8.55/share total FY26 payout across interim and final dividends) makes REC one of the highest-yielding stocks in this entire dataset, appealing directly to income-focused investors.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RECLTD','2026-03-31','bull','As a Maharatna CPSE financing the complete power sector value chain — generation, transmission, distribution and renewable energy — REC has direct exposure to India''s structural, multi-decade power capacity build-out.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RECLTD','2026-03-31','bear','Q4 FY26 net profit fell sharply, down 21.7% YoY to ₹3,375 crore, with total income also declining nearly 5% — a genuinely weak quarter that the full-year growth figure understates.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RECLTD','2026-03-31','bear','The approved merger into PFC (at an 88:100 share swap ratio, with REC being absorbed into the surviving PFC entity) means REC as a standalone listed company will eventually cease to exist — a structural event investors must factor into any long-term holding decision.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('RECLTD','2026-03-31','bear','ROCE of just 9.71% is meaningfully lower than the strong ROE figure, hinting at a business that relies significantly on financial leverage to generate shareholder returns rather than pure operating efficiency.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('RECLTD','REC''s board-approved merger into PFC at an 88:100 share swap ratio will end REC''s standalone existence as a listed company, with shareholders receiving PFC shares upon completion','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('RECLTD','Q4 FY26''s 21.7% profit decline, even amid a positive full-year growth number, signals real near-term earnings volatility that a simple annual view would miss','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('RECLTD','REC''s deep, decades-long relationships across the entire power sector value chain — from generation to renewable energy — position the combined PFC-REC entity to dominate power-sector financing post-merger','tailwind',TRUE);
