INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('RECLTD',52.6,'Government of India, via the Ministry of Power','No pledge flagged in current shareholding trackers.','Recommended a final dividend of ₹1.55/share plus ₹7/share in interim dividends already paid (four tranches), totalling ₹8.55/share for FY26; separately proposed raising up to ₹40,000 crore via bonds/debentures alongside the PFC merger process.','Mar 2026','Screener.in; Tickertape FY26 results coverage; ScanX merger coverage; Groww');
