INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('BRITANNIA','Britannia Industries','NSE','FMCG','Packaged Foods','FMCG','Britannia Industries manufactures and sells packaged food products — primarily biscuits, along with bread, dairy, cakes and adjacent categories — under well-known brands sold through extensive domestic retail and rural distribution networks as well as export markets in over 60 countries. It is one of India''s oldest and most trusted FMCG companies, particularly dominant in the biscuits category.','Britannia FY26 & Q4 FY26 results coverage (MarketsMojo, ChartAlert, ScanX, Univest); Screener.in','Decades of brand trust in Indian households across biscuits (NutriChoice, Bourbon, Good Day) and dairy, combined with one of the deepest rural distribution networks in Indian FMCG — advantages that support pricing power new entrants cannot easily replicate.','Britannia converts commodity agricultural inputs — wheat flour, palm oil, sugar and dairy — into branded, packaged biscuits, bread, dairy and adjacent food products, sold through India''s vast retail and rural distribution networks as well as 60+ export markets.','Because its core inputs are agricultural commodities with volatile global pricing, Britannia''s margin story each quarter is as much about input cost timing and hedging as it is about brand strength or volume growth — a structurally different risk profile from a services or technology business.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BRITANNIA','2026-03-31','revenue_growth_pct',6.7,'%','Revenue Growth (FY26)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BRITANNIA','2026-03-31','pat_growth_pct',16.5,'%','PAT Growth (FY26)','Outpaced revenue growth on margin expansion and a lower effective tax rate.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BRITANNIA','2026-03-31','roe_pct',74.67,'%','Return on Equity','Among the very highest in Indian FMCG, behind only Nestle India.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('BRITANNIA','2026-03-31','dividend_payout_pct',71,'%','Dividend Payout Ratio','Dividends paid exceeded PAT in FY26 — generous but limits reinvestment capacity.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BRITANNIA','2026-03-31','bull','FY26 PAT grew 16.5% to ₹2,537 crore, outpacing revenue growth of 6.7%, on the back of margin expansion and near-perfect earnings quality (operating cash flow was ~103% of reported profit).',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BRITANNIA','2026-03-31','bull','Return on equity of 74.67% is exceptional even by FMCG standards, trailing only Nestle India among major Indian consumer companies, while the balance sheet remains net cash with negligible debt.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BRITANNIA','2026-03-31','bull','International operations spanning 60+ countries, including manufacturing in the UAE and Oman, give Britannia a genuine diversification lever beyond the Indian market that many domestic-focused FMCG peers lack.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BRITANNIA','2026-03-31','bear','Operating margin compressed 186 basis points sequentially to 18.20% in Q4 FY26, and revenue actually declined 5% quarter-on-quarter — the year-over-year growth story masks real within-year volatility.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BRITANNIA','2026-03-31','bear','At a P/E of 52.47x and P/BV of 35.61x, the stock is priced for continued flawless execution, leaving little room for the wheat flour and palm oil price volatility management itself flagged as a key FY27 risk.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('BRITANNIA','2026-03-31','bear','Associate and joint-venture losses nearly tripled during FY26, and current borrowings almost doubled even as long-term debt fell — small but real signs of financial discipline loosening at the margins.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BRITANNIA','Rural and semi-urban demand recovery, aided by better monsoon conditions in FY26, directly drove Britannia''s volume-led revenue growth','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BRITANNIA','Wheat flour and palm oil price volatility remains the single biggest input-cost risk flagged by management for FY27, directly affecting margin sustainability','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('BRITANNIA','Rising employee costs (up 16.9% YoY, well above 6.7% revenue growth) are quietly eroding some of the raw material cost relief the company has benefited from','risk',TRUE);
