INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('BRITANNIA','downstream','Domestic retail & rural distribution network',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('BRITANNIA','downstream','Export markets across 60+ countries, incl. UAE & Oman manufacturing',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('BRITANNIA','downstream','Adjacent categories: dairy, cakes & premium biscuits','tailwind','premiumisation (NutriChoice, Bourbon) supports margin expansion');
