INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('GODREJCP','Godrej Consumer Products','NSE','FMCG','Home & Personal Care','FMCG','Godrej Consumer Products manufactures and sells home care products (household insecticides, air fresheners), personal care (soaps) and hair care (colorants) under well-known brands, distributed across India and a significant international footprint including Africa, Indonesia and Latin America. It is one of India''s largest home and personal care companies, with genuine geographic diversification beyond the domestic market.','Godrej Consumer Products FY26 & Q4 FY26 results coverage (InvestyWise, ScanX, Univest); Screener.in; Yahoo Finance','Decades of brand trust in Indian home and personal care categories (household insecticides, soaps, hair color), combined with genuine international distribution reach across Africa and other emerging markets that few Indian FMCG peers have replicated.','Godrej Consumer Products manufactures and sells home care, personal care and hair care products — household insecticides, soaps, air fresheners and hair colorants — through domestic retail distribution in India and a meaningful international footprint including Africa, positioning it as a branded consumer goods company with genuine geographic diversification beyond most India-focused FMCG peers.','Because a meaningful share of GCPL''s business sits outside India, particularly in Africa, its growth story is more exposed to emerging-market currency and demand volatility than domestically-focused peers like Britannia — a real structural difference in risk profile within the same FMCG sector.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('GODREJCP','2026-03-31','revenue_growth_pct',11,'%','Revenue Growth (Q4 YoY)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('GODREJCP','2026-03-31','volume_growth_pct',6,'%','Underlying Volume Growth (Q4)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('GODREJCP','2026-03-31','ebitda_margin_pct',21.7,'%','EBITDA Margin (Q4)',NULL,'verified');
