INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GODREJCP','2026-03-31','bull','Q4 FY26 revenue grew 11% with 6% underlying volume growth and EBITDA up 10% at a healthy 21.7% margin, with the Home Care segment (household insecticides, air fresheners) delivering 12% value growth and market share gains.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GODREJCP','2026-03-31','bull','The standalone India business significantly outperformed the consolidated numbers — 10% sales growth and 8% volume growth at a 24.7% margin — showing the core domestic franchise is healthier than the group total suggests.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GODREJCP','2026-03-31','bull','The company''s ''Speedboats'' portfolio of newer, high-growth products is targeted to deliver 30%+ growth over the medium term, a genuine innovation-led growth lever beyond the mature core categories.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GODREJCP','2026-03-31','bear','FY26 PAT growth fell below the company''s own 15-18% target, with management explicitly attributing the shortfall to headwinds in the Africa business — a real geographic diversification risk, not just a domestic execution issue.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GODREJCP','2026-03-31','bear','Promoter holding has declined 10.2 percentage points over three years, and at a P/E near 46-57x depending on the period measured, the stock is priced at a premium that recent growth has struggled to fully justify.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GODREJCP','2026-03-31','bear','A significant portion of promoter shares (held by Burjis, Sohrab and Hormazd Godrej) carry legacy transfer restrictions dating to 2020, with voting rights concentrated in a single family member — a governance structure worth understanding for any long-term shareholder.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GODREJCP','Africa business headwinds caused FY26 PAT growth to fall below the company''s own 15-18% target, a geographic diversification risk distinct from purely domestic FMCG peers','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GODREJCP','The ''Speedboats'' portfolio of newer product categories is targeted for 30%+ medium-term growth, an innovation-led lever management is betting on to reaccelerate overall growth','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GODREJCP','A regulatory accounting presentation change (netting customer-related spends against revenue, per ICAI Expert Advisory Committee guidance) affects how revenue is reported from Q4 FY26 onward, though it does not change underlying EBITDA or cash flow','neutral',TRUE);
