INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('GODREJCP',53.0,'Godrej family (Adi Godrej, Nadir Godrej and family trusts), plus corporate promoter entities Godrej Industries, Godrej Properties and Godrej Agrovet — 67 entities total','No new encumbrances in FY26; legacy FY20 transfer restrictions on shares held by Burjis, Sohrab and Hormazd Godrej remain, with voting rights vested in Nadir Godrej.','Declared a dividend of ₹5/share for FY26, more modest than some FMCG peers, reflecting continued investment in the ''Speedboats'' growth portfolio and Africa business stabilisation.','Mar 2026','Screener.in; ScanX SEBI filing coverage; InvestyWise Q4 FY26 earnings call transcript; Univest analyst coverage');
