INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('UNITDSPR','United Spirits','NSE','FMCG','Alcoholic Beverages','FMCG','United Spirits manufactures, bottles, markets and distributes alcoholic beverages across India, including whisky, rum, vodka, brandy and gin under more than 80 brands spanning popular to luxury price segments. As a subsidiary of global spirits leader Diageo, it combines internationally recognised brands (Johnnie Walker, Smirnoff) with market-leading India-origin brands (McDowell''s No.1, Royal Challenge, Signature), making it India''s largest alcoholic beverage company.','United Spirits FY26 & Q4 FY26 results coverage (MarketsMojo, Univest, INDmoney); Screener.in; Kotak Neo','Market leadership as India''s largest spirits company, combined with access to Diageo''s global brand portfolio and international distribution expertise — a scale and brand-access advantage that would be extremely difficult for a standalone Indian competitor to replicate.','United Spirits manufactures, bottles and distributes alcoholic beverages — whisky, rum, vodka, brandy and gin — across more than 80 brands spanning popular to luxury price segments, leveraging parent Diageo''s global brand portfolio (Johnnie Walker, Smirnoff) alongside its own India-origin brands (McDowell''s, Royal Challenge, Signature).','As a subsidiary of the world''s largest spirits company, United Spirits benefits from global brand access and international distribution relationships that a standalone Indian competitor could not easily replicate, but its category is also uniquely exposed to state-by-state Indian alcohol regulation — a patchwork of excise duties and restrictions unlike almost any other consumer category in this dataset.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('UNITDSPR','2026-03-31','pat_growth_pct',28.03,'%','PAT Growth (Q4 YoY)',NULL,'verified');
