INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('UNITDSPR','2026-03-31','pat_margin_pct',18.6,'%','PAT Margin (Q4)','Up sharply from 15.55% a year earlier.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('UNITDSPR','2026-03-31','bull','Q4 FY26 net profit surged 28.03% YoY to ₹539 crore with PAT margin expanding to 18.60% from 15.55%, reflecting genuine operational efficiency gains and effective cost management, not just favourable one-offs.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('UNITDSPR','2026-03-31','bull','As India''s largest spirits company and a subsidiary of global leader Diageo, United Spirits combines an unmatched portfolio (Johnnie Walker, McDowell''s No.1, Royal Challenge, Signature, Black Dog) with the parent''s global distribution expertise and brand-building capability.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('UNITDSPR','2026-03-31','bull','Return on equity of 20.74%, well above the industry average, and a stable, unchanged 56.67% promoter holding from Diageo Relay B.V. across five straight quarters reflect both strong capital efficiency and long-term parent commitment.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('UNITDSPR','2026-03-31','bear','Revenue growth of just 3.67% YoY significantly lagged profit growth, and profit before tax excluding other income actually declined 7.50% versus the trailing four-quarter average — the headline profit surge looks stronger than core operating performance.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('UNITDSPR','2026-03-31','bear','Interest costs more than tripled to ₹69 crore in Q4 FY26 from ₹22 crore a year earlier despite the company maintaining a net cash position, a genuinely puzzling detail worth understanding rather than dismissing.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('UNITDSPR','2026-03-31','bear','The Indian alcoholic beverages industry faces persistent regulatory headwinds — state-level excise duty changes, periodic prohibition discussions, and advertising restrictions — creating an operating environment private consumer companies in less-regulated categories don''t face.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('UNITDSPR','State-level excise duty increases and intensifying competition in key markets like Karnataka, Telangana and Maharashtra have periodically compressed margins, a recurring regulatory risk specific to the alcoholic beverages category','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('UNITDSPR','Rising disposable incomes and premiumisation trends support continued growth in the prestige and premium segments (Royal Challenge, Signature, Black Dog), a structural tailwind for the category','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('UNITDSPR','A sharp, unexplained tripling of interest costs despite a net cash position raises questions about short-term working capital or borrowing patterns worth monitoring in coming quarters','risk',TRUE);
