INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('VBL','Varun Beverages','NSE','FMCG','Beverages (PepsiCo Franchisee)','FMCG','Varun Beverages is PepsiCo''s largest franchisee outside the United States, manufacturing, bottling and distributing PepsiCo''s carbonated soft drinks, juices and packaged water across India and a growing footprint of international territories including Africa. It is India''s largest beverages company by market capitalisation, with a business model built on exclusive bottling rights rather than brand ownership.','Varun Beverages FY26 & Q4 FY26 results coverage (MarketsMojo, Business Standard, Kotak Neo); Screener.in','Exclusive, deeply entrenched PepsiCo bottling rights across India and expanding international territories, combined with extensive manufacturing and cold-chain distribution infrastructure that would take a new entrant many years and enormous capital to replicate.','Varun Beverages bottles, manufactures and distributes PepsiCo beverages (colas, juices, packaged water) under an exclusive franchise agreement across India and a growing set of international territories, sitting downstream of PepsiCo''s brand ownership and upstream of the retail and on-trade outlets that sell to consumers.','As a franchise bottler rather than a brand owner, VBL''s growth ceiling and brand strategy are ultimately set by PepsiCo''s global decisions, even as VBL itself controls manufacturing scale, distribution execution and geographic expansion — a structurally different position from brand-owning FMCG peers like Britannia or Godrej Consumer elsewhere in this dataset.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('VBL','2026-03-31','revenue_growth_pct',18.3,'%','Revenue Growth (Q4 YoY)','FY26 full-year revenue reached ₹22,693 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('VBL','2026-03-31','volume_growth_pct',16.3,'%','Case Volume Growth (Q4 YoY)','India +14.4%, international territories +21.4% — international growing faster than domestic.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('VBL','2026-03-31','ebitda_margin_pct',23.26,'%','EBITDA Margin (Q4)','Up from 22.70% a year earlier.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('VBL','2026-03-31','roe_pct',22.82,'%','Return on Equity','Among the highest in the beverages sector.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VBL','2026-03-31','bull','Q4 FY26 (peak summer quarter) net profit grew 20.08% YoY to ₹872 crore with revenue up 18.3% and EBITDA margin expanding to 23.26%, showing that scale is translating directly into profitability, not just volume.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VBL','2026-03-31','bull','International territories grew case volume 21.4% YoY, faster than India''s 14.4%, and the company continues expanding geographically — including a full acquisition of South Africa''s Crickley Dairy and a new partnership with Asahi to launch CALPIS in India — giving VBL multiple growth vectors beyond its core PepsiCo bottling business.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VBL','2026-03-31','bull','A five-year sales CAGR of 27.27% and EBIT CAGR of 44.29%, combined with a conservative debt-to-EBITDA of ~1.13-1.30x, reflect a genuinely fast-growing, financially disciplined business — a rare combination.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VBL','2026-03-31','bear','The beverages business is highly seasonal — Q3 FY26 (winter) PAT margin compressed to just 6.18% from Q2''s 15.22%, and investors need to look at full-year, not single-quarter, numbers to judge the business properly.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VBL','2026-03-31','bear','At a P/E near 55x, the stock prices in continued rapid growth, and FII holdings have declined for two consecutive quarters (from a peak of 25.26% to under 20%), suggesting some international investors are booking profits or growing cautious at current valuations.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VBL','2026-03-31','bear','As the largest PepsiCo franchisee outside the US, VBL''s fortunes are structurally tied to a single global brand licensor — any change in that franchise relationship would be a material risk that a company with owned brands wouldn''t face.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('VBL','Continued geographic expansion — including the Crickley Dairy acquisition in South Africa and a new Asahi partnership to launch CALPIS in India — diversifies VBL''s growth beyond its core PepsiCo carbonated beverages franchise','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('VBL','Pronounced seasonality between summer and winter quarters means single-quarter results can be highly misleading without full-year context, a structural feature of the beverages category','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('VBL','As a franchise bottler rather than a brand owner, VBL''s long-term strategic direction remains ultimately dependent on PepsiCo''s global brand and licensing decisions','risk',TRUE);
