INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('VBL',59.4,'RJ Corp Limited (25.28%), Ravi Kant Jaipuria (16.71%) and Varun Jaipuria (15.43%)','No pledge flagged; promoter holding has declined modestly over three years (down 4.45%), reflecting gradual public float expansion rather than promoter selling pressure.','Declared an interim dividend of ₹0.50/share for FY26, retaining most capital for continued capacity expansion and international acquisitions like Crickley Dairy.','Mar 2026','Screener.in; MarketsMojo Q4 & Q3 FY26 result analyses; Business Standard & Kotak Neo Q4 FY26 coverage');
