INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('DIVISLAB','Divi''s Laboratories','NSE','Pharma','API & Custom Synthesis Manufacturing','Pharma','Divi''s Laboratories manufactures active pharmaceutical ingredients (APIs), pharmaceutical intermediates and nutraceutical ingredients (carotenoids, vitamins) for global pharmaceutical and nutraceutical companies. It operates as a specialist, behind-the-scenes supplier rather than a branded drug maker, earning revenue through generic API sales, custom synthesis contract manufacturing for Big Pharma, and nutraceutical ingredient supply.','Divi''s Laboratories FY26 & Q4 FY26 results coverage (Zerodha/Reuters, Alpha Spread investor relations); Screener.in','World''s largest manufacturer for 10 major generic APIs, combined with decade-plus relationships with 12 of the top 20 global Big Pharma companies — regulatory trust, quality consistency and manufacturing complexity that took decades to build and cannot be replicated quickly.','Divi''s Laboratories sits upstream in the pharmaceutical value chain as a specialist manufacturer — it makes the active pharmaceutical ingredients (APIs) and intermediates that global pharmaceutical companies then formulate into finished, branded or generic medicines, rather than selling any drugs under its own brand.','Because Divi''s manufactures the building blocks rather than the final medicine, its fortunes are tied to global pharma companies'' sourcing and pricing decisions — both a strength (deep, long-term customer relationships with Big Pharma) and a structural exposure (generic API pricing pressure that finished-drug companies can pass upstream).','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DIVISLAB','2026-03-31','pat_growth_pct',13.4,'%','PAT Growth (Q4 YoY)','Driven by strong performance in custom synthesis and nutraceuticals.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DIVISLAB','2026-03-31','custom_synthesis_mix_pct',53,'%','Custom Synthesis Share of Product Mix',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DIVISLAB','2026-03-31','roe_pct',16.19,'%','Return on Equity',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DIVISLAB','2026-03-31','capex_cr',1544,'crore','Capex Capitalized (FY26)','Funding new dedicated customer projects; management expects capex to normalise next year.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DIVISLAB','2026-03-31','bull','Q4 FY26 consolidated profit grew 13.4% YoY on strong performance in custom synthesis and nutraceuticals, with custom synthesis now contributing 53% of the product mix — a genuine shift toward higher-value, relationship-driven manufacturing rather than commodity generics.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DIVISLAB','2026-03-31','bull','Divi''s is the world''s largest API manufacturer for 10 generic APIs, exports to 100+ countries, and counts 12 of the top 20 global Big Pharma companies as customers with relationships spanning 10+ years — exceptional customer stickiness in a business built on trust and regulatory compliance.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DIVISLAB','2026-03-31','bull','Investment in next-generation technology platforms (solid phase peptide synthesis, flow chemistry, biocatalysis) has attracted strong multinational interest for GLP-1-related peptide capacity — positioning Divi''s to capture a slice of the global obesity-drug manufacturing boom.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DIVISLAB','2026-03-31','bear','Despite no production stoppages, West Asia-related logistics disruption and force majeure issues made raw material sourcing genuinely harder in Q4 FY26 — a live geopolitical supply chain risk the company had to actively manage around, not merely a theoretical one.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DIVISLAB','2026-03-31','bear','Generic segment pricing pressure and elevated freight/logistics costs have compressed gross margins for several consecutive quarters, and management has been reluctant to give a precise margin outlook, citing ongoing uncertainty.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DIVISLAB','2026-03-31','bear','At a P/E near 70x, the stock prices in continued exceptional execution, while capex remains very high (₹1,544 crore capitalized in FY26 alone) to fund new dedicated customer projects whose commercial payoff depends on customer timelines Divi''s doesn''t fully control.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DIVISLAB','West Asia-related logistics disruption made raw material sourcing harder in Q4 FY26, forcing greater reliance on domestic suppliers, though without production stoppages or revenue loss','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DIVISLAB','Strong multinational interest in Divi''s new peptide manufacturing capacity, particularly for GLP-1-related (obesity/diabetes) projects, positions the company to benefit from one of pharma''s fastest-growing global drug categories','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DIVISLAB','Persistent generic API pricing pressure globally continues to compress margins in the base generics business, even as custom synthesis and nutraceuticals partially offset the impact','risk',TRUE);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('DIVISLAB','upstream','Chemical raw material suppliers, incl. domestic sourcing amid West Asia disruption','risk','geopolitical logistics disruption forced greater reliance on domestic suppliers in Q4 FY26');
