INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('TORNTPHARM','Torrent Pharmaceuticals','NSE','Pharma','Branded Generics & Generics','Pharma','Torrent Pharmaceuticals develops, manufactures and markets branded generic pharmaceutical formulations across cardiovascular, central nervous system, gastrointestinal, diabetes and other therapeutic areas, primarily in India and Brazil, alongside a generics business in regulated markets like the US and Europe. Following its January 2026 acquisition of a controlling stake in JB Chemicals & Pharmaceuticals, it has significantly expanded its scale and market presence.','Torrent Pharmaceuticals FY26 & Q4 FY26 results coverage (InvestyWise, Tickertape); Screener.in; Yahoo Finance','Strong branded generics positioning in India and Brazil built over decades, now reinforced by the JB Pharma acquisition''s complementary portfolio and manufacturing scale — brand trust with prescribing physicians that is difficult and slow for new entrants to build.','Torrent Pharmaceuticals develops, manufactures and markets branded generic and generic pharmaceutical formulations across therapeutic areas including cardiovascular, central nervous system, and diabetes, selling primarily in India and Brazil under its own brands, plus generics in regulated markets like the US and Europe — and now, following the JB Pharma acquisition, an expanded India and international branded generics footprint.','The JB Pharma acquisition is a genuine structural shift in Torrent''s value chain position — rather than only building organically, the company is now consolidating scale through M&A, which changes both its growth profile and its balance sheet risk simultaneously.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('TORNTPHARM','2026-03-31','revenue_growth_pct',21,'%','Revenue Growth (FY26)','Q4 alone grew 42% YoY, reflecting the JB Pharma acquisition consolidation.','verified');
