INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('TORNTPHARM','2026-03-31','debt_equity_pct',85.45,'%','Debt / Equity','Meaningfully leveraged, largely reflecting the JB Pharma acquisition financing.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TORNTPHARM','2026-03-31','bull','FY26 consolidated revenue grew 21% to ₹13,980 crore with Q4 alone surging 42% YoY, driven by the acquisition of a controlling stake in JB Chemicals & Pharmaceuticals (effective January 2026) — a transformative, revenue-accretive deal, not just organic growth.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TORNTPHARM','2026-03-31','bull','Geographic growth was broad-based: India base business +15%, US +24%, Brazil +24%, and even Germany grew 10% despite supply chain challenges — strength across multiple markets, not dependent on any single region.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TORNTPHARM','2026-03-31','bull','A zero-observation US FDA inspection in April 2026 (no Form 483 issued) at a key facility signals strong regulatory compliance, particularly supportive of the oncology portfolio''s US market standing.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TORNTPHARM','2026-03-31','bear','Debt-to-equity of 85.45% is meaningfully elevated, largely a function of financing the JB Pharma acquisition — successful integration and deleveraging execution now matter as much as the underlying pharma business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TORNTPHARM','2026-03-31','bear','The approved ₹5,000 crore QIP fundraising plan signals the company may need additional equity capital, which could dilute existing shareholders depending on how and when it''s executed.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('TORNTPHARM','2026-03-31','bear','At a P/E near 72-73x, the stock already prices in successful JB Pharma integration and continued strong execution, leaving limited room for integration missteps or delays.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TORNTPHARM','The completed acquisition of a controlling stake in JB Chemicals & Pharmaceuticals (effective January 2026) is the single largest structural event in Torrent''s recent history, reshaping both its revenue base and its balance sheet','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TORNTPHARM','A zero-observation US FDA inspection in April 2026 strengthens Torrent''s regulatory standing in the US market, particularly for its oncology portfolio','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('TORNTPHARM','Elevated leverage from the JB Pharma acquisition, combined with a planned ₹5,000 crore QIP fundraise, means integration execution and capital structure management are now as important to the investment case as underlying drug demand','risk',TRUE);
