INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('ZYDUSLIFE','Zydus Lifesciences','NSE','Pharma','Diversified Pharma & Consumer Wellness','Pharma','Zydus Lifesciences develops, manufactures and markets pharmaceutical formulations across North America generics, India branded formulations, international markets, and a growing biosimilars pipeline, alongside a distinct Consumer Wellness division selling market-leading over-the-counter brands (Glucon-D, Nycil, Sugar Free, Complan, Nutralite). It is one of India''s most diversified pharmaceutical and consumer health companies, ranking 3rd among US generic companies by prescription volume.','Zydus Lifesciences FY26 & Q4 FY26 results coverage (Business Standard, Groww, InvestyWise); Screener.in','Rare diversification across prescription generics, branded formulations, biosimilars and market-leading consumer wellness brands (Glucon-D, Sugar Free, Nycil all rank #1 in their categories) — a breadth of moats across genuinely different businesses that few pure pharmaceutical peers can match.','Zydus Lifesciences develops, manufactures and sells pharmaceutical formulations across generics (primarily North America), branded formulations (India), consumer wellness products, and international markets, alongside an increasingly important biosimilars pipeline — a diversified pharmaceutical and consumer health company spanning both prescription and over-the-counter products.','Zydus''s Consumer Wellness segment (Glucon-D, Nycil, Sugar Free, Complan, Nutralite) is an unusual feature among pure pharmaceutical companies in this dataset — it gives Zydus a direct-to-consumer branded goods business layered on top of its core prescription drug manufacturing, diversifying its value chain position beyond a typical pharma company''s B2B-heavy model.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ZYDUSLIFE','2026-03-31','revenue_growth_pct',17,'%','Revenue Growth (FY26)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ZYDUSLIFE','2026-03-31','pat_growth_pct',11,'%','PAT Growth (FY26)','Q4 alone grew a more modest 8.7% YoY.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ZYDUSLIFE','2026-03-31','us_revenue_share_pct',40,'%','North America Share of Q4 Revenue','Zydus ranks 3rd among US generic companies by prescription volume (TRx).','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ZYDUSLIFE','2026-03-31','consumer_wellness_share_pct',20,'%','Consumer Wellness Share of Q4 Revenue','Includes market-leading brands Glucon-D, Sugar Free and Nycil.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ZYDUSLIFE','2026-03-31','bull','FY26 revenue grew 17% to ₹27,148 crore with PAT up 11% to ₹5,124 crore, and the company ranks 3rd among US generic companies by prescription volume (TRx) — a genuine, improving competitive position in the world''s largest pharma market, not just a domestic growth story.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ZYDUSLIFE','2026-03-31','bull','A truly diversified business — North America formulations (40% of revenue), India formulations (24%), Consumer Wellness (20%, with #1-ranked brands like Glucon-D, Sugar Free and Nycil), and International Markets (11%) — means no single segment or geography dominates the risk profile.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ZYDUSLIFE','2026-03-31','bull','Real innovation momentum: launched Tishtha (the world''s first Nivolumab biosimilar) and Anyra (India''s first indigenous Aflibercept biosimilar), plus semaglutide injections under three brands, entering co-marketing partnerships with Lupin and Torrent Pharmaceuticals — positioning Zydus at the frontier of India''s biosimilar and obesity-drug capabilities.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ZYDUSLIFE','2026-03-31','bear','Q4 FY26 PAT growth of just 8.7% lagged the 16% revenue growth, and full-year PAT growth (11%) also trailed revenue growth (17%) — a persistent margin dilution pattern worth watching even amid otherwise strong results.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ZYDUSLIFE','2026-03-31','bear','The $166.4 million acquisition of US-based Assertio (gaining oncology drug Rolvedon and a US specialty platform) adds real integration execution risk on top of Zydus''s existing complexity across four business segments and multiple geographies.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ZYDUSLIFE','2026-03-31','bear','The Consumer Wellness segment, while market-leading in its niches, operates in mature, low-growth categories (glucose supplements, prickly heat powder, sugar substitutes) that cap the segment''s contribution to overall company growth regardless of market share dominance.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ZYDUSLIFE','Zydus''s launch of Tishtha (world''s first Nivolumab biosimilar) and Anyra (India''s first indigenous Aflibercept biosimilar) positions the company at the frontier of India''s growing biosimilars industry, a high-value, high-complexity manufacturing niche','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ZYDUSLIFE','Entry into the obesity/diabetes therapy segment with semaglutide injections, including co-marketing partnerships with Lupin and Torrent Pharmaceuticals, taps directly into pharma''s fastest-growing global drug category','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ZYDUSLIFE','The $166.4 million Assertio acquisition expands Zydus''s US specialty drug platform but adds cross-border integration complexity on top of an already multi-segment, multi-geography business','neutral',TRUE);
