INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('ZYDUSLIFE',75.0,'Zydus Family Trust and related promoter entities','No pledge flagged; promoter group participated in a ₹1,100 crore share buyback via tender offer at ₹1,260/share, with Zydus Family Trust''s stake rising slightly from 74.96% to 74.98% post-buyback.','Completed a ₹1,100 crore share buyback via tender offer, alongside continued investment in biosimilars R&D and the $166.4 million Assertio acquisition to expand US specialty drug capabilities.','Mar 2026','Screener.in; Business Standard Q4 FY26 results coverage; Groww buyback coverage; InvestyWise');
