INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('DMART','Avenue Supermarts (DMart)','NSE','Consumer Services','Value Retail','Consumer Services','Avenue Supermarts operates the DMart chain of value-format supermarkets across India, selling food, non-food FMCG and general merchandise & apparel under an ''Everyday Low Cost - Everyday Low Price'' strategy built on owned real estate, bulk procurement and operational efficiency. It is India''s most profitable large-format organised retailer, though it also operates DMart Ready, a still-developing e-commerce and quick-commerce-adjacent channel.','Avenue Supermarts (DMart) FY26 & Q4 FY26 results coverage (Angel One, ScanX, Univest, Multibagg AI); Screener.in','Industry-leading store-level economics from owned (not leased) real estate and disciplined bulk procurement, built over two decades and extremely difficult for a new entrant to replicate at DMart''s scale and cost structure.','Avenue Supermarts operates the DMart chain of large-format, owned-real-estate supermarkets, buying in bulk directly from manufacturers and suppliers to offer everyday low prices, then selling directly to consumers — a value-retailing model built on owning (rather than leasing) store real estate and minimising operating costs at every step.','DMart''s traditional moat — owned real estate and bulk procurement driving the lowest cost-per-unit in Indian retail — is now being tested by quick commerce players who compete on convenience and speed rather than price, forcing DMart to build out DMart Ready even though that channel doesn''t yet match its physical stores'' economics.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DMART','2026-03-31','revenue_growth_pct',18.9,'%','Revenue Growth (Q4 YoY)','FY26 full-year revenue reached ₹68,821 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DMART','2026-03-31','pat_growth_pct',19.18,'%','PAT Growth (Q4 YoY)','Full-year PAT growth was more modest at 9.7%.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DMART','2026-03-31','store_count',500,'stores','Store Count','Record 85 stores added in FY26, including a record 58 in Q4 alone.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('DMART','2026-03-31','roe_pct',13.6,'%','Return on Equity','Modest for a stock trading near 80-85x earnings.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DMART','2026-03-31','bull','Q4 FY26 revenue grew 18.9% and profit 19.18% YoY, with the company crossing a landmark 500-store milestone after adding a record 85 stores in FY26 — genuine, accelerating physical expansion.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DMART','2026-03-31','bull','Two-year-and-older stores grew same-store sales 10.8% in Q4, up from 8.1% a year earlier, showing DMart''s core ''Everyday Low Price'' value proposition still resonates even as quick commerce competition intensifies.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DMART','2026-03-31','bull','Management''s long-term ambition of 2,000-2,200 full-fledged stores, against just 500 today, implies a multi-decade runway for physical expansion if the model continues to work in smaller Tier 2-3 cities.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DMART','2026-03-31','bear','Same-store sales growth has structurally decelerated from 12-15% in FY22-23 to a much lower range now, as post-COVID normalisation completes — the easy growth phase appears over.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DMART','2026-03-31','bear','DMart Ready (e-commerce) remains loss-making and, as its share of revenue grows, creates a blended margin drag versus DMart''s industry-leading physical-store economics — a genuine strategic tension between defending against quick commerce and protecting margins.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('DMART','2026-03-31','bear','Free cash flow turned negative and debt has risen as capex accelerates to fund store growth, while at a P/E near 80-85x, the stock prices in flawless execution with essentially no dividend to cushion any disappointment.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DMART','Intensifying quick commerce competition is reshaping Indian retail toward convenience and speed, a structural threat to DMart''s traditional value-and-bulk-buying model that management is countering with DMart Ready, still loss-making','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DMART','A brief geopolitical-tension-driven buying spike in March 2026 temporarily boosted sales before normalising, illustrating how even a value retailer''s short-term numbers can be swayed by external shocks unrelated to its core business','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('DMART','Deliberate expansion into smaller Tier 2-3 cities, where quick commerce competition is less intense, opens a large long-term store count runway but comes with lower per-household spending power than DMart''s established metro markets','tailwind',TRUE);
