INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('DMART','upstream','Owned real estate & store construction',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('DMART','downstream','Physical retail customers across 500 stores in 17 states/UTs',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('DMART','downstream','DMart Ready e-commerce customers','risk','still loss-making; margin-dilutive as its revenue share grows');
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('DMART','downstream','Tier 2-3 city expansion','tailwind','lower quick-commerce competition intensity, though also lower spending power per household');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('DMART',74.5,'Radhakishan Damani and family','No pledge flagged in current shareholding trackers.','Pays no dividend, reinvesting all capital into store expansion (capex rose sharply in FY26) and continued investment in DMart Ready and the DMart miniMAX small-format concept, both still loss-making.','Mar 2026','Screener.in; Angel One & ScanX FY26 results coverage; Univest analyst coverage; Axis Securities Q3 FY26 result update');
