INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('INDHOTEL','Indian Hotels Company (IHCL)','NSE','Consumer Services','Hotels & Hospitality','Consumer Services','The Indian Hotels Company (IHCL) owns, operates and manages hotels under the Taj, Vivanta, SeleQtions and Ginger brands across India and internationally, alongside adjacent hospitality businesses including F&B delivery (Qmin), boutique home stays (amã Stays & Trails) and resorts (Tree of Life). It is India''s largest and most storied hospitality company, part of the Tata Group, with an accelerating shift toward asset-light, management-fee-based growth.','Indian Hotels Company (IHCL) FY26 & Q4 FY26 results coverage (Hotelier India, MarketsMojo); Screener.in','The Taj brand''s century-plus reputation for luxury Indian hospitality, combined with an accelerating asset-light management-contract growth model that extends the brand''s reach without proportional capital investment — a durable, increasingly capital-efficient moat.','Indian Hotels Company (IHCL) owns, operates and manages hotels under the Taj, Vivanta, SeleQtions and Ginger brands, plus adjacent hospitality businesses (F&B delivery via Qmin, boutique stays via amã, resorts via Tree of Life), earning revenue from room bookings, food & beverage, and management fees on hotels it operates but doesn''t own — positioning it at the direct consumer-facing end of India''s hospitality and tourism value chain.','IHCL''s growing management-fee income (+22% in FY26) reflects a deliberate shift toward an asset-light growth model — expanding its brand footprint into hotels it manages but doesn''t own — a structurally different, higher-return growth path than the capital-intensive owned-hotel model that built the Taj brand originally.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('INDHOTEL','2026-03-31','revenue_growth_pct',16,'%','Revenue Growth (FY26)','FY26 consolidated revenue reached ₹9,971 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('INDHOTEL','2026-03-31','ebitda_margin_pct',34.9,'%','EBITDA Margin (FY26)','All-time high EBITDA of ₹3,477 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('INDHOTEL','2026-03-31','pat_cr',2084,'crore','PAT (FY26)','Best-ever annual profit; 16th consecutive quarter of record performance.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('INDHOTEL','2026-03-31','debt_equity',0.03,'x','Debt / Equity','Dramatically deleveraged from levels above 1x just a few years ago.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDHOTEL','2026-03-31','bull','FY26 delivered the company''s best-ever annual PAT of ₹2,084 crore on revenue of ₹9,971 crore (+16% YoY) and an all-time high EBITDA of ₹3,477 crore — the 16th consecutive quarter of record performance, an exceptional run of consistency.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDHOTEL','2026-03-31','bull','The balance sheet has been aggressively deleveraged, with debt-to-equity falling to a negligible 0.03x from much higher levels just a few years ago — rare financial discipline for a capital-intensive hospitality business, freeing up capacity for growth investment.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDHOTEL','2026-03-31','bull','Diversification beyond core hotels is real and growing: Qmin (100+ F&B outlets), amã Stays & Trails (370 bungalows), and Tree of Life (34 resorts) all expanding, alongside 22% growth in management fee income — a genuine asset-light growth engine layered on top of owned-hotel operations.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDHOTEL','2026-03-31','bear','Q4 FY26 PAT margin collapsed to 22.61% from 32.88% in Q3 FY26 — a 1,027 basis point sequential contraction — reflecting hospitality''s structural seasonality (Q3 winter travel peak vs Q4 lean season) that investors must factor into any single-quarter read.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDHOTEL','2026-03-31','bear','Management explicitly acknowledged the West Asia conflict as a headwind during FY26, a reminder that international travel demand and hospitality revenue can be directly affected by geopolitical events outside the company''s control.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('INDHOTEL','2026-03-31','bear','Rising employee costs (up to 23.74% of sales from 22.57%) alongside continued heavy capital expenditure on hotel renovation and expansion mean margin compression during any demand softening is a real, recurring risk, not a one-off.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INDHOTEL','Management explicitly cited the West Asia conflict as a FY26 headwind, directly linking Middle East geopolitical tensions to Indian hospitality demand and international travel patterns','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INDHOTEL','Growth in management fee income (+22%) and new hotel signings reflect an accelerating shift toward an asset-light expansion model, adding hotels to the portfolio without the capital intensity of ownership','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('INDHOTEL','Hospitality''s structural seasonality — Q3 winter peak versus Q4 lean season — means single-quarter margin swings are a normal, recurring feature of the business rather than a sign of deteriorating fundamentals','neutral',TRUE);
