INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('NAUKRI','Info Edge (Naukri)','NSE','Consumer Services','Online Classifieds & Marketplaces','Consumer Services','Info Edge (India) operates India''s leading online classifieds platforms — Naukri.com (recruitment), 99acres.com (real estate), Jeevansathi.com (matrimony) and Shiksha.com (education) — while also functioning as an active startup investor and incubator, holding significant stakes in companies including Eternal (Zomato) and PolicyBazaar. Founded by Sanjeev Bikhchandani in 1995, it pioneered India''s internet classifieds industry.','Info Edge FY26 & Q4 FY26 results coverage (Upstox, Storyboard18, Tickertape); Choice & Tijori Finance shareholding data; Bajaj Finserv company history','Category-leading network effects across Naukri''s 115-million-resume database and dominant brand recall in recruitment, reinforced by a two-decade head start and a startup investment track record (including an early stake in Eternal/Zomato) that gives Info Edge insight into and capital exposure to India''s broader digital economy.','Info Edge operates a portfolio of online classifieds and marketplace platforms — Naukri (recruitment), 99acres (real estate), Jeevansathi (matrimony), and Shiksha (education) — connecting job seekers, property buyers, and consumers with employers, property listings and educational institutions, while also acting as an investment holding vehicle for stakes in startups it has incubated or funded, most notably Eternal (Zomato).','Info Edge''s dual identity — an operating classifieds business plus a startup investment arm — means its value chain position spans both a direct-to-consumer digital marketplace and an indirect stake in companies like Eternal, already present elsewhere in this dataset, creating a real financial link between two companies that look unrelated on the surface.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('NAUKRI','2026-03-31','recruitment_revenue_growth_pct',12.05,'%','Recruitment Revenue Growth (Q4 YoY)','Naukri remains the largest contributor to overall revenue growth.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('NAUKRI','2026-03-31','annual_pat_growth_pct',9,'%','Consolidated PAT Growth (FY26)','FY26 profit reached ₹2,121 crore; quarterly profit is volatile due to investment gains/losses on stakes like Eternal (Zomato).','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('NAUKRI','2026-03-31','naukri_resume_db_mn',115,'million','Naukri Resume Database Size','Growing by ~21,000 resumes added daily.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('NAUKRI','2026-03-31','dividend_growth_pct',40,'%','Total FY26 Dividend Growth','Reflects management''s stated focus on increased cash returns to shareholders.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NAUKRI','2026-03-31','bull','The core Recruitment Solutions business (Naukri) remains a clear earnings engine with ~40% operating margins and durable monetisation, backed by a database of 115 million resumes growing by ~21,000 daily — a genuine, hard-to-replicate data and network moat.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NAUKRI','2026-03-31','bull','99acres and Jeevansathi both continued gaining market share and strengthening their positions in FY26, with 99acres'' web traffic time-share rising to 49% — real evidence of category leadership beyond just the flagship Naukri brand.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NAUKRI','2026-03-31','bull','Total FY26 dividend payout rose 40%, reflecting management''s explicit commitment to increased cash returns to shareholders even while continuing to fund AI investment and new product development.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NAUKRI','2026-03-31','bear','Recruitment billings growth decelerated materially after a strong FY25, and the Naukri Gulf business specifically slowed due to geopolitical headwinds in the Middle East, after delivering 20%+ growth in the first nine months of the year — a real, current external risk to a core growth driver.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NAUKRI','2026-03-31','bear','The education business (Shiksha) saw billings decline 13% YoY even as revenue grew, driven partly by AI-driven changes in how students search for education content online — a structural disruption risk specific to that vertical.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('NAUKRI','2026-03-31','bear','Info Edge''s reported quarterly profit is heavily distorted by investment gains and losses on its stakes in companies like Eternal (Zomato) and PolicyBazaar, making quarter-to-quarter profit comparisons genuinely difficult to interpret without separating the core classifieds business from the investment portfolio.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NAUKRI','Geopolitical headwinds in the Middle East slowed the Naukri Gulf recruitment business in Q4 FY26, after 20%+ growth in the first nine months of the year, directly linking regional tensions to a core India-adjacent revenue stream','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NAUKRI','AI-driven changes in how students search for educational content online are disrupting the Shiksha business, causing billings to decline even as reported revenue grew — an early signal of AI''s disruptive effect on traditional lead-generation business models','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('NAUKRI','Info Edge''s dating platform Aisle grew more than 30% in Q4 FY26, a small but genuinely fast-growing new vertical beyond the company''s four established classifieds businesses','tailwind',TRUE);
