INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('HINDZINC','Hindustan Zinc','NSE','Metals & Mining','Zinc, Lead & Silver Mining','Metals & Mining','Hindustan Zinc mines and refines zinc, lead and silver from integrated operations in Rajasthan, selling refined metal domestically and internationally. It is the world''s largest integrated zinc producer and among the top global silver producers, operating as a majority-owned subsidiary of Vedanta Limited, with the Government of India holding a significant minority stake.','Hindustan Zinc FY26 & Q4 FY26 results coverage (Sahi, Univest, MarketsMojo, Upstox); Screener.in','World''s largest integrated zinc producer with a best-in-class, low-cost operating structure and decades of mining rights across Rajasthan''s Zawar, Rajpura Dariba, Kayad, Rampura Agucha and Sindesar Khurd mines — scale and resource access that would take a competitor decades to replicate.','Hindustan Zinc mines zinc, lead and silver ore, then smelts and refines it into finished metal, selling into steel galvanisation (zinc''s primary end-use), battery and industrial applications (lead), and jewellery, electronics and solar/EV manufacturing (silver) — an integrated upstream-to-refined-metal producer rather than a pure miner.','As a majority-owned subsidiary of Vedanta Limited, Hindustan Zinc''s capital allocation — including how much cash gets paid out as dividends versus reinvested — is significantly influenced by its parent''s own financial needs, a structural governance dynamic that doesn''t apply to standalone metals companies.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HINDZINC','2026-03-31','revenue_growth_pct',19.8,'%','Revenue Growth (FY26)','FY26 revenue reached ₹40,844 crore; Q4 alone grew 49% YoY.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HINDZINC','2026-03-31','pat_growth_pct',33.6,'%','PAT Growth (FY26)','Record FY26 PAT of ₹13,832 crore; Q4 alone grew 68% YoY.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HINDZINC','2026-03-31','silver_revenue_growth_pct',61,'%','Silver Revenue Growth (FY26)','Silver EBIT nearly matched the entire zinc-lead segment''s profit contribution in Q4 — the real driver behind this year''s results.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HINDZINC','2026-03-31','net_debt_equity',0.36,'x','Debt / Equity','Improved sharply from 0.80x a year earlier.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDZINC','2026-03-31','bull','Record FY26 PAT of ₹13,832 crore (+33.6% YoY) and Q4 EBITDA margin of 57% reflect exceptional operating leverage, with net worth growing 70% in a single year driven almost entirely by retained earnings.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDZINC','2026-03-31','bull','Silver, not zinc, was the real story: FY26 silver revenue grew 61% to ₹9,841 crore on a global price surge (industrial demand from solar, EVs and electronics, plus safe-haven buying), with Q4 silver EBIT of ₹3,396 crore roughly matching the entire zinc-lead business''s profit.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDZINC','2026-03-31','bull','Debt-to-equity improved sharply to 0.36x from 0.80x, and the company is targeting a doubling of metal production to 2 MTPA by 2030, backed by a strong pipeline including roaster and fertiliser plant projects and new critical minerals bidding.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDZINC','2026-03-31','bear','Parent Vedanta Limited has been extracting aggressive special dividends from Hindustan Zinc (over ₹8,000 crore in FY25-26 alone) to help service its own group debt — minority shareholders, including the Government of India, have raised concerns this prioritises the parent''s needs over long-term reinvestment in the subsidiary.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDZINC','2026-03-31','bear','Promoter Vedanta has been steadily reducing its stake (from 63.42% to 60.71% over the year), which some analysts read as a signal of monetising near peak valuations rather than long-term conviction.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HINDZINC','2026-03-31','bear','Mining royalties rose 47% YoY in Q4 as they scale directly with metal prices — an unavoidable cost drag that grows precisely when the business looks most profitable, and the exceptional Q4 growth rate is unlikely to repeat if global zinc or silver prices normalise.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDZINC','A global silver price surge, driven by industrial demand from solar, EVs and electronics plus safe-haven buying, has made silver roughly as profitable as the entire zinc-lead business for Hindustan Zinc — India''s largest silver producer','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDZINC','Parent Vedanta''s pattern of extracting large special dividends to service its own debt has drawn minority shareholder concern about whether Hindustan Zinc is being managed for long-term value creation or short-term cash extraction','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HINDZINC','Short-seller allegations against Vedanta group entities, including Hindustan Zinc, remain unresolved; auditors signed off without qualification and management calls them baseless, but the matter is worth continued monitoring','neutral',TRUE);
