INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('HINDZINC',60.71,'Vedanta Limited','No pledge flagged; promoter (Vedanta) has been reducing its stake, down from 63.42% to 60.71% over the past year.','Declared an early FY27 interim dividend of ₹11/share (₹4,648 crore total, of which Vedanta receives ~₹2,821 crore as majority owner); simultaneously funding mine expansion toward a 2 MTPA production target by 2030.','Mar 2026','Screener.in; Sahi & Univest FY26 results analysis; DSIJ & Upstox coverage');
