INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('JINDALSTEL','Jindal Steel','NSE','Metals & Mining','Integrated Steel','Metals & Mining','Jindal Steel manufactures and sells steel products across flat and long categories, with integrated captive iron ore, thermal coal and coking coal mining operations that secure raw material supply and provide cost advantages. Recently renamed from Jindal Steel & Power after separating its power business, it is one of India''s major integrated steel producers, undergoing a significant capacity expansion at its Angul facility.','Jindal Steel FY26 & Q4 FY26 results coverage (InvestyWise, MarketsMojo); Screener.in; company Q4 FY26 earnings presentation','Vertical integration across captive iron ore, thermal coal and coking coal mining feeding directly into steelmaking, combined with a newly doubled capacity base at Angul — raw material security and scale that pure steelmakers without captive mines cannot match on cost.','Jindal Steel mines its own iron ore, coal and coking coal, then converts these raw materials into finished steel products (flats and longs) at its integrated plants, selling to construction, infrastructure and industrial customers — a vertically integrated model that captures value from raw material extraction through to finished steel.','The company''s captive mining operations for iron ore, thermal coal and coking coal reduce its exposure to volatile global raw material markets compared to steel producers that must buy these inputs externally, a structural cost advantage reinforced by the recently completed Angul capacity doubling.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('JINDALSTEL','2026-03-31','production_growth_pct',14,'%','Production Growth (FY26)','FY26 production reached 9.25 million tonnes; sales grew 9% to 8.68 million tonnes.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('JINDALSTEL','2026-03-31','ebitda_per_tonne',10482,'₹/tonne','Adjusted EBITDA per Tonne','FY26 adjusted EBITDA of ₹9,099 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('JINDALSTEL','2026-03-31','pat_growth_pct',18,'%','PAT Growth (FY26)','Q4 alone saw a 448% sequential surge from a weak Q3, though YoY comparisons are distorted by an exceptional prior-year base.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('JINDALSTEL','2026-03-31','net_debt_ebitda',1.5,'x','Net Debt / EBITDA Target','Company''s stated ceiling for this ratio as it pursues continued deleveraging.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JINDALSTEL','2026-03-31','bull','The Angul facility expansion from 6.0 to 12.0 MTPA was successfully completed in FY26, doubling capacity at the company''s key growth site, alongside the successful ramp-up of the 1,050 MW captive Shree Bhoomi Power Plant.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JINDALSTEL','2026-03-31','bull','FY26 production of 9.25 million tonnes (+14% YoY) met guidance despite a volatile global demand environment, with captive iron ore, thermal coal and coking coal mines reinforcing raw material security and cost advantages across the value chain.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JINDALSTEL','2026-03-31','bull','The company is pursuing genuine AI-driven operational transformation — including ''JARVIS'' for real-time visibility and autonomous plant initiatives at Raigarh and Angul — aimed at optimising production planning, safety and supply chain reliability.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JINDALSTEL','2026-03-31','bear','Q4 FY26 profit of ₹1,044.75 crore, while a dramatic sequential recovery from a weak Q3, actually declined sharply on a year-on-year basis versus an exceptionally strong prior-year quarter — the headline growth narrative depends heavily on which comparison period is used.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JINDALSTEL','2026-03-31','bear','10.91% of promoter shares are pledged, a real liquidity and governance signal worth monitoring even though overall promoter holding (62.7%) has remained stable.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('JINDALSTEL','2026-03-31','bear','Return on equity of just 9.84% over the past three years is modest for a capital-intensive steel producer that has invested heavily in expansion, and FY26 capital expenditure exceeded operating cash flow, requiring debt funding for growth.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JINDALSTEL','Global trade uncertainty and a volatile demand environment created headwinds throughout FY26, even as the company still met its production guidance through captive raw material security and operational discipline','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JINDALSTEL','The completed Angul expansion (6 to 12 MTPA) and successful Shree Bhoomi captive power plant ramp-up materially increase both capacity and cost competitiveness heading into FY27','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('JINDALSTEL','AI-driven initiatives like ''JARVIS'' and autonomous plant operations at Raigarh and Angul represent a genuine operational technology upgrade aimed at safety, efficiency and supply chain reliability','tailwind',TRUE);
