INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('JINDALSTEL',62.7,'Jindal family, via OPJ Trading Private Limited (18.47%) and other promoter entities','10.91% of promoter shares are pledged, a factor worth monitoring despite otherwise stable promoter holding.','Invested ₹9,574-12,322 crore in FY26 capex (source estimates vary) for the Angul expansion and raw material integration; targets keeping net debt/EBITDA below 1.5x while pursuing continued growth.','Mar 2026','Screener.in; MarketsMojo Q4 FY26 result analysis; company Q4 FY26 earnings presentation');
