INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('VEDL','Vedanta Limited','NSE','Metals & Mining','Diversified Natural Resources','Metals & Mining','Vedanta Limited is India''s leading diversified natural resources company, historically spanning zinc, aluminium, oil & gas, power and iron & steel. In FY26, Vedanta completed one of the largest corporate restructurings in Indian corporate history, demerging its aluminium, oil & gas, power, and iron & steel businesses into separately listed entities, leaving the remaining Vedanta Limited more narrowly focused, while it continues to hold a majority stake in separately-listed Hindustan Zinc.','Vedanta FY26 & Q4 FY26 results coverage (Tickertape); Screener.in','Majority ownership of Hindustan Zinc, the world''s largest integrated zinc producer, remains Vedanta''s core enduring asset post-demerger — a stake built over decades that would be effectively impossible to reassemble today.','Following the FY26 demerger, Vedanta Limited''s most significant remaining asset is its majority stake in Hindustan Zinc, alongside residual natural resources operations; the aluminium, oil & gas, power and iron & steel businesses that once made Vedanta a fully diversified conglomerate now operate as independent, separately listed companies.','Vedanta''s relationship with Hindustan Zinc is now the central value chain link for the parent company — dividends flowing up from Hindustan Zinc to Vedanta (and from Vedanta further up to Twin Star Holdings and ultimately Vedanta Resources) are a direct, quantifiable financial connection between two companies in this dataset.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('VEDL','2026-03-31','revenue_growth_pct',47.48,'%','Revenue Growth (Q4 YoY)','Q4 FY26 revenue of ₹24,609 crore; FY26 full-year revenue reached ₹78,437 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('VEDL','2026-03-31','pat_growth_pct',88.51,'%','PAT Growth (Q4 YoY)','Q4 FY26 consolidated net profit of ₹9,352 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('VEDL','2026-03-31','promoter_pct_ref',56.38,'%','Promoter Group Holding (context metric)','Twin Star Holdings alone holds 40.02%; also recorded in the management profile.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('VEDL','2026-03-31','market_cap_growth_pct',62.6,'%','Market Cap Growth (1-Year)','Reflects value unlocked through the FY26 demerger, though tempered by recent promoter share-sale news.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VEDL','2026-03-31','bull','Q4 FY26 consolidated net profit surged 88.51% YoY to ₹9,352 crore on 47.48% revenue growth, and the completed demerger of aluminium, oil & gas, power and iron & steel into separately listed entities has been credited with unlocking real shareholder value — market cap grew 62.6% over the past year.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VEDL','2026-03-31','bull','The remaining Vedanta Limited retains a majority stake in Hindustan Zinc, a genuinely high-quality, high-margin business elsewhere in this dataset, giving continuing shareholders direct exposure to the zinc-silver story without the complexity of the pre-demerger conglomerate structure.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VEDL','2026-03-31','bull','The demerger itself created independent, sector-focused entities that can now be valued and managed on their own merits, addressing a long-standing conglomerate discount that affected the pre-restructuring Vedanta.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VEDL','2026-03-31','bear','Promoter entity Twin Star Holdings was reported to be offloading up to 6.5 crore shares via block deal at a discount to the prevailing price just weeks after the demerger completed — the stock crashed 7.76% in a single session on this news, a genuinely current and material promoter-selling event.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VEDL','2026-03-31','bear','Screening tools flag that Vedanta may be capitalising interest costs, an accounting practice that can make reported profitability look stronger than underlying cash generation — worth independent scrutiny.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('VEDL','2026-03-31','bear','Post-demerger, Vedanta Limited''s business scope and historical financial comparisons are fundamentally altered, making it genuinely difficult to assess the ''new'' Vedanta against its own multi-year track record without careful adjustment for what businesses have been spun off.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('VEDL','The completed FY26 demerger into separately listed aluminium, oil & gas, power and iron & steel entities is one of the largest corporate restructurings in Indian history, fundamentally reshaping what ''Vedanta Limited'' now represents as an investment','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('VEDL','Promoter entity Twin Star Holdings'' reported share sale, just weeks after the demerger, triggered a sharp single-day stock decline and raises questions about near-term promoter conviction even as the group highlights long-term value creation','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('VEDL','Continuing majority ownership of Hindustan Zinc means Vedanta''s own results remain closely tied to global zinc and silver prices, the same commodity exposure driving Hindustan Zinc''s results elsewhere in this dataset','neutral',TRUE);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('VEDL','upstream','Majority stake in Hindustan Zinc','tailwind','the core remaining high-quality asset post-demerger');
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('VEDL','upstream','Residual natural resources operations not yet demerged',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('VEDL','downstream','Dividend upstreaming to Twin Star Holdings & Vedanta Resources','risk','group-level debt servicing needs influence capital allocation decisions');
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('VEDL','downstream','Independently listed demerged entities (aluminium, oil & gas, power, iron & steel)',NULL,NULL);
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('VEDL',56.38,'Twin Star Holdings (40.02%) and the broader Vedanta Resources promoter group (Anil Agarwal family)','Reports indicate Twin Star Holdings sought to sell up to 6.5 crore shares via block deal with a 90-day lock-up on its remaining stake — a notable, current promoter liquidity event worth monitoring closely.','Completed the FY26 demerger restructuring; continues to rely significantly on dividend upstreaming from majority-owned Hindustan Zinc to support group-level capital needs, including Vedanta Resources'' international debt servicing.','Mar 2026','Screener.in; Tickertape FY26 results & promoter transaction coverage');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,status) VALUES ('VEDL','2026-03-31','market_cap_cr',107985,'crore','Market Capitalisation','verified');
INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('AMBUJACEM','Ambuja Cements','NSE','Cement','Cement Manufacturing (Adani Group)','Cement','Ambuja Cements manufactures, markets and sells cement and ready-mix concrete to home builders, developers, institutional clients, masons, contractors and construction professionals across India. Part of the Adani Group''s cement platform (which also includes ACC, Sanghi and Penna Cement, recently consolidated under a ''One Cement Platform'' strategy), it is one of India''s largest cement producers by volume.','Ambuja Cements FY26 & Q4 FY26 results coverage (Upstox, Tribune India, ScanX earnings call, TradeBrains); Screener.in','Scale as part of the Adani Group''s consolidated cement platform (Ambuja, ACC, Sanghi, Penna), a debt-free balance sheet with the highest credit ratings in the sector, and an extensive pan-India plant and distribution network built over decades.','Ambuja Cements mines limestone and other raw materials, manufactures cement and clinker at integrated plants and grinding units across India, and sells finished cement and ready-mix concrete to builders, contractors and institutional construction customers — a vertically integrated cement manufacturer within the broader Adani Group materials portfolio.','As part of Adani Group''s cement consolidation strategy (Ambuja, ACC, Sanghi, Penna, Orient all being merged under one platform), Ambuja''s value chain now includes integrating recently acquired plants whose cost structures and regional demand exposure (like Penna''s South India concentration) differ meaningfully from its legacy assets.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('AMBUJACEM','2026-03-31','volume_growth_pct',16,'%','Sales Volume Growth (FY26)','Record annual volume of 73.7 million tonnes.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('AMBUJACEM','2026-03-31','normalized_pat_growth_pct',17,'%','Normalised PAT Growth (FY26)','Reported PAT growth of 6% included one-time accounting adjustments; normalised PAT of ₹2,647 crore better reflects core performance.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('AMBUJACEM','2026-03-31','ebitda_per_tonne',887,'₹/tonne','EBITDA per Tonne (FY26)','Q4 alone saw EBITDA/tonne fall to ₹735 from ₹1,028 a year earlier, due to rising fuel, freight and packaging costs.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('AMBUJACEM','2026-03-31','capacity_mtpa',109,'MTPA','Current Cement Capacity','Targeting 119 MTPA by FY27 and 155 MTPA by FY30.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AMBUJACEM','2026-03-31','bull','FY26 delivered record annual volume of 73.7 million tonnes (+16% YoY) and normalised EBITDA growth of 31% to ₹6,539 crore, with volumes growing well ahead of the broader industry despite a genuinely challenging demand environment.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AMBUJACEM','2026-03-31','bull','The company completed the amalgamation of Sanghi Industries and Penna Cement under its ''One Cement Platform'' strategy, consolidating the Adani Group''s cement assets, while remaining completely debt-free with a net worth of ₹71,846 crore.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AMBUJACEM','2026-03-31','bull','Capacity expansion is on track toward 119 MTPA by FY27 and a longer-term target of 155 MTPA by FY30, with the company targeting a ₹150-200 per tonne cost reduction through better fuel mix, renewable energy and logistics optimisation.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AMBUJACEM','2026-03-31','bear','Q4 FY26 EBITDA margin fell sharply to 13.2-13.4% from 18-18.7% a year earlier, and EBITDA per tonne dropped to ₹735 from ₹1,028, driven by West Asia conflict-linked packing cost escalations, higher freight, and a weaker rupee — real, current cost pressures management expects to persist into H1 FY27.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AMBUJACEM','2026-03-31','bear','Recently acquired Penna and Sanghi assets (19 million tonnes of combined capacity) are dragging down blended profitability — normalised EBITDA per tonne for legacy Ambuja and ACC assets alone is at least ₹800, meaning the acquired plants are a genuine, quantifiable integration drag.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('AMBUJACEM','2026-03-31','bear','Reported FY26 PAT growth of 6% included one-time and accounting-related adjustments, meaning investors need to look at the normalised 17% growth figure to understand true underlying performance — a reminder that headline numbers require careful reading.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('AMBUJACEM','West Asia conflict-linked cost escalations in packing materials, freight and a weaker rupee pushed Q4 FY26 production costs to a peak of ₹4,500 per tonne, directly linking Middle East geopolitics to Indian cement industry costs','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('AMBUJACEM','GST 2.0 reforms and industry consolidation reshaped the competitive and cost landscape for cement companies during FY26, alongside adverse weather and state elections affecting regional demand patterns','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('AMBUJACEM','A below-normal monsoon forecast for FY27 is expected to constrain industry cement demand growth to around 5%, below Ambuja''s own targeted 8% volume growth, meaning the company is targeting share gains rather than relying purely on market growth','risk',TRUE);
