INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('AMBUJACEM','upstream','Coal, petcoke & alternative fuel supply','risk','West Asia conflict-linked freight and packing cost escalations hit Q4 FY26 costs');
