INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('AMBUJACEM',67.3,'Adani Group','No pledge flagged in current shareholding trackers.','Declared a dividend of ₹2/share; remains debt-free while funding capacity expansion (10.7 MTPA of new grinding capacity and 7 MTPA of clinker capacity commissioned in FY26) entirely through internal accruals.','Mar 2026','Screener.in; Upstox & Tribune India FY26 results coverage; ScanX JM Financial-hosted earnings call summary');
