INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('SHREECEM','Shree Cement','NSE','Cement','Cement Manufacturing','Cement','Shree Cement manufactures and sells cement, with a growing Ready-Mix Concrete (RMC) business and a strong premium products push, positioning itself as India''s third-largest cement producer by capacity. The company is known for industry-leading green energy usage and cost discipline, recently commissioning a new integrated plant in Karnataka to expand its national footprint.','Shree Cement FY26 & Q4 FY26 results coverage (Angel One, ScanX, MarketsMojo, Alpha Spread earnings call); Screener.in','Industry-leading cost discipline anchored in extensive captive green power capacity (888.6 MW) and water-positive operations, combined with a premiumising product mix and a multi-decade reputation for capital efficiency in cement manufacturing.','Shree Cement manufactures cement and clinker at integrated plants across India, increasingly supplemented by a growing Ready-Mix Concrete business, selling to builders, contractors and institutional construction customers — a traditional cement manufacturer now diversifying into higher-value adjacent concrete products.','Shree Cement''s heavy investment in captive green power (888.6 MW, 61% of consumption) and water-positive, zero-liquid-discharge operations reflects a genuine sustainability-driven cost strategy, distinct from peers competing primarily on scale or acquisition-led consolidation.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SHREECEM','2026-03-31','volume_growth_pct',11,'%','Cement Volume Growth (Q4 YoY)','Premium products rose to 22% of trade volume from 16% a year earlier.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SHREECEM','2026-03-31','revenue_growth_pct',10.29,'%','Revenue Growth (Q4 YoY)','Q4 net sales of ₹6,101 crore, up 27.09% sequentially from a weak Q3.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SHREECEM','2026-03-31','operating_margin_pct',22.68,'%','Operating Margin (Q4)','Down 314 basis points YoY from 25.82%, though up 295 bps sequentially.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SHREECEM','2026-03-31','roe_pct',7.66,'%','Return on Equity','Deteriorating from a 10.04% average, signalling weakening capital efficiency despite volume growth.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHREECEM','2026-03-31','bull','Q4 FY26 profit surged 97.11% sequentially to ₹525.69 crore, reversing three consecutive quarters of subdued performance, with cement volume up 11% YoY and premium product mix rising to 22% of trade volume from 16% a year earlier.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHREECEM','2026-03-31','bull','The company commissioned its Kodla integrated project in Karnataka, lifting installed capacity to 69.3 MTPA, while maintaining a genuinely strong balance sheet: zero promoter pledging, net cash position, and a debt-to-EBITDA of just 0.55x.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHREECEM','2026-03-31','bull','Total FY26 dividend rose 36% to ₹150/share, and green electricity reached 61% of total consumption in Q4 — among the highest in the Indian cement industry, backed by 888.6 MW of captive green power capacity.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHREECEM','2026-03-31','bear','Despite the strong sequential recovery, Q4 FY26 profit actually declined 8.47% year-on-year, and operating margin compressed 314 basis points YoY — the headline ''strong quarter'' narrative depends heavily on which comparison period investors focus on.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHREECEM','2026-03-31','bear','Return on equity has deteriorated from a 10.04% average to 7.66% latest, and five-year EBIT growth stands at -5.66% — genuine, multi-year evidence of sustained margin and capital efficiency pressure, not just a one-quarter blip.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SHREECEM','2026-03-31','bear','At a P/E near 50x and P/BV of 4.01x, the stock carries an extremely premium valuation despite these underlying profitability challenges, and analyst opinion is genuinely split — Citi maintains Buy while Morgan Stanley maintains Underweight on the same results.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SHREECEM','West Asia conflict-linked cost inflation in fuel, freight and packaging is a shared industry-wide pressure also affecting Ambuja Cements elsewhere in this dataset, though Shree''s captive green power partially insulates it from fuel cost volatility','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SHREECEM','Management narrowed its pricing gap with the largest industry peer from roughly ₹50 to ₹15-20 per bag, choosing a volume-focused strategy over initiating a price war, a deliberate competitive positioning choice','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SHREECEM','A moderate monsoon forecast and geopolitical tensions are flagged as short-term risks to FY27 demand, even as the company guides to 10% YoY volume growth','risk',TRUE);
