INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('SHREECEM','downstream','Builders, contractors & institutional construction customers',NULL,NULL);
INSERT INTO chain_nodes (ticker,direction,node_name,tag,note) VALUES ('SHREECEM','downstream','Ready-Mix Concrete (RMC) customers — expanding to 36 plants','tailwind','a nascent but growing higher-value adjacent business');
INSERT INTO mgmt_profiles (ticker,promoter_pct,promoter_who,pledge_note,capital_note,as_of,source_note) VALUES ('SHREECEM',60,'Bangur family (exact current promoter percentage not independently disclosed in available results coverage; institutional holdings of 24.97% and public holding of 15.32% imply a promoter stake of roughly 60%)','No promoter share encumbrance confirmed for FY26 per SEBI Reg 31(4) filing.','Declared a total FY26 dividend of ₹150/share, up 36% YoY, while guiding FY27 capex of approximately ₹1,500 crore focused on RMC plants, railway sidings and the Meghalaya project.','Mar 2026','ScanX regulatory filing coverage; Angel One & MarketsMojo Q4 FY26 result analysis; Alpha Spread earnings call summary');
