INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('SOLARINDS','Solar Industries India','NSE','Chemicals','Industrial Explosives & Defence','Chemicals','Solar Industries India manufactures industrial explosives and initiating devices used in mining, infrastructure and defence applications, and has expanded into defence ordnance and specialty chemicals manufacturing. It is India''s largest manufacturer in its category, serving both domestic and growing international markets.','Solar Industries Q4 FY26 results coverage (MarketsMojo); Screener.in','India''s largest manufacturer of industrial explosives and initiating devices, with deep regulatory approvals, safety certifications and manufacturing scale that are extremely difficult and slow for a new entrant to replicate in this tightly regulated industry.','Solar Industries manufactures industrial explosives, initiating devices and defence ordnance, selling to mining companies (for rock blasting), infrastructure contractors (for construction and demolition), and defence customers (ordnance and munitions) — an upstream industrial input supplier whose products enable extraction and construction activity elsewhere in the economy.','Solar Industries'' expansion into defence ordnance manufacturing represents a deliberate diversification beyond its traditional commercial explosives business, tapping into India''s growing indigenous defence manufacturing push alongside companies like HAL and Mazagon Dock elsewhere in this dataset.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SOLARINDS','2026-03-31','revenue_growth_pct',40.9,'%','Revenue Growth (Q4 YoY)','All-time high quarterly net sales of ₹3,052.75 crore; significantly accelerated from FY25''s 24.20% annual growth rate.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SOLARINDS','2026-03-31','pat_growth_pct',69.95,'%','PAT Growth (Q4 YoY)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SOLARINDS','2026-03-31','operating_margin_pct',27.06,'%','Operating Margin (Q4)','Within the company''s historical 24-28% range despite inflationary pressures.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('SOLARINDS','2026-03-31','pat_margin_pct',18.21,'%','PAT Margin (Q4)','Expanded from 15.98% a year earlier.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SOLARINDS','2026-03-31','bull','Q4 FY26 net sales hit an all-time high of ₹3,052.75 crore, up 40.90% YoY — a significant acceleration from FY25''s already-strong 24.20% annual growth rate, driven by robust demand across defence, infrastructure and mining segments.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SOLARINDS','2026-03-31','bull','PAT grew even faster than revenue (69.95% YoY) with PAT margin expanding to 18.21% from 15.98%, demonstrating genuine operating leverage and pricing power rather than just volume-driven growth.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SOLARINDS','2026-03-31','bull','A stable, high promoter holding of 73.15% with minimal pledging (1.76%) and consistent execution across recent quarters reflect strong governance and management confidence in the company''s expanding defence and industrial explosives franchise.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SOLARINDS','2026-03-31','bear','The business is inherently tied to cyclical mining, infrastructure and defence procurement cycles — the exceptional 40%+ revenue growth rate seen in Q4 FY26 may not be sustainable at the same pace if any of these underlying demand drivers slow.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SOLARINDS','2026-03-31','bear','As a manufacturer of explosives and defence ordnance, Solar Industries operates in a highly regulated, safety-sensitive industry where any operational incident or regulatory change could have outsized reputational and financial consequences.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('SOLARINDS','2026-03-31','bear','Foreign institutional investor holdings have been gradually declining for three consecutive quarters (from 7.11% to 6.60%), which, while likely profit-booking after a strong rally, is worth monitoring for signs of waning international conviction.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SOLARINDS','Strong order books and expanding international operations reflect Solar Industries'' growing role beyond India''s domestic mining and infrastructure explosives market','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SOLARINDS','India''s defence indigenisation push provides a structural tailwind for Solar Industries'' expanding defence ordnance manufacturing business, part of a broader domestic defence manufacturing ecosystem','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('SOLARINDS','As a safety-sensitive explosives and ordnance manufacturer, the company operates under continuous regulatory scrutiny where any incident or policy shift could materially affect operations','risk',TRUE);
