INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('GAIL','GAIL (India)','NSE','Oil & Gas','Natural Gas Transmission & Marketing (PSU)','Oil & Gas','GAIL (India) transports natural gas through its pipeline network (Natural Gas Transmission), buys and resells gas to industrial and commercial customers (Natural Gas Marketing), distributes gas to households and vehicles (City Gas), and converts gas into petrochemical products. It is India''s largest natural gas transmission and marketing company, majority-owned by the Government of India.','GAIL FY26 & Q4 FY26 results coverage (ChartAlert, Univest, PSU Connect); Screener.in','An extensive, largely irreplaceable national natural gas pipeline network built over decades with government backing — a genuine infrastructure moat in the regulated transmission business, even though the marketing and petrochemical segments face open commodity competition.','GAIL sits in the middle of India''s natural gas value chain — it transports gas from producers (like ONGC) through its pipeline network, markets and resells gas to industrial customers, distributes gas to city consumers, and converts a portion into petrochemical products, making it both an infrastructure operator and a commodity trader within the same company.','GAIL''s dual nature — part regulated infrastructure utility (transmission, which behaves like a toll road), part commodity trader (marketing and petrochemicals, which behaves like a volatile trading business) — means its overall results can look confusing unless these segments are understood separately, exactly as FY26 demonstrated.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('GAIL','2026-03-31','transmission_ebit_growth_pct',13.5,'%','Natural Gas Transmission EBIT Growth','The one structural bright spot — regulated, annuity-like earnings grew steadily even as other segments struggled.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('GAIL','2026-03-31','pat_margin_pct',5.3,'%','PAT Margin (FY26)','Down sharply from 8.8% in FY25.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('GAIL','2026-03-31','petrochem_ebit_cr',-1410,'crore','Petrochemicals EBIT (FY26)','Swung to a deep loss from near-breakeven the prior year.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('GAIL','2026-03-31','operating_cf_growth_pct',-28.5,'%','Operating Cash Flow Growth (FY26)','A genuine decline in cash generation quality alongside falling earnings.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GAIL','2026-03-31','bull','Natural Gas Transmission, GAIL''s regulated and highest-quality segment, grew EBIT 13.5% YoY — durable, annuity-like earnings that provide a floor under an otherwise volatile business.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GAIL','2026-03-31','bull','City Gas revenue grew 22.3% YoY, the strongest growth vector across all segments, reflecting genuine expansion in household and vehicle gas distribution.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GAIL','2026-03-31','bull','Active capex cycle (gross block additions of ~₹10,071 crore) is building future pipeline capacity and transmission tariff income, which should support a structural re-rating if gas volume throughput scales as planned.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GAIL','2026-03-31','bear','Natural Gas Marketing EBIT crashed 59.3% and Petrochemicals swung to a ₹1,410 crore loss — together these two commodity-linked segments erased more than ₹6,000 crore of EBIT in FY26, overwhelming strength in the regulated businesses.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GAIL','2026-03-31','bear','FY26 dividend payouts exceeded free cash flow and were funded by incremental borrowing — explicitly flagged as unsustainable without an FY27 earnings recovery, a genuine capital allocation concern.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('GAIL','2026-03-31','bear','The Middle East conflict directly hampered gas supply during Q4 FY26, forcing GAIL to buy spot LNG cargoes (including from Oman) to cover shortages — a live, current geopolitical disruption to core operations, not a theoretical risk.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GAIL','The Middle East conflict directly disrupted gas supply in Q4 FY26, forcing GAIL to source spot LNG cargoes including from Oman to cover shortages, a live geopolitical impact on core operations','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GAIL','Natural Gas Marketing spread compression and Petrochemicals losses together erased over ₹6,000 crore of EBIT in FY26, showing how exposed GAIL''s non-regulated segments are to commodity price swings','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('GAIL','India''s structural push toward greater natural gas usage in the energy mix, reflected in City Gas''s 22.3% revenue growth, remains a genuine long-term tailwind for GAIL''s distribution infrastructure','tailwind',TRUE);
