INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('IOC','Indian Oil Corporation','NSE','Oil & Gas','Oil Refining & Marketing (PSU)','Oil & Gas','Indian Oil Corporation refines crude oil into petrol, diesel, LPG, aviation fuel and other products at its extensive refinery network, then sells them through India''s largest fuel retail network, alongside petrochemicals and gas distribution businesses. As India''s largest oil marketing company and a Maharatna PSU, its earnings are driven by refining margins and steady domestic fuel demand.','Indian Oil Corporation FY26 & Q4 FY26 results coverage (InvestyWise, PSU Connect); Screener.in; Yahoo Finance','Scale as India''s largest oil refiner and fuel retailer, with an extensive refinery network and retail distribution footprint built over decades of PSU investment that would be effectively impossible for a private competitor to replicate at comparable scale.','Indian Oil Corporation refines crude oil into petrol, diesel, LPG and other fuels at its extensive refinery network, then sells them through India''s largest retail fuel network, alongside petrochemicals and gas distribution — a fully integrated downstream oil major spanning refining through to the retail pump.','IOC''s scale advantage — both in refining throughput and retail distribution reach — gives it structural cost and market-access advantages that smaller private refiners and marketers cannot easily replicate, even though its pricing remains subject to government policy influence.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('IOC','2026-03-31','revenue_cr',784415,'crore','Revenue (FY26)','The largest company by revenue in this entire dataset.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('IOC','2026-03-31','refinery_throughput_mmt',75.451,'MMT','Refinery Throughput (FY26)','Domestic product sales reached 99.904 MMT for the year.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('IOC','2026-03-31','roe_pct',20.97,'%','Return on Equity','Genuinely strong despite the stock''s very low valuation multiple.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('IOC','2026-03-31','pe_ratio',4.57,'x','P/E Ratio','Extremely cheap, typical of PSU oil marketing companies.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IOC','2026-03-31','bull','IOC''s Q4 FY26 performance remained largely insulated from Middle East supply uncertainty due to strategic inventory procurement completed prior to the geopolitical tensions — genuinely proactive risk management, not luck.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IOC','2026-03-31','bull','Return on equity of 20.97% is strong for a company trading at just 4.57x earnings, a valuation gap that reflects the market''s structural discount on PSU oil marketing companies rather than weak underlying profitability.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IOC','2026-03-31','bull','As India''s largest fuel retail network with 99.904 million tonnes of domestic product sales in FY26, IOC has unmatched scale and distribution reach across the country''s oil marketing landscape.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IOC','2026-03-31','bear','As a PSU oil marketing company, IOC''s fuel pricing and subsidy exposure are ultimately subject to government policy rather than pure market economics, a structural constraint private refiners don''t carry.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IOC','2026-03-31','bear','Refining margins (GRM) remain volatile and dependent on global crude dynamics; analyst estimates for the sector broadly assumed some sequential moderation in profitability due to softer margins even before results were confirmed.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('IOC','2026-03-31','bear','The petrochemicals segment, while smaller than core petroleum products, adds commodity-cycle exposure on top of the already-volatile refining business, similar to challenges seen at peer GAIL elsewhere in this dataset.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IOC','Strategic inventory procurement ahead of Middle East geopolitical tensions in early 2026 insulated IOC''s Q4 FY26 performance from supply disruptions that affected less-prepared competitors','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IOC','Global crude price volatility from West Asia tensions and OPEC+ policy decisions remain the dominant swing factor for IOC''s refining margins and overall profitability','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('IOC','As India''s largest PSU oil marketing company, IOC''s retail fuel pricing carries government policy influence that private-sector refiners do not face, a structural characteristic shared with peers like BPCL elsewhere in this dataset','neutral',TRUE);
