INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('HAVELLS','Havells India','NSE','Consumer Durables','Electrical Equipment & Appliances','Consumer Durables','Havells India manufactures and sells electrical products across 24 product verticals spanning cables, consumer durables (via its Lloyd brand of air conditioners, washing machines, refrigerators and TVs), electrical fans and appliances, switchgears, and lighting & fixtures. It is one of India''s leading electrical equipment companies, selling to both retail consumers and industrial/infrastructure customers.','Havells India FY26 & Q4 FY26 results coverage (InvestyWise); Screener.in','Decades of brand trust across a diversified electrical products portfolio, from industrial cables to consumer appliances, giving Havells resilience across different demand cycles that narrower single-category competitors lack.','Havells manufactures a broad range of electrical products — cables, switchgears, fans, lighting, and consumer appliances under the Lloyd brand — selling through both retail consumer channels and to industrial/infrastructure project customers, giving it exposure to both steady B2B infrastructure demand and more volatile, weather-sensitive consumer demand.','Havells'' strategic investment in Goldi Solar, a solar equipment maker, gives it indirect exposure to India''s renewable energy build-out — a financial link to the same sector already well-represented elsewhere in this dataset (Adani Green, Waaree, Suzlon, NTPC Green), even though Havells itself doesn''t manufacture solar products directly.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HAVELLS','2026-03-31','revenue_growth_pct',3.3,'%','Revenue Growth (FY26)','FY26 revenue reached ₹22,466 crore; growth was modest overall.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HAVELLS','2026-03-31','pat_growth_pct',14.5,'%','PAT Growth (FY26)','Q4 alone grew 40.6%, though significantly boosted by a one-time fair value gain.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HAVELLS','2026-03-31','cables_segment_share_pct',39,'%','Cables Segment Share of Revenue','Up from 33% in FY25 — the largest and fastest-growing segment, driven by industrial infrastructure demand.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('HAVELLS','2026-03-31','lloyd_segment_share_pct',18,'%','Lloyd Consumer (AC/Appliances) Segment Share','Down from 24% in FY25 as a milder summer start hurt cooling product demand.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAVELLS','2026-03-31','bull','Cables, Havells'' largest segment, grew to 39% of FY26 revenue from 33% the prior year, directly benefiting from strong industrial infrastructure demand even as consumer-facing categories softened.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAVELLS','2026-03-31','bull','FY26 PAT grew 14.5% to ₹1,705 crore despite modest revenue growth, reflecting genuine operational discipline; the company also made a strategic ₹600 crore investment in Goldi Solar, a solar equipment maker, diversifying its exposure into renewable energy adjacencies.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAVELLS','2026-03-31','bull','The company continues investing in capacity expansion, particularly in Cables and Refrigerators, positioning for demand recovery once consumer segments like Lloyd stabilise.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAVELLS','2026-03-31','bear','A significant portion of Q4 FY26''s 40.6% PAT growth came from a ₹283 crore fair value gain on the Goldi Solar investment, not core operations — underlying operating profit growth was considerably more modest than the headline number suggests.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAVELLS','2026-03-31','bear','The Lloyd Consumer segment (air conditioners, appliances) fell to 18% of revenue from 24% a year earlier, as a milder start to the summer season directly hurt cooling product stocking and sales — a real, weather-driven demand risk specific to this category.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('HAVELLS','2026-03-31','bear','Overall FY26 revenue growth of just 3.3% is modest for a company in a growing electrical equipment market, suggesting demand headwinds extend beyond just the weather-sensitive Lloyd segment.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HAVELLS','A milder-than-usual start to the FY26 summer season directly reduced cooling product (air conditioner) stocking and demand, a weather-driven risk specific to the Lloyd Consumer segment','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HAVELLS','Strong industrial infrastructure demand drove the Cables segment to its largest-ever share of revenue, reflecting broader momentum in India''s infrastructure and construction capex cycle','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('HAVELLS','A ₹600 crore strategic investment in Goldi Solar gives Havells indirect financial exposure to India''s renewable energy manufacturing boom, a sector with substantial representation elsewhere in this dataset','tailwind',TRUE);
