INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('CGPOWER','CG Power and Industrial Solutions','NSE','Capital Goods','Power & Industrial Equipment','Capital Goods','CG Power and Industrial Solutions manufactures power equipment (transformers, switchgears), industrial motors, and rail transportation systems, and has recently expanded into semiconductor assembly and testing through its CG Semi subsidiary. Part of the Murugappa Group (via Tube Investments of India), it is a major Indian electrical equipment manufacturer undergoing rapid capacity expansion.','CG Power FY26 & Q4 FY26 results coverage (Power Peak Digest, Tickertape); Screener.in','Established brand trust and manufacturing scale in power equipment built over decades under the Murugappa Group umbrella, now reinforced by an early, capital-backed entry into semiconductor assembly and testing — a genuinely differentiated diversification most power equipment peers lack.','CG Power manufactures transformers, switchgears and industrial motors sold to utilities, industrial customers and infrastructure developers, plus rail transportation equipment, and has now added semiconductor assembly and testing services — positioning it both as a traditional power equipment supplier and an emerging participant in India''s electronics manufacturing supply chain.','The move into semiconductor assembly and testing (via CG Semi) is a genuine strategic diversification beyond CG Power''s traditional power equipment business, positioning it to benefit from India''s government-backed semiconductor manufacturing push — a structurally different growth vector than its legacy transformer and motor businesses.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('CGPOWER','2026-03-31','revenue_growth_pct',25,'%','Revenue Growth (FY26, Consolidated)','Standalone FY26 revenue grew 21% to ₹11,331 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('CGPOWER','2026-03-31','pat_growth_pct',39,'%','PAT Growth (FY26, before exceptional items)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('CGPOWER','2026-03-31','order_backlog_cr',15719,'crore','Unexecuted Order Backlog (Standalone)','Power Systems backlog alone stands at ₹12,644 crore, giving multi-quarter revenue visibility.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('CGPOWER','2026-03-31','working_capital_days',81.6,'days','Working Capital Days','Up sharply from 35.3 days — a genuine cash-conversion concern amid rapid growth.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CGPOWER','2026-03-31','bull','FY26 consolidated revenue grew 25% to ₹12,418 crore with PAT (before exceptional items) up 39% to ₹1,352 crore, and an unexecuted order backlog of ₹15,719 crore — led by a ₹12,644 crore Power Systems backlog — gives exceptional multi-quarter revenue visibility.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CGPOWER','2026-03-31','bull','Transformer capacity has been ramped from ~17-18k MVA to nearly 65k MVA, targeting roughly 110,000 MVA by year-end, directly capturing India''s power infrastructure build-out demand.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CGPOWER','2026-03-31','bull','CG Semi, the company''s new semiconductor assembly and test subsidiary, commissioned its first facility in Sanand, Gujarat in August 2025 with a second facility underway — a genuine, early-mover position in India''s emerging semiconductor manufacturing ecosystem, backed by a ₹3,000 crore QIP raise.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CGPOWER','2026-03-31','bear','Working capital days nearly tripled from 35.3 to 81.6 — a significant deterioration in cash conversion that often accompanies rapid growth but deserves close monitoring as a potential early warning sign.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CGPOWER','2026-03-31','bear','Investments in the new semiconductor vertical are weighing on near-term margins, and the Industrial Systems segment faces margin pressure from product-mix shifts, competitive rail pricing, and higher material costs.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('CGPOWER','2026-03-31','bear','At a P/E near 124x, the stock prices in years of continued exceptional execution across both its traditional power equipment business and its unproven new semiconductor venture — a demanding valuation with little room for missteps.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CGPOWER','India''s semiconductor manufacturing push, backed by government incentives, is driving CG Power''s diversification into chip assembly and testing through its new CG Semi subsidiary — an early-mover position in a strategically important emerging industry','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CGPOWER','Massive transformer capacity expansion (from ~17-18k MVA toward a targeted 110,000 MVA) directly positions CG Power to capture India''s accelerating power infrastructure investment cycle','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('CGPOWER','Working capital days nearly tripling during a period of rapid growth is a pattern worth monitoring closely, as it can signal either temporary growth-related strain or a more structural cash conversion problem','risk',TRUE);
