INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('LTIM','LTIMindtree','NSE','IT Services','IT Services & Consulting','IT Services','LTIMindtree provides IT services and consulting across digital transformation, cloud, data and enterprise applications for global clients, as a subsidiary of the Larsen & Toubro Group. It is India''s sixth-largest IT services provider by market capitalisation, formed from the 2022 merger of L&T Infotech and Mindtree.','LTIMindtree Q4 FY26 results coverage (MarketsMojo); Screener.in','Scale as India''s sixth-largest IT services provider with an asset-light, high-return business model (ROCE near 49%), backed by the Larsen & Toubro Group''s brand and relationships, though operating in a competitive market without a structural moat beyond talent and client relationships.','LTIMindtree provides IT services, consulting and digital transformation work to global enterprise clients, converting skilled technology talent into billable services — an asset-light, people-driven business model positioned downstream of client technology budgets rather than any physical supply chain.','As a Larsen & Toubro Group subsidiary, LTIMindtree benefits from the parent''s brand and potential cross-referral relationships, though it operates independently in the globally competitive IT services market alongside peers like TCS, Infosys, HCLTech, Wipro and Tech Mahindra elsewhere in this dataset.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LTIM','2026-03-31','revenue_growth_pct',15.56,'%','Revenue Growth (Q4 YoY)','Q4 FY26 revenue of ₹11,291.70 crore — the highest quarterly sales in company history.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LTIM','2026-03-31','pat_growth_pct',23.38,'%','PAT Growth (Q4 YoY)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LTIM','2026-03-31','operating_margin_pct',17.47,'%','Operating Margin (Q4)','Down from 18.58% the prior quarter — a 111 basis point sequential compression.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LTIM','2026-03-31','roce_pct',48.78,'%','Return on Capital Employed','Reflects an asset-light business model earning nearly ₹49 for every ₹100 of capital employed.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LTIM','2026-03-31','bull','Q4 FY26 revenue reached an all-time high of ₹11,291.70 crore (+15.56% YoY), with consolidated PAT growing even faster at 23.38% YoY — genuine, accelerating momentum rather than a one-off beat.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LTIM','2026-03-31','bull','Return ratios are exceptional: average ROE of 26.97% and ROCE of 48.78% reflect a highly capital-efficient, asset-light business model that significantly outperforms many IT services peers.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LTIM','2026-03-31','bull','A comfortable current ratio above 3.5x and growing treasury investments reflect a genuinely strong balance sheet, providing ample liquidity to fund growth initiatives without financial strain.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LTIM','2026-03-31','bear','Operating margin compressed 111 basis points sequentially to 17.47%, driven by employee costs rising to 61.03% of revenue — wage inflation and talent retention costs are outpacing revenue growth, a genuine and persistent margin headwind.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LTIM','2026-03-31','bear','Despite strong operational performance, the stock has fallen 29.13% year-to-date, reflecting a significant disconnect between fundamentals and market sentiment that investors should understand rather than dismiss.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LTIM','2026-03-31','bear','FY26 operating margins averaged only marginally higher than FY25''s, showing that despite healthy revenue growth, the company has struggled to meaningfully expand margins in an increasingly competitive IT services market.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LTIM','Rising employee costs (61.03% of revenue, up from 60.75%) reflect ongoing wage inflation and talent retention pressures across the Indian IT services industry, directly compressing margins despite strong revenue growth','risk',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LTIM','Record quarterly revenue despite a challenging global macro environment for technology spending suggests LTIMindtree is winning market share even as overall IT budgets remain cautious','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LTIM','A significant disconnect between strong operational results and a 29.13% year-to-date stock decline suggests broader IT services sector sentiment concerns are weighing on the stock beyond company-specific fundamentals','neutral',TRUE);
