INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('ENRIN','Siemens Energy India','NSE','Power','Power Transmission & Generation Equipment (MNC)','Power','Siemens Energy India designs and supplies power transmission and power generation equipment, including grid technologies and turbines, to utilities and industrial customers. The company was demerged from Siemens Ltd''s India operations in March 2025, becoming an independently listed entity focused specifically on the energy equipment business that Siemens Ltd previously housed internally.','Siemens Energy India results coverage (Business Standard, ScanX); Screener.in','Siemens global engineering technology and brand trust in power transmission and generation equipment, combined with deep, longstanding utility customer relationships inherited from its time as part of Siemens Ltd''s India operations.','Siemens Energy India manufactures and supplies power transmission equipment (grid technologies, transformers) and power generation equipment (turbines) to utility and industrial customers, positioning it as a critical equipment supplier to the same power generation and transmission companies covered elsewhere in this dataset.','As a demerged entity from Siemens Ltd (also in this dataset), Siemens Energy India''s separate listing is itself a real, current structural event — the two companies share a corporate history but now operate, report and trade completely independently, a useful example of how corporate structures in this dataset can change over time.','Quarter ended Mar 2026 (SEIL follows an Oct-Sep fiscal year)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ENRIN','2026-03-31','revenue_growth_pct',27.4,'%','Revenue Growth (Quarter YoY)','Revenue of ₹2,394 crore for the quarter ended March 2026.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ENRIN','2026-03-31','pat_growth_pct',52.4,'%','PAT Growth (Quarter YoY)','Net profit of ₹375 crore, up from ₹246 crore a year earlier.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('ENRIN','2026-03-31','order_backlog_growth_pct',22.2,'%','Order Backlog Growth (YoY)','Order backlog expanded to ₹18,433 crore.','verified');
