INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ENRIN','2026-03-31','bull','Revenue grew 27.4% and net profit surged 52.4% YoY for the quarter ended March 2026, with EBIT margin improving 160 basis points YoY — genuine, accelerating profitable growth since becoming independently listed.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ENRIN','2026-03-31','bull','Order backlog expanded 22.2% YoY to ₹18,433 crore, driven by robust growth in both Power Transmission and Power Generation segments, providing strong multi-quarter revenue visibility.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ENRIN','2026-03-31','bull','The company is investing in significant capacity expansion — including a new Greenfield Transformer factory — directly positioning it to capture India''s accelerating power infrastructure and grid modernisation investment cycle.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ENRIN','2026-03-31','bear','As a newly demerged entity (separated from Siemens Ltd in March 2025), Siemens Energy India has limited independent trading history, making multi-year historical comparisons and valuation benchmarking genuinely difficult.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ENRIN','2026-03-31','bear','At a P/B ratio of 26.3x, the stock is priced at a significant premium, leaving little room for execution missteps as the company builds out its independent operating track record.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('ENRIN','2026-03-31','bear','New Power Transmission orders showed a sequential decline in the first half of the fiscal year compared to the prior year, raising questions about whether order intake momentum can be sustained at the pace embedded in current valuations.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ENRIN','India''s grid modernisation and power infrastructure investment cycle is directly driving order growth for Siemens Energy India''s transmission and generation equipment, mirroring the capacity expansion themes seen at power sector peers elsewhere in this dataset','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ENRIN','As a recently demerged, independently listed entity, the company''s short trading history and evolving investor understanding of its standalone financials add a distinct layer of valuation uncertainty','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('ENRIN','Investment in a new Greenfield Transformer factory signals confidence in sustained multi-year demand for grid equipment as India''s transmission network expands to accommodate renewable energy integration','tailwind',TRUE);
