INSERT INTO companies (ticker,name,exchange,sector,sub_sector,compare_group,business_core,source_note,moat_note,value_chain_position,value_chain_note,as_of,fetched_at) VALUES ('LODHA','Lodha (Macrotech Developers)','NSE','Realty','Residential Real Estate Developer','Realty','Lodha (formerly Macrotech Developers) develops residential and commercial real estate primarily in Mumbai, Pune and Bengaluru, under the LODHA, LODHA LUXURY and PALAVA brand names, with recent expansion into Delhi NCR. It is one of India''s largest listed real estate developers by pre-sales, with a stated goal of accelerating both sales and profit growth over the coming years.','Lodha (Macrotech Developers) FY26 results coverage (5paisa, company Q4 FY26 earnings transcript); Screener.in','A premium brand built over decades in India''s most valuable residential real estate markets (Mumbai Metropolitan Region), combined with a large land bank and demonstrated execution capability that new entrants would need many years and enormous capital to replicate.','Lodha acquires land, develops residential and commercial real estate projects, and sells completed or under-construction units to homebuyers and investors, primarily in India''s most expensive metro markets (Mumbai, Pune, Bengaluru, and now Delhi NCR) — a large-scale, brand-driven residential developer positioned at the premium end of India''s real estate market.','Lodha''s expansion into Delhi NCR represents a genuine geographic diversification beyond its historical Mumbai Metropolitan Region stronghold, a strategic shift that broadens its addressable market but also introduces execution risk in markets where the brand has less established presence.','FY26 (year ended 31 Mar 2026)','2026-07-03');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LODHA','2026-03-31','presales_growth_pct',28,'%','Pre-Sales CAGR (FY21-FY26)','Pre-sales grew from ₹6,000 crore (FY21) to ₹20,500 crore (FY26).','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LODHA','2026-03-31','pat_growth_pct',24.02,'%','PAT Growth (FY26)','FY26 PAT reached ₹3,431 crore.','verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LODHA','2026-03-31','pat_margin_pct',20,'%','PAT Margin (FY26)',NULL,'verified');
INSERT INTO metric_snapshots (ticker,snapshot_date,metric_key,metric_value,metric_unit,metric_label,metric_note,status) VALUES ('LODHA','2026-03-31','roe_pct',13.8,'%','Return on Equity','Modest relative to the company''s strong reported margins, reflecting a large capital base.','verified');
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LODHA','2026-03-31','bull','FY26 pre-sales reached ₹20,500 crore, a 28% CAGR since FY21''s COVID-low base of ₹6,000 crore, with PAT growing more than six-fold over the same period to ₹3,431 crore at a 20% margin.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LODHA','2026-03-31','bull','Management has set an explicit medium-term target of 20% PAT CAGR, aiming to grow annual profit from ₹3,400 crore (FY26) to more than ₹8,500 crore by FY31 — a clearly communicated, ambitious growth roadmap.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LODHA','2026-03-31','bull','The company is actively expanding beyond its core Mumbai/Pune/Bengaluru markets into Delhi NCR, with ~₹19,000 crore of new project launches planned across its existing core cities, diversifying its geographic growth base.',3);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LODHA','2026-03-31','bear','Return on equity of just 13.8% is modest for a company reporting 20% PAT margins, suggesting a large capital base that isn''t yet generating proportionate shareholder returns — worth watching as the company scales.',1);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LODHA','2026-03-31','bear','A former director of the company (prior to its rename from Macrotech Developers) was reported arrested by Mumbai crime branch on matters unrelated to routine business operations — while not a company-wide financial concern, it is a governance matter worth being aware of.',2);
INSERT INTO bull_bear_cases (ticker,snapshot_date,case_type,case_text,case_order) VALUES ('LODHA','2026-03-31','bear','Real estate developer earnings are inherently tied to property market cycles and project completion timing; sustaining a 20% PAT CAGR through FY31 requires consistent execution across multiple new geographic markets simultaneously.',3);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LODHA','India''s premium residential real estate upcycle continues to support strong pre-sales growth for established developers with strong brands and execution track records, mirroring trends seen at peer DLF elsewhere in this dataset','tailwind',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LODHA','Expansion into Delhi NCR, a new geographic market, tests whether Lodha''s Mumbai-honed brand and execution model can be successfully replicated in a market with different dynamics and established local competitors','neutral',TRUE);
INSERT INTO tech_geo_tags (ticker,label,tag_type,is_active) VALUES ('LODHA','Management''s explicit 20% PAT CAGR target through FY31 sets a clear, trackable benchmark against which future performance can be measured — a level of forward guidance specificity that''s relatively rare in Indian real estate','neutral',TRUE);
